// Storage Code For Pan and Zoom

void mainImage(out vec4 fragColor, in vec2 fragCoord) {
    // Default output for unused pixels
    fragColor = texelFetch(iChannel0, ivec2(fragCoord), 0);

    // Pan State at (0,0)
    if (ivec2(fragCoord.xy) == ivec2(0, 0)) {
        vec4 prev_info = textureLod(iChannel0, vec2(0.0, 0.0), 0.0);
        float Zoom =
            textureLod(iChannel0, vec2(10.5, 10.5) / iResolution.xy, 0.0).x;
        float prev_pan_x = prev_info.x;
        float prev_pan_y = prev_info.y;
        float legacy_pan_x = prev_info.z;
        float legacy_pan_y = prev_info.w;

        float pan_x = (iMouse.x - abs(iMouse.z)) * Zoom + legacy_pan_x;
        float pan_y = (iMouse.y - abs(iMouse.w)) * Zoom + legacy_pan_y;

        if (iMouse.z < 0.0) {
            legacy_pan_x = prev_pan_x;
            legacy_pan_y = prev_pan_y;
            pan_x = legacy_pan_x;
            pan_y = legacy_pan_y;
        }
        fragColor = vec4(pan_x, pan_y, legacy_pan_x, legacy_pan_y);
    }

    // Zoom State at (10,10)
    if (ivec2(fragCoord.xy) == ivec2(10, 10)) {
        float x =
            textureLod(iChannel0, vec2(10.5, 10.5) / iResolution.xy, 0.0).y;
        x += ReadKey(Key_W) - ReadKey(Key_S);
        float Zoom = pow(2.71, -x * 0.05);
        fragColor = vec4(Zoom, x, 0.0, 0.0);
    }

    // Animation State at (1,0)
    if (ivec2(fragCoord.xy) == ivec2(1, 0)) {
        // Read previous animation state
        float prev_anim_t = texelFetch(iChannel0, ivec2(1, 0), 0).x;

        float key_a = ReadKey(Key_A);
        float key_b = ReadKey(Key_B);

        float target_t = 0.0;
        if (key_a > 0.0) {
            target_t = 1.0;
        } else if (key_b > 0.0) {
            target_t = -1.0;
        }
        float speed = 1.;
        float anim_t =
            mix(prev_anim_t, target_t, 1.0 - exp(-iTimeDelta * speed));
        fragColor = vec4(anim_t, 0.0, 0.0, 1.0);
    }
    if (ivec2(fragCoord.xy) == ivec2(2, 0)) {
        vec4 prev_c_state = texelFetch(iChannel0, ivec2(2, 0), 0);
        float k_from = prev_c_state.x;
        float k_to = prev_c_state.y;
        float anim_timer = prev_c_state.z;
        float prev_key_c_state = prev_c_state.w;

        float key_c = ReadKey(Key_C);
        if (anim_timer < 1.0) {
            float anim_speed = 1.;
            anim_timer += iTimeDelta * anim_speed;
        }
        anim_timer = min(anim_timer, 1.0);

        if (key_c > 0.0 && prev_key_c_state == 0.0 && anim_timer >= 1.0) {
            k_from = k_to;
            k_to = mod(k_to + 1.0, 16.0);
            anim_timer = 0.0;
        }

        fragColor = vec4(k_from, k_to, anim_timer, key_c);
    }
    if (ivec2(fragCoord.xy) == ivec2(3, 0)) {
        float current_mode = texelFetch(iChannel0, ivec2(3, 0), 0).x;
        if (iFrame < 2)
            current_mode = 0.0;
        if (ReadKey(Key_1) > 0.0)
            current_mode = 0.0;
        if (ReadKey(Key_2) > 0.0)
            current_mode = 1.0;
        if (ReadKey(Key_3) > 0.0)
            current_mode = 2.0;

        fragColor = vec4(current_mode, 0.0, 0.0, 1.0);
    }
    if (ivec2(fragCoord.xy) == ivec2(4, 0)) {
        vec4 prev_state = texelFetch(iChannel0, ivec2(4, 0), 0);
        float current_toggle = prev_state.x;
        float prev_key_c_state = prev_state.y;

        float key_c = ReadKey(Key_C);
        if (key_c > 0.0 && prev_key_c_state == 0.0) {
            current_toggle = 1.0 - current_toggle;
        }
        fragColor = vec4(current_toggle, key_c, 0.0, 1.0);
    }
}

/*
Mapping Class Group of the Torus and Sturmian words


Left-hand side of the UI:

**SLOPE**:

A geodesic with slope p/q. This is a periodic orbit in the
square, and a closed geodesic on the torus:
it winds around the horizontal circle q times and the
vertical circle p times on the torus.

**TWIST**: Any matrix in SL(2,Z). It acts on the torus and
its geodesics, sending a geodesic line with slope p/q to
a geodesic with slope M * (p/q,1). On the right-hand 3D
view, you can see how this twists the torus and changes
the geodesic.

**Sturmian word**: Each time the geodesic crosses a
vertical edge of the square, we write down A; each time
it crosses a horizontal edge, we write down B.
This produces an infinite sequence of A's and B's,
called a Sturmian word. When the slope is rational,
the Sturmian word has a finite repetend, which contains exactly
q A's and p B's. This repetend is displayed right below
the TWIST matrix.

At the bottom of the UI, you see the geodesic inside the square.

The Sturmian word depends on both the slope p/q and
the starting position of the geodesic inside the square.
I chose the starting position at (0.9, 0.0) so that the
results match those shown on page 325 of Indra’s Pearls.
*/

#define AA 3

const float TUBE_RADIUS = 0.035;
const float MAX_DIST = 100.0;
const float SURF_DIST = 0.001;
const vec2 start_pos = vec2(0.9, 0.);

int gcd(int a, int b) {
    a = abs(a);
    b = abs(b);
    while (b != 0) {
        int temp = b;
        b = a % b;
        a = temp;
    }
    return (a == 0) ? 1 : a;
}
float sdTorus(vec3 p, vec2 t) {
    vec2 q = vec2(length(p.xz) - t.x, p.y);
    return length(q) - t.y;
}

float sdGeodesicTube(vec3 pos, vec2 tor, float p_t, float q_t, float offset_angle) {
    float d_torus = sdTorus(pos, tor);
    float u = atan(pos.z, pos.x);
    float v = atan(pos.y, length(pos.xz) - tor.x + 1e-9);
    float val = p_t * (u / (2. * PI)) - q_t * (v / (2. * PI)) + offset_angle;

    float d_line = fract(val);
    d_line = min(d_line, 1.0 - d_line);
    float n = length(vec2(p_t, q_t));
    if (n < 0.1)
        n = 1.;
    float d_geodesic = tor.y * d_line * 2.0 * PI / n;
    return length(vec2(d_torus, d_geodesic)) - TUBE_RADIUS;
}

vec2 map(vec3 pos, vec2 tor, float p_t, float q_t, float offset_angle) {
    float dt = sdTorus(pos, tor);
    float dtu = sdGeodesicTube(pos, tor, p_t, q_t, offset_angle);
    if (dtu < dt)
        return vec2(dtu, 2.);
    return vec2(dt, 1.);
}

// MODIFIED: Pass offset_angle through
vec3 calcNormal(vec3 pos, vec2 tor, float p_t, float q_t, float offset_angle) {
    vec2 e = vec2(.001, 0.);
    float d = map(pos, tor, p_t, q_t, offset_angle).x;
    return normalize(vec3(d - map(pos - e.xyy, tor, p_t, q_t, offset_angle).x,
                          d - map(pos - e.yxy, tor, p_t, q_t, offset_angle).x,
                          d - map(pos - e.yyx, tor, p_t, q_t, offset_angle).x));
}

// MODIFIED: Pass offset_angle through
vec2 raymarch(vec3 ro, vec3 rd, vec2 tor, float p_t, float q_t, float offset_angle) {
    float t = 0., m = -1.;
    for (int i = 0; i < 100; i++) {
        vec3 p = ro + t * rd;
        vec2 res = map(p, tor, p_t, q_t, offset_angle);
        float d = res.x;
        if (!(d > -1000. && d < 1000.))
            break;
        m = res.y;
        if (d < SURF_DIST || t > MAX_DIST)
            break;
        t += d;
    }
    if (t > MAX_DIST)
        t = -1.;
    return vec2(t, m);
}

mat2 getAnimatedMatrix(out mat2 M_inv, out float show_cross) {
    vec2 active_ab = texelFetch(iChannel0, REG_ACTIVE_MATRIX_AB, 0).xy;
    vec2 active_cd = texelFetch(iChannel0, REG_ACTIVE_MATRIX_CD, 0).xy;
    vec2 old_active_ab = texelFetch(iChannel0, REG_OLD_ACTIVE_MATRIX_AB, 0).xy;
    vec2 old_active_cd = texelFetch(iChannel0, REG_OLD_ACTIVE_MATRIX_CD, 0).xy;
    vec4 anim_state = texelFetch(iChannel0, REG_ANIM_TIMER, 0);
    float anim_timer = anim_state.x;
    show_cross = anim_state.y;
    mat2 M_old = mat2(old_active_ab.x, old_active_cd.x, old_active_ab.y,
                      old_active_cd.y);
    mat2 M_new = mat2(active_ab.x, active_cd.x, active_ab.y, active_cd.y);
    float t = smoothstep(0.0, 1.0, anim_timer);
    mat2 M_anim = M_old * (1.0 - t) + M_new * t;
    float det = determinant(M_anim);
    if (abs(det) > 0.0001) {
        M_inv = inverse(M_anim);
    } else {
        M_inv = mat2(1.0);
    }
    return M_anim;
}

int generateSturmianWord(vec2 slope, out int word[MAX_WORD_LEN]) {
    ivec2 s_int = ivec2(round(abs(slope)));
    int common_divisor = gcd(s_int.x, s_int.y);
    s_int /= common_divisor;
    int p = s_int.x; // p is vertical component
    int q = s_int.y; // q is horizontal component
    if (p < 0 || q < 0)
        return 0;
    if (p == 0 && q == 0)
        return 0;

    // If horizontal component (q) is 0, path is vertical, only crosses horizontal edges -> 'B'
    if (q == 0) {
        word[0] = 66; // 'B'
        return 1;
    }
    // If vertical component (p) is 0, path is horizontal, only crosses vertical edges -> 'A'
    if (p == 0) {
        word[0] = 65; // 'A'
        return 1;
    }

    int len = p + q;
    int loop_len = min(len, MAX_WORD_LEN);
    float x0 = start_pos.x;
    float y0 = start_pos.y;
    int ix = 0;
    int iy = 0;
    for (int i = 0; i < loop_len; ++i) {
        // This condition correctly gives q 'A's and p 'B's
        if (float(p) * (float(ix) + 1.0 - x0) <
            float(q) * (float(iy) + 1.0 - y0)) {
            word[i] = 65; // 'A' for crossing vertical edge
            ix++;
        } else {
            word[i] = 66; // 'B' for crossing horizontal edge
            iy++;
        }
    }
    return loop_len;
}

vec3 render_scene(vec2 fragCoord, vec2 resolution, float p, float q,
                  vec2 camera_rot) {
    mat2 M_inv;
    float show_cross_unused;
    mat2 M_anim = getAnimatedMatrix(M_inv, show_cross_unused);
    ivec2 slope_int = ivec2(round(p), round(q));
    int common_divisor = gcd(slope_int.x, slope_int.y);
    vec2 reduced_slope = vec2(slope_int) / float(common_divisor);
    vec2 twisted_slope = M_anim * reduced_slope;
    float p_twisted = twisted_slope.x;
    float q_twisted = twisted_slope.y;

    bool p_is_zero = abs(p_twisted) < 1e-6;
    bool q_is_zero = abs(q_twisted) < 1e-6;
    float offset_for_3d = 1.0/sqrt(2.0) * PI;
    if (p_is_zero || q_is_zero) {
        offset_for_3d = 0.0;
    }

    float yaw = camera_rot.x;
    float pitch = camera_rot.y;
    if (iMouse.z <= 0.0) {
        yaw += iTime * 0.3;
    }
    float dist = 3.0;
    vec3 ro;
    ro.x = dist * cos(pitch) * sin(yaw);
    ro.y = dist * sin(pitch);
    ro.z = dist * cos(pitch) * cos(yaw);
    ro.y += 0.5;
    vec3 ta = vec3(0.0, -0.1, 0.0);
    vec3 ww = normalize(ta - ro);
    vec3 uu = normalize(cross(ww, vec3(0.0, 1.0, 0.0)));
    vec3 vv = normalize(cross(uu, ww));
    vec2 p_scene = (-resolution + 2.0 * fragCoord) / resolution.y;
    vec3 rd = normalize(p_scene.x * uu + p_scene.y * vv + 1.5 * ww);
    vec2 torus = vec2(1.0, 0.5);
    vec2 hit = raymarch(ro, rd, torus, p_twisted, q_twisted, offset_for_3d);
    float t = hit.x;
    float materialID = hit.y;
    vec3 col = vec3(0.08) * (1.0 - 0.3 * length(p_scene)) + 0.02 * rd.y;
    if (t > 0.0) {
        vec3 pos = ro + t * rd;
        vec3 nor = calcNormal(pos, torus, p_twisted, q_twisted, offset_for_3d);
        vec3 lig = normalize(vec3(0.7, 0.6, 0.3));
        vec3 hal = normalize(-rd + lig);
        float dif = clamp(dot(nor, lig), 0.0, 1.0);
        float amb = clamp(0.7, 0.0, 1.0) + 0.3 * nor.y;
        if (materialID > 1.5) {
            col = UI_ACCENT_COLOR;
            col = col * (amb * 0.3 + dif * 0.7);
            float spe = pow(clamp(dot(nor, hal), 0.0, 1.0), 32.0);
            col += vec3(1.0) * spe * 0.5;
        } else {
            const float fr = 16.0;
            vec2 uv =
                vec2(atan(pos.z, pos.x), atan(pos.y, length(pos.xz) - torus.x));
            vec2 transformed_uv = M_inv * (uv / (2.0 * PI));
            vec2 scaled_uv = transformed_uv * fr;
            vec2 iuv = floor(scaled_uv);
            float checker_pattern = mod(iuv.x + iuv.y, 2.0);
            vec3 base_col = (checker_pattern > 0.5) ? vec3(1.0) : vec3(0.6);
            vec2 fuv = fract(scaled_uv);
            vec2 dist_to_edge = min(fuv, 1.0 - fuv);
            float dist_to_line = min(dist_to_edge.x, dist_to_edge.y);
            float line_width = 0.02;
            float aa = fwidth(dist_to_line) * 1.5;
            float line_intensity =
                1.0 -
                smoothstep(line_width - aa, line_width + aa, dist_to_line);
            vec3 line_color = vec3(0.1);
            col = mix(base_col, line_color, line_intensity);
            col *=
                vec3(0.15, 0.25, 0.35) * amb + 1.05 * vec3(1.0, 0.9, 0.7) * dif;
        }
    }
    return sqrt(col);
}

