//The implicit function -------------------------------------
//This is a degree 6 algebraic implicit function discovered by Barth.
float Barth(float x, float y, float z){
float f = pow(x * pow(x - 1.0, 2.0) * (x - 2.0) + y*y, 2.0) + z*z - 0.005;
return f;
}

