    // 棋盘格的密度
    float scale = 4.0;

    // 计算三维棋盘格的值
    // mod(floor(x*s) + floor(y*s) + floor(z*s), 2.0)
    float checker = mod(floor(p.x * scale) + floor(p.y * scale) + floor(p.z * scale), 2.0);

    // 定义两种颜色
    vec3 color1 = vec3(0.2, 0.3, 1.0); // 蓝色
    vec3 color2 = vec3(1.0, 0.8, 0.2); // 黄色

    // 根据棋盘格的值选择颜色
    vec3 final_color;
    if (checker > 0.5) {
        final_color = color1;
    } else {
        final_color = color2;
    }

    return final_color;
}

