def Dervish(x,y,z):
   z=-z
   c=math.sqrt(5-math.sqrt(5))/2                            #constant
   r=(1+3*math.sqrt(5))/4
   q=(1-c*z)*(x**2+y**2-1+r*z**2)**2;                       #not a constant
   a=-(8/5)*(1+1/math.sqrt(5))*math.sqrt(5-math.sqrt(5))    
   Pi=math.pi
   h1=x-z
   h2=cos(2*Pi/5)*x-sin(2*Pi/5)*y-z                         #hopefully the autodiff fully computes the constants in this case
   h3=cos(4*Pi/5)*x-sin(4*Pi/5)*y-z
   h4=cos(6*Pi/5)*x-sin(6*Pi/5)*y-z
   h5=cos(8*Pi/5)*x-sin(8*Pi/5)*y-z
   FF=h1*h2*h3*h4*h5
   return a*FF+q

