float isInside(vec2 p, vec2 vs[MAX_VERTICES], int n) {
    bool c = false;
    for (int i = 0, j = n - 1; i < n; j = i++) {
        if (((vs[i].y > p.y) != (vs[j].y > p.y)) &&
            (p.x < (vs[j].x - vs[i].x) * (p.y - vs[i].y) / (vs[j].y - vs[i].y) + vs[i].x)) {
            c = !c;
        }
    }
    return float(c);
}

float distToSegment(vec2 p, vec2 a, vec2 b) {
    vec2 pa = p - a, ba = b - a;
    float h = clamp(dot(pa, ba) / dot(ba, ba), 0.0, 1.0);
    return length(pa - ba * h);
}

float distToPath(vec2 p, vec2 vs[MAX_VERTICES], int n, bool closed) {
    float d = 1e10;
    for (int i = 0; i < n - 1; i++) {
        d = min(d, distToSegment(p, vs[i], vs[i+1]));
    }
    if (closed && n > 1) {
        d = min(d, distToSegment(p, vs[n-1], vs[0]));
    }
    return d;
}

vec3 drawFilledPoly(vec3 back_col, vec3 poly_col, float inside_val, float aa) {
    return mix(back_col, poly_col, smoothstep(0.5 - aa, 0.5 + aa, inside_val));
}

vec3 drawStrokedPath(vec3 back_col, vec3 stroke_col, float dist, float width, float aa) {
    return mix(back_col, stroke_col, 1.0 - smoothstep(width - aa, width + aa, dist));
}

