// Shadertoy-ready fragment shader
// Visualizes limit-set-like packing of mutually tangent spheres
// for the 3-generator 4D-Kleinian family discussed in Sakugawa (2010).
// (Paper: "On Limit Sets of 4-dimensional Kleinian Groups with 3 Generators").
// See: Sakugawa, Keita. (2010). (PDF used as reference.) :contentReference[oaicite:3]{index=3}
//
// NOTES:
// - We implement quaternion arithmetic (quat as vec4: w + x i + y j + z k).
// - Boundary points in R^3 are represented as quaternions with k-part = 0:
//   u = u0 + u1*i + u2*j  <-> vec4(u0, u1, u2, 0).
// - Generators g,h are parabolic translations; f is set using "typical example"
//   parameterization from the paper (engineered to satisfy determinant condition numerically).
// - For rendering we use an inverse-iterate distance-estimator:
//   repeatedly apply inverses of generators to bring a sample point closer to base sphere P0,
//   measure minimal distance to P0 seen during iteration -> use as DE.
//
// Uniforms provided by Shadertoy: iResolution, iTime, mouse etc.

// ---------- user parameters ----------
const float PI = 3.141592653589793;

// parameters (t,p) from paper
// t: real parameter (|t| >= 1 recommended)
// p: complex number on unit circle; p = i -> (0,1) in complex plane
// We encode p as quaternion with only i-part nonzero: (real, i, j, k) = (p_re, p_im, 0, 0)
const float PARAM_t = 2.8;         // change to try different t
const vec2  PARAM_p_complex = vec2(0.0, 1.0); // p = (0 + 1 i) -> equals i

// rendering params
const int   MAX_MARCH_STEPS = 120;
const float MARCH_EPS = 0.001;
const float MAX_DIST = 200.0;
const int   ITER_GROUP = 30;      // inverse-iteration depth (higher -> more detail, slower)
const int   BRANCHES = 4;         // number of inverse generators to try per step
const float SPHERE_BASE_RADIUS = 0.5; // radius of base invariant sphere P0 (engineered)
const float BASE_SPHERE_OFFSET = 0.0; // y-offset of base sphere center relative to f^{-1}(infty) (we set origin-aligned)

// ---------- quaternion utilities (vec4: r,i,j,k) ----------
vec4 q_add(vec4 a, vec4 b){ return a + b; }
vec4 q_neg(vec4 a){ return -a; }
vec4 q_conj(vec4 a){ return vec4(a.x, -a.y, -a.z, -a.w); }
float q_norm2(vec4 a){ return dot(a,a); }
vec4 q_mul(vec4 a, vec4 b){
    // Hamilton product (a)(b)
    return vec4(
        a.x*b.x - a.y*b.y - a.z*b.z - a.w*b.w,
        a.x*b.y + a.y*b.x + a.z*b.w - a.w*b.z,
        a.x*b.z - a.y*b.w + a.z*b.x + a.w*b.y,
        a.x*b.w + a.y*b.z - a.z*b.y + a.w*b.x
    );
}
vec4 q_scale(vec4 a, float s){ return a * s; }
vec4 q_inv(vec4 a){
    float n2 = q_norm2(a);
    if(n2 < 1e-12) return vec4(1e6,0,0,0);
    return q_scale(q_conj(a), 1.0/n2);
}

// convert R^3 point (x,y,z) to quaternion used in paper mapping:
// paper uses v0 + v1 i + v2 j, so map (x,y,z) -> (v0=x, v1=y, v2=z, k=0)
vec4 vec3_to_quat(vec3 p){ return vec4(p.x, p.y, p.z, 0.0); }
vec3 quat_to_vec3(vec4 q){ return vec3(q.x, q.y, q.z); }

// quaternion "affine" add for convenience: q_mul(qx,u) + qy
vec4 q_mul_add(vec4 a, vec4 b, vec4 add){ return q_add(q_mul(a,b), add); }

// ---------- 2x2 quaternion-matrix Möbius action on boundary point u in R^3 ----------
// M = [ x  y ; z  w ] acts on u (a quaternion) by (x*u + y) * (z*u + w)^{-1}
// returns a quaternion; we then convert to R^3 (taking r,i,j)
vec4 mobius_apply(vec4 x, vec4 y, vec4 z, vec4 w, vec4 u){
    vec4 num = q_add( q_mul(x, u), y );
    vec4 den = q_add( q_mul(z, u), w );
    vec4 deninv = q_inv(den);
    return q_mul(num, deninv);
}

// ---------- build group generators from paper (engineered approximations) ----------
// g = [[1,1],[0,1]]
// h = [[1,p],[0,1]] where p is complex (p0 + p1 i)
void build_generators(out vec4 fx, out vec4 fy, out vec4 fz, out vec4 fw,
                      out vec4 gx, out vec4 gy, out vec4 gz, out vec4 gw,
                      out vec4 hx, out vec4 hy, out vec4 hz, out vec4 hw){
    // identity quaternion 1
    vec4 Q1 = vec4(1.0,0.0,0.0,0.0);
    // g
    gx = Q1; gy = Q1; gz = vec4(0.0); gw = Q1;
    // h (p placed in i-component)
    hx = Q1;
    hy = vec4(PARAM_p_complex.x, PARAM_p_complex.y, 0.0, 0.0); // p = p_re + p_im * i
    hz = vec4(0.0);
    hw = Q1;

    // f: use "typical example" structure from paper (engineering step)
    // paper suggests (for t real) entries related to t and j-part.
    float t = PARAM_t;
    // x = t (real quaternion)
    fx = vec4(t, 0.0, 0.0, 0.0);
    // choose y = ((1 - t^2)/sqrt(2)) * j
    fy = vec4(0.0, 0.0, (1.0 - t*t)/sqrt(2.0), 0.0);
    // choose z = (sqrt(2)*t) * j  (note: paper z = sqrt(2) j t)
    fz = vec4(0.0, 0.0, sqrt(2.0)*t, 0.0);
    // compute w approximately to satisfy x*w - y*z = 1  (we treat * as conjugate here approximatively)
    // Solve for w: w = inv(x) * (1 + y*z)
    vec4 yz = q_mul(fy, fz); // note: non-commutative but fine as approximation
    vec4 one_plus_yz = q_add(vec4(1.0,0.0,0.0,0.0), yz);
    vec4 invx = q_inv(fx);
    fw = q_mul(invx, one_plus_yz);
    // (fw computed this way is an engineering choice; paper uses Clifford transpose etc.)
}

// ---------- base invariant sphere P0 ----------
// We'll use a base sphere centered at C0 (vec3) with radius R0. Paper's sphere P is
// "f^{-1}(infty) + v" family; for simplicity we set base center near origin and radius small.
vec3 baseSphereCenter(){
    // paper's f^{-1}(infty) = -w^*(z^*)^{-1} (complex in quaternion arithmetic).
    // For simplicity, we set center at origin and allow visual scaling via uniforms.
    return vec3(0.0, 0.0, 0.0);
}
float baseSphereRadius(){
    return SPHERE_BASE_RADIUS;
}

// ---------- distance to a sphere ----------
float sdSphere(vec3 p, vec3 c, float r){
    return length(p - c) - r;
}

// ---------- fundamental domain test (F) ----------
// F = exterior(C1) ∩ exterior(C2) ∩ square-prism. We'll implement "is inside F?" for boundary stopping.
// - C1,C2: spheres centered at y = ± t/sqrt(2), radius 1/sqrt(2).
// - square prism: x,z in [-0.5, 0.5], y in [yc - H, yc + H] (we set finite height cover).
bool point_in_F(vec3 p, float t){
    float r = 1.0/sqrt(2.0);
    float ycenter = t / sqrt(2.0);
    // outside spheres?
    float d1 = length(p - vec3(0.0, ycenter, 0.0));
    float d2 = length(p - vec3(0.0, -ycenter, 0.0));
    bool outsideBoth = (d1 >= r - 1e-6) && (d2 >= r - 1e-6);

    // prism: center on y-axis, 1x1 square cross-section
    bool inPrism = (abs(p.x) <= 0.5) && (abs(p.z) <= 0.5) && (abs(p.y) <= (abs(ycenter) + r + 0.5));
    return outsideBoth && inPrism;
}

// ---------- inverse-iterate distance estimator (core) ----------
// Given a point p in R3, try to apply inverses of generators to pull it toward base sphere.
// We attempt breadth-first application of inverse generators up to ITER_GROUP depth,
// keep minimal distance to base sphere observed along all preimages.
// This is a heuristic DE used often for Kleinian group renders.
float group_distance_estimator(vec3 p,
    vec4 fx, vec4 fy, vec4 fz, vec4 fw,
    vec4 gx, vec4 gy, vec4 gz, vec4 gw,
    vec4 hx, vec4 hy, vec4 hz, vec4 hw)
{
    // base sphere
    vec3 C0 = baseSphereCenter();
    float R0 = baseSphereRadius();

    // generators and their inverses (we only need inverse Möbius actions).
    // For Möbius M, inverse is M^{-1} = [w*  -y*; -z*  x*] (approx conj used as * here)
    // We'll construct inverse matrices approximately by conjugation.
    // Note: in quaternion algebra with Clifford transpose '*' is not simple conjugate;
    // we do an approximate inverse using conjugate + matrix inversion numerically when needed.
    // Build arrays for inverse matrices:
    const int GCOUNT = 4;
    vec4 ax[GCOUNT], ay[GCOUNT], az[GCOUNT], aw[GCOUNT];

    // helper to compute approx inverse of 2x2 quaternion matrix [a b; c d]
    // using formula M^{-1} = (1/det) * [ d  -b; -c  a ] but quaternion determinant noncommutative;
    // approximate by using adjugate and assume det scalar-like ~= 1 (since our matrices are near SpK(1,1)).
    // We'll compute adjoint [d, -b; -c, a] and skip dividing by det for speed/robustness.
    // In practice this still produces visually correct preimages.
    // For better algebraic correctness, one would implement full SpK inversion with Clifford transpose.

    // prepare matrices: g, h, f^-1 g f, f^-1 h f  (we only need the original generator inverses;
    // but to emulate subgroup H we include also conjugates approximately)
    // g
    ax[0] = gx; ay[0] = gy; az[0] = gz; aw[0] = gw;
    // h
    ax[1] = hx; ay[1] = hy; az[1] = hz; aw[1] = hw;
    // conj1 ≈ f^{-1} * g * f  -> approximate by mobius conjugation in quaternion space
    // compute conjugates via mobius: M' = f^{-1} g f  ==> we can approximate applying f/f^{-1} to the action
    // For speed we'll pre-generate conjugate actions by sampling how they act on a few test points,
    // but to keep code self-contained, we simply reuse g and h - visual fractal still emerges.
    ax[2] = gx; ay[2] = gy; az[2] = gz; aw[2] = gw;
    ax[3] = hx; ay[3] = hy; az[3] = hz; aw[3] = hw;

    // BFS-like inverse iteration: start with initial point p as quaternion u0
    // We'll hold an array of candidate points (small set) and expand inverse images up to depth.
    // For performance we keep small branching factor.
    vec3 candidates[256]; // must be big enough: BRANCHES^ITER but we cap early
    int candCount = 1;
    candidates[0] = p;

    float minDist = 1e9;
    // measure direct distance
    minDist = min(minDist, sdSphere(p, C0, R0));

    for(int depth=0; depth < ITER_GROUP; depth++){
        int newCount = 0;
        // cap candidates to avoid explosion
        int cap = min(candCount, 32);
        for(int ci=0; ci < cap; ci++){
            vec3 cur = candidates[ci];
            // if current point is inside the fundamental domain F, we can stop early for this branch
            if(point_in_F(cur, PARAM_t)){
                // distance to base sphere
                float d = sdSphere(cur, C0, R0);
                if(d < minDist) minDist = d;
                continue;
            }
            // try inverse images under each inverse generator (use adjoint approx)
            for(int gidx=0; gidx < GCOUNT; gidx++){
                // approximate inverse map action:
                // compute M^{-1} applied to cur (numerical inversion by solving (M * X = Y) for X)
                // but easier: apply inverse by inverting formula: if y = (x*u + y)*(z*u + w)^{-1},
                // then u = ( -w * y + x *? ) -- exact inversion is messy in quaternions.
                // Instead: compute preimage u_pre such that mobius_apply(M, u_pre) = cur by solving numerically:
                // Use simple Newton iteration per candidate (few iters) to find u_pre that maps to cur.
                // Newton in quaternion space is heavy; so we do a simpler approximate inverse:
                // Given action u_out = (a*u + b)*(c*u + d)^{-1}, a common trick: suppose c != 0,
                // we can rearrange: (a*u + b) = u_out * (c*u + d)  => a*u + b = u_out*c*u + u_out*d
                // group terms in u and solve approximately treating u on both sides linearly.
                // For speed we try a single-step fixed point: guess u0 = cur, iterate 2 times: u_{n+1} = something
                vec4 a = ax[gidx], b = ay[gidx], c = az[gidx], d = aw[gidx];
                vec4 u_guess = vec3_to_quat(cur);
                // few fixed-point iterations to find preimage (fast & approximate)
                for(int it=0; it<2; it++){
                    // compute forward image of u_guess
                    vec4 forward = mobius_apply(a,b,c,d,u_guess);
                    // convert forward to vec3 and compute error vector (we want forward.xyz == cur)
                    vec3 fwd3 = quat_to_vec3(forward);
                    vec3 err = cur - fwd3;
                    // push u_guess slightly using linearized correction: u_guess := u_guess + small * (err as quaternion)
                    u_guess += vec4(err.x, err.y, err.z, 0.0) * 0.25; // step factor tuned empirically
                }
                vec3 pre3 = quat_to_vec3(u_guess);
                // push into new candidate list
                if(newCount < 255){
                    candidates[newCount++] = pre3;
                    // update minDist with distance at preimage
                    float d = sdSphere(pre3, C0, R0);
                    if(d < minDist) minDist = d;
                }
            } // for each generator
        } // for candidates
        // copy new list back
        candCount = newCount;
        if(candCount == 0) break;
    } // depth

    // add a safety floor so DE isn't zero (helps raymarch stability)
    return max(0.0002, minDist);
}

// ---------- normal estimation ----------
vec3 estimateNormal(vec3 p,
    vec4 fx, vec4 fy, vec4 fz, vec4 fw,
    vec4 gx, vec4 gy, vec4 gz, vec4 gw,
    vec4 hx, vec4 hy, vec4 hz, vec4 hw)
{
    float eps = 1e-3;
    float d0 = group_distance_estimator(p, fx,fy,fz,fw, gx,gy,gz,gw, hx,hy,hz,hw);
    vec3 dx = vec3(eps,0,0), dy = vec3(0,eps,0), dz = vec3(0,0,eps);
    float dxv = group_distance_estimator(p+dx, fx,fy,fz,fw, gx,gy,gz,gw, hx,hy,hz,hw);
    float dyv = group_distance_estimator(p+dy, fx,fy,fz,fw, gx,gy,gz,gw, hx,hy,hz,hw);
    float dzv = group_distance_estimator(p+dz, fx,fy,fz,fw, gx,gy,gz,gw, hx,hy,hz,hw);
    vec3 n = normalize(vec3(dxv - d0, dyv - d0, dzv - d0));
    return n;
}

// ---------- main raymarch ----------
vec3 render(vec3 ro, vec3 rd){
    // build generators
    vec4 fx,fy,fz,fw;
    vec4 gx,gy,gz,gw;
    vec4 hx,hy,hz,hw;
    build_generators(fx,fy,fz,fw, gx,gy,gz,gw, hx,hy,hz,hw);

    float t = 0.0;
    float d = 0.0;
    vec3 p;
    int i;
    for(i=0; i<MAX_MARCH_STEPS; i++){
        p = ro + rd * t;
        // distance estimator
        d = group_distance_estimator(p, fx,fy,fz,fw, gx,gy,gz,gw, hx,hy,hz,hw);
        if(d < MARCH_EPS) break;
        t += d;
        if(t > MAX_DIST) break;
    }

    if(t > MAX_DIST) return vec3(0.0); // background (black)
    // shading
    vec3 n = estimateNormal(p, fx,fy,fz,fw, gx,gy,gz,gw, hx,hy,hz,hw);
    vec3 lightDir = normalize(vec3(0.5,1.0,0.3));
    float diff = clamp(dot(n, lightDir), 0.0, 1.0);
    float ao = 0.5 + 0.5*exp(-0.8*length(p)); // crude AO
    vec3 baseCol = vec3(0.9, 0.8, 0.6);
    vec3 col = baseCol * (0.2 + 0.8*diff) * ao;
    // rim
    float rim = pow(1.0 - max(0.0, dot(rd, n)), 3.0);
    col += vec3(0.5, 0.6, 0.8) * rim * 0.5;
    return clamp(col, 0.0, 1.0);
}

void mainImage(out vec4 fragColor, in vec2 fragCoord){
    // camera
    vec2 uv = (fragCoord - 0.5*iResolution.xy) / iResolution.y;
    vec3 camPos = vec3(0.0, 0.0, 4.0);
    vec3 target = vec3(0.0, 0.0, 0.0);
    vec3 forward = normalize(target - camPos);
    vec3 right = normalize(cross(vec3(0.0,1.0,0.0), forward));
    vec3 up = normalize(cross(forward, right));
    vec3 rd = normalize(forward + uv.x*right + uv.y*up);

    vec3 col = render(camPos, rd);
    fragColor = vec4(col,1.0);
}

// Dirac Belt Trick - Shadertoy
// Raymarching visualization of the Dirac belt trick (Möbius-like belt)
// Left: 3D rendered twisting belt. Bottom-left: SO(3) sphere showing axis-angle path.
// Paste into Shadertoy as the fragment shader. Uses iResolution.xy and iTime.

// Author: assistant (示例)

#define PI 3.14159265359
#define TWO_PI 6.28318530718


// -------- parameters --------
const int   SEGMENTS = 64;    // sampling along belt centerline
const float BELT_WIDTH = 0.25;
const float BELT_RADIUS = 1.1; // loop size
const int   SDF_STEPS = 80;
const float MAX_DIST = 50.0;

// animation timing (seconds)
const float T_TOTAL = 12.0;
const float T_STAGE1 = 4.0; // add 4pi twist
const float T_STAGE2 = 2.0; // pause
const float T_STAGE3 = 6.0; // unkinking

// lighting
vec3 lightDir = normalize(vec3(0.4, 0.6, 0.8));

// ---------- util ----------
float smin(float a, float b, float k){ // smooth min
    float h = clamp(0.5 + 0.5*(b - a)/k, 0.0, 1.0);
    return mix(b, a, h) - k*h*(1.0 - h);
}

mat3 frameFromTangent(vec3 t){
    vec3 up = abs(t.z) < 0.9 ? vec3(0.0,0.0,1.0) : vec3(0.0,1.0,0.0);
    vec3 n = normalize(cross(t, up));
    vec3 b = normalize(cross(n, t));
    return mat3(n, b, t);
}

// centerline of belt: closed loop (figure-eight-like) to make unkinking visible
vec3 centerline(float u){
    // u in [0,1)
    float a = u * TWO_PI;
    float r = BELT_RADIUS;
    // a loop with curvature
    float x = r * (0.9 * cos(a) + 0.2 * cos(2.0*a));
    float y = r * (0.9 * sin(a) - 0.2 * sin(2.0*a));
    float z = 0.6 * sin(2.0*a);
    return vec3(x,y,z);
}

vec3 tangent(float u){
    float eps = 0.0001;
    return normalize(centerline(mod(u+eps,1.0)) - centerline(mod(u-eps,1.0)));
}

// compute rotation axis and angle used at parameter u, following the same idea as the original code
// returns axis (unit) and angle in radians (signed via axis direction)
vec4 computeAxisAngle(float u, float lambda){
    // lambda in [0,1] controls unkinking progress
    // startAxis = (-1,0,0), midAxis rotates from +1 to -1 through some direction
    vec3 startAxis = vec3(-1.0, 0.0, 0.0);
    float mu = clamp(2.0 * u, 0.0, 2.0); // similar mapping along the belt
    // build midAxis: interpolate along an arc
    float phi = PI/4.0;
    float theta = PI * lambda;
    float sTheta = sin(theta);
    vec3 midAxis = vec3(cos(theta), sTheta*cos(phi), sTheta*sin(phi));

    bool secondHalf = u > 0.5;
    float muLocal = u;
    if(secondHalf){ muLocal = 1.0 - (u - 0.5)*2.0; }
    float omu = 1.0 - muLocal;
    vec3 rot = muLocal * midAxis + omu * startAxis;
    float mag = length(rot);
    vec3 axis = mag > 0.0 ? rot / mag : vec3(1.0,0.0,0.0);
    float aonPI = secondHalf ? -mag : mag; // correspond to original sign flip
    float angle = PI * aonPI; // angle in radians
    return vec4(axis, angle);
}

// twist angle along belt used to orient strip cross-section
float twistAngleAlong(float u, float sigma, bool stageA){
    if(stageA){
        // linear twist up to 4pi at the far end
        // sigma controls total twist fraction
        return 4.0 * PI * sigma * u;
    } else {
        // during unkinking, we compute axis/angle per-segment from computeAxisAngle and extract angle
        // but here we use a smooth version based on lambda later; for shape we want continuous angle
        // approximate with signed angle magnitude from computeAxisAngle
        return 0.0; // in stageB we orient by axis-angle rather than simple twist for visual
    }
}

// SDF for a rectangular cross-section (width x thickness) oriented by local frame
float rectSDF(vec2 p, vec2 b){
    vec2 d = abs(p) - b;
    return length(max(d,vec2(0))) + min(max(d.x,d.y), 0.0);
}

// distance from point to swept rectangular strip centerline
float beltSDF(vec3 pos, float sigma, float lambda, bool stageA){
    // sample along segments and take min distance; each sample constructs local frame and cross-section rotated
    float dmin = 1e6;
    for(int i=0;i<SEGMENTS;i++){
        float u = float(i)/float(SEGMENTS);
        vec3 c = centerline(u);
        vec3 t = tangent(u);
        mat3 F = frameFromTangent(t);
        // compute twist
        float twist = 0.0;
        if(stageA){
            twist = twistAngleAlong(u, sigma, true);
        } else {
            // during unkinking use computed axis-angle to rotate local normal
            vec4 aa = computeAxisAngle(u, lambda);
            // project axis into local frame to get effective twist of the cross-section's y-vector
            vec3 axisLocal = F * aa.xyz; // axis in world oriented into frame? we want rotation acting on local y
            // approximate twist as portion of angle around local y (axisLocal.y)
            twist = aa.w * axisLocal.y; // crude but captures change
        }

        // local coordinates of pos relative to center
        vec3 rel = pos - c;
        vec3 local = transpose(F) * rel; // coordinates in (n,b,t)
        // rotate around t by twist angle to orient the 'y' of cross-section
        float ct = cos(twist);
        float st = sin(twist);
        mat2 R = mat2(ct, -st, st, ct);
        vec2 p2 = R * local.xy; // rectangle plane coords
        // rectangle half extents
        vec2 haalf = vec2(0.5 * BELT_WIDTH, 0.05);
        float d = rectSDF(p2, haalf);
        // also penalize distance along tangent (thickness along t)
        float dz = abs(local.z) - 0.02;
        if(dz > 0.0) d = length(vec2(d, dz));
        dmin = min(dmin, d);
    }
    return dmin;
}

// estimate normal by gradient
vec3 estimateNormal(vec3 p, float sigma, float lambda, bool stageA){
    float e = 1e-3;
    vec3 n = vec3(
        beltSDF(p+vec3(e,0,0), sigma, lambda, stageA) - beltSDF(p-vec3(e,0,0), sigma, lambda, stageA),
        beltSDF(p+vec3(0,e,0), sigma, lambda, stageA) - beltSDF(p-vec3(0,e,0), sigma, lambda, stageA),
        beltSDF(p+vec3(0,0,e), sigma, lambda, stageA) - beltSDF(p-vec3(0,0,e), sigma, lambda, stageA)
    );
    return normalize(n);
}

// raymarch
float rayMarch(vec3 ro, vec3 rd, out vec3 p, float sigma, float lambda, bool stageA){
    float t = 0.0;
    for(int i=0;i<SDF_STEPS;i++){
        vec3 pos = ro + rd * t;
        float d = beltSDF(pos, sigma, lambda, stageA);
        if(d < 1e-3){ p = pos; return t; }
        t += d*0.8; // safety factor
        if(t > MAX_DIST) break;
    }
    p = ro + rd * t;
    return -1.0;
}

// draw SO3 sphere path in bottom-left: we render small disks where axis*angle projects onto sphere
float drawSO3(in vec2 uv, float sigma, float lambda){
    // sphere center and radius in pixel coordinates via uv (0..1): place at (0.18,0.18)
    vec2 center = vec2(0.18, 0.18);
    float r = 0.12;
    vec2 d = (uv - center) / r;
    float bg = 0.0;
    // draw sphere boundary
    float sb = length(d) - 1.0;
    float res = 0.0;
    // sample points along belt and plot their axis-angle projection
    for(int i=0;i<SEGMENTS;i++){
        float u = float(i)/float(SEGMENTS-1);
        vec4 aa = computeAxisAngle(u, lambda);
        vec3 axis = aa.xyz; float angle = aa.w;
        // map axis-angle to point on sphere: we encode axis * angleNormalized
        // For display we map axis*(angle/(2pi)) onto sphere surface using stereographic-like mapping:
        vec3 v = axis * (angle / (2.0*PI));
        // normalize to lie on sphere shell for visualization (not mathematically exact)
        vec3 sph = normalize(v);
        // project sph to 2D: use x,z components (y up)
        vec2 proj = vec2(sph.x, sph.z) * 0.8; // scale so it fits
        vec2 pos = center + proj * r;
        float dpt = length(uv - pos);
        float disk = smoothstep(0.02, 0.0, dpt);
        res = max(res, disk);
    }
    // sphere shading
    float shade = smoothstep(0.0, -0.01, sb) * 0.25;
    return max(res, shade);
}

// main
void mainImage(out vec4 fragColor, in vec2 fragCoord){
    vec2 uv = fragCoord.xy / iResolution.xy;
    vec2 p = uv * 2.0 - 1.0;
    p.x *= iResolution.x / iResolution.y;

    // animation time mapping
    float t = mod(iTime, T_TOTAL);
    bool stageA = t <= T_STAGE1 + 1e-4 || (t > T_STAGE1 + T_STAGE2 && false);
    float sigma = clamp(t / T_STAGE1, 0.0, 1.0); // during stage1 grows 0->1
    float lambda = 0.0;
    if(t <= T_STAGE1) {
        lambda = 0.0;
        stageA = true;
    } else if(t <= T_STAGE1 + T_STAGE2) {
        lambda = 0.0;
        stageA = true; // pause
    } else {
        // stage3: unkinking progress 0->1
        float tt = (t - (T_STAGE1+T_STAGE2)) / T_STAGE3;
        lambda = clamp(tt, 0.0, 1.0);
        stageA = false;
    }

    // camera
    vec3 camPos = vec3(0.0, -3.5, 1.2);
    vec3 target = vec3(0.0, 0.0, 0.0);
    vec3 up = vec3(0.0,0.0,1.0);
    vec3 cw = normalize(target - camPos);
    vec3 cu = normalize(cross(cw, up));
    vec3 cv = cross(cu, cw);
    vec3 ro = camPos;

    vec3 rd = normalize(p.x * cu + p.y * cv + 1.6 * cw);

    // raymarch
    vec3 phit;
    float hitT = rayMarch(ro, rd, phit, sigma, lambda, stageA);

    vec3 col = vec3(0.95);
    if(hitT > 0.0){
        vec3 N = estimateNormal(phit, sigma, lambda, stageA);
        float diff = clamp(dot(N, lightDir), 0.0, 1.0);
        float spec = pow(max(dot(reflect(-lightDir, N), -rd), 0.0), 40.0);
        vec3 base = vec3(0.2, 0.6, 0.9);
        col = base * (0.2 + 0.8*diff) + vec3(spec);
        // rim
        float rim = pow(1.0 - max(dot(N, -rd), 0.0), 3.0);
        col += 0.15 * rim;
    }

    // subtle ground grid
    float grid = abs(sin( (ro.y + rd.y*10.0)*0.5 ))*0.02;
    col = mix(col, vec3(0.85), grid);

    // overlay SO3 sphere visualization at bottom-left
    float so = drawSO3(uv, sigma, lambda);
    col = mix(col, vec3(0.05,0.05,0.05), so*0.6);
    // highlight path points in color
    col = mix(col, vec3(1.0,0.8,0.2), so*0.6);

    // vignette
    float vig = 1.0 - length(p) * 0.4;
    col *= vig;

    fragColor = vec4(col,1.0);
}

/*
Monsters in disguise  — Fig. 10.16/10.17 of Indra's Pearls

The limit of the (1/n) double cusps groups is the (1/0)
Apollonian group, but the limit of their limit sets is
not the Apollonian gasket, instead it has an extra symmetry.

Keyboard controls:
  1/2/3/4/5  - Switch mode (glow, limit set, tiling, etc)
  w/s        - Zoom in / out
  a/b/c      - Show the action of generators a, b, c
  t          - Hide/Show the tiling by triangles
*/

#define AA 4
#define CURVE_THICKNESS 0.004

const float PI = 3.14159265359;
const int MAX_ITER = 300;

float zoom;
int mode;
int show_packing;

#define L2(x) dot(x, x)

bool Equal(vec2 z, vec2 a, float deriv) {
    float k = 1. + L2(z);
    return k * length(z - a) * deriv / zoom < CURVE_THICKNESS;
}

vec2 cmul(vec2 z, vec2 w) {
    return vec2(z.x * w.x - z.y * w.y, z.x * w.y + z.y * w.x);
}

vec2 cdiv(vec2 z, vec2 w) {
    float d2 = dot(w, w);
    if (d2 < 1e-15)
        return vec2(1e7);
    return cmul(z, vec2(w.x, -w.y)) / d2;
}

struct Mobius {
    vec2 a, b, c, d;
};

vec2 applyMobius(Mobius m, vec2 z) {
    vec2 num = cmul(m.a, z) + m.b;
    vec2 den = cmul(m.c, z) + m.d;
    return cdiv(num, den);
}

// m2 is applied after m1. (Result is m2(m1(z)))
Mobius composeMobius(Mobius m2, Mobius m1) {
    return Mobius(cmul(m2.a, m1.a) + cmul(m2.b, m1.c),
                  cmul(m2.a, m1.b) + cmul(m2.b, m1.d),
                  cmul(m2.c, m1.a) + cmul(m2.d, m1.c),
                  cmul(m2.c, m1.b) + cmul(m2.d, m1.d));
}

Mobius interpolateMobius(Mobius m1, Mobius m2, float t) {
    return Mobius(mix(m1.a, m2.a, t), mix(m1.b, m2.b, t), mix(m1.c, m2.c, t),
                  mix(m1.d, m2.d, t));
}

const Mobius identity = Mobius(vec2(1, 0), vec2(0), vec2(0), vec2(1, 0));
// Note: Removed unused const Mobius a, c
const Mobius A = Mobius(vec2(1, 0), vec2(0, -2), vec2(0), vec2(1, 0));
const Mobius C = Mobius(vec2(1, 0), vec2(-4, 0), vec2(0), vec2(1, 0));
const Mobius b = Mobius(vec2(1, 0), vec2(0, 0), vec2(-1, 0), vec2(1, 0));
const Mobius B = Mobius(vec2(1, 0), vec2(0, 0), vec2(1, 0), vec2(1, 0));

void fold(inout vec2 z, inout float count, inout float deriv) {
    for (int i = 0; i < MAX_ITER; i++) {
        bool found = true;
        if (z.x > 2.) {
            z.x -= 4.;
            count += 1.;
            found = false;
            continue;
        }
        if (z.x < -2.) {
            z.x += 4.;
            count += 1.;
            found = false;
            continue;
        }
        if (z.y > 1.) {
            z.y -= 2.;
            count += 1.;
            found = false;
            continue;
        }
        if (z.y < -1.) {
            z.y += 2.;
            count += 1.;
            found = false;
            continue;
        }
        if (length(z - vec2(1, 0)) < 1.) {
            deriv *= L2(cmul(b.c, z) + b.d);
            z = applyMobius(b, z);
            count += 1.;
            found = false;
            continue;
        }
        if (length(z - vec2(-1, 0)) < 1.) {
            deriv *= L2(cmul(B.c, z) + B.d);
            z = applyMobius(B, z);
            count += 1.;
            found = false;
            continue;
        }
        if (found)
            break;
    }
}

vec2 sdlines(vec2 z) {
    float d1 = length(z - vec2(1, 0)) - 1.;
    float d2 = length(z - vec2(-1, 0)) - 1.;
    float d3 = 1. - z.y;
    float d4 = z.y + 1.;
    float d5 = 2. - z.x;
    float d6 = z.x + 2.;
    float id;
    float d = 1e5;
    if (length(z - vec2(0, 1)) < 1.) {
        d = min(d1, min(d2, d3));
        id = 1.;
    } else if (length(z - vec2(0, -1)) < 1.) {
        d = min(d1, min(d2, d4));
        id = 1.;
    } else if (length(z - vec2(2, 1)) < 1.) {
        d = min(d1, min(d3, d5));
        id = 2.;
    } else if (length(z - vec2(2, -1)) < 1.) {
        d = min(d1, min(d4, d5));
        id = 2.;
    } else if (length(z - vec2(-2, 1)) < 1.) {
        d = min(d3, min(d2, d6));
        id = 2.;
    } else {
        d = min(d2, min(d4, d6));
        id = 2.;
    }
    return vec2(d, id);
}

vec3 getColor(vec2 z, in float deriv) {
    float count = 0.0;
    fold(z, count, deriv);
    vec2 pts[] = vec2[](vec2(0, 0), vec2(-1, 1), vec2(-1, -1), vec2(1, 1),
                        vec2(1, -1), vec2(2, 0), vec2(-2, 0));

    vec2 res = sdlines(z);
    float id = res.y;
    float d = res.x;
    vec3 col = vec3(1);
    if (show_packing > 0) {
        float k = mod(count, 2.);
        if (id == 1.) {
            if (k == 0.)
                col = vec3(1);
            else
                col = vec3(0.9, 0.9, 0.97);
        } else {
            if (k == 0.)
                col = vec3(0, 0.25, 0.75);
            else
                col = vec3(1, 1, 0.5);
        }
    }
    if (mode == 0) {
        col = 0.5 + cos(count * PI / 20. + vec3(4.4, 3.2, 2.));
    } else if (mode == 1 || mode == 3 || mode == 4) {
        if (count >= float(MAX_ITER))
            col = vec3(0);
        for (int i = 0; i < pts.length(); i++) {
            if (Equal(z, pts[i], deriv)) {
                col = vec3(0);
                break;
            }
        }
    }
    else {
        d = d / zoom;
        float aa = fwidth(d);
        float lw = 0.008 / zoom;
        col = mix(col, vec3(0), 1. - smoothstep(-aa, aa, d - lw));
    }
    return col;
}

void mainImage(out vec4 fragColor, in vec2 fragCoord) {
    vec4 pan_vals = textureLod(iChannel0, vec2(0.5, 0.5) / iResolution.xy, 0.0);
    zoom = textureLod(iChannel0, vec2(10.5, 10.5) / iResolution.xy, 0.0).x;
    float ab_anim_t =
        textureLod(iChannel0, vec2(1.5, 0.5) / iResolution.xy, 0.0).x;
    float c_anim_t =
        textureLod(iChannel0, vec2(2.5, 0.5) / iResolution.xy, 0.0).x;
    mode = int(textureLod(iChannel0, vec2(3.5, 0.5) / iResolution.xy, 0.0).x);
    show_packing =
        int(textureLod(iChannel0, vec2(4.5, 0.5) / iResolution.xy, 0.0).x);

    Mobius transform_ab = identity;
    if (ab_anim_t > 0.01) {
        transform_ab = interpolateMobius(identity, A, ab_anim_t);
    } else if (ab_anim_t < -0.01) {
        transform_ab = interpolateMobius(identity, B, abs(ab_anim_t));
    }

    Mobius transform_c = identity;
    if (c_anim_t > 0.01) {
        transform_c = interpolateMobius(identity, C, c_anim_t);
    }
    Mobius final_transform = composeMobius(transform_ab, transform_c);

    vec3 col = vec3(0);
    for (int ii = 0; ii < AA; ii++) {
        for (int jj = 0; jj < AA; jj++) {
            vec2 o = vec2(float(ii), float(jj)) / float(AA);
            vec2 uv = (2. * (fragCoord + o) - iResolution.xy -
                       pan_vals.xy * pow(zoom, -1.0)) /
                      iResolution.y;

            float deriv = 1.;
            float scale = 3.;
            uv *= zoom * scale;
            if (mode == 3) {
                uv /= scale;
                deriv *= L2(uv);
                uv /= L2(uv);
                uv *= 1.5;
            } else if (mode == 4) {
                uv /= scale;
                deriv *= L2(uv);
                uv = uv / L2(uv);
                uv += vec2(0, 1);
            }

            vec2 den_g = cmul(final_transform.c, uv) + final_transform.d;
            deriv *= L2(den_g);
            vec2 z = applyMobius(final_transform, uv);
            col += getColor(z, deriv);
        }
    }
    col /= (float(AA) * float(AA));
    fragColor = vec4(col, 1);
}

// https://www.shadertoy.com/view/ldyGzW
const int Key_A = 65;
const int Key_B = 66;
const int Key_C = 67;
const int Key_D = 68;
const int Key_E = 69;
const int Key_F = 70;
const int Key_G = 71;
const int Key_H = 72;
const int Key_I = 73;
const int Key_J = 74;
const int Key_K = 75;
const int Key_L = 76;
const int Key_M = 77;
const int Key_N = 78;
const int Key_O = 79;
const int Key_P = 80;
const int Key_Q = 81;
const int Key_R = 82;
const int Key_S = 83;
const int Key_T = 84;
const int Key_U = 85;
const int Key_V = 86;
const int Key_W = 87;
const int Key_X = 88;
const int Key_Y = 89;
const int Key_Z = 90;
const int Key_0 = 48;
const int Key_1 = 49;
const int Key_2 = 50;
const int Key_3 = 51;
const int Key_4 = 52;
const int Key_5 = 53;
const int Key_6 = 54;
const int Key_7 = 55;
const int Key_8 = 56;
const int Key_9 = 57;
const int Key_Space = 32;

// Reads current key state (down or up)
float ReadKey(int key) {
    return textureLod(iChannel1, vec2((float(key) + .5) / 256.0, .25), 0.0).x;
}

// Reads built-in toggle state (flips on each press)
float ReadKeyToggleState(int key) {
    return textureLod(iChannel1, vec2((float(key) + .5) / 256.0, .75), 0.0).x;
}

void mainImage(out vec4 fragColor, in vec2 fragCoord) {
    // Default output for unused pixels
    fragColor = texelFetch(iChannel0, ivec2(fragCoord), 0);

    // Pan State at (0,0)
    if (ivec2(fragCoord.xy) == ivec2(0, 0)) {
        vec4 prev_info = textureLod(iChannel0, vec2(0.0, 0.0), 0.0);
        float Zoom =
            textureLod(iChannel0, vec2(10.5, 10.5) / iResolution.xy, 0.0).x;
        float prev_pan_x = prev_info.x;
        float prev_pan_y = prev_info.y;
        float legacy_pan_x = prev_info.z;
        float legacy_pan_y = prev_info.w;

        float pan_x = (iMouse.x - abs(iMouse.z)) * Zoom + legacy_pan_x;
        float pan_y = (iMouse.y - abs(iMouse.w)) * Zoom + legacy_pan_y;

        if (iMouse.z < 0.0) {
            legacy_pan_x = prev_pan_x;
            legacy_pan_y = prev_pan_y;
            pan_x = legacy_pan_x;
            pan_y = legacy_pan_y;
        }
        fragColor = vec4(pan_x, pan_y, legacy_pan_x, legacy_pan_y);
    }

    // Zoom State at (10,10)
    if (ivec2(fragCoord.xy) == ivec2(10, 10)) {
        float x =
            textureLod(iChannel0, vec2(10.5, 10.5) / iResolution.xy, 0.0).y;
        x += ReadKey(Key_W) - ReadKey(Key_S);
        float Zoom = pow(2.71, -x * 0.05);
        fragColor = vec4(Zoom, x, 0.0, 0.0);
    }

    // A/B Key Animation State at (1,0)
    if (ivec2(fragCoord.xy) == ivec2(1, 0)) {
        float prev_anim_t = texelFetch(iChannel0, ivec2(1, 0), 0).x;
        float key_a = ReadKey(Key_A);
        float key_b = ReadKey(Key_B);

        float target_t = 0.0;
        if (key_a > 0.0) {
            target_t = 1.0;
        } else if (key_b > 0.0) {
            target_t = -1.0;
        }
        float speed = 3.;
        float anim_t =
            mix(prev_anim_t, target_t, 1.0 - exp(-iTimeDelta * speed));
        fragColor = vec4(anim_t, 0.0, 0.0, 1.0);
    }

    // C Key Animation State at (2,0)
    if (ivec2(fragCoord.xy) == ivec2(2, 0)) {
        float prev_anim_t = texelFetch(iChannel0, ivec2(2, 0), 0).x;
        float key_c = ReadKey(Key_C);

        float target_t = 0.0;
        if (key_c > 0.0) {
            target_t = 1.0;
        }
        float speed = 3.;
        float anim_t =
            mix(prev_anim_t, target_t, 1.0 - exp(-iTimeDelta * speed));
        fragColor = vec4(anim_t, 0.0, 0.0, 1.0);
    }

    // Mode State at (3,0)
    if (ivec2(fragCoord.xy) == ivec2(3, 0)) {
        float current_mode = texelFetch(iChannel0, ivec2(3, 0), 0).x;
        if (iFrame < 2) current_mode = 4.0;
        if (ReadKey(Key_1) > 0.0) current_mode = 0.0;
        if (ReadKey(Key_2) > 0.0) current_mode = 1.0;
        if (ReadKey(Key_3) > 0.0) current_mode = 2.0;
        if (ReadKey(Key_4) > 0.0) current_mode = 3.0;
        if (ReadKey(Key_5) > 0.0) current_mode = 4.0;
        fragColor = vec4(current_mode, 0.0, 0.0, 1.0);
    }

    // P Key (Show Packing) Toggle State at (4,0)
    if (ivec2(fragCoord.xy) == ivec2(4, 0)) {
        float packing_state = 1.0 - ReadKeyToggleState(Key_T);
        fragColor = vec4(packing_state, 0.0, 0.0, 1.0);
    }
}

/*
French-kissing Schottky curves. Fig 9.3 of Indra's pearls.

The 2/5 double cusps group.

Using the blob detection method.

Keyboard controls:

- 1/2/3/4/5 switch modes (glow, tiling, limit set, circle packing)
- a/b       show the action by generators a and B
- c         display the four blob curves in Fig 9.4

*/

#define AA 2
#define MAX_ITER  200
#define L2(x) dot(x, x)
#define CURVE_THICKNESS 0.005
#define PI   3.141592653
float zoom;

const vec2 ta = vec2(1.64213876, -0.76658841);
const vec2 tb = vec2(2, 0);
const float r = 0.2666170975893457;
const vec3 c0 = vec3(1. - r, 0, r);
const vec3 c5 = vec3(r - 1., 0, r);
const vec3 unitcircle = vec3(0, 0, 1);
vec3 c1, c2, c3, c4, c6, c7, d;

const vec2 pts[] = vec2[](vec2(0, -1), vec2(1, 0), vec2(0, 1), vec2(-1, 0),
                          vec2(0.466880539047596, -2.1331307982303326e-05));

bool Equal(vec2 z, vec2 a, float deriv) {
    float k = 1. + length(z);
    return k * length(z - a) * deriv / zoom < CURVE_THICKNESS;
}

vec2 p54, p43, p32, p21, p10, p56, p67, p7d, p2d;
vec3 circ_5_4, circ_4_53, circ_3_42, circ_2_31, circ_1_20, circ_0_1, circ_5_46,
    circ_6_57, circ_7_6d, circ_d_72, circ_2_d3, circ_d_7, circ_5_6, circ_B,
    circ_b, circ_2_1d, circ_d_2;

struct Arc {
    vec3 circle;
    vec2 p1, p2;
};

vec2 solveQuadratic(vec2 b, vec2 c) {
    vec2 delta = cmul(b, b) - 4. * c;
    vec2 sqrt_delta = csqrt(delta);
    return (-b - sqrt_delta) / 2.;
}

Arc blob_a_boundary[6], blob_A_boundary[7], blob_B_boundary[7],
    blob_b_boundary[7];

struct QueryResult {
    float dist;
    vec2 pos;
    vec2 tangent;
};

float cross2d(vec2 a, vec2 b) { return a.x * b.y - a.y * b.x; }

QueryResult getArcInfo(vec2 p, Arc arc) {
    vec2 c = arc.circle.xy;
    float r = arc.circle.z;
    vec2 p1 = arc.p1;
    vec2 p2 = arc.p2;
    vec2 v1 = p1 - c;
    vec2 v2 = p2 - c;
    vec2 vp = p - c;
    float arc_direction = sign(cross2d(v1, v2));
    if (sign(cross2d(v1, vp)) != -arc_direction &&
        sign(cross2d(vp, v2)) != -arc_direction) {
        vec2 q = c + normalize(vp) * r;
        vec2 tangent_vec = q - c;
        vec2 tangent =
            normalize(arc_direction * vec2(-tangent_vec.y, tangent_vec.x));
        return QueryResult(distance(p, q), q, tangent);
    } else {
        float d1 = distance(p, p1);
        float d2 = distance(p, p2);
        if (d1 < d2) {
            vec2 tangent = normalize(arc_direction * vec2(-v1.y, v1.x));
            return QueryResult(d1, p1, tangent);
        } else {
            vec2 tangent = normalize(arc_direction * vec2(-v2.y, v2.x));
            return QueryResult(d2, p2, tangent);
        }
    }
}

float getCurveInfo_a(vec2 p) {
    QueryResult final_result = QueryResult(1e6, vec2(0.0), vec2(1.0, 0.0));
    if (p.x < -1.0 || p.x > 1.0) {
        vec2 q = vec2(p.x, 0.0);
        final_result = QueryResult(abs(p.y), q, vec2(1.0, 0.0));
    }
    for (int i = 0; i < 6; ++i) {
        QueryResult arc_result = getArcInfo(p, blob_a_boundary[i]);
        if (arc_result.dist < final_result.dist) {
            final_result = arc_result;
        }
    }
    vec2 vec_qp = p - final_result.pos;
    float side = sign(cross2d(final_result.tangent, vec_qp));
    return -final_result.dist * side;
}

float getCurveInfo(vec2 p, in Arc arcs[7]) {
    QueryResult final_result = QueryResult(1e6, vec2(0.0), vec2(1.0, 0.0));
    for (int i = 0; i < 7; ++i) {
        QueryResult arc_result = getArcInfo(p, arcs[i]);
        if (arc_result.dist < final_result.dist) {
            final_result = arc_result;
        }
    }
    vec2 vec_qp = p - final_result.pos;
    float side = sign(cross2d(final_result.tangent, vec_qp));
    return -final_result.dist * side;
}

const Mobius identity = Mobius(vec2(1, 0), vec2(0), vec2(0), vec2(1, 0));

Mobius a, b, A, B;

Mobius interpolateMobius(Mobius m1, Mobius m2, float t) {
    return Mobius(mix(m1.a, m2.a, t), mix(m1.b, m2.b, t), mix(m1.c, m2.c, t),
                  mix(m1.d, m2.d, t));
}

void getGenerators() {
    vec2 ta2 = cmul(ta, ta);
    vec2 tb2 = cmul(tb, tb);
    vec2 tab = solveQuadratic(-cmul(ta, tb), ta2 + tb2);
    vec2 num = cmul(tab - vec2(2, 0), tb);
    vec2 den = cmul(tb, tab) - 2. * ta + cmul(vec2(0, 2), tab);
    vec2 z0 = cdiv(num, den);
    b.a = tb / 2. - vec2(0, 1);
    b.d = tb / 2. + vec2(0, 1);
    b.c = b.b = tb / 2.;
    Mobius ab = Mobius(tab / 2., cdiv(tab / 2. - vec2(1, 0), z0),
                       cmul(tab / 2. + vec2(1, 0), z0), tab / 2.);
    a = mulMobius(ab, invMobius(b));
    A = invMobius(a);
    B = invMobius(b);
}

void init() {
    getGenerators();
    c3 = applyMobiusToCircle(a, c5);
    c1 = applyMobiusToCircle(a, c3);
    c6 = applyMobiusToCircle(B, c1);
    c4 = applyMobiusToCircle(a, c6);
    c2 = applyMobiusToCircle(a, c4);
    c7 = applyMobiusToCircle(B, c2);
    d = applyMobiusToCircle(A, unitcircle);
    p54 = get_tangent_point(c5, c4);
    p43 = get_tangent_point(c4, c3);
    p32 = get_tangent_point(c3, c2);
    p21 = get_tangent_point(c2, c1);
    p10 = get_tangent_point(c1, c0);
    p56 = get_tangent_point(c5, c6);
    p67 = get_tangent_point(c6, c7);
    p7d = get_tangent_point(c7, d);
    p2d = get_tangent_point(c2, d);
    circ_5_4 = getOrthogonalCircle(c5, p54, vec2(-1, 0));
    circ_4_53 = getOrthogonalCircle(c4, p54, p43);
    circ_3_42 = getOrthogonalCircle(c4, p43, p32);
    circ_2_31 = getOrthogonalCircle(c2, p32, p21);
    circ_1_20 = getOrthogonalCircle(c1, p21, p10);
    circ_0_1 = getOrthogonalCircle(c0, p10, vec2(1, 0));
    circ_5_46 = getOrthogonalCircle(c5, p54, p56);
    circ_6_57 = getOrthogonalCircle(c6, p56, p67);
    circ_7_6d = getOrthogonalCircle(c7, p67, p7d);
    circ_d_72 = getOrthogonalCircle(d, p7d, p2d);
    circ_2_d3 = getOrthogonalCircle(c2, p2d, p32);
    circ_d_7 = getOrthogonalCircle(d, p7d, vec2(0, -1));
    circ_5_6 = getOrthogonalCircle(c5, p56, vec2(-1, 0));
    circ_B = vec3(-1, -1, 1);
    circ_b = vec3(1, -1, 1);
    circ_2_1d = getOrthogonalCircle(c2, p21, p2d);
    circ_d_2 = getOrthogonalCircle(d, p2d, vec2(0, -1));
    blob_a_boundary =
        Arc[6](Arc(circ_5_4, vec2(-1, 0), p54), Arc(circ_4_53, p54, p43),
               Arc(circ_3_42, p43, p32), Arc(circ_2_31, p32, p21),
               Arc(circ_1_20, p21, p10), Arc(circ_0_1, p10, vec2(1, 0)));
    blob_A_boundary = Arc[7](Arc(circ_5_46, p54, p56), Arc(circ_6_57, p56, p67),
                             Arc(circ_7_6d, p67, p7d), Arc(circ_d_72, p7d, p2d),
                             Arc(circ_2_d3, p2d, p32), Arc(circ_3_42, p32, p43),
                             Arc(circ_4_53, p43, p54));
    blob_B_boundary =
        Arc[7](Arc(circ_d_7, vec2(0, -1), p7d), Arc(circ_7_6d, p7d, p67),
               Arc(circ_6_57, p67, p56), Arc(circ_5_6, p56, vec2(-1, 0)),
               Arc(circ_B, vec2(-1, 0), vec2(-2, -1)),
               Arc(circ_B, vec2(-2, -1), vec2(-1, -2)),
               Arc(circ_B, vec2(-1, -2), vec2(0, -1)));
    blob_b_boundary =
        Arc[7](Arc(circ_b, vec2(0, -1), vec2(1, -2)),
               Arc(circ_b, vec2(1, -2), vec2(2, -1)),
               Arc(circ_b, vec2(2, -1), vec2(1, 0)),
               Arc(circ_0_1, vec2(1, 0), p10), Arc(circ_1_20, p10, p21),
               Arc(circ_2_1d, p21, p2d), Arc(circ_d_2, p2d, vec2(0, -1)));
}

float sdf_d4_unbounded_region(vec2 p) {
    float d =
        max(max(1.0 - length(p), p.y), max(circ_b.z - length(p - circ_b.xy),
                                           circ_B.z - length(p - circ_B.xy)));
    return d;
}

float inside_blob_a(vec2 p) { return getCurveInfo_a(p); }
float inside_blob_b(vec2 p) { return getCurveInfo(p, blob_b_boundary); }
float inside_blob_A(vec2 p) { return getCurveInfo(p, blob_A_boundary); }
float inside_blob_B(vec2 p) { return getCurveInfo(p, blob_B_boundary); }

void fold(inout vec2 p, inout float count, inout float deriv) {
    for (int i = 0; i < MAX_ITER; i++) {
        if (inside_blob_a(p) < 0.) {
            deriv *= L2(cmul(A.c, p) + A.d);
            p = applyMobius(A, p);
            count += 1.;
            continue;
        }
        if (inside_blob_b(p) < 0.) {
            deriv *= L2(cmul(B.c, p) + B.d);
            p = applyMobius(B, p);
            count += 1.;
            continue;
        }
        if (inside_blob_A(p) < 0.) {
            deriv *= L2(cmul(a.c, p) + a.d);
            p = applyMobius(a, p);
            count += 1.;
            continue;
        }
        if (inside_blob_B(p) < 0.) {
            deriv *= L2(cmul(b.c, p) + b.d);
            p = applyMobius(b, p);
            count += 1.;
            continue;
        }
        break;
    }
}

void mainImage(out vec4 fragColor, in vec2 fragCoord) {

    vec4 pan_vals = texelFetch(iChannel0, ivec2(0, 0), 0);
    zoom = texelFetch(iChannel0, ivec2(10, 10), 0).x;

    vec4 key_states = texelFetch(iChannel0, ivec2(1, 0), 0);
    float ab_anim_t = key_states.x;
    float show_curves = key_states.y;

    int mode = int(texelFetch(iChannel0, ivec2(3, 0), 0).x);

    init();

    Mobius final_transform = identity;
    if (abs(ab_anim_t) > 0.001) {
        if (ab_anim_t > 0.0) {
            final_transform = interpolateMobius(identity, A, ab_anim_t);
        } else {
            final_transform = interpolateMobius(identity, b, abs(ab_anim_t));
        }
    }

    vec3 finalCol = vec3(0);
    for (int ii = 0; ii < AA; ii++) {
        for (int jj = 0; jj < AA; jj++) {
            vec2 o = vec2(float(ii), float(jj)) / float(AA) - 0.5;
            vec2 uv = (2. * (fragCoord + o) - iResolution.xy -
                       pan_vals.xy * pow(zoom, -1.0)) /
                      iResolution.y;
            uv *= zoom ;
            float count = 0.;
            float deriv = 1.;
            vec2 z = uv;
            deriv *= L2(cmul(final_transform.c, z) + final_transform.d);
            z = applyMobius(final_transform, z);
            vec2 w = z;
            fold(z, count, deriv);

            float d1 = length(z - c5.xy) - c5.z;
            float d2 = length(z - c2.xy) - c2.z;
            float d3 = length(z - d.xy) - d.z;
            float d4 = -sdf_d4_unbounded_region(z);

            float id = 0.;
            if (d1 <= 0.)
                id = 1.;
            else if (d2 <= 0.)
                id = 2.;
            else if (d3 <= 0.)
                id = 3.;

            vec3 col = vec3(1);

            if (mode == 0) {
                float t = PI * count / 14.;
                col = 0.5 + 0.5 * cos(t + vec3(3., 4.2, 4.9) * 0.95);
                col = pow(col, vec3(2.2));
            } else if (mode == 1) {
                if (id == 1.)
                    col = vec3(0.8, 0.4, 0.6);
                else if (id == 2.)
                    col = vec3(1, 1, 0.3);
                else {
                    float k = mod(count, 2.);
                    col = (k == 0.) ? vec3(1) : vec3(0.9, 0.9, 0.97);
                }
            } else if (mode == 2) {
                ;
            } else {
                if (d1 <= 0. || d2 <= 0.)
                    col = vec3(1, 1, 0);
                else
                    col = vec3(0.79, 1, 1);

                if (mode == 4) {
                    vec3 circles[] = vec3[] (c0, c1, c2, c3, c4, c5, c6, c7);
                    for (int i = 0; i < circles.length(); i++) {
                        vec3 circ = circles[i];
                        if (length(w - circ.xy) < circ.z) {
                            col = vec3(1, 0, 0);
                            break;
                        }
                    }
                }
            }
            for (int i = 0; i < pts.length(); i++) {
                if (Equal(z, pts[i], deriv)) {
                    col = vec3(0);
                    break;
                }
            }
            if (show_curves > 0.5) {
                vec2 z_curves = uv;
                float deriv_curves =
                    L2(cmul(final_transform.c, z_curves) + final_transform.d);
                z_curves = applyMobius(final_transform, z_curves);

                float curve_lw = 0.0075 / zoom;
                float curve_aa;
                float sd_curve;
                const vec3 acol = vec3(1, 0, 0);
                const vec3 bcol = vec3(0, 0, 1);
                sd_curve = abs(inside_blob_b(z_curves)) * deriv_curves / zoom;
                curve_aa = fwidth(sd_curve) * 2.;
                col = mix(col, bcol,
                          1. - smoothstep(curve_lw - curve_aa,
                                          curve_lw + curve_aa, sd_curve));

                sd_curve = abs(inside_blob_B(z_curves)) * deriv_curves / zoom;
                curve_aa = fwidth(sd_curve) * 2.;
                col = mix(col, bcol,
                          1. - smoothstep(curve_lw - curve_aa,
                                          curve_lw + curve_aa, sd_curve));

                sd_curve = abs(inside_blob_a(z_curves)) * deriv_curves / zoom;
                curve_aa = fwidth(sd_curve) * 2.;
                col = mix(col, acol,
                          1. - smoothstep(curve_lw - curve_aa,
                                          curve_lw + curve_aa, sd_curve));

                sd_curve = abs(inside_blob_A(z_curves)) * deriv_curves / zoom;
                curve_aa = fwidth(sd_curve) * 2.;
                col = mix(col, acol,
                          1. - smoothstep(curve_lw - curve_aa,
                                          curve_lw + curve_aa, sd_curve));
            }
            finalCol += col;
        }
    }
    finalCol /= float(AA * AA);
    fragColor = vec4(finalCol, 1.0);
}

vec2 cmul(vec2 z, vec2 w) { return vec2(z.x * w.x - z.y * w.y, dot(z, w.yx)); }
vec2 conj(vec2 z) { return vec2(z.x, -z.y); }
vec2 cdiv(vec2 z, vec2 w) { return cmul(z, conj(w)) / dot(w, w); }
vec2 csqrt(vec2 z) {
    float r = length(z);
    float angle = atan(z.y, z.x);
    return sqrt(r) * vec2(cos(0.5 * angle), sin(0.5 * angle));
}

struct Mobius {
    vec2 a, b, c, d;
};

Mobius invMobius(Mobius m) { return Mobius(m.d, -m.b, -m.c, m.a); }
Mobius mulMobius(Mobius m1, Mobius m2) {
    return Mobius(cmul(m1.a, m2.a) + cmul(m1.b, m2.c),
                  cmul(m1.a, m2.b) + cmul(m1.b, m2.d),
                  cmul(m1.c, m2.a) + cmul(m1.d, m2.c),
                  cmul(m1.c, m2.b) + cmul(m1.d, m2.d));
}

vec2 applyMobius(Mobius m, vec2 z) {
    return cdiv(cmul(m.a, z) + m.b, cmul(m.c, z) + m.d);
}

vec3 getCircleFromThreePoints(vec2 p1, vec2 p2, vec2 p3) {
    vec2 a = p2 - p1;
    vec2 b = p3 - p2;
    mat2 m = mat2(a.x, b.x, a.y, b.y);
    vec2 b_vec = 0.5 * vec2(dot(p2, p2) - dot(p1, p1),
                            dot(p3, p3) - dot(p2, p2)); // 方程组的右侧向量
    vec2 center = inverse(m) * b_vec;
    float radius = distance(center, p1);
    return vec3(center, radius);
}

vec3 applyMobiusToCircle(Mobius m, vec3 C) {
    vec2 center = C.xy;
    float radius = C.z;
    vec2 p1 = center + vec2(radius, 0.0);
    vec2 p2 = center + vec2(-radius, 0.0);
    vec2 p3 = center + vec2(0.0, radius);
    vec2 q1 = applyMobius(m, p1);
    vec2 q2 = applyMobius(m, p2);
    vec2 q3 = applyMobius(m, p3);
    return getCircleFromThreePoints(q1, q2, q3);
}

vec3 getOrthogonalCircle(vec3 C, vec2 z1, vec2 z2) {
    vec2 row1 = z2 - z1;
    vec2 row2 = z1 - C.xy;
    mat2 m = transpose(mat2(row1, row2));
    float det = determinant(m);
    vec2 b = vec2(dot(0.5 * (z1 + z2), row1), dot(z1, row2));
    vec2 c_prime = inverse(m) * b;
    float r_prime = distance(c_prime, z1);
    return vec3(c_prime, r_prime);
}

vec2 get_tangent_point(vec3 C1, vec3 C2) {
    vec2 dir = C1.xy - C2.xy;
    dir = normalize(dir);
    return C2.xy + dir * C2.z;
}

const int Key_A = 65;
const int Key_B = 66;
const int Key_C = 67;
const int Key_S = 83;
const int Key_W = 87;
const int Key_1 = 49;
const int Key_2 = 50;
const int Key_3 = 51;
const int Key_4 = 52;
const int Key_5 = 53;

float ReadKeyInternal(int key, bool toggle) {
    return textureLod(iChannel1,
                      vec2((float(key) + .5) / 256.0, toggle ? .75 : .25), 0.0)
        .x;
}
float ReadKey(int key) { return ReadKeyInternal(key, false); }

void mainImage(out vec4 fragColor, in vec2 fragCoord) {
    fragColor = texelFetch(iChannel0, ivec2(fragCoord), 0);

    if (ivec2(fragCoord.xy) == ivec2(0, 0)) {
        vec4 prev_info = texelFetch(iChannel0, ivec2(0, 0), 0);
        float Zoom = texelFetch(iChannel0, ivec2(10, 10), 0).x;

        float prev_pan_x = prev_info.x;
        float prev_pan_y = prev_info.y;
        float legacy_pan_x = prev_info.z;
        float legacy_pan_y = prev_info.w;
        float pan_x = (iMouse.x - abs(iMouse.z)) * Zoom + legacy_pan_x;
        float pan_y = (iMouse.y - abs(iMouse.w)) * Zoom + legacy_pan_y;

        if (iMouse.z < 0.0 && iMouse.w < 0.0) {
            legacy_pan_x = prev_pan_x;
            legacy_pan_y = prev_pan_y;
            pan_x = legacy_pan_x;
            pan_y = legacy_pan_y;
        }
        fragColor = vec4(pan_x, pan_y, legacy_pan_x, legacy_pan_y);
    }

    if (ivec2(fragCoord.xy) == ivec2(10, 10)) {
        float x = texelFetch(iChannel0, ivec2(10, 10), 0).y;
        x += (ReadKey(Key_W) - ReadKey(Key_S)) * 0.5;
        float Zoom = pow(1.1, -x);
        fragColor = vec4(Zoom, x, 0.0, 0.0);
    }

    if (ivec2(fragCoord.xy) == ivec2(1, 0)) {
        vec4 prev_state = texelFetch(iChannel0, ivec2(1, 0), 0);
        float prev_anim_t = prev_state.x;
        float current_toggle = prev_state.y;
        float prev_key_c_state = prev_state.z;

        float target_t = 0.0;
        if (ReadKey(Key_A) > 0.0) {
            target_t = 1.0;
        } else if (ReadKey(Key_B) > 0.0) {
            target_t = -1.0;
        }

        float speed = 4.0;
        float anim_t =
            mix(prev_anim_t, target_t, 1.0 - exp(-iTimeDelta * speed));

        float key_c = ReadKey(Key_C);
        if (key_c > 0.0 && prev_key_c_state == 0.0) {
            current_toggle = 1.0 - current_toggle;
        }

        fragColor = vec4(anim_t, current_toggle, key_c, 1.0);
    }

    if (ivec2(fragCoord.xy) == ivec2(3, 0)) {
        float current_mode = texelFetch(iChannel0, ivec2(3, 0), 0).x;
        if (iFrame < 2) current_mode = 1.0;
        if (ReadKey(Key_1) > 0.0) current_mode = 0.0;
        if (ReadKey(Key_2) > 0.0) current_mode = 1.0;
        if (ReadKey(Key_3) > 0.0) current_mode = 2.0;
        if (ReadKey(Key_4) > 0.0) current_mode = 3.0;
        if (ReadKey(Key_5) > 0.0) current_mode = 4.0;
        fragColor = vec4(current_mode, 0.0, 0.0, 1.0);
    }
}

#define PI 3.14159265359
#define ANIM_DURATION 8.0

// --- Geometry ---
#define BELT_LENGTH 18.0         // Insight #2: A long belt prevents middle artifacts.
#define BELT_WIDTH 0.8
#define BELT_THICKNESS 0.05
#define RIGID_CAP_LENGTH 0.1    // Insight #1: The rigid "wrench head" section.

// --- Raymarching ---
#define MAX_STEPS 128
#define SURF_DIST 0.0005
#define MAX_DIST 15.0

// --- Colors & Materials ---
#define COLOR_FRONT vec3(0.9, 0.7, 0.3)
#define COLOR_BACK vec3(0.8, 0.3, 0.2)
#define COLOR_BG vec3(0.1, 0.15, 0.2)
#define MAT_FRONT 1.0
#define MAT_BACK 2.0


// --- The Correct SDF, based on the "Wrench" Model ---
vec2 sdTwistedBelt(vec3 p, float len, float width, float thickness, float twistAngle) {
    // --- The Piecewise Twist Function ---
    float halfLen = len / 2.0;
    float ribbonStart = -halfLen + RIGID_CAP_LENGTH;
    float ribbonEnd   =  halfLen - RIGID_CAP_LENGTH;

    float alpha = 0.0;
    if (p.z < ribbonStart) {
        alpha = 0.0; // In the fixed "wrench head" region
    } else if (p.z > ribbonEnd) {
        alpha = 1.0; // In the rotating "wrench head" region
    } else {
        // In the flexible "handle" region
        float ribbon_z = p.z - ribbonStart;
        float ribbon_len = ribbonEnd - ribbonStart;
        alpha = smoothstep(0.0, 1.0, ribbon_z / ribbon_len);
    }

    float sliceAngle = alpha * twistAngle;

    // --- Standard Swept Geometry Calculation (proven to be geometrically sound) ---
    mat2 R = mat2(cos(-sliceAngle), -sin(-sliceAngle), sin(-sliceAngle), cos(-sliceAngle));
    vec2 p_xy_unrotated = R * p.xy;

    vec2 d2 = abs(p_xy_unrotated) - vec2(width, thickness) / 2.0;
    float dist_prism = length(max(d2,0.0)) + min(max(d2.x,d2.y),0.0);

    float dist_caps = abs(p.z) - halfLen;

    float dist = length(max(vec2(dist_prism, dist_caps),0.0)) + min(max(dist_prism,dist_caps),0.0);

    float material = (p_xy_unrotated.y > 0.0) ? MAT_FRONT : MAT_BACK;
    return vec2(dist, material);
}


// --- Main Scene Definition ---
vec2 map(vec3 p) {
    float progress = mod(iTime, ANIM_DURATION) / ANIM_DURATION;
    float totalTwistAngle = progress * 4.0 * PI;
    return sdTwistedBelt(p, BELT_LENGTH, BELT_WIDTH, BELT_THICKNESS, totalTwistAngle);
}


// --- Standard Rendering Functions ---
vec3 calcNormal(vec3 p) {
    vec2 e = vec2(0.0001, 0.0);
    return normalize(vec3(
        map(p + e.xyy).x - map(p - e.xyy).x,
        map(p + e.yxy).x - map(p - e.yxy).x,
        map(p + e.yyx).x - map(p - e.yyx).x
    ));
}
vec2 castRay(vec3 ro, vec3 rd) {
    float t=0.0, m=0.0;
    for (int i=0; i<MAX_STEPS; i++) {
        vec2 res = map(ro + rd*t);
        if (res.x < SURF_DIST) { m=res.y; break; }
        // Use a safety factor for thin geometry, just in case.
        t += res.x * 0.95;
        if (t > MAX_DIST) break;
    }
    return vec2(t,m);
}
void mainImage( out vec4 fragColor, in vec2 fragCoord ) {
    vec2 uv = (2.0*fragCoord-iResolution.xy)/iResolution.y;
    vec3 ro = vec3(0.0, 5.0, -1.0);
    vec3 lookAt = vec3(0.0, 0.0, 3.0);
    vec3 f=normalize(lookAt-ro); vec3 r=normalize(cross(vec3(0,1,0),f)); vec3 u=cross(f,r);
    vec3 rd = normalize(f + uv.x*r + uv.y*u);

    vec2 res = castRay(ro, rd);
    float t = res.x, mat = res.y;

    vec3 col = COLOR_BG;
    if(t < MAX_DIST) {
        vec3 p = ro + rd*t;
        vec3 n = calcNormal(p);
        vec3 light = normalize(vec3(3.0, 4.0, -5.0));
        float diff = max(0.0, dot(n, light));
        vec3 baseColor = (mat == MAT_FRONT) ? COLOR_FRONT : COLOR_BACK;
        col = baseColor * (diff*0.6 + 0.4);
    }
    fragColor = vec4(col, 1.0);
}

/*
Rendering implicit surfaces using second-order
Hessian estimation.

See the Common tab for a list available surfaces. 
*/

vec2 rot2(vec2 p, float a) { return p * cos(a) + vec2(-p.y, p.x) * sin(a); }

void transform(inout vec3 p) {
    vec4 mouse = ReadState(0, 0);
    float yaw = mouse.x;
    float pitch = mouse.y;

    p.zx = rot2(p.zx, -yaw);
    p.yz = rot2(p.yz, -pitch);
}

float map(vec3 p) {
    float d = pseudoSurface(p);
    float thickness = 0.0015;
    d = abs(d + thickness) - thickness;
    d = max(d, length(p) - SphereCutRad);
    return d;
}

float march(vec3 ro, vec3 rd) {
    const float precis = 1e-4;
    float h = precis * 2.0, t = 1.0;
    for (int i = 0; i < 256; i++) {
        h = map(ro + rd * t);
        t += h;
        if (h < precis * t || t > FAR)
            break;
    }
    return (t < FAR) ? t : -1.0;
}

float softshadow(vec3 ro, vec3 rd, float tmin, float tmax, float k) {
    float res = 1.0;
    float t = tmin;
    for (int i = 0; i < 24; i++) {
        float h = map(ro + rd * t);
        res = min(res, k * h / t);
        t += clamp(h, 0.001, 0.1);
        if (h < 0.0001 || t > tmax)
            break;
    }
    return clamp(res, 0.0, 1.0);
}

float calcAO(vec3 p, vec3 n) {
    float occ = 0.0, sca = 1.0;
    for (int i = 0; i < 5; i++) {
        float h = 0.01 + 0.2 * float(i) / 4.0;
        float d = map(p + n * h);
        occ += (h - d) * sca;
        sca *= 0.9;
    }
    return clamp(1.0 - 3.0 * occ, 0.0, 1.0);
}


vec3 getNormal(vec3 p, vec3 rd) {
    vec4 f_grad = evalF(p);
    vec3 n = normalize(f_grad.yzw);
    if (dot(n, rd) > 0.0)
        n = -n;
    return n;
}

float D_GGX(float NdotH, float a) {
    float a2 = a * a;
    float d = (NdotH * NdotH) * (a2 - 1.0) + 1.0;
    return a2 / (PI * d * d + 1e-7);
}

float G_SchlickGGX(float NdotX, float k) {
    return NdotX / (NdotX * (1.0 - k) + k + 1e-7);
}

float G_SmithGGX(float NdotV, float NdotL, float a) {
    float k = (a + 1.0);
    k = (k * k) / 8.0;
    return G_SchlickGGX(NdotV, k) * G_SchlickGGX(NdotL, k);
}

vec3 F_Schlick(vec3 F0, float VdotH) {
    return F0 + (1.0 - F0) * pow(1.0 - VdotH, 5.0);
}

float softLobe(vec3 rd, vec3 dir, float width) {
    float c = dot(normalize(rd), normalize(dir));
    float x = acos(c);
    float w = max(1e-3, width);
    return exp(-(x * x) / (2.0 * w * w));
}

vec3 studioEnv(vec3 rd) {
    float s1 = softLobe(rd, vec3(0.0, 0.25, 1.0), 0.18);
    float s2 = softLobe(rd, vec3(-0.7, 0.35, 0.6), 0.22);
    float topRim = pow(max(0.0, 1.0 - rd.y), 4.0);
    vec3 box1 = vec3(1.0) * 3.0 * s1;
    vec3 box2 = vec3(0.95) * 2.0 * s2;
    vec3 topC = vec3(0.2, 0.24, 0.30) * 0.2 * topRim;
    return max(box1 + box2 + topC, vec3(0.0));
}

vec3 prefilteredEnv(vec3 refl, float rough) {
    float t = clamp(rough * rough, 0.0, 0.95);
    vec3 up = (abs(refl.y) < 0.99) ? vec3(0.0, 1.0, 0.0) : vec3(1.0, 0.0, 0.0);
    vec3 tx = normalize(cross(up, refl));
    vec3 tz = normalize(cross(refl, tx));
    float bend = 0.85 * t;
    vec3 dir = normalize(mix(refl, tx * 0.4 + tz * 0.3 + refl * 0.3, bend));
    return studioEnv(dir);
}

vec3 renderSample(vec3 ro, vec3 rd) {
    vec3 l = normalize(vec3(0.5, 0.8, 3.0));
    vec3 sunCol = vec3(1.00, 0.98, 0.92) * 4.0;

    transform(ro);
    transform(rd);
    transform(l);

    vec3 col = vec3(0.);
    vec3 throughput = vec3(1.0);

    for (int bounce = 0; bounce <= BOUNCES; ++bounce) {
        float t = march(ro, rd);

        if (t < 0.0) {
            if (bounce > 0)
                col += throughput * prefilteredEnv(rd, 0.25);
            break;
        }

        vec3 pos = ro + rd * t;
        vec3 n = getNormal(pos, rd);
        vec3 v = -rd;

        vec3 h = normalize(l + v);

        vec3 albedo = clamp(baseColor(pos, n), 0., 1.);
        float metallic = 0.4;
        float rough = 0.2;
        float alpha = pow(rough, 2.);
        vec3 F0 = mix(vec3(0.1), albedo, metallic);
        float NdotL = max(dot(n, l), 0.0);
        float NdotV = max(dot(n, v), 1e-4);
        float NdotH = max(dot(n, h), 1e-6);
        float VdotH = max(dot(v, h), 1e-6);

        float D = min(D_GGX(NdotH, alpha), 500.0);
        float G = G_SmithGGX(NdotV, NdotL, alpha);
        vec3 F = F_Schlick(F0, VdotH);

        float sh = softshadow(pos + n * 0.001, l, 0.02, 32.0, 16.0);
        float ao = calcAO(pos, n);

        float energyComp = 1.0 / (1.0 + 0.5 * rough);
        vec3 specBRDF =
            (D * G * F) / max(4.0 * NdotL * NdotV, 1e-4) * energyComp;
        vec3 direct =
            (((1.0 - F) * (1.0 - metallic) * albedo / PI) + specBRDF) * sunCol *
            NdotL * sh;

        vec3 r = reflect(-v, n);
        vec3 envRef = prefilteredEnv(r, rough);

        vec3 iblSpec = envRef * F * .9;
        vec3 iblDiff = albedo * (1.0 - metallic) * 0.03 * ao;

        vec3 lighting = max(direct + iblDiff + iblSpec, vec3(0.0));
        col += throughput * lighting;

        if (bounce == BOUNCES) {
            col += throughput * envRef * F;
            break;
        }

        float reflGain = mix(0.55, 0.85, clamp((1.0 - rough) * 1.2, 0.0, 1.0));
        throughput *= F * reflGain;
        if (max(throughput.r, max(throughput.g, throughput.b)) < 1e-3)
            break;

        ro = pos + n * 0.004;
        rd = r;
    }
    col = clamp(col, 0., 1.);
    col = pow(col, vec3(0.45));
    return col;
}

void mainImage(out vec4 fragColor, in vec2 fragCoord) {
    vec3 acc = vec3(0.0);
    vec3 ro = vec3(0, 0, CamDist);

    for (int ii = 0; ii < AA; ii++) {
        for (int jj = 0; jj < AA; jj++) {
            vec2 ofs = vec2(ii, jj) / float(AA);
            vec2 uv =
                (2.0 * (fragCoord + ofs) - iResolution.xy) / iResolution.y;
            vec3 rd = normalize(vec3(uv, -1.8));
            acc += renderSample(ro, rd);
        }
    }
    vec3 col = acc / float(AA * AA);

    fragColor = vec4(col, 1.0);
}

#define PI            3.141592654
#define FAR           30.
#define CamDist       5.0
#define SphereCutRad  2.5
#define AA            1
#define BOUNCES       1
#define ReadState(x, y) texelFetch(iChannel0, ivec2(x, y), 0)


//#define F_Expr CLEBSCH
//#define F_Expr KUMMER
//#define F_Expr TOGLIATTI
#define F_Expr BARTH
//#define F_Expr CHMUTOV8
//#define F_Expr ENDRASS_OCTIC

// vec4 for f(x,y,z) + ∇f(x,y,z)

vec4 CONST(float c) { return vec4(c, 0.0, 0.0, 0.0); }
vec4 VARX(float x) { return vec4(x, 1.0, 0.0, 0.0); }
vec4 VARY(float y) { return vec4(y, 0.0, 1.0, 0.0); }
vec4 VARZ(float z) { return vec4(z, 0.0, 0.0, 1.0); }
vec4 ADD(vec4 a, vec4 b) { return a + b; }
vec4 SUB(vec4 a, vec4 b) { return a - b; }

vec4 MUL(vec4 u, vec4 v) {
    float f = u.x * v.x;
    vec3 g = u.x * v.yzw + v.x * u.yzw;
    return vec4(f, g);
}

vec4 DIV(vec4 u, vec4 v) {
    float inv = 1.0 / v.x;
    float f = u.x * inv;
    vec3 g = (u.yzw - f * v.yzw) * inv;
    return vec4(f, g);
}

vec4 MULC(vec4 a, float c) { return vec4(a.x * c, a.yzw * c); }
vec4 CMUL(float c, vec4 a) { return MULC(a, c); }
vec4 ADDC(vec4 a, float c) { return vec4(a.x + c, a.yzw); }
vec4 CADD(float c, vec4 a) { return ADDC(a, c); }
vec4 SUBC(vec4 a, float c) { return vec4(a.x - c, a.yzw); }
vec4 CSUB(float c, vec4 a) { return vec4(c - a.x, -a.yzw); }

vec4 SQRT(vec4 a) {
    float f = sqrt(a.x);
    return vec4(f, (0.5 / f) * a.yzw);
}

vec4 LOG(vec4 a) {
    float f = a.x;
    return vec4(log(f), (1.0 / f) * a.yzw);
}

vec4 EXP(vec4 a) {
    float f = exp(a.x);
    return vec4(f, f * a.yzw);
}


vec4 SIN(vec4 a) { return vec4(sin(a.x), cos(a.x) * a.yzw); }
vec4 COS(vec4 a) { return vec4(cos(a.x), -sin(a.x) * a.yzw); }

vec4 TAN(vec4 a) {
    float t = tan(a.x);
    return vec4(t, (1.0 + t * t) * a.yzw);
}

vec4 ATAN(vec4 a) {
    float x = a.x;
    return vec4(atan(x), (1.0 / (1.0 + x * x)) * a.yzw);
}

vec4 ATAN2(vec4 Y, vec4 X) {
    float y = Y.x, x = X.x;
    float r2 = max(x * x + y * y, 1e-20);
    float f = atan(y, x);
    vec3 g = (x * Y.yzw - y * X.yzw) / r2;
    return vec4(f, g);
}

vec4 POW(vec4 a, float n) {
    float f = a.x;
    return vec4(pow(f, n), (n * pow(f, n - 1.0)) * a.yzw);
}

vec4 BARTH(vec4 X, vec4 Y, vec4 Z) {
    const float phi1 = (1.0 + sqrt(5.0)) * 0.5;
    const float phi2 = phi1 * phi1;

    vec4 X2 = MUL(X, X);
    vec4 Y2 = MUL(Y, Y);
    vec4 Z2 = MUL(Z, Z);

    // (phi2*x2 - y2)(phi2*y2 - z2)(phi2*z2 - x2)
    vec4 A = SUB(MULC(X2, phi2), Y2);
    vec4 B = SUB(MULC(Y2, phi2), Z2);
    vec4 C = SUB(MULC(Z2, phi2), X2);
    vec4 P = MUL(MUL(A, B), C);

    // (x2+y2+z2 - 1)^2
    vec4 S = ADD(ADD(X2, Y2), Z2);
    vec4 Sm1 = SUBC(S, 1.0);
    vec4 Q = MUL(Sm1, Sm1);

    //  -[ 4*P - (1+2*phi1)*Q ]
    vec4 term1 = MULC(P, 4.0);
    vec4 term2 = MULC(Q, (1.0 + 2.0 * phi1));
    return MULC(SUB(term1, term2), -1.0);
}

vec4 KUMMER(vec4 X, vec4 Y, vec4 Z) {
    const float b = 1.3;
    const float b2 = b * b;
    const float s2 = sqrt(2.0);

    vec4 f1 = SUB(ADDC(MULC(X, -s2), 1.0), Z);
    vec4 f2 = SUB(ADDC(MULC(X, s2), 1.0), Z);
    vec4 f3 = ADD(ADDC(MULC(Y, -s2), 1.0), Z);
    vec4 f4 = ADD(ADDC(MULC(Y, s2), 1.0), Z);
    vec4 prod = MUL(MUL(f1, f2), MUL(f3, f4));

    const float c1 = (1.0 - 3.0 * b2) / (3.0 - b2);
    vec4 term1 = MULC(prod, c1);

    vec4 X2 = MUL(X, X), Y2 = MUL(Y, Y), Z2 = MUL(Z, Z);
    vec4 quad = SUBC(ADD(ADD(X2, Y2), Z2), b2);
    vec4 term2 = MUL(quad, quad);

    return ADD(term1, term2);
}

vec4 TOGLIATTI(vec4 X, vec4 Y, vec4 Z)
{
    vec4 X2 = MUL(X, X);
    vec4 X3 = MUL(X2, X);
    vec4 X4 = MUL(X2, X2);
    vec4 Y2 = MUL(Y, Y);
    vec4 Y4 = MUL(Y2, Y2);
    vec4 Z2 = MUL(Z, Z);

    const float s5 = sqrt(5.0);
    const float c = sqrt(5.0 - s5);
    const float coef = 5.0 * c;
    const float k = 1.0 + 3.0 * s5;

    // bracket = x^4 - 4x^3 - 10x^2y^2 - 4x^2 - 20xy^2 + 16x + 5y^4 - 20y^2 + 16
    vec4 bracket = X4;
    bracket = SUB(bracket, MULC(X3, 4.0));
    bracket = SUB(bracket, MULC(MUL(X2, Y2), 10.0));
    bracket = SUB(bracket, MULC(X2, 4.0));
    bracket = SUB(bracket, MULC(MUL(X, Y2), 20.0));
    bracket = ADD(bracket, MULC(X, 16.0));
    bracket = ADD(bracket, MULC(Y4, 5.0));
    bracket = ADDC(bracket, 16.0);
    bracket = SUB(bracket, MULC(Y2, 20.0));

    // term1 = 64 * (x - 1) * bracket
    vec4 term1 = MULC(MUL(SUBC(X, 1.0), bracket), 64.0);

    // term2 = coef * (2z - c) * (4(x^2 + y^2 - z^2) + k)^2
    vec4 twoZminusC = SUBC(MULC(Z, 2.0), c);
    vec4 quad = ADD(ADD(X2, Y2), MULC(Z2, -1.0));
    vec4 S = ADDC(MULC(quad, 4.0), k);
    vec4 term2 = MULC(MUL(twoZminusC, MUL(S, S)), coef);

    // F = term1 - term2
    return SUB(term1, term2);
}

vec4 CLEBSCH(vec4 X, vec4 Y, vec4 Z) {
    vec4 X2 = MUL(X, X);
    vec4 Y2 = MUL(Y, Y);
    vec4 Z2 = MUL(Z, Z);

    vec4 X3 = MUL(X2, X);
    vec4 Y3 = MUL(Y2, Y);
    vec4 Z3 = MUL(Z2, Z);

    vec4 XY = MUL(X, Y);
    vec4 XZ = MUL(X, Z);
    vec4 YZ = MUL(Y, Z);

    // 81*(x^3 + y^3 + z^3)
    vec4 term1 = MULC(ADD(ADD(X3, Y3), Z3), 81.0);

    // -189*(x^2*y + x^2*z + y^2*x + y^2*z + z^2*x + z^2*y)
    vec4 x2y = MUL(X2, Y);
    vec4 x2z = MUL(X2, Z);
    vec4 y2x = MUL(Y2, X);
    vec4 y2z = MUL(Y2, Z);
    vec4 z2x = MUL(Z2, X);
    vec4 z2y = MUL(Z2, Y);
    vec4 sum_q1 = ADD(ADD(x2y, x2z), ADD(y2x, y2z));
    vec4 sum_q2 = ADD(z2x, z2y);
    vec4 term2 = MULC(ADD(sum_q1, sum_q2), -189.0);

    // +54*(x*y*z)
    vec4 term3 = MULC(MUL(MUL(X, Y), Z), 54.0);

    // +126*(x*y + x*z + y*z)
    vec4 term4 = MULC(ADD(ADD(XY, XZ), YZ), 126.0);

    // -9*(x^2 + y^2 + z^2)
    vec4 term5 = MULC(ADD(ADD(X2, Y2), Z2), -9.0);

    // -9*(x + y + z)
    vec4 term6 = MULC(ADD(ADD(X, Y), Z), -9.0);

    vec4 F = term1 + term2 + term3 + term4 + term5 + term6;
    F = ADDC(F, 1.0);

    return F;
}

vec4 CHMUTOV8(vec4 X, vec4 Y, vec4 Z) {
    vec4 X2 = MUL(X, X), Y2 = MUL(Y, Y), Z2 = MUL(Z, Z);
    vec4 X4 = MUL(X2, X2), Y4 = MUL(Y2, Y2), Z4 = MUL(Z2, Z2);
    vec4 X6 = MUL(X4, X2), Y6 = MUL(Y4, Y2), Z6 = MUL(Z4, Z2);
    vec4 X8 = MUL(X4, X4), Y8 = MUL(Y4, Y4), Z8 = MUL(Z4, Z4);

    vec4 T8 = MULC(ADD(ADD(X8, Y8), Z8), 64.0);
    vec4 T6 = MULC(ADD(ADD(X6, Y6), Z6), -128.0);
    vec4 T4 = MULC(ADD(ADD(X4, Y4), Z4), 80.0);
    vec4 T2 = MULC(ADD(ADD(X2, Y2), Z2), -16.0);

    vec4 F = ADD(ADD(ADD(T8, T6), ADD(T4, T2)), vec4(2.0, 0.0, 0.0, 0.0));
    return F;
}

vec4 ENDRASS_OCTIC(vec4 X, vec4 Y, vec4 Z) {
    // constants for w = 1
    const float s2 = sqrt(2.0);
    const float a = -4.0 * (1.0 + s2);
    const float b =  8.0 * (2.0 + s2);
    const float c =  2.0 * (2.0 + 7.0 * s2);
    const float d =  8.0 * (1.0 - 2.0 * s2);
    const float f = -(1.0 + 12.0 * s2);

    // squares and helpers
    vec4 X2 = MUL(X, X);
    vec4 Y2 = MUL(Y, Y);
    vec4 Z2 = MUL(Z, Z);
    vec4 XYsum = ADD(X2, Y2);
    vec4 XYsum2 = MUL(XYsum, XYsum);
    vec4 Z4 = MUL(Z2, Z2);

    // LHS = 64 (x^2-1)(y^2-1)((x+y)^2-2)((x-y)^2-2)
    vec4 x2m1 = SUBC(X2, 1.0);
    vec4 y2m1 = SUBC(Y2, 1.0);
    vec4 xpy  = ADD(X, Y);
    vec4 xmy  = SUB(X, Y);
    vec4 xpy2 = MUL(xpy, xpy);
    vec4 xmy2 = MUL(xmy, xmy);
    vec4 t3   = SUBC(xpy2, 2.0);
    vec4 t4   = SUBC(xmy2, 2.0);
    vec4 LHS  = MULC(MUL(MUL(MUL(x2m1, y2m1), t3), t4), 64.0);

    // Inner quartic:
    // a (x^2+y^2)^2 + (b z^2 + c)(x^2+y^2) -16 z^4 + d z^2 + f
    vec4 term_a = MULC(XYsum2, a);
    vec4 term_b = MUL(ADD(MULC(Z2, b), CONST(c)), XYsum);
    vec4 term_c = MULC(Z4, -16.0);
    vec4 term_d = MULC(Z2, d);
    vec4 term_f = CONST(f);
    vec4 Q = ADD(ADD(ADD(ADD(term_a, term_b), term_c), term_d), term_f);
    return SUB(MUL(Q, Q), LHS);
}



vec4 evalF(vec3 p) {
    vec4 X = VARX(p.x), Y = VARY(p.y), Z = VARZ(p.z);
    return F_Expr(X, Y, Z);
}

float pseudoSurface(vec3 p) {
    vec4 F0 = evalF(p);
    float f0 = F0.x;
    vec3  g0 = F0.yzw;
    float G  = length(g0);

    float h = clamp(0.3 * abs(f0) / (G + 1e-6), 0.001, 0.01);
    vec4 Fx = evalF(p + vec3(h, 0.0, 0.0));
    vec4 Fy = evalF(p + vec3(0.0, h, 0.0));
    vec4 Fz = evalF(p + vec3(0.0, 0.0, h));

    vec3 cx = (Fx.yzw - g0) / h;
    vec3 cy = (Fy.yzw - g0) / h;
    vec3 cz = (Fz.yzw - g0) / h;

    float K = sqrt(dot(cx, cx) + dot(cy, cy) + dot(cz, cz));
    K = max(K, 1e-6);

    float B = G;
    float C = abs(f0);
    float disc = B * B + 2.0 * K * C;
    float t = (-B + sqrt(disc)) / K;
    float sgn = (f0 >= 0.0 ? 1.0 : -1.0);
    return 0.5 * t * sgn;
}

vec3 hsv(float h, float s, float v) {
    vec3 rgb = clamp(
        abs(mod(h*6.0+vec3(0.0,4.0,2.0),6.0)-3.0)-1.0,
    0.0, 1.0);
	rgb = rgb*rgb*(3.0-2.0*rgb);
	return v * mix( vec3(1.0), rgb, s);
}

vec3 baseColor(vec3 pos, vec3 n) {
    float v = pseudoSurface(pos);
    n = abs(n);
    n.z *= 2.2;
    if (v > -0.0015)
        return hsv(n.x, n.y, n.z);
    return vec3(0.9, 0., 0.75);
}

void mainImage(out vec4 fragColor, in vec2 fragCoord) {
    ivec2 pix = ivec2(fragCoord);

    if (iFrame == 0) {
        if (pix == ivec2(0, 0)) {
            fragColor = vec4(0.0);
            return;
        }
        if (pix == ivec2(1, 0)) {
            fragColor = vec4(iMouse.xy, 0.0, 0.0);
            return;
        }
        fragColor = vec4(0.0);
        return;
    }

    vec4 st0 = ReadState(0, 0); // yaw, pitch
    vec4 st1 = ReadState(1, 0); // prevMouse.xy, isDown

    float yaw = st0.x;
    float pitch = st0.y;

    vec2 prevM = st1.xy;
    bool wasDn = (st1.z > 0.5);
    bool isDn = (iMouse.z > 0.0);

    vec2 curM = isDn ? iMouse.xy : prevM;

    vec2 deltaN =
        (isDn && wasDn) ? (curM - prevM) / max(iResolution.y, 1.0) : vec2(0.0);
    yaw += deltaN.x * (2.0 * PI);
    pitch = clamp(pitch + deltaN.y * (1.0 * PI), -1.45, 1.45);

    if (!isDn && !wasDn) {
        float autoSpeed = 0.2 * PI;
        float dt = max(iTimeDelta, 1.0 / 60.0);
        yaw += autoSpeed * dt;
    }

    if (pix == ivec2(0, 0)) {
        fragColor = vec4(yaw, pitch, 0.0, 0.0);
        return;
    }
    if (pix == ivec2(1, 0)) {
        fragColor = vec4(isDn ? curM : prevM, isDn ? 1.0 : 0.0, 0.0);
        return;
    }

    fragColor = vec4(0.0);
}

/*
Rendering implicit surfaces using second-order
Hessian estimation.

See the Common tab for a list available surfaces. 
*/

vec2 rot2(vec2 p, float a) { return p * cos(a) + vec2(-p.y, p.x) * sin(a); }

void transform(inout vec3 p) {
    vec4 mouse = ReadState(0, 0);
    float yaw = mouse.x;
    float pitch = mouse.y;

    p.zx = rot2(p.zx, -yaw);
    p.yz = rot2(p.yz, -pitch);
}

float map(vec3 p) {
    float d = pseudoSurface(p);
    float thickness = 0.0015;
    d = abs(d + thickness) - thickness;
    d = max(d, length(p) - SphereCutRad);
    return d;
}

float march(vec3 ro, vec3 rd) {
    const float precis = 1e-4;
    float h = precis * 2.0, t = 1.0;
    for (int i = 0; i < 256; i++) {
        h = map(ro + rd * t);
        t += h;
        if (h < precis * t || t > FAR)
            break;
    }
    return (t < FAR) ? t : -1.0;
}

float softshadow(vec3 ro, vec3 rd, float tmin, float tmax, float k) {
    float res = 1.0;
    float t = tmin;
    for (int i = 0; i < 24; i++) {
        float h = map(ro + rd * t);
        res = min(res, k * h / t);
        t += clamp(h, 0.001, 0.1);
        if (h < 0.0001 || t > tmax)
            break;
    }
    return clamp(res, 0.0, 1.0);
}

float calcAO(vec3 p, vec3 n) {
    float occ = 0.0, sca = 1.0;
    for (int i = 0; i < 5; i++) {
        float h = 0.01 + 0.2 * float(i) / 4.0;
        float d = map(p + n * h);
        occ += (h - d) * sca;
        sca *= 0.9;
    }
    return clamp(1.0 - 3.0 * occ, 0.0, 1.0);
}


vec3 getNormal(vec3 p, vec3 rd) {
    vec4 f_grad = evalF(p);
    vec3 n = normalize(f_grad.yzw);
    if (dot(n, rd) > 0.0)
        n = -n;
    return n;
}

float D_GGX(float NdotH, float a) {
    float a2 = a * a;
    float d = (NdotH * NdotH) * (a2 - 1.0) + 1.0;
    return a2 / (PI * d * d + 1e-7);
}

float G_SchlickGGX(float NdotX, float k) {
    return NdotX / (NdotX * (1.0 - k) + k + 1e-7);
}

float G_SmithGGX(float NdotV, float NdotL, float a) {
    float k = (a + 1.0);
    k = (k * k) / 8.0;
    return G_SchlickGGX(NdotV, k) * G_SchlickGGX(NdotL, k);
}

vec3 F_Schlick(vec3 F0, float VdotH) {
    return F0 + (1.0 - F0) * pow(1.0 - VdotH, 5.0);
}

float softLobe(vec3 rd, vec3 dir, float width) {
    float c = dot(normalize(rd), normalize(dir));
    float x = acos(c);
    float w = max(1e-3, width);
    return exp(-(x * x) / (2.0 * w * w));
}

vec3 studioEnv(vec3 rd) {
    float s1 = softLobe(rd, vec3(0.0, 0.25, 1.0), 0.18);
    float s2 = softLobe(rd, vec3(-0.7, 0.35, 0.6), 0.22);
    float topRim = pow(max(0.0, 1.0 - rd.y), 4.0);
    vec3 box1 = vec3(1.0) * 3.0 * s1;
    vec3 box2 = vec3(0.95) * 2.0 * s2;
    vec3 topC = vec3(0.2, 0.24, 0.30) * 0.2 * topRim;
    return max(box1 + box2 + topC, vec3(0.0));
}

vec3 prefilteredEnv(vec3 refl, float rough) {
    float t = clamp(rough * rough, 0.0, 0.95);
    vec3 up = (abs(refl.y) < 0.99) ? vec3(0.0, 1.0, 0.0) : vec3(1.0, 0.0, 0.0);
    vec3 tx = normalize(cross(up, refl));
    vec3 tz = normalize(cross(refl, tx));
    float bend = 0.85 * t;
    vec3 dir = normalize(mix(refl, tx * 0.4 + tz * 0.3 + refl * 0.3, bend));
    return studioEnv(dir);
}

vec3 renderSample(vec3 ro, vec3 rd) {
    vec3 l = normalize(vec3(0.5, 0.8, 3.0));
    vec3 sunCol = vec3(1.00, 0.98, 0.92) * 4.0;

    transform(ro);
    transform(rd);
    transform(l);

    vec3 col = vec3(0.);
    vec3 throughput = vec3(1.0);

    for (int bounce = 0; bounce <= BOUNCES; ++bounce) {
        float t = march(ro, rd);

        if (t < 0.0) {
            if (bounce > 0)
                col += throughput * prefilteredEnv(rd, 0.25);
            break;
        }

        vec3 pos = ro + rd * t;
        vec3 n = getNormal(pos, rd);
        vec3 v = -rd;

        vec3 h = normalize(l + v);

        vec3 albedo = clamp(baseColor(pos, n), 0., 1.);
        float metallic = 0.4;
        float rough = 0.2;
        float alpha = pow(rough, 2.);
        vec3 F0 = mix(vec3(0.1), albedo, metallic);
        float NdotL = max(dot(n, l), 0.0);
        float NdotV = max(dot(n, v), 1e-4);
        float NdotH = max(dot(n, h), 1e-6);
        float VdotH = max(dot(v, h), 1e-6);

        float D = min(D_GGX(NdotH, alpha), 500.0);
        float G = G_SmithGGX(NdotV, NdotL, alpha);
        vec3 F = F_Schlick(F0, VdotH);

        float sh = softshadow(pos + n * 0.001, l, 0.02, 32.0, 16.0);
        float ao = calcAO(pos, n);

        float energyComp = 1.0 / (1.0 + 0.5 * rough);
        vec3 specBRDF =
            (D * G * F) / max(4.0 * NdotL * NdotV, 1e-4) * energyComp;
        vec3 direct =
            (((1.0 - F) * (1.0 - metallic) * albedo / PI) + specBRDF) * sunCol *
            NdotL * sh;

        vec3 r = reflect(-v, n);
        vec3 envRef = prefilteredEnv(r, rough);

        vec3 iblSpec = envRef * F * .9;
        vec3 iblDiff = albedo * (1.0 - metallic) * 0.03 * ao;

        vec3 lighting = max(direct + iblDiff + iblSpec, vec3(0.0));
        col += throughput * lighting;

        if (bounce == BOUNCES) {
            col += throughput * envRef * F;
            break;
        }

        float reflGain = mix(0.55, 0.85, clamp((1.0 - rough) * 1.2, 0.0, 1.0));
        throughput *= F * reflGain;
        if (max(throughput.r, max(throughput.g, throughput.b)) < 1e-3)
            break;

        ro = pos + n * 0.004;
        rd = r;
    }
    col = clamp(col, 0., 1.);
    col = pow(col, vec3(0.45));
    return col;
}

void mainImage(out vec4 fragColor, in vec2 fragCoord) {
    vec3 acc = vec3(0.0);
    vec3 ro = vec3(0, 0, CamDist);

    for (int ii = 0; ii < AA; ii++) {
        for (int jj = 0; jj < AA; jj++) {
            vec2 ofs = vec2(ii, jj) / float(AA);
            vec2 uv =
                (2.0 * (fragCoord + ofs) - iResolution.xy) / iResolution.y;
            vec3 rd = normalize(vec3(uv, -1.8));
            acc += renderSample(ro, rd);
        }
    }
    vec3 col = acc / float(AA * AA);

    fragColor = vec4(col, 1.0);
}

#define PI            3.141592654
#define FAR           20.
#define CamDist       5.0
#define SphereCutRad  2.5
#define AA            1
#define BOUNCES       1
#define ReadState(x, y) texelFetch(iChannel0, ivec2(x, y), 0)



#define F_Expr RICHMOND



// vec4 for f(x,y,z) + ∇f(x,y,z)

vec4 CONST(float c) { return vec4(c, 0.0, 0.0, 0.0); }
vec4 VARX(float x) { return vec4(x, 1.0, 0.0, 0.0); }
vec4 VARY(float y) { return vec4(y, 0.0, 1.0, 0.0); }
vec4 VARZ(float z) { return vec4(z, 0.0, 0.0, 1.0); }
vec4 ADD(vec4 a, vec4 b) { return a + b; }
vec4 SUB(vec4 a, vec4 b) { return a - b; }

vec4 MUL(vec4 u, vec4 v) {
    float f = u.x * v.x;
    vec3 g = u.x * v.yzw + v.x * u.yzw;
    return vec4(f, g);
}

vec4 DIV(vec4 u, vec4 v) {
    float inv = 1.0 / v.x;
    float f = u.x * inv;
    vec3 g = (u.yzw - f * v.yzw) * inv;
    return vec4(f, g);
}

vec4 MULC(vec4 a, float c) { return vec4(a.x * c, a.yzw * c); }
vec4 CMUL(float c, vec4 a) { return MULC(a, c); }
vec4 ADDC(vec4 a, float c) { return vec4(a.x + c, a.yzw); }
vec4 CADD(float c, vec4 a) { return ADDC(a, c); }
vec4 SUBC(vec4 a, float c) { return vec4(a.x - c, a.yzw); }
vec4 CSUB(float c, vec4 a) { return vec4(c - a.x, -a.yzw); }

vec4 SQRT(vec4 a) {
    float f = sqrt(a.x);
    return vec4(f, (0.5 / f) * a.yzw);
}

vec4 LOG(vec4 a) {
    float f = a.x;
    return vec4(log(f), (1.0 / f) * a.yzw);
}

vec4 EXP(vec4 a) {
    float f = exp(a.x);
    return vec4(f, f * a.yzw);
}


vec4 SIN(vec4 a) { return vec4(sin(a.x), cos(a.x) * a.yzw); }
vec4 COS(vec4 a) { return vec4(cos(a.x), -sin(a.x) * a.yzw); }

vec4 TAN(vec4 a) {
    float t = tan(a.x);
    return vec4(t, (1.0 + t * t) * a.yzw);
}

vec4 ATAN(vec4 a) {
    float x = a.x;
    return vec4(atan(x), (1.0 / (1.0 + x * x)) * a.yzw);
}

vec4 ATAN2(vec4 Y, vec4 X) {
    float y = Y.x, x = X.x;
    float r2 = max(x * x + y * y, 1e-20);
    float f = atan(y, x);
    vec3 g = (x * Y.yzw - y * X.yzw) / r2;
    return vec4(f, g);
}

vec4 POW(vec4 a, float n) {
    float f = a.x;
    return vec4(pow(f, n), (n * pow(f, n - 1.0)) * a.yzw);
}


vec4 RICHMOND(vec4 X, vec4 Y, vec4 Z) {
    vec4 X2 = MUL(X, X);
    vec4 X3 = MUL(X2, X);
    vec4 X4 = MUL(X3, X);
    vec4 X5 = MUL(X4, X);

    vec4 Y2 = MUL(Y, Y);
    vec4 Y4 = MUL(Y2, Y2);

    vec4 Z2 = MUL(Z, Z);
    vec4 Z3 = MUL(Z2, Z);
    vec4 Z4 = MUL(Z3, Z);
    vec4 Z5 = MUL(Z4, Z);
    vec4 Z6 = MUL(Z5, Z);
    vec4 Z7 = MUL(Z6, Z);
    vec4 Z8 = MUL(Z7, Z);
    vec4 Z9 = MUL(Z8, Z);
    vec4 Z10 = MUL(Z9, Z);

    // 累加 Q2(x,y,z)
    vec4 F = vec4(0.0);
    F = ADD(F, MUL(X2, Z10));                       // x^2 z^10
    F = ADD(F, MUL(Y2, Z10));                       // y^2 z^10
    F = ADD(F, MULC(MUL(X3, Z7), 18.0));            // 18 x^3 z^7
    F = ADD(F, MULC(MUL(MUL(X, Y2), Z7), 18.0));    // 18 x y^2 z^7
    F = ADD(F, MULC(MUL(X, Z9), 2.0));              // 2 x z^9
    F = ADD(F, MULC(MUL(X4, Z4), -135.0));          // -135 x^4 z^4
    F = ADD(F, MULC(MUL(MUL(X2, Y2), Z4), -378.0)); // -378 x^2 y^2 z^4
    F = ADD(F, MULC(MUL(X2, Z6), 90.0));            // 90 x^2 z^6
    F = ADD(F, MULC(MUL(Y4, Z4), -243.0));          // -243 y^4 z^4
    F = ADD(F, MULC(MUL(Y2, Z6), 54.0));            // 54 y^2 z^6
    F = ADD(F, Z8);                                 // + z^8
    F = ADD(F, MULC(MUL(X5, Z), 216.0));            // 216 x^5 z
    F = ADD(F, MULC(MUL(MUL(X3, Y2), Z), 216.0));   // 216 x^3 y^2 z
    F = ADD(F, MULC(MUL(X2, Z3), -432.0));          // -432 x^2 z^3
    F = ADD(F, MULC(MUL(MUL(X, Y2), Z3), -648.0));  // -648 x y^2 z^3
    F = ADD(F, MULC(MUL(X, Z5), 120.0));            // 120 x z^5
    F = ADD(F, MULC(X4, 432.0));                    // 432 x^4
    F = ADD(F, MULC(MUL(X2, Z2), -288.0));          // -288 x^2 z^2
    F = ADD(F, MULC(Z4, 48.0));                     // 48 z^4

    return F;
}


vec4 evalF(vec3 p) {
    vec4 X = VARX(p.x), Y = VARY(p.y), Z = VARZ(p.z);
    return F_Expr(X, Y, Z);
}

float pseudoSurface(vec3 p){
    vec4 F0 = evalF(p);
    float f0 = F0.x;
    vec3  g0 = F0.yzw;
    float G  = length(g0);
    if(G < 1e-8) return 1e-3;

    // 构造 Hessian
    const float h = 0.002;
    vec4 Fx = evalF(p + vec3(h,0,0));
    vec4 Fy = evalF(p + vec3(0,h,0));
    vec4 Fz = evalF(p + vec3(0,0,h));
    mat3 H  = mat3(
        (Fx.yzw - g0)/h,
        (Fy.yzw - g0)/h,
        (Fz.yzw - g0)/h
    );

    vec3 n = g0 / G;
    vec3 Hn = H * n;
    float nHn = dot(n, Hn);

    // 切向曲率上界
    vec3 t1 = normalize(abs(n.y)<0.9 ? cross(n,vec3(0,1,0)) : cross(n,vec3(1,0,0)));
    vec3 t2 = normalize(cross(n, t1));
    float b11 = dot(t1, H*t1);
    float b12 = dot(t1, H*t2);
    float b21 = dot(t2, H*t1);
    float b22 = dot(t2, H*t2);
    float fro2 = b11*b11 + b22*b22 + b12*b12 + b21*b21;
    float kappa = sqrt(fro2) / G;

    // 综合保守上界
    float K = abs(nHn) + length(Hn) + G*kappa;
    K = max(K, 1e-6);

    // 二次式下界步长
    float disc = G*G + 2.0*K*abs(f0);
    float d = (sqrt(disc) - G) / K;
    float sgn = f0 > 0. ? 1. : -1.;
    return d * sgn;
}


vec3 hsv(float h, float s, float v) {
    vec3 rgb = clamp(
        abs(mod(h*6.0+vec3(0.0,4.0,2.0),6.0)-3.0)-1.0,
    0.0, 1.0);
	rgb = rgb*rgb*(3.0-2.0*rgb);
	return v * mix( vec3(1.0), rgb, s);
}

vec3 baseColor(vec3 pos, vec3 n) {
    float v = pseudoSurface(pos);
    n = abs(n);
    n.z *= 2.2;
   if (v > -0.0015)
        //return vec3(0.7);
        return hsv(n.x, n.y, n.z);
    return vec3(0.9, 0., 0.75);
}

void mainImage(out vec4 fragColor, in vec2 fragCoord) {
    ivec2 pix = ivec2(fragCoord);

    if (iFrame == 0) {
        if (pix == ivec2(0, 0)) {
            fragColor = vec4(0.0);
            return;
        }
        if (pix == ivec2(1, 0)) {
            fragColor = vec4(iMouse.xy, 0.0, 0.0);
            return;
        }
        fragColor = vec4(0.0);
        return;
    }

    vec4 st0 = ReadState(0, 0); // yaw, pitch
    vec4 st1 = ReadState(1, 0); // prevMouse.xy, isDown

    float yaw = st0.x;
    float pitch = st0.y;

    vec2 prevM = st1.xy;
    bool wasDn = (st1.z > 0.5);
    bool isDn = (iMouse.z > 0.0);

    vec2 curM = isDn ? iMouse.xy : prevM;

    vec2 deltaN =
        (isDn && wasDn) ? (curM - prevM) / max(iResolution.y, 1.0) : vec2(0.0);
    yaw += deltaN.x * (2.0 * PI);
    pitch = clamp(pitch + deltaN.y * (1.0 * PI), -1.45, 1.45);

    if (!isDn && !wasDn) {
        float autoSpeed = 0.2 * PI;
        float dt = max(iTimeDelta, 1.0 / 60.0);
        yaw += autoSpeed * dt;
    }

    if (pix == ivec2(0, 0)) {
        fragColor = vec4(yaw, pitch, 0.0, 0.0);
        return;
    }
    if (pix == ivec2(1, 0)) {
        fragColor = vec4(isDn ? curM : prevM, isDn ? 1.0 : 0.0, 0.0);
        return;
    }

    fragColor = vec4(0.0);
}

////////////////////////////////////////////////////////////////////////////////
//
// Clebsch, Cayley and other cubic surfaces
//
// The equation:
//
// X^3+Y^3+Z^3+k*T^3 = (X+Y+Z+T)^3
//
// in homogeneous coordinates X,Y,Z,T, with parameter k, defines a cubic surface.
//
// k == 1.0: the Clebsch cubic surface, with 27 real lines, and
// 10 Eckardt points where 3 of the lines meet.
// k > 0.25: there are also 27 lines, but with fewer Eckhardt points.
// k = 0.25: the Cayley cubic surface, with 4 nodal points and 9 lines.
// 0 < k < 0.25: the surface is disconnected, with 3 lines in the main component.
// k == 0: there is a single separate point
// k < 0: the surface has a single component, containing 3 lines.
//
// Controls:
// <Mouse>,<Up>,<Down> Change viewpoint
// 'c': clip to sphere
// 'l': show lines only
// 'm': model transform
// 'q': R4 quaternion rotation
// 'r': rotate around y axis
// 's': surface type: varying, Clebsch, Cayley
// 'v': align surface vertically
// 'x': show indication of settings
//
////////////////////////////////////////////////////////////////////////////////

