#define cubic cubic0
//#define cubic blinn_cubic // Blinn solver from @nilrem's https://www.shadertoy.com/view/4s2yRm
#define TAU 6.28318530718
#define PI 3.141592654

// The Kahan algorithm, for explanation see:
// https://people.eecs.berkeley.edu/~wkahan/Math128/Cubic.pdf

float sgn(float x) {
  return x < 0.0? -1.0: 1.0; // Return 1 for x == 0
}

bool qdrtc(float A, float B, float C, out vec2 res) {
  float x1,x2;
  float b = -0.5*B;
  float q = b*b - A*C;
  if (q < 0.0) return false;
  float r = b + sgn(b)*sqrt(q);
  if (r == 0.0) {
    x1 = C/A; x2 = -x1;
  } else {
    x1 = C/r; x2 = r/A;
  }
  res = (x1 < x2)? vec2(x1,x2): vec2(x2,x1);
  return true;
}

void eval(float X, float A, float B, float C, float D,
          out float Q, out float Q1, out float B1,out float C2) {
  float q0 = A*X;
  B1 = q0+B;
  C2 = B1*X+C;
  Q1 = (q0+B1)*X + C2;
  Q = C2*X + D;
}

int qbc(float A, float B, float C, float D, out vec3 res) {
  float X,b1,c2;
  if (A == 0.0) {
    X = 1e8; A = B; b1 = C; c2 = D;
  } else if (D == 0.0) {
    X = 0.0; b1 = B; c2 = C;
  } else {
    X = -(B/A)/3.0;
    float t,r,s,q,dq;
    eval(X,A,B,C,D,q,dq,b1,c2);
    t = q/A; r = pow(abs(t),1.0/3.0); s = sgn(t);
    t = -dq/A; if (t > 0.0) r = 1.324718*max(r,sqrt(t));
    X -= s*r;
      // Newton-Raphson, simplified from Kahan to use
      // a fixed length loop.
      for (int i = 0; i < 4; i++) {
        eval(X,A,B,C,D,q,dq,b1,c2);
        X -= (q/dq);
      }
      if (abs(A)*X*X > abs(D/X)) {
        c2 = -D/X; b1 = (c2 - C)/X;
      }
  }
  res.x = X;
  if (!qdrtc(A,b1,c2,res.yz)) return 1;
  if (res.x > res.y) res.xy = res.yx;
  if (res.y > res.z) res.yz = res.zy;
  return 3;
}

int cubic0(vec4 coeffs, out vec3 res) {
  float A = coeffs[0], B = coeffs[1], C = coeffs[2], D = coeffs[3];
  return qbc(A,B,C,D,res);
}

// Some alterative cubic solvers.
//https://www.shadertoy.com/view/4dsfRS
int cubic1(vec4 coeffs, out vec3 res) {
  float a = coeffs[1]/coeffs[0];
  float b = coeffs[2]/coeffs[0];
  float c = coeffs[3]/coeffs[0];
    float p = b - a*a / 3.0, p3 = p*p*p;
    float q = a * (2.0*a*a - 9.0*b) / 27.0 + c;
    float d = q*q + 4.0*p3 / 27.0;
    float offset = -a / 3.0;
    if(d >= 0.0) { 
        float z = sqrt(d);
        vec2 x = (vec2(z, -z) - q) / 2.0;
        vec2 uv = sign(x)*pow(abs(x), vec2(1.0/3.0));
        res[0] = offset + uv.x + uv.y;
        return 1;
    }
    float v = acos(-sqrt(-27.0 / p3) * q / 2.0) / 3.0;
    float m = cos(v), n = sin(v)*1.732050808;
    res = vec3(m + m, -n - m, n - m) * sqrt(-p / 3.0) + offset;
    if (res.x > res.y) res.xy = res.yx;
    if (res.y > res.z) res.yz = res.zy;
    if (res.x > res.y) res.xy = res.yx;
    return 3;
}
// Cubic bezier - Signed Distance - NinjaKoala
// https://www.shadertoy.com/view/4sKyzW
int cubic2(vec4 coeffs, inout vec3 r)
{

	float a = coeffs[1]/coeffs[0];
	float b = coeffs[2]/coeffs[0];
	float c = coeffs[3]/coeffs[0];

	float p = b - a*a/3.;
	float q = a * (2.*a*a - 9.*b)/27. + c;
	float p3 = p*p*p;
	float d = q*q + 4.*p3/27.;
	float offset = -a/3.;

	if(d >= 0.0) { // Single solution.

        /*
		float z = sqrt(d);
		float u = (-q + z)/2.;
		float v = (-q - z)/2.;
		u = sign(u)*pow(abs(u), 1./3.);
		v = sign(v)*pow(abs(v), 1./3.);
		r[0] = offset + u + v;	
		*/

        vec2 uv = (vec2(1, -1)*sqrt(d) - q)/2.;
        uv = sign(uv)*pow(abs(uv), vec2(1./3.));
        r[0] = offset + uv.x + uv.y;	

		// CHANGE
		// Single newton iteration to account for cancellation.
		float f = ((r[0] + a)*r[0] + b)*r[0] + c;
		float f1 = (3.*r[0] + 2. * a)*r[0] + b;

		r[0] -= f/f1;

		return 1;
	}

	float u = sqrt(-p/3.);
	float v = acos(-sqrt(-27./p3)*q/2.)/3.;
	float m = cos(v), n = sin(v)*1.732050808;

	// Single newton iteration to account for cancellation
	// (once for every root).

	float f,f1;
	r[0] = offset + u * (m + m);

	f = ((r[0] + a)*r[0] + b)*r[0] + c;
	f1 = (3.*r[0] + 2. * a)*r[0] + b;

	r[0] -= f / f1;

	r[1] = offset - u * (n + m);

	f = ((r[1] + a)*r[1] + b) * r[1] + c;
	f1=(3.*r[1] + 2. * a)*r[1] + b;

	r[1] -= f / f1;

	r[2] = offset + u * (n - m);

	f = ((r[2] + a)*r[2] + b)*r[2] + c;
	f1 = (3.*r[2] + 2. * a)*r[2] + b;

	r[2] -= f / f1;
    if (r.x > r.y) r.xy = r.yx;
    if (r.y > r.z) r.yz = r.zy;
    if (r.x > r.y) r.xy = r.yx;

	return 3;
}

// https://www.shadertoy.com/view/3tyczd by oneshade
int cubic3(vec4 coeffs, out vec3 roots) {
    float a=coeffs[0],b=coeffs[1],c=coeffs[2],d=coeffs[3];
    float denom = 3.0 * a * a;
    float inflection = -b / (3.0 * a);

    float p = c / a - b * b / denom;
    float q = 2.0 * b * b * b / (27.0 * a * a * a) - b * c / denom + d / a;

    float discr = q * q / 4.0 + p * p * p / 27.0;
    int numRoots = discr > 0.0 ? 1 : 3;

    roots = vec3(0);
    if (numRoots == 1) {
        if (4.0 * p * p * p > -27.0 * q * q && p < 0.0) {
            roots[0] = -2.0 * sign(q) * sqrt(-p / 3.0) * cosh(acosh(-3.0 * abs(q) / (2.0 * p) * sqrt(-3.0 / p)) / 3.0) + inflection;
        }

        if (p > 0.0) {
            roots[0] = -2.0 * sqrt(p / 3.0) * sinh(asinh(3.0 * q / (2.0 * p) * sqrt(3.0 / p)) / 3.0) + inflection;
        }
    }

    if (numRoots == 3) {
        float tspt = 2.0 * sqrt(-p / 3.0);
        float ac = acos(3.0 * q / (2.0 * p) * sqrt(-3.0 / p));
        roots[0] = tspt * cos( ac              / 3.0) + inflection;
        roots[1] = tspt * cos((ac -       TAU) / 3.0) + inflection;
        roots[2] = tspt * cos((ac - 2.0 * TAU) / 3.0) + inflection;
        if (roots.x > roots.y) roots.xy = roots.yx;
        if (roots.y > roots.z) roots.yz = roots.zy;
        if (roots.x > roots.y) roots.xy = roots.yx;
    }

    return numRoots;
}

// https://www.shadertoy.com/view/7tBGzK by oneshade
int solveCubic(in float a, in float b, in float c, in float d, out vec3 roots) {
    float u = b / (3.0 * a);

    // Depress to x^3 + px + q by substituting x-b/3a
    // This can be found by substituting x+u and solving for u so that the x^3
    // term gets eliminated (then of course dividing by the leading coefficient)
    float p = (c - b * u) / a;
    float q = (d - (c - 2.0 * b * b / (9.0 * a)) * u) / a;

    // Everything blows up when p=0 so give this case special treatment
    // Also, GLSL doesn't like negative pows(), even when its valid so we also have to treat this carefully.
    if (abs(p) < 1e-9) { roots.x = -sign(q) * pow(abs(q), 1.0 / 3.0) - u; return 1; }

    // Hyperbolic solution for one real root (see https://en.wikipedia.org/wiki/Cubic_equation)
    if (4.0 * p * p * p + 27.0 * q * q > 0.0) { // Check depressed cubic discriminant
        float ip = 3.0 / abs(p), sp = sqrt(ip), k = 0.5 * q * ip * sp;
        if (p > 0.0) roots.x = -2.0 / sp * sinh(asinh(k) / 3.0) - u;
        else roots.x = -2.0 / sp * cosh(acosh(abs(k)) / 3.0) * sign(q) - u;
        return 1;
    }

    // Solve by mapping an inverse smoothstep between the critical points
    // I found a whole lot simplified right out so now it probably looks rather obfuscated
    float m = sqrt(-p / 3.0);
    roots.x = -2.0 * m * sin(asin(1.5 * q / (p * m)) / 3.0);

    // Factor out the root to solve for the rest as a quadratic
    float h = sqrt(-3.0 * roots.x * roots.x - 4.0 * p);
    roots.yz = 0.5 * vec2(h - roots.x, -h - roots.x);
    roots -= u; // Undo the change in variable

    return 3;
}

int cubic4(vec4 coeffs, out vec3 res) {
  float A = coeffs[0], B = coeffs[1], C = coeffs[2], D = coeffs[3];
  int nroots = solveCubic(A,B,C,D,res);
  return nroots;
}

