//const float NaN = intBitsToFloat(~0);
float NaN = uintBitsToFloat(0x7f800001u);

float Linear(float b, float a)
{
    return -b / a;
}

int Quadratic(float c, float b, float a, out vec2 res)
{
    if (a == 0.) {
        res[0] = Linear(c, b); // handle malformed eqn
        return 1;
    }
    float n = b * b - 4. * a * c; // discriminant
    if (n < 0.0) return 0;
    res = .5 / a * (sign(a) * sqrt(n) * vec2(-1, 1) - b); // two solutions, lesser first (may be identical)
    return 2;
}


// spalmer, https://www.shadertoy.com/view/flyGDD
// http://en.wikipedia.org/wiki/Cubic_equation "General cubic formula"
// evaluated using complex arithmetic only as much as absolutely required.
//vec3 Cubic(float d, float c, float b, float a)
int cubic5(vec4 coeffs, out vec3 res) {
  float a = coeffs[0], b = coeffs[1], c = coeffs[2], d = coeffs[3];
    if (a == 0.) {
        return Quadratic(d, c, b, res.xy); // handle malformed eqn
        return 2;
    }
    float h = 27.*a*a
    , o = -1./3./a
    , p = b*b - 3.*a*c
    , j = (2.*b*b - 9.*a*c) * b
    , q = j + h*d
    , g = q*q - 4.*p*p*p // discriminant
    ;
    //vec3 r;
    if (g > 0.) { // 1-root case all real arithmetic
        float y = .5*(q + sqrt(g)), z = sign(y) * pow(abs(y), 1./3.); //scbrt(y);
        res = vec3((b + z + p/z) * o, NaN, NaN);
        return 1;
    } else { // 3-root case requires complex arithmetic
        const vec2 E = vec2(-.5, sqrt(.75)); // primitive cube root of complex unity
        vec2 u = vec2(q, sqrt(-g)) // q +- sqrt(-g) complex result
        , C = sin(vec2(acos(0.), 0.) + atan(u.y, u.x) / 3.) 
            * pow(.25 * dot(u, u), 1./6.) // inlined trigonometry
        , s1 = vec2(E.x * C.x - E.y * C.y
                  , E.x * C.y + E.y * C.x)
        , s0 = vec2(E.x * C.x + E.y * C.y
                  , E.x * C.y - E.y * C.x);
        res = (vec3(
            (1. + p / dot(C , C )) * C .x,
            (1. + p / dot(s0, s0)) * s0.x,
            (1. + p / dot(s1, s1)) * s1.x
          ) + b) * o;
        if (a < 0.)
            res.xz = res.zx; // order 3-root case
    }
    return 3;
}

float cbrt(float x) {
  return sign(x)*pow(abs(x),1.0/3.0);
}

int CubicSpalmer(float d, float c, out vec3 roots) // b = 0, a = 1
{
    float l = c / 3.
    , s = l*l*l
    , m = d*d + 4.*s;
    if (m > 0.) { // 1 real root
        vec2 w = (sqrt(m) * vec2(1,-1) - d) * .5;
        float v = cbrt(abs(w.x) < abs(w.y) ? w.y : w.x);
        roots[0] = v - l / v; // Blinn single cbrt idea
        return 1;
    }
    // 2 or 3 distinct roots
    float t = atan(sqrt(-m), -sign(c)*(d));
    roots = 2. * sign(l)*sqrt(l) * cos((t - PI * vec3(0,2,4))/3.);
    return 3;
}

// solve x³ + cx + d = 0
int CubicDepressed(float d, float c, out vec3 roots)
{
    //vec3 k = vec3(d, c, 0.);
//    return Cubiciq(k); // ok
