//    return CubicBloxard(d, c); // ok
//    return CubicCardano(d, c); // busted WIP
//    return CubicSpalmerSaved(d, c);
    return CubicSpalmer(d, c,roots);
}

// by spalmer
int CubicDepress(vec4 k, out vec3 roots)
{
    float a = k.x, b = k.y/a, c = k.z/a, d = k.w/a, // a = 1.
        x = b/-3.; // inflection point
    int nroots = CubicDepressed((c - 2.*x*x)*x + d, c + b*x,roots);
    roots += x;
    return nroots;
}

// From https://www.shadertoy.com/view/4s2yRm by @nilrem
// Finds roots of homogeneous cubic polynomial Ax³ + 3Bx² + 3Cx + D   (Ax³ + 3Bx²w + 3Cxw² + Dw³)
// Algorithm by Jim Blinn, see https://courses.cs.washington.edu/courses/cse590b/13au/lecture_notes
// This implementation directly converts the roots from homogeneous to cartesian space
int blinn_cubic(vec4 a, out vec3 roots)
{
   float A = a[0], B = a[1]/3.0, C = a[2]/3.0, D = a[3];

    // Hessian coefficients
    float d_1 = A*C - B*B;
    float d_2 = A*D - B*C;
    float d_3 = B*D - C*C;

    // Hessian determinant ( = cubic discriminant)
    float d   = (4.0 * d_1 * d_3) - (d_2 * d_2);


    if ( d <= 0.0 )     // one real root (a double root if d=0, a triple root if d_1=d_2=d_3=d=0)
    {
        // Subscript b for "bar", t for "tilde"

        // Depressed polynomial coefficients
        float A_t;  // A or D
        float C_b;  // 1/2 H(t, u)
        float D_b;  // J(t, u)

        // save predicate B³D >= AC³ to avoid multiple evaluations
        bool B3D_ge_AC3 = B*B*B*D >= A*C*C*C;

        if ( B3D_ge_AC3 )
        {
            // Algorithm A, t = 1, u = 0
            A_t = A;
            C_b = d_1;
            D_b = -2.0 * B * d_1 + A * d_2;
        } else
        {
            // Algorithm D, t = 0, u = 1  (reversed order of coefficients)
            A_t = D;
            C_b = d_3;
            D_b = -D * d_2 + 2.0 * C * d_3;
        }

        float T0   = -sgn(D_b) * abs(A_t) * sqrt(-d);
        float T1   = -D_b + T0;
        float p    = cbrt( T1*0.5 );
        float q    = T1 == T0  ? -p : -C_b/p;
        float x_t1 = C_b <= 0. ? p + q : -D_b / (p*p + q*q + C_b);

        // Get back from tilde'ed space to homogeneous space and invert result if algorithm D
        float x1   = B3D_ge_AC3 ? x_t1 - B : -D;
        float w1   = B3D_ge_AC3 ? A : x_t1 + C;

        // Convert from homogeneous to cartesian space
        roots.x    = x1/w1;
    }
    else    // d > 0    // three real roots (with potentially one double root)
    {
        // variables subscripted with A and D according to algorithms A and D
        // t is the angle theta
        // x_L/w_L is the first root, x_S/w_S the second root, x_M/w_M the third root

        // Use both algorithms A and D to find the first two roots
        // Same C_b and D_b as before, according to algorithm A's and D's choices of t,u

        // 0.866025403784 -> sqrt(3)/2

        // Algorithm A
        float C_bA  = d_1;
        float D_bA  = -2.0 * B * d_1 + A*d_2;

        float t_A   = 0.333333333333 * abs( atan( A*sqrt(d), -D_bA) );
        float x_t1A = 2.0 * sqrt(-C_bA) * cos( t_A );
        float x_t3A = 2.0 * sqrt(-C_bA) * ( -0.5 * cos(t_A) - 0.866025403784 * sin(t_A) );
        float x_tL  = (x_t1A + x_t3A > 2.0 * B) ? x_t1A : x_t3A;

        // Get back from tilde'ed space, same as before
        float x_L   = x_tL - B;
        float w_L   = A;

        roots.x     = x_L/w_L;


        // Algorithm D
        // same as Algorithm A except for choice of t,u (and thus inverted result)
        float C_bD  = d_3;
        float D_bD  = -D * d_2 + 2.0 * C * d_3;

        float t_D   = 0.333333333333 * abs( atan( D*sqrt(d), -D_bD) );
        float x_t1D = 2.0 * sqrt(-C_bD) * cos( t_D );
        float x_t3D = 2.0 * sqrt(-C_bD) * ( -0.5 * cos(t_D) - 0.866025403784 * sin(t_D) );
        float x_tS  = (x_t1D + x_t3D < 2.0 * C) ? x_t1D : x_t3D;

        // Get back from tilde'ed space, same as before
        float x_S   = -D;
        float w_S   = x_tS + C;

        roots.y     = x_S/w_S;


        // Third root from the first two (no more to and from tilde'ed space here)
        float E   =  w_L * w_S;
        float F   = -x_L * w_S - w_L * x_S;
        float G   =  x_L * x_S;

        float x_M =  C*F - B*G;
        float w_M = -B*F + C*E;

        roots.z   = x_M/w_M;
    }

    return d <= 0.0 ? 1 : 3;   // return number of roots
}

