// 使用“参数曲面 + Harnack tracing”替代隐式 SDF raymarch。

#define PI            3.141592654
#define CamDist       5.0
#define AA            1
#define BOUNCES       1
#define ReadState(x, y) texelFetch(iChannel0, ivec2(x, y), 0)

// ---------- 相机旋转 ----------
vec2 rot2(vec2 p, float a){ return p * cos(a) + vec2(-p.y, p.x) * sin(a); }
void transform(inout vec3 p){
    vec4 mouse = ReadState(0, 0);
    float yaw = mouse.x;
    float pitch = mouse.y;
    p.zx = rot2(p.zx, -yaw);
    p.yz = rot2(p.yz, -pitch);
}

// ---------- 形变参数（θ：catenoid→helicoid；ψ：螺旋相位可多圈） ----------
float getAssocTheta(){
    // 鼠标按下时用横向位置控制 θ；否则随时间自动在 [0,π/2] 摆动
    if(iMouse.z > 0.5){
        float u = clamp(iMouse.x/iResolution.x, 0.0, 1.0);
        return mix(0.0, 0.5*PI, u);
    }
    return 0.5*PI*(0.5 + 0.5*sin(0.35*iTime));
}
float getHelixPhase(){
    const float TAU = 6.28318530718;
    // 鼠标纵向可拖到 12 圈；否则每秒 1.2 圈自动旋转
    if(iMouse.z > 0.5){
        float v = clamp(iMouse.y/iResolution.y, 0.0, 1.0);
        return TAU * 12.0 * v;
    }
    return TAU * 1.2 * iTime;
}

// ---------- Harnack tracing（参数曲面） ----------
const float HIT_EPS      = 0.0015;
const int   MAX_ITERS    = 2000;

bool harnack_param(vec3 ro, vec3 rd, float tMax,
                   out float tHit, out vec3 hitPos, out vec3 hitNormal)
{
    rd = normalize(rd);

    // 把形变参数注入到 common（本文件读 iTime/iMouse，common 不读）
    setAssocAngle(getAssocTheta());
    setHelixPhase(getHelixPhase());

    float t0 = 0.0, t1 = tMax;
    if (true){ // 用包围球做裁剪加速
        bool ok = intersectSphere(ro, rd, vec3(0.0), SphereCutRad, t0, t1);
        if (!ok || t1 < 0.0) return false;
        if (t0 > 0.0) tHit = t0; else tHit = 0.0;
        if (t1 < tMax) t1 = tMax;
    } else {
        tHit = 0.0;
    }

    // 参数域圆盘半径（Ruv 大圆、ruv 小圆）
    const float Ruv = 0.9;
    const float ruv = 0.5 * Ruv;

    vec2  uv = vec2(0.0); // 初值在投影时写入
    bool  uvInit = false;
    float tover  = 0.0;

    for (int it=0; it<MAX_ITERS && tHit < t1; ++it){
        vec3 p = ro + (tHit + tover) * rd;

        vec3 X,N; assocProject(p, uv, uvInit, X, N);
        float distN = dot(X - p, N);
        if (abs(distN) < HIT_EPS){
            hitPos    = X;
            hitNormal = (dot(N, rd) > 0.0) ? -N : N;
            return true;
        }

        // Harnack 给出的“安全步长”
        float stepH = harnackStep_t(ro, rd, tHit + tover, uv, Ruv, ruv);
        // 和法向距离二取一，避免穿透
        float stepT = min(stepH, max(0.0008, abs(distN)));

        float next_over = 0.75 * stepT;
        tHit += stepT + tover;
        tover = next_over;
    }
    return false;
}

// ---------- 你原来的 PBR 工具（保持不变） ----------
float D_GGX(float NdotH, float a){
    float a2 = a*a;
    float d = (NdotH*NdotH)*(a2-1.0)+1.0;
    return a2 / (PI * d * d + 1e-7);
}
float G_SchlickGGX(float NdotX, float k){ return NdotX / (NdotX*(1.0-k)+k+1e-7); }
float G_SmithGGX(float NdotV, float NdotL, float a){
    float k=(a+1.0); k=(k*k)/8.0;
    return G_SchlickGGX(NdotV,k)*G_SchlickGGX(NdotL,k);
}
vec3 F_Schlick(vec3 F0, float VdotH){ return F0 + (1.0-F0)*pow(1.0-VdotH,5.0); }

float softLobe(vec3 rd, vec3 dir, float width){
    float c = dot(normalize(rd), normalize(dir));
    float x = acos(c);
    float w = max(1e-3, width);
    return exp(-(x*x)/(2.0*w*w));
}
vec3 studioEnv(vec3 rd){
    float s1 = softLobe(rd, vec3(0.0,0.25,1.0), 0.18);
    float s2 = softLobe(rd, vec3(-0.7,0.35,0.6),0.22);
    float topR = pow(max(0.0, 1.0 - rd.y), 4.0);
    vec3 box1 = vec3(1.0)*3.0*s1;
    vec3 box2 = vec3(0.95)*2.0*s2;
    vec3 topC = vec3(0.2,0.24,0.30)*0.2*topR;
    return max(box1+box2+topC, vec3(0.0));
}
vec3 prefilteredEnv(vec3 refl, float rough){
    float t = clamp(rough*rough, 0.0, 0.95);
    vec3 up = (abs(refl.y)<0.99)? vec3(0,1,0): vec3(1,0,0);
    vec3 tx = normalize(cross(up, refl));
    vec3 tz = normalize(cross(refl, tx));
    float bend = 0.85 * t;
    vec3 dir = normalize(mix(refl, tx*0.4 + tz*0.3 + refl*0.3, bend));
    return studioEnv(dir);
}

// 简易阴影：再次用 Harnack cast 一条光线（硬阴影）
float hardShadow(vec3 pos, vec3 n, vec3 lightDir, float maxDist){
    float t; vec3 hp,hn;
    bool occ = harnack_param(pos + n*0.01, lightDir, maxDist, t, hp, hn);
    return occ ? 0.0 : 1.0;
}

// ---------- 单次样本渲染 ----------
vec3 renderSample(vec3 ro, vec3 rd){
    vec3 l = normalize(vec3(0.5, 0.8, 3.0));
    vec3 sunCol = vec3(1.00, 0.98, 0.92) * 4.0;

    transform(ro); transform(rd); transform(l);

    vec3 col = vec3(0.0);
    vec3 throughput = vec3(1.0);

    for (int bounce=0; bounce<=BOUNCES; ++bounce){
        float t; vec3 pos,n;
        bool hit = harnack_param(ro, rd, FAR, t, pos, n);

        if (!hit){
            if (bounce>0) col += throughput * prefilteredEnv(rd, 0.25);
            break;
        }

        vec3 v = -rd;
        vec3 h = normalize(l + v);

        vec3 albedo = clamp(baseColor(pos, n), 0.0, 1.0);
        float metallic = 0.4;
        float rough = 0.2;
        float alpha = pow(rough, 2.0);
        vec3 F0 = mix(vec3(0.1), albedo, metallic);

        float NdotL = max(dot(n, l), 0.0);
        float NdotV = max(dot(n, v), 1e-4);
        float NdotH = max(dot(n, h), 1e-6);
        float VdotH = max(dot(v, h), 1e-6);

        float D = min(D_GGX(NdotH, alpha), 500.0);
        float G = G_SmithGGX(NdotV, NdotL, alpha);
        vec3  F = F_Schlick(F0, VdotH);

        float sh = hardShadow(pos, n, l, 32.0); // 0/1 阴影
        float ao = 1.0;

        float energyComp = 1.0 / (1.0 + 0.5*rough);
        vec3 specBRDF = (D*G*F)/max(4.0*NdotL*NdotV,1e-4) * energyComp;
        vec3 direct   = (((1.0-F)*(1.0-metallic)*albedo/PI) + specBRDF) * sunCol * NdotL * sh;

        vec3 r = reflect(-v, n);
        vec3 envRef = prefilteredEnv(r, rough);

        vec3 iblSpec = envRef * F * 0.9;
        vec3 iblDiff = albedo * (1.0 - metallic) * 0.03 * ao;

        vec3 lighting = max(direct + iblDiff + iblSpec, vec3(0.0));
        col += throughput * lighting;

        if (bounce == BOUNCES){
            col += throughput * envRef * F;
            break;
        }

        float reflGain = mix(0.55, 0.85, clamp((1.0-rough)*1.2, 0.0, 1.0));
        throughput *= F * reflGain;
        if (max(throughput.r, max(throughput.g, throughput.b)) < 1e-3) break;

        ro = pos + n * 0.004;
        rd = r;
    }

    col = clamp(col, 0.0, 1.0);
    col = pow(col, vec3(0.45)); // gamma
    return col;
}

void mainImage(out vec4 fragColor, in vec2 fragCoord){
    vec3 acc = vec3(0.0);
    vec3 ro = vec3(0, 0, CamDist);

    for (int ii=0; ii<AA; ++ii){
        for (int jj=0; jj<AA; ++jj){
            vec2 ofs = vec2(ii, jj) / float(AA);
            vec2 uv = (2.0 * (fragCoord + ofs) - iResolution.xy) / iResolution.y;
            vec3 rd = normalize(vec3(uv, -1.8));
            acc += renderSample(ro, rd);
        }
    }
    vec3 col = acc / float(AA*AA);
    fragColor = vec4(col, 1.0);
}

// ===================== common.frag =====================
// 只包含参数曲面 + 近点投影 + Harnack 辅助；不读任何 iTime/iMouse/纹理。

#define PI            3.141592654
#define FAR           30.0
#define SphereCutRad  2.5
#define HELIX_ALPHA   0.55   // a：螺距，可按需微调
#define ReadState(x, y) texelFetch(iChannel0, ivec2(x, y), 0)

// ---------- 小工具 ----------
vec3 orthogonal(vec3 v){
    vec3 a = abs(v);
    if (a.x <= a.y && a.x <= a.z) return normalize(vec3(0., -v.z, v.y));
    else if (a.y <= a.x && a.y <= a.z) return normalize(vec3(v.z, 0., -v.x));
    else return normalize(vec3(-v.y, v.x, 0.));
}

bool intersectSphere(vec3 ro, vec3 rd, vec3 center, float radius,
                     inout float t0, inout float t1)
{
    vec3 oc = ro - center;
    float b = dot(rd, oc);
    float c = dot(oc, oc) - radius*radius;
    float h = b*b - c;
    if (h < 0.0) return false;
    h = sqrt(h);
    t0 = -b - h;
    t1 = -b + h;
    if (t1 < t0){ float tmp=t0; t0=t1; t1=tmp; }
    return true;
}

// ---------- 形变控制（由 image.frag 调 set*；本文件不读外部状态） ----------
float g_ass_s = 0.0;  // sin(theta)
float g_ass_c = 1.0;  // cos(theta)
float g_helix_phase = 0.0; // 螺旋相位（可转很多圈）

void setAssocAngle(float theta){ g_ass_s = sin(theta); g_ass_c = cos(theta); }
void setHelixPhase(float phase){ g_helix_phase = phase; }

// ---------- 数值稳定的双曲函数 ----------
float my_cosh(float x){ float e=exp(x), en=1.0/e; return 0.5*(e+en); }
float my_sinh(float x){ float e=exp(x), en=1.0/e; return 0.5*(e-en); }
float my_asinh(float x){ return log(x + sqrt(x*x + 1.0)); }

// ---------- Associate family 参数化 X(u,v;θ,ψ) 及导数 ----------
// 约定：u 沿绕轴方向（角度型），v 沿轴方向；a=HELIX_ALPHA
void assocSurfaceUV(float u, float v, out vec3 X, out vec3 Xu, out vec3 Xv){
    float a   = HELIX_ALPHA;
    float su  = sin(a*u - g_helix_phase);
    float cu  = cos(a*u - g_helix_phase);
    float sh  = my_sinh(a*v);
    float ch  = my_cosh(a*v);
    float sT  = g_ass_s, cT = g_ass_c;

    // 位置（x,y 做 1/a 尺度匹配，保证两端大小一致）
    X = (1.0/a) * vec3(
        sT*ch*cu + cT*sh*su,
        sT*ch*su - cT*sh*cu,
        a*(v*sT + u*cT)/a
    );

    // 一阶导（已抵消链式的 a，数值更稳）
    Xu = vec3(
        -sT*ch*su + cT*sh*cu,
         sT*ch*cu + cT*sh*su,
         cT
    );
    Xv = vec3(
         sT*sh*cu + cT*ch*su,
         sT*sh*su - cT*ch*cu,
         sT
    );
}

// ---------- 最近点投影（Gauss–Newton） ----------
void assocProject(vec3 p, inout vec2 uv, inout bool uvInit, out vec3 X, out vec3 N){
    float a = HELIX_ALPHA;
    if(!uvInit){
        float r = length(p.xy);
        float phi = atan(p.y, p.x);
        // helicoid 初值
        float uH = p.z;
        float vH = my_asinh(max(a*r,1e-6))/a;
        // catenoid 初值
        float uC = phi / a;
        float vC = p.z;
        // 根据 θ 在两者间插值
        float w  = g_ass_c * g_ass_c;   // cos^2 θ
        uv = vec2(mix(uC,uH,w), mix(vC,vH,w));
        uvInit = true;
    }

    for (int i=0;i<6;i++){
        vec3 Xu,Xv; assocSurfaceUV(uv.x,uv.y,X,Xu,Xv);
        vec3 r3 = X - p;
        float a11=dot(Xu,Xu), a12=dot(Xu,Xv), a22=dot(Xv,Xv);
        vec2  b  = vec2(dot(Xu,r3), dot(Xv,r3));
        float det=a11*a22-a12*a12+1e-8;
        vec2  d  = -(1.0/det)*vec2(a22*b.x-a12*b.y, -a12*b.x+a11*b.y);
        uv -= 0.8*d;
    }
    vec3 Xu,Xv; assocSurfaceUV(uv.x,uv.y,X,Xu,Xv);
    N = normalize(cross(Xu,Xv));
}

// ---------- Harnack：对 ψ(u,v)=rd·X(u,v) 在 B_r(uv0) 的上下界 ----------
struct HarnackBounds { float infv; float supv; };

HarnackBounds harnackBounds(vec2 uv0, vec3 rd, float R, float r){
    vec3 X0,Xu0,Xv0; assocSurfaceUV(uv0.x,uv0.y,X0,Xu0,Xv0);
    float psi0 = dot(rd, X0);

    // 正移位 β，保证 h=ψ+β>0（越大越保守）
    float beta = exp(1.2*R);
    float g    = (R+r)/(R-r);   // Harnack 常数

    float h0   = psi0 + beta;
    HarnackBounds B;
    B.infv = (1.0/g)*h0 - beta;
    B.supv = g*h0 - beta;
    return B;
}

// 给出沿射线参数 t 的“保底步长”（|rd|=1）
float harnackStep_t(vec3 ro, vec3 rd, float t, vec2 uv0, float Ruv, float ruv){
    float s = dot(rd, ro) + t;              // ψ 右端：rd·(ro+t rd)
    HarnackBounds B = harnackBounds(uv0, rd, Ruv, ruv);

    float stepSafe = 0.0;
    if (s < B.infv) stepSafe = B.infv - s;
    else if (s > B.supv) stepSafe = s - B.supv;
    else stepSafe = min(B.supv - s, s - B.infv);
    return max(1e-3, 0.9*stepSafe);
}

// ---------- 简单配色（保持你原本接口） ----------
vec3 hsv(float h, float s, float v){
    vec3 rgb = clamp(abs(mod(h*6.0+vec3(0.0,4.0,2.0),6.0)-3.0)-1.0,0.0,1.0);
    rgb = rgb*rgb*(3.0-2.0*rgb);
    return v * mix(vec3(1.0), rgb, s);
}

vec3 baseColor(vec3 pos, vec3 n){
    vec3 nn = abs(n); nn.z *= 2.2;
    return hsv(nn.x, nn.y, nn.z);
}

void mainImage(out vec4 fragColor, in vec2 fragCoord) {
    ivec2 pix = ivec2(fragCoord);

    if (iFrame == 0) {
        if (pix == ivec2(0, 0)) {
            fragColor = vec4(0.0);
            return;
        }
        if (pix == ivec2(1, 0)) {
            fragColor = vec4(iMouse.xy, 0.0, 0.0);
            return;
        }
        fragColor = vec4(0.0);
        return;
    }

    vec4 st0 = ReadState(0, 0); // yaw, pitch
    vec4 st1 = ReadState(1, 0); // prevMouse.xy, isDown

    float yaw = st0.x;
    float pitch = st0.y;

    vec2 prevM = st1.xy;
    bool wasDn = (st1.z > 0.5);
    bool isDn = (iMouse.z > 0.0);

    vec2 curM = isDn ? iMouse.xy : prevM;

    vec2 deltaN =
        (isDn && wasDn) ? (curM - prevM) / max(iResolution.y, 1.0) : vec2(0.0);
    yaw += deltaN.x * (2.0 * PI);
    pitch = clamp(pitch + deltaN.y * (1.0 * PI), -1.45, 1.45);

    if (!isDn && !wasDn) {
        float autoSpeed = 0.2 * PI;
        float dt = max(iTimeDelta, 1.0 / 60.0);
        yaw += autoSpeed * dt;
    }

    if (pix == ivec2(0, 0)) {
        fragColor = vec4(yaw, pitch, 0.0, 0.0);
        return;
    }
    if (pix == ivec2(1, 0)) {
        fragColor = vec4(isDn ? curM : prevM, isDn ? 1.0 : 0.0, 0.0);
        return;
    }

    fragColor = vec4(0.0);
}

/*
Rendering implicit surfaces using second-order
Hessian estimation.

See the Common tab for a list available surfaces. 
*/
float getAssocTheta() {
    // 鼠标按下时用 X 轴控制：0..π
    if (iMouse.z > 0.5) {
        float u = clamp(iMouse.x / iResolution.x, 0.0, 1.0);
        return mix(0.0, PI, u);
    }
    // 否则自动在 [0, π/2] 之间往返（螺旋面 <-> 悬链面）
    return 0.5 * PI * (0.5 + 0.5 * sin(iTime * 0.5));
}

float getHelixPhase() {
    const float TAU = 6.28318530718;
    float turns_per_second = 1.0;   // 每秒转几圈（随意调大）
    float turns_when_drag   = 8.0;  // 鼠标拖动时可得到的最大圈数
    if (iMouse.z > 0.5) {
        // 鼠标 X 位置决定转了多少圈
        float u = clamp(iMouse.x / iResolution.x, 0.0, 1.0);
        return TAU * turns_when_drag * u;
    }
    // 自动旋转：连续多圈
    return TAU * turns_per_second * iTime;
}


vec2 rot2(vec2 p, float a) { return p * cos(a) + vec2(-p.y, p.x) * sin(a); }

void transform(inout vec3 p) {
    vec4 mouse = ReadState(0, 0);
    float yaw = mouse.x;
    float pitch = mouse.y;

    p.zx = rot2(p.zx, -yaw);
    p.yz = rot2(p.yz, -pitch);
}

float map(vec3 p) {
    float d = pseudoSurface(p);
    float thickness = 0.0015;
    d = abs(d + thickness) - thickness;
    d = max(d, length(p) - SphereCutRad);
    return d;
}

float march(vec3 ro, vec3 rd) {
    const float precis = 1e-4;
    float h = precis * 2.0, t = 1.0;
    for (int i = 0; i < 256; i++) {
        h = map(ro + rd * t);
        t += h;
        if (h < precis * t || t > FAR)
            break;
    }
    return (t < FAR) ? t : -1.0;
}

float softshadow(vec3 ro, vec3 rd, float tmin, float tmax, float k) {
    float res = 1.0;
    float t = tmin;
    for (int i = 0; i < 24; i++) {
        float h = map(ro + rd * t);
        res = min(res, k * h / t);
        t += clamp(h, 0.001, 0.1);
        if (h < 0.0001 || t > tmax)
            break;
    }
    return clamp(res, 0.0, 1.0);
}

float calcAO(vec3 p, vec3 n) {
    float occ = 0.0, sca = 1.0;
    for (int i = 0; i < 5; i++) {
        float h = 0.01 + 0.2 * float(i) / 4.0;
        float d = map(p + n * h);
        occ += (h - d) * sca;
        sca *= 0.9;
    }
    return clamp(1.0 - 3.0 * occ, 0.0, 1.0);
}


vec3 getNormal(vec3 p, vec3 rd) {
    vec4 f_grad = evalF(p);
    vec3 n = normalize(f_grad.yzw);
    if (dot(n, rd) > 0.0)
        n = -n;
    return n;
}

float D_GGX(float NdotH, float a) {
    float a2 = a * a;
    float d = (NdotH * NdotH) * (a2 - 1.0) + 1.0;
    return a2 / (PI * d * d + 1e-7);
}

float G_SchlickGGX(float NdotX, float k) {
    return NdotX / (NdotX * (1.0 - k) + k + 1e-7);
}

float G_SmithGGX(float NdotV, float NdotL, float a) {
    float k = (a + 1.0);
    k = (k * k) / 8.0;
    return G_SchlickGGX(NdotV, k) * G_SchlickGGX(NdotL, k);
}

vec3 F_Schlick(vec3 F0, float VdotH) {
    return F0 + (1.0 - F0) * pow(1.0 - VdotH, 5.0);
}

float softLobe(vec3 rd, vec3 dir, float width) {
    float c = dot(normalize(rd), normalize(dir));
    float x = acos(c);
    float w = max(1e-3, width);
    return exp(-(x * x) / (2.0 * w * w));
}

vec3 studioEnv(vec3 rd) {
    float s1 = softLobe(rd, vec3(0.0, 0.25, 1.0), 0.18);
    float s2 = softLobe(rd, vec3(-0.7, 0.35, 0.6), 0.22);
    float topRim = pow(max(0.0, 1.0 - rd.y), 4.0);
    vec3 box1 = vec3(1.0) * 3.0 * s1;
    vec3 box2 = vec3(0.95) * 2.0 * s2;
    vec3 topC = vec3(0.2, 0.24, 0.30) * 0.2 * topRim;
    return max(box1 + box2 + topC, vec3(0.0));
}

vec3 prefilteredEnv(vec3 refl, float rough) {
    float t = clamp(rough * rough, 0.0, 0.95);
    vec3 up = (abs(refl.y) < 0.99) ? vec3(0.0, 1.0, 0.0) : vec3(1.0, 0.0, 0.0);
    vec3 tx = normalize(cross(up, refl));
    vec3 tz = normalize(cross(refl, tx));
    float bend = 0.85 * t;
    vec3 dir = normalize(mix(refl, tx * 0.4 + tz * 0.3 + refl * 0.3, bend));
    return studioEnv(dir);
}

vec3 renderSample(vec3 ro, vec3 rd) {
    vec3 l = normalize(vec3(0.5, 0.8, 3.0));
    vec3 sunCol = vec3(1.00, 0.98, 0.92) * 4.0;

    transform(ro);
    transform(rd);
    transform(l);
  float theta = getAssocTheta();
    setAssocAngle(theta);

    float psi   = getHelixPhase();
setHelixPhase(psi);    

    vec3 col = vec3(0.);
    vec3 throughput = vec3(1.0);

    for (int bounce = 0; bounce <= BOUNCES; ++bounce) {
        float t = march(ro, rd);

        if (t < 0.0) {
            if (bounce > 0)
                col += throughput * prefilteredEnv(rd, 0.25);
            break;
        }

        vec3 pos = ro + rd * t;
        vec3 n = getNormal(pos, rd);
        vec3 v = -rd;

        vec3 h = normalize(l + v);

        vec3 albedo = clamp(baseColor(pos, n), 0., 1.);
        float metallic = 0.4;
        float rough = 0.2;
        float alpha = pow(rough, 2.);
        vec3 F0 = mix(vec3(0.1), albedo, metallic);
        float NdotL = max(dot(n, l), 0.0);
        float NdotV = max(dot(n, v), 1e-4);
        float NdotH = max(dot(n, h), 1e-6);
        float VdotH = max(dot(v, h), 1e-6);

        float D = min(D_GGX(NdotH, alpha), 500.0);
        float G = G_SmithGGX(NdotV, NdotL, alpha);
        vec3 F = F_Schlick(F0, VdotH);

        float sh = softshadow(pos + n * 0.001, l, 0.02, 32.0, 16.0);
        float ao = calcAO(pos, n);

        float energyComp = 1.0 / (1.0 + 0.5 * rough);
        vec3 specBRDF =
            (D * G * F) / max(4.0 * NdotL * NdotV, 1e-4) * energyComp;
        vec3 direct =
            (((1.0 - F) * (1.0 - metallic) * albedo / PI) + specBRDF) * sunCol *
            NdotL * sh;

        vec3 r = reflect(-v, n);
        vec3 envRef = prefilteredEnv(r, rough);

        vec3 iblSpec = envRef * F * .9;
        vec3 iblDiff = albedo * (1.0 - metallic) * 0.03 * ao;

        vec3 lighting = max(direct + iblDiff + iblSpec, vec3(0.0));
        col += throughput * lighting;

        if (bounce == BOUNCES) {
            col += throughput * envRef * F;
            break;
        }

        float reflGain = mix(0.55, 0.85, clamp((1.0 - rough) * 1.2, 0.0, 1.0));
        throughput *= F * reflGain;
        if (max(throughput.r, max(throughput.g, throughput.b)) < 1e-3)
            break;

        ro = pos + n * 0.004;
        rd = r;
    }
    col = clamp(col, 0., 1.);
    col = pow(col, vec3(0.45));
    return col;
}

void mainImage(out vec4 fragColor, in vec2 fragCoord) {
    vec3 acc = vec3(0.0);
    vec3 ro = vec3(0, 0, CamDist);

    for (int ii = 0; ii < AA; ii++) {
        for (int jj = 0; jj < AA; jj++) {
            vec2 ofs = vec2(ii, jj) / float(AA);
            vec2 uv =
                (2.0 * (fragCoord + ofs) - iResolution.xy) / iResolution.y;
            vec3 rd = normalize(vec3(uv, -1.8));
            acc += renderSample(ro, rd);
        }
    }
    vec3 col = acc / float(AA * AA);

    fragColor = vec4(col, 1.0);
}

#define PI            3.141592654
#define FAR           40.
#define CamDist       20.0
#define SphereCutRad  10.
#define AA            1
#define BOUNCES       1
#define ReadState(x, y) texelFetch(iChannel0, ivec2(x, y), 0)
#define HELIX_ALPHA   .5
// ===== Parameter grid lines =====
#define SHOW_GRID            1          // 0 关，1 开
#define GRID_COLOR           vec3(0.0) // 线条颜色（深灰）
#define GRID_THICKNESS_NORM  0.1      // 线条归一化厚度（越大越粗）

// u 方向：每圈显示多少条母线（与 α 自适应）
#define U_LINES_PER_TURN     12.0
#define U_STEP               (2.0*PI/(HELIX_ALPHA*U_LINES_PER_TURN)) // Δz

// v 方向：半径等距的条数密度（按你的场景调）
#define V_STEP               1.       // Δρ
// ==== 在文件顶部或 ASSOC 之上新增 ====
float g_helix_phase = 0.0;  // 由 image.frag 传入
void setHelixPhase(float phase) { g_helix_phase = phase; }


