// vec4 for f(x,y,z) + ∇f(x,y,z)

vec4 CONST(float c) { return vec4(c, 0.0, 0.0, 0.0); }
vec4 VARX(float x) { return vec4(x, 1.0, 0.0, 0.0); }
vec4 VARY(float y) { return vec4(y, 0.0, 1.0, 0.0); }
vec4 VARZ(float z) { return vec4(z, 0.0, 0.0, 1.0); }
vec4 ADD(vec4 a, vec4 b) { return a + b; }
vec4 SUB(vec4 a, vec4 b) { return a - b; }

vec4 MUL(vec4 u, vec4 v) {
    float f = u.x * v.x;
    vec3 g = u.x * v.yzw + v.x * u.yzw;
    return vec4(f, g);
}

vec4 DIV(vec4 u, vec4 v) {
    float inv = 1.0 / v.x;
    float f = u.x * inv;
    vec3 g = (u.yzw - f * v.yzw) * inv;
    return vec4(f, g);
}

vec4 MULC(vec4 a, float c) { return vec4(a.x * c, a.yzw * c); }
vec4 CMUL(float c, vec4 a) { return MULC(a, c); }
vec4 ADDC(vec4 a, float c) { return vec4(a.x + c, a.yzw); }
vec4 CADD(float c, vec4 a) { return ADDC(a, c); }
vec4 SUBC(vec4 a, float c) { return vec4(a.x - c, a.yzw); }
vec4 CSUB(float c, vec4 a) { return vec4(c - a.x, -a.yzw); }

vec4 SQRT(vec4 a) {
    float f = sqrt(a.x);
    return vec4(f, (0.5 / f) * a.yzw);
}

vec4 LOG(vec4 a) {
    float f = a.x;
    return vec4(log(f), (1.0 / f) * a.yzw);
}

vec4 EXP(vec4 a) {
    float f = exp(a.x);
    return vec4(f, f * a.yzw);
}


vec4 SIN(vec4 a) { return vec4(sin(a.x), cos(a.x) * a.yzw); }
vec4 COS(vec4 a) { return vec4(cos(a.x), -sin(a.x) * a.yzw); }

vec4 TAN(vec4 a) {
    float t = tan(a.x);
    return vec4(t, (1.0 + t * t) * a.yzw);
}

vec4 ATAN(vec4 a) {
    float x = a.x;
    return vec4(atan(x), (1.0 / (1.0 + x * x)) * a.yzw);
}

vec4 ATAN2(vec4 Y, vec4 X) {
    float y = Y.x, x = X.x;
    float r2 = max(x * x + y * y, 1e-20);
    float f = atan(y, x);
    vec3 g = (x * Y.yzw - y * X.yzw) / r2;
    return vec4(f, g);
}

vec4 POW(vec4 a, float n) {
    float f = a.x;
    return vec4(pow(f, n), (n * pow(f, n - 1.0)) * a.yzw);
}

vec4 HELICOID(vec4 X, vec4 Y, vec4 Z) {
    const float a = HELIX_ALPHA;
    vec4 s = SIN(MULC(Z, a)); // sin(α z)
    vec4 c = COS(MULC(Z, a)); // cos(α z)
    // F = y*cos(α z) - x*sin(α z)
    return SUB(MUL(Y, c), MUL(X, s));
}


// ===== Associate family: helicoid <-> catenoid =====
// 全局存 sinθ / cosθ，由 image.frag 通过函数设置
float g_ass_s = 0.0; // sin(theta)
float g_ass_c = 1.0; // cos(theta)

// 在 image.frag 里调用：设置当前形变角
void setAssocAngle(float theta) {
    g_ass_s = sin(theta);
    g_ass_c = cos(theta);
}

// F_H (helicoid): r * sin(phi - a z)
// F_C (catenoid): r - (1/a) * cosh(a z)
// 其中 a = HELIX_ALPHA
vec4 ASSOC(vec4 X, vec4 Y, vec4 Z) {
    const float a = HELIX_ALPHA;

    // cylindrical coords
    vec4 R2  = ADD(MUL(X,X), MUL(Y,Y));
    vec4 R   = SQRT(R2);
    vec4 Phi = ATAN2(Y, X);
    vec4 aZ  = MULC(Z, a);

    // helicoid term: H = r * sin(phi - a z)
   vec4 H = MUL(R, SIN(SUBC(SUB(Phi, aZ), g_helix_phase)));


    // catenoid term: C = r - (1/a) * cosh(a z)
    // cosh(t) = (e^t + e^{-t}) / 2   （用已实现的 EXP 做自动微分）
    vec4 ePos = EXP(aZ);
    vec4 eNeg = EXP(MULC(aZ, -1.0));
    vec4 cosh_aZ = MULC(ADD(ePos, eNeg), 0.5);
    vec4 C = SUB(R, MULC(cosh_aZ, 1.0 / a));

    // Fθ = cosθ * H + sinθ * C
    return ADD(MULC(H, g_ass_c), MULC(C, g_ass_s));
}



vec4 evalF(vec3 p) {
    vec4 X = VARX(p.x), Y = VARY(p.y), Z = VARZ(p.z);
    return F_Expr(X, Y, Z);
}

float pseudoSurface(vec3 p) {
    vec4 F0 = evalF(p);
    float f0 = F0.x;
    vec3  g0 = F0.yzw;
    float G  = length(g0);

    float h = clamp(0.3 * abs(f0) / (G + 1e-6), 0.001, 0.01);
    vec4 Fx = evalF(p + vec3(h, 0.0, 0.0));
    vec4 Fy = evalF(p + vec3(0.0, h, 0.0));
    vec4 Fz = evalF(p + vec3(0.0, 0.0, h));

    vec3 cx = (Fx.yzw - g0) / h;
    vec3 cy = (Fy.yzw - g0) / h;
    vec3 cz = (Fz.yzw - g0) / h;

    float K = sqrt(dot(cx, cx) + dot(cy, cy) + dot(cz, cz));
    K = max(K, 1e-6);

    float B = G;
    float C = abs(f0);
    float disc = B * B + 2.0 * K * C;
    float t = (-B + sqrt(disc)) / K;
    float sgn = (f0 >= 0.0 ? 1.0 : -1.0);
    return 0.5 * t * sgn;
}

vec3 hsv(float h, float s, float v) {
    vec3 rgb = clamp(
        abs(mod(h*6.0+vec3(0.0,4.0,2.0),6.0)-3.0)-1.0,
    0.0, 1.0);
	rgb = rgb*rgb*(3.0-2.0*rgb);
	return v * mix( vec3(1.0), rgb, s);
}

// 在 value 上每隔 period 画一条线；返回 0..1 的遮罩（1 表示在线上）
float gridLinePeriodic(float value, float period, float thicknessNorm) {
    float p = max(1e-5, period);
    float t = value / p;
    // 到最近整数的“归一化距离” a∈[0,1]，a=0 正在线中心
    float a = abs(fract(t) - 0.5) * 2.0;
    // 屏幕空间抗锯齿宽度：fwidth(t) 是 1 个周期内的像素宽
    float aa = thicknessNorm + fwidth(t);
    // 线条遮罩：越接近 0 越在中心，反转得到 1=在线
    return 1.0 - smoothstep(0.0, aa, a);
}

// ====== Geodesic helpers ======
float geodesicPhase_Ceq1(float rho, float alpha) {
    // Φ(ρ,θ) = θ - (1/(2α^2)) ln((u-1)/(u+1))  是常数
    float a2 = alpha*alpha;
    float u  = sqrt(1.0 + a2*rho*rho);
    // 避免 log 的数值问题
    float num = max(u - 1.0, 1e-6);
    float den = u + 1.0;
    return -0.5 / a2 * log(num / den);  // 这是要从 θ 里减去的项
}

// 通用 C 的积分核 dθ/dρ
float dtheta_drho(float rho, float C, float alpha) {
    float a2 = alpha*alpha;
    float denom = 1.0 + a2*rho*rho;
    float s = 1.0 - (C*C)/denom;
    if (s <= 0.0) return 0.0; // 不可达区域（C>1 时 ρ<ρ_min）
    return C / (denom * sqrt(s));
}

// Simpson 积分（小步数即可）；把 C<=1 时 ρ* 从 0 积到 rho；C>1 从 ρmin+eps 起
float theta_from_rho_numeric(float rho, float C, float alpha) {
    float a2 = alpha*alpha;
    float rho_min = 0.0;
    if (C > 1.0) rho_min = sqrt(max(C*C - 1.0, 0.0)) / alpha;
    float r0 = (C > 1.0) ? (rho_min + 1e-4) : 0.0;
    float r1 = rho;
    float sign = 1.0;
    if (r1 < r0) { float tmp = r0; r0 = r1; r1 = tmp; sign = -1.0; }
    // N 必须是偶数
    const int N = 10;
    float h = (r1 - r0) / float(N);
    float sum = 0.0;
    for (int i = 0; i <= N; ++i) {
        float r = r0 + float(i) * h;
        float w = (i==0 || i==N) ? 1.0 : ((i%2)==1 ? 4.0 : 2.0);
        sum += w * dtheta_drho(r, C, alpha);
    }
    return sign * (h/3.0) * sum;
}

// 角度条纹（AA），在 φ ≡ 0 (mod period) 处出线
float phaseStripeAA(float phi, float period, float halfWidthPx) {
    float p = max(1e-5, period);
    float t = phi / p;
    float s = sin(2.0 * PI * t);
    float w = max(fwidth(s), 1e-4) * halfWidthPx;
    return 1.0 - smoothstep(0.0, w, abs(s));
}

