vec3 baseColor(vec3 pos, vec3 n) {
    // 原底色（随你）
    vec3 nn = abs(n); nn.z *= 2.2;
    vec3 albedo = hsv(nn.x, nn.y, nn.z);

    // 参数坐标
    float rho = length(pos.xy);
    float theta = pos.z;

    // ====== 画两类测地线 ======

    // (A) C=1 的闭式测地线：Φ(ρ,θ)=常数
    float PhiC1 = theta - geodesicPhase_Ceq1(rho, HELIX_ALPHA);
    // 每隔 Δ 绘一条线：例如 Δ = 0.6（你可以调）
    float maskC1 = phaseStripeAA(PhiC1, 1., 2.);

    // (B) 一条通用 C 的测地线（例如 C=1.3；C>1 不穿轴，会绕着走）
    // 可以多画几条不同 θ0 的平移：把 PhiC = θ - Θ_C(ρ) - θ0
    float C = 1.3;
    float ThetaC = theta_from_rho_numeric(rho, C, HELIX_ALPHA);
    float PhiC = theta - ThetaC;              // 先不加偏移
    float maskC = phaseStripeAA(PhiC, 4., 2.);

    // 合成遮罩（你也可以分色显示）
    float geoMask = max(maskC1, maskC);

    // 混到底色（把颜色调亮一些易辨识）
    vec3 geoColor = vec3(0.05); // 深灰测地线
    albedo = mix(albedo, geoColor, clamp(geoMask, 0.0, 1.0));

    return albedo;
}

void mainImage(out vec4 fragColor, in vec2 fragCoord) {
    ivec2 pix = ivec2(fragCoord);

    if (iFrame == 0) {
        if (pix == ivec2(0, 0)) {
            fragColor = vec4(0.0);
            return;
        }
        if (pix == ivec2(1, 0)) {
            fragColor = vec4(iMouse.xy, 0.0, 0.0);
            return;
        }
        fragColor = vec4(0.0);
        return;
    }

    vec4 st0 = ReadState(0, 0); // yaw, pitch
    vec4 st1 = ReadState(1, 0); // prevMouse.xy, isDown

    float yaw = st0.x;
    float pitch = st0.y;

    vec2 prevM = st1.xy;
    bool wasDn = (st1.z > 0.5);
    bool isDn = (iMouse.z > 0.0);

    vec2 curM = isDn ? iMouse.xy : prevM;

    vec2 deltaN =
        (isDn && wasDn) ? (curM - prevM) / max(iResolution.y, 1.0) : vec2(0.0);
    yaw += deltaN.x * (2.0 * PI);
    pitch = clamp(pitch + deltaN.y * (1.0 * PI), -1.45, 1.45);

    if (!isDn && !wasDn) {
        float autoSpeed = 0.2 * PI;
        float dt = max(iTimeDelta, 1.0 / 60.0);
        yaw += autoSpeed * dt;
    }

    if (pix == ivec2(0, 0)) {
        fragColor = vec4(yaw, pitch, 0.0, 0.0);
        return;
    }
    if (pix == ivec2(1, 0)) {
        fragColor = vec4(isDn ? curM : prevM, isDn ? 1.0 : 0.0, 0.0);
        return;
    }

    fragColor = vec4(0.0);
}

/* 
-----------------------------------------------
Centroidal Voronoi tessellation cooling process
-----------------------------------------------

This shader visualizes the stationary state of N particles
moving inside a domain tiled by N regular hexagons,
updated by a noisy Lloyd relaxation process:

1. At each iteration we compute the Voronoi diagram
induced by the current particle positions.

2. We estimate the centroid of every Voronoi cell using
Monte Carlo sampling.

3. Each particle is moved to the estimated centroid of
its own Voronoi cell (hence there is sampling error).

4. We repeat until every hexagon center has a particle
whose distance to that center is below a given tolerance.

5. At that point we freeze all particles exactly onto the
hexagon centers for a cleaner final picture.

Only step (5) is an artificial “cheat”, but for a somewhat
subtle reason. If we always moved particles to the exact
Voronoi centroids, Lloyd’s algorithm could get stuck in
locally optimal but slightly irregular configurations.
The Monte Carlo estimate of the centroids injects noise:
this slows down convergence, but it also gives the system
enough randomness to escape those local optima and
(almost) always find the globally optimal configuration,
where each particle sits at the center of one hexagon.
However, once the particles are very close to the hex centers,
the same noise prevents them from settling exactly, so in
the final step we snap them onto the centers purely for
visual aesthetics.

*/

vec3 hotMap(float t) {
    t = clamp(t, 0.0, 1.0);
    const vec3 HOT_LOW = vec3(0.45, 0.0, 0.05);
    const vec3 HOT_MID = vec3(0.90, 0.20, 0.00);
    const vec3 HOT_HIGH = vec3(1.00, 0.95, 0.40);

    if (t < 0.5) {
        float k = t * 2.0;
        return mix(HOT_LOW, HOT_MID, k);
    } else {
        float k = (t - 0.5) * 2.0;
        return mix(HOT_MID, HOT_HIGH, k);
    }
}

void mainImage(out vec4 fragColor, in vec2 fragCoord) {
    vec2 gridSize = getGridSize();
    float screenAspect = iResolution.x / iResolution.y;
    float gridAspect = gridSize.x / gridSize.y;

    float zoom;
    if (screenAspect > gridAspect) {
        zoom = (iResolution.y * 0.95) / gridSize.y;
    } else {
        zoom = (iResolution.x * 0.95) / gridSize.x;
    }

    vec2 uv = (fragCoord - 0.5 * iResolution.xy) / zoom;
    float px = 1.0 / zoom;

    float regionSDF = sdHexRegion(uv);
    bool isInside = regionSDF < 0.0;

    vec3 color_background = hotMap(0.03);
    vec3 color_polygonfill = hotMap(0.12);
    vec3 color_shadow = color_polygonfill * 0.765;
    vec3 cellHotTop = hotMap(1.0);

    vec3 col = color_background;

    float shadowDist = max(regionSDF, 0.0);
    float shadowRadius = HEX_R * .05;
    float shadowAlpha = 1.0 - smoothstep(0.0, shadowRadius, shadowDist);

    if (!isInside) {
        col = mix(col, color_shadow, shadowAlpha);
    }

    if (isInside) {
        col = color_polygonfill;

        float d1 = 1e9;
        float d2 = 1e9;
        int closestID = -1;
        vec2 closestPos = vec2(0.0);
        vec2 secondPos = vec2(0.0);

        for (int i = 0; i < TOTAL_POINTS; i++) {
            vec4 data = texelFetch(iChannel0, ivec2(i, 0), 0);
            if (data.z > 0.5) {
                vec2 p = data.xy;
                float d = length(uv - p);
                if (d < d1) {
                    d2 = d1;
                    secondPos = closestPos;
                    d1 = d;
                    closestID = i;
                    closestPos = p;
                } else if (d < d2) {
                    d2 = d;
                    secondPos = p;
                }
            }
        }

        if (closestID >= 0) {
            ivec2 hexId = getClosestHexID(closestPos);
            vec2 hexCenter = getHexCenter(hexId.x, hexId.y);
            float dist = length(closestPos - hexCenter);
            float t = clamp(dist / HEX_R, 0.0, 1.0);

            vec3 baseShadeColor = hotMap(t);
            float baseAlpha = smoothstep(0.10, 0.90, t) * 0.6;
            float highlightMask = smoothstep(0.75, 1.0, t);

            if (highlightMask > 0.0) {
                vec3 darkerBase = hotMap(t) * 0.765;
                float rand =
                    fract(sin(float(closestID) * 12.9898) * 43758.5453);
                float phase = rand * 6.2831853;
                float blink = 0.5 + 0.5 * sin(iTime * 35.0 + phase);
                vec3 flickerColor = mix(darkerBase, cellHotTop, blink);

                baseShadeColor =
                    mix(baseShadeColor, flickerColor, highlightMask);

                float flickerAlpha = mix(0.4, 0.9, blink);
                baseAlpha = mix(baseAlpha, flickerAlpha, highlightMask);
            }

            col = mix(col, baseShadeColor, baseAlpha);

            if (d2 < 1e8) {
                vec2 p1 = closestPos;
                vec2 p2 = secondPos;
                vec2 diff = p2 - p1;
                float distBetween = length(diff);

                if (distBetween > 0.0001) {
                    vec2 mid = 0.5 * (p1 + p2);
                    vec2 dir = diff / distBetween;
                    float distToLine = abs(dot(uv - mid, dir));
                    float lineWidth = .75 * px;
                    float borderA = 1.0 - smoothstep(lineWidth * 0.5,
                                                     lineWidth * 0.5 + 1.5 * px,
                                                     distToLine);

                    col = mix(col, vec3(0), borderA);
                }
            }

            float pointRadius = 3.0 * px;
            float pointAlpha =
                1.0 - smoothstep(pointRadius - 1.0 * px, pointRadius, d1);
            col = mix(col, vec3(0), pointAlpha);
        }
        ivec2 hid = getClosestHexID(uv);
        vec2 hCenter = getHexCenter(hid.x, hid.y);
        float distEdge = abs(sdHexagon(uv - hCenter, HEX_R));
        float lineW = 1.0 * px;
        float gridA = smoothstep(lineW, 0.0, distEdge - 0.5 * lineW);
        col = mix(col, vec3(0), gridA);
    }

    float borderA = 1.0 - smoothstep(1.0 * px, 2.5 * px, abs(regionSDF));
    col = mix(col, vec3(0), borderA * 0.4);
    fragColor = vec4(col, 1.0);
}

#define COLS 21
#define ROWS 10
#define HEX_R 0.5
#define TOTAL_POINTS (COLS * ROWS)
#define MC_SAMPLES 200

const float ERR_FREEZE = 0.05 * HEX_R;
const float ERR_MAX = 1. * HEX_R;
const float MAX_STEP = 0.4 * HEX_R;
const float CLOSE_THRESHOLD = 0.2 * HEX_R;

const float SQRT3 = 1.7320508;
const float s = 2.0 * HEX_R / SQRT3; // side length of a hexagon
const float cx = 0.75 * s * (float(COLS) - 1.0);
const float cy = 0.5 * HEX_R * (2.0 * float(ROWS) - 1.0);

float hash11(float p) {
    p = fract(p * .1031);
    p *= p + 33.33;
    p *= p + p;
    return fract(p);
}

vec2 hash22(vec2 p) {
    vec3 p3 = fract(vec3(p.xyx) * vec3(.1031, .1030, .0973));
    p3 += dot(p3, p3.yzx + 33.33);
    return fract((p3.xx + p3.yz) * p3.zy);
}

float sdHexagon(in vec2 p, in float r) {
    const vec3 k = vec3(-SQRT3 / 2., 0.5, SQRT3 / 3.);
    p = abs(p);
    p -= 2.0 * min(dot(k.xy, p), 0.0) * k.xy;
    p -= vec2(clamp(p.x, -k.z * r, k.z * r), r);
    return length(p) * sign(p.y);
}

vec2 getGridSize() {
    float w = s * (1.5 * float(COLS) + 0.5);
    float h = HEX_R * (2.0 * float(ROWS) + 1.0);
    return vec2(w, h);
}

vec2 getHexCenter(int col, int row) {
    float x = 1.5 * s * float(col);
    float y = 2.0 * HEX_R * (float(row) + 0.5 * float(col & 1));
    return vec2(x - cx, y - cy);
}

ivec2 getClosestHexID(vec2 p) {
    vec2 q = p + vec2(cx, cy);
    float col_f = q.x / (1.5 * s);
    float row_f = q.y / (2.0 * HEX_R);

    int col0 = int(floor(col_f));
    int row0 = int(floor(row_f));

    col0 = clamp(col0, 0, COLS - 1);
    row0 = clamp(row0, 0, ROWS - 1);
    float minD = 1e5;
    ivec2 bestID = ivec2(0);

    for (int dc = -1; dc <= 1; ++dc) {
        int c = col0 + dc;
        if (c < 0 || c >= COLS)
            continue;
        for (int dr = -1; dr <= 1; ++dr) {
            int r = row0 + dr;
            if (r < 0 || r >= ROWS)
                continue;

            vec2 center = getHexCenter(c, r);
            float d = dot(p - center, p - center);

            if (d < minD) {
                minD = d;
                bestID = ivec2(c, r);
            }
        }
    }

    return bestID;
}

float sdHexRegion(vec2 p) {
    ivec2 id = getClosestHexID(p);
    vec2 center = getHexCenter(id.x, id.y);
    return sdHexagon(p - center, HEX_R);
}

vec2 getParticlePos(int id) {
    return texelFetch(iChannel0, ivec2(id, 0), 0).xy;
}

bool inMyVoronoiCell(vec2 p, int myID, vec2 myPos) {
    float myDist2 = dot(p - myPos, p - myPos);
    for (int i = 0; i < TOTAL_POINTS; i++) {
        if (i == myID)
            continue;
        vec2 otherPos = getParticlePos(i);
        float d2 = dot(p - otherPos, p - otherPos);
        if (d2 < myDist2)
            return false;
    }
    return true;
}

float computeGlobalError() {
    float maxErr = 0.0;
    for (int r = 0; r < ROWS; ++r) {
        for (int c = 0; c < COLS; ++c) {
            vec2 center = getHexCenter(c, r);
            float minD2 = 1e5;
            for (int i = 0; i < TOTAL_POINTS; ++i) {
                vec2 p = getParticlePos(i);
                vec2 d = p - center;
                float d2 = dot(d, d);
                if (d2 < minD2)
                    minD2 = d2;
            }
            float d = sqrt(minD2);
            if (d > maxErr)
                maxErr = d;
        }
    }
    return maxErr;
}

void mainImage(out vec4 fragColor, in vec2 fragCoord) {
    if (fragCoord.y > 0.5 || fragCoord.x >= float(TOTAL_POINTS)) {
        discard;
    }
    int id = int(fragCoord.x);

    vec4 data = texelFetch(iChannel0, ivec2(id, 0), 0);
    vec2 pos = data.xy;
    float alive = data.z;
    float errSmoothPrev = texelFetch(iChannel0, ivec2(0, 0), 0).w;

    if (iFrame == 0) {
        vec2 rnd = hash22(vec2(float(id), iDate.w));
        pos = (rnd - 0.5) * 0.1 * HEX_R;
        fragColor = vec4(pos, 1.0, 100.0);
        return;
    }

    if (errSmoothPrev > ERR_FREEZE) {
        float e = clamp(errSmoothPrev, ERR_FREEZE, ERR_MAX);
        float stepGlobal = (e - ERR_FREEZE) / (ERR_MAX - ERR_FREEZE);

        vec2 centroidAccum = vec2(0.0);
        float sampleCount = 0.0;
        vec2 seedBase = vec2(float(id), iTime);
        float searchRadius = SQRT3 * HEX_R;

        for (int i = 0; i < MC_SAMPLES; i++) {
            vec2 r = hash22(seedBase + float(i) * 123.45);
            vec2 probe = pos + (r - 0.5) * 2.0 * searchRadius;

            if (sdHexRegion(probe) <= 0.0 && inMyVoronoiCell(probe, id, pos)) {
                centroidAccum += probe;
                sampleCount += 1.0;
            }
        }

        if (sampleCount > 0.0) {
            vec2 target = centroidAccum / sampleCount;
            vec2 dp = target - pos;
            float dist = length(dp);
            if (dist > 1e-5) {
                float localFactor = smoothstep(0.0, CLOSE_THRESHOLD, dist);
                float step = min(dist * stepGlobal * localFactor, MAX_STEP);
                pos += dp * (step / dist);
            }
        }

        if (sdHexRegion(pos) > 0.1)
            pos *= 0.95;

        ivec2 bestID = getClosestHexID(pos);
        vec2 idealPos = getHexCenter(bestID.x, bestID.y);
        if (length(pos - idealPos) < ERR_FREEZE) {
            pos = idealPos;
        }
    }

    float wOut = errSmoothPrev;
    if (id == 0) {
        float errNow = computeGlobalError();
        wOut = mix(errSmoothPrev, errNow, 0.2);
    }

    fragColor = vec4(pos, alive, wOut);
}

// Harnack tracing parameters
const bool harnackTrace = true;
const float epsilon = 0.0025;
const int iter_max = 1500;

// ============== Scenes
// -1 : z
//  0 : arg( z )
//  1 : log( (3z + 1) / (3z - 1) )
//  2 : sqrt( z )
//  3 : z^1/3
//  4 : just draw a car
const int scene = 1;

// === scene parameters
const bool clipToSphere = true;
const vec3 sphereCenter = vec3(0.f, 0.f, 0.f);
const float sphereRadius = 1.f;
const float outerRadius = sphereRadius + 0.5;

// === color modes
// 0 : rainbow
// 1 : tartan
// 2 : road (draws implicit car from https://www.shadertoy.com/view/Ms33Dj with space background from https://www.shadertoy.com/view/MslGWN)
// 3 : normals
const int colorMode = 2;

const float animationSpeed = .75; // only applies to `road` colorMode
const bool drawTanBackground = false;

//=======================================================
//
//               Complex Analysis Code
// (for evaluating and bounding complex functions, etc)
//=======================================================

// find greatest val - k * period which is still less than c and
// the least val + k * period which is still greater than c
vec2 periodicBounds( float val, float c, float nPeriods ) {
    const float period = 2. * PI;

    // find greatest val - k * period which is still less than c
    float kLow = ceil( ( val - c ) / period );
    if ( nPeriods >= 0. ) kLow = max( min( kLow, nPeriods ), -nPeriods );
    float valLow = val - kLow * period;

    // find least val + k * period which is still greater than c
    float kHigh = ceil( ( c - val ) / period );
    if (nPeriods >= 0. ) kHigh = max( min( kHigh, nPeriods ), -nPeriods );
    float valHigh = val + kHigh * period;

    return vec2( valLow, valHigh );
}

// find the greatest im[exp(2πi/n k)*f] still less than c and
// the least im[exp(2πi/n k)*f] still greater than c
vec2 rootOfUnityBounds( vec2 f, float c, int n ) {
    vec2 omega0 = cexp( 2. * PI / float( n ) );
    vec2 omega = vec2(1., 0.);

    float valLow = -INF;
    float valHigh = INF;

    for ( int k = 0; k < n; k++ ) {
        float val = im( mul( omega, f ) );
        if ( val >= valLow && val <= c ) valLow = val;
        if ( val <= valHigh && val >= c ) valHigh = val;
        omega = mul( omega, omega0 );
    }

    return vec2( valLow, valHigh );
}

const float height = 9.; // 9 for first two, 5 for second two?
float yScale() {
    switch ( scene ) {
        case 0:
        case 1:
            // use thinner branches if drawing cars
            return colorMode == 2 ? 1.5 * height : 1. * height;
        case 2:
            return 0.25 * height;
        case 3:
            return 0.15 * height;
    }
    return 1. * height;
}

vec2 complexFunction( vec2 p ) {
    vec2 z = p;
    vec2 one = vec2( 1. , 0. );

    switch ( scene ) {
        case 0: // log( z )
            return clog( z );
        case 1: // log( (3z + 1) / (3z - 1) )
            return clog( div( 3. * z + one, 3. * z - one ) );
        case 2: // sqrt( z )
            return csqrt( z );
        case 3: // z^1/3
            return cpow( z, 1. / 3. );
    }
    return p;
}

float color( vec2 z ) { // color scheme to use when plotting
    switch ( scene ) {
        case 0: // log( z )
        case 1: // log( (3z + 1) / (3z - 1) )
            return im( z );
        case 2: // sqrt( z )
        case 3: // z^1/3
            return arg( z );
    }
    return im( z );
}

// parameter for visualization of cars driving along Riemann surface
float carRadius() {
    if ( scene == 1 ) return .2;
    return .5;
}

float laneWidth() {
    if ( scene == 1 ) return .1;
    return .25;
}

int carLanes() {
    return 2;
}

float carScale() {
    switch ( scene ) {
    case 1:
        return 0.4;
    case 4:
        return 5.;
    case 0:
    case 2:
    case 3:
        return 1.;
    }
    return 1.;
}

vec2 identifyRootOfUnity( vec3 pos, int n ) {
    vec2 f = complexFunction( pos.xz );

    vec2 omega0 = cexp( 2. * PI / float( n ) );
    vec2 omega = vec2(1., 0.);

    for ( int k = 0; k < n; k++ ) {
        if ( abs( im( mul( omega, f ) ) - pos.y * yScale() ) < epsilon ) return omega;
        omega = mul( omega, omega0 );
    }

    return vec2(1, 0);
}

// find the branch of the complex function closest to our point
vec2 branchedComplexFunction( vec3 pos ) {
    vec2 f = complexFunction( pos.xz );
    switch ( scene ) {
        case 0: // log( z )
        case 1: // log( (3z + 1) / (3z - 1) )
            return f;
        case 2: // sqrt( z )
            return mul( identifyRootOfUnity( pos, 2 ), f );
        case 3: // z^1/3
            return mul( identifyRootOfUnity( pos, 3 ), f );
    }
    return f;
}

// evaluate the derivative of the complex function, using the branch closest to our point
vec2 complexDerivative( vec3 pos ) {
    vec2 z = pos.xz;
    vec2 one = vec2( 1., 0. );

    switch ( scene ) {
        case 0: // log( z )
            return div( one, z );
        case 1: // log( (3z + 1) / (3z - 1) )
            return 6. * div( one, one - 9. * mul( z, z ) );
        case 2: // sqrt( z )
            return mul( identifyRootOfUnity( pos, 2), div( one, 2. * csqrt( z ) ) );
        case 3: // z^1/3
            return mul( identifyRootOfUnity( pos, 3), div( one, 3. * cpow( z, 2. / 3. ) ) );
    }
    return vec2(1, 0);
}

// evaluate the derivative of the complex function, on the given branch
vec2 complexDerivative( vec3 pos, int branch ) {
    vec2 z = pos.xz;
    vec2 one = vec2( 1., 0. );

    switch ( scene ) {
        case 0: // log( z )
            return div( one, z );
        case 1: // log( (3z + 1) / (3z - 1) )
            return 6. * div( one, one - 9. * mul( z, z ) );
        case 2: // sqrt( z )
            return mul( cexp( 2. * PI * float( branch ) / 2. ), div( one, 2. * csqrt( z ) ) );
        case 3: // z^1/3
            return mul( cexp( 2. * PI * float( branch ) / 3. ), div( one, 3. * cpow( z, 2. / 3. ) ) );
    }
    return vec2(1, 0);
}

vec3 normal( in vec3 pos ) {
    if ( scene == 4 ) return vec3( 0., -1., 0. );

    vec2 df_dp = complexDerivative( pos );

    // df_dp components look backwards because we're plotting the imaginary part of f
    vec3 grad = vec3( df_dp.y, -yScale(), df_dp.x );

    return grad / length( grad );
}

// compute the normal on a fixed branch
vec3 normal( in vec3 pos, int branch ) {
    if ( scene == 4 ) return vec3( 0., -1., 0. );

    vec2 df_dp = complexDerivative( pos, branch );

    // df_dp components look backwards because we're plotting the imaginary part of f
    vec3 grad = vec3( df_dp.y, -yScale(), df_dp.x );

    return grad / length( grad );
}

float computeR( vec2 p ) {
    switch ( scene ) {
        case 0:   // log( z )
            return dist2D( p, vec2(0, 0) );
        case 1: { // log( (3z + 1) / (3z - 1) )
            vec2 pole = vec2( 1. / 3., 0. );
            return min( dist2D( p, pole ), dist2D( p, -pole ) );
        }
        case 2:   // sqrt( z )
        case 3:   // z^1/3
            return dist2D( p, vec2(0, 0) );
    }
    return 1.;
}

vec2 closestPole( vec2 p ) {
    vec2 pole = vec2( 0, 0 );
    if ( scene == 1 ) {
        pole = sign( p.x ) * vec2( 1. / 3., 0. );
    } else if ( scene == 4 ) {
        pole = vec2( 1000, 0 );
    }
    return pole;
}

// identify level set values above and below our current position
vec2 fBounds( float h, float val, vec2 f ) {
    switch ( scene ) {
        case 0: // log( z )
        case 1: // log( (3z + 1) / (3z - 1) )
            return periodicBounds( val, h, -1. ); // infinite stacked sheets
        case 2: // sqrt( z )
            return rootOfUnityBounds( f, h, 2 );
        case 3: // z^1/3
            return rootOfUnityBounds( f, h, 3 );
    }
    return periodicBounds( val, h, 0. );
}

vec3 groundTexture( vec3 pos ) {
    vec2 scaled_pos = mod( 3000. * mod( pos.xz, 1. ), vec2(1024));
    return texelFetch(iChannel2, ivec2(scaled_pos), 0).xyz;
}

vec3 albedo( vec2 z, vec3 pos, bool diffuse ) {
    float s = diffuse ? 0.8 : 1.0;
    float v = diffuse ? 1.0 : 0.7;
    switch ( colorMode ) {
    case 0: // rainbow
        return hsv( color( z ) / (2. * PI), s, v);
    case 1: // tartan
        return tartan( 0.5 * z );
    case 2: // road
        return road( pos.xz, closestPole( pos.xz ), groundTexture( pos ), carRadius(), laneWidth(), carLanes() );
    }
    return vec3(0);
}

vec3 complexColor( in vec3 pos, in vec3 rd ) {
    if ( colorMode == 3 ) { // normal shading
        vec3 nor = 0.9 * normal( pos );
        bool onFront = dot( nor, rd ) < 0.;
        nor *= onFront ? 1. : -1.;
        return ( nor + vec3(1) ) / 2.;
    }

    vec2 z = branchedComplexFunction( pos );
    float u_modLen = 0.15 * PI;
    // from polyscope/src/render/opengl/shaders/rules.cpp : SHADE_GRID_VALUE2
    float mX = mod(z.x, 2.0 * u_modLen) / u_modLen - 1.f; // in [-1, 1]
    float mY = mod(z.y, 2.0 * u_modLen) / u_modLen - 1.f;
    float minD = min(min(abs(mX), 1.0 - abs(mX)), min(abs(mY), 1.0 - abs(mY))) * 2.; // rect distace from flipping sign in [0,1]
    float slope = length(z); // length(abs(dFdx(z)) + abs(dFdy(z)));
    float width = .05 ;
    float pWidth = 0.015 * slope ;
    float s = smoothstep(width, width + pWidth, minD);
    float front_mask = s;
    float back_mask = ( colorMode <= 1 ) ? s : 1.25 - s/4.;
    vec3 dif_alb = (back_mask) * albedo( z, pos, true  );
    vec3 amb_alb = (back_mask) * albedo( z, pos, false );
    vec3 nor = normal( pos );
    bool onFront = dot( nor, rd ) < 0.;
    if ( onFront ) {
        // float s = 0.3;
        // dif_alb = 0.75 * ( ( 1. - s ) * dif_alb + s * vec3( 1., 1., 1. ) );
        // amb_alb = 0.75 * ( ( 1. - s ) * amb_alb + s * vec3( 1., 1., 1. ) );
        dif_alb = front_mask * vec3( 0.3, 0.4, 0.7 );
        amb_alb = front_mask * vec3( 0.1, 0.2, 0.8 );
    }
    float dif = clamp( dot( nor, normalize( vec3( 1., -1., 0. ) ) ), 0.0, 1.0 );
    float amb = 0.25 + 0.75 * clamp( dot( nor, normalize( vec3( 0.0, -1.0, 1.0 ) ) ), 0., 1. );
    return amb_alb*amb + dif_alb*dif;
    // return nor;
}


//=======================================================
//
//               Harnack Tracing Code
//
//=======================================================

float getMaxStep3D( float target, float R, float fx, float shift ) {
    float a    = (fx + shift) / (target + shift);
    return R / 2. * abs(a + 2. - sqrt(a * a + 8. * a));
}

float getMaxStep3D( float lo_bound, float up_bound, float R, float fx, float shift ) {
    if ( lo_bound <= -INF ) {
        return getMaxStep3D( up_bound, R, fx, shift );
    } else if ( up_bound >= INF ) {
        return getMaxStep3D( lo_bound, R, fx, shift );
    }

    float w    = (fx + shift) / (up_bound + shift);
    float v    = (fx + shift) / (lo_bound + shift);
    float lo_r = -R / 2. * (v + 2. - sqrt(v * v + 8. * v));
    float up_r =  R / 2. * (w + 2. - sqrt(w * w + 8. * w));

    return min(lo_r, up_r);
}

bool harnack( vec3 ro, vec3 rd, inout vec3 pos, inout float t, in float tmax, inout bool maxSteps ) {
    int iStep = 0;

    float t0 = 0.;
    t = 0.f;
    float shift = 4.;
    maxSteps = false;

    if ( clipToSphere ) {
        // special case for drawing cars on ``parking garage''
        if ( scene == 1 && colorMode == 2 ) {
            bool hitSphere = intersectEllipsoid(ro, rd, sphereCenter, sphereRadius, vec3( .9, .8, .7 ), t0, tmax);

            if ( !hitSphere || tmax < 0.) return false;
            if ( t0 > 0.f ) t = t0;
        } else {
            bool hitSphere = intersectSphere(ro, rd, sphereCenter, sphereRadius, t0, tmax);

            if ( !hitSphere || tmax < 0.) return false;
            if ( t0 > 0.f ) t = t0;
        }
    }

    pos = ro+t*rd;
    while ( t < tmax ){
        if ( iStep > iter_max ) {
            maxSteps = true;
            return false;
        }

        vec2 f = complexFunction( pos.xz );
        float val = im( f );
        float h = pos.y * yScale();
        vec2 bounds = fBounds( h, val, f );
        if ( min( h - bounds.x, bounds.y - h ) < epsilon ) return true;

        float R = computeR( pos.xz );
        float stepSize;

        if ( bounds.x <= -INF ) {
            val = h;
            stepSize = getMaxStep3D( bounds.y, R, val, shift );
        } else {
            val = h - bounds.x;
            bounds.y -= bounds.x;
            bounds.x = 0.;
            if ( val < bounds.x ) return false;
            stepSize = getMaxStep3D( bounds.x, bounds.y, R, val, shift );
        }

        t += stepSize;
        pos = ro + t * rd;
        iStep++;
    }

     return false;
}

bool raymarch(vec3 ro, vec3 rd, inout float t, float tmax, inout vec3 finalPos){
    float t0, t1;
    t = 0.;

    if ( clipToSphere ) {
        bool hitSphere = intersectSphere(ro, rd, sphereCenter, sphereRadius, t0, t1);

        if ( !hitSphere || tmax < 0.) return false;
        if ( t0 > 0. ) t = t0 + 0.01;
    }

    for( int i=0; i<iter_max; i++ ) {
        vec3 pos = ro+t*rd;

        vec2 f = complexFunction( pos.xz );
        float val = im( f );
        float h = pos.y * yScale();
        vec2 bounds = fBounds( h, val, f );

        if ( min( h - bounds.x, bounds.y - h ) < epsilon ) {
            finalPos = ro + t * rd;
            return true;
        } else if(t > tmax || t > t1) {
            return false;
        }
        t += 0.0025;
    }
    return false;

}

//========== Drawing Cars
// implicit car equation defined in `Common` tab

// ( from https://www.shadertoy.com/view/7tKfz1 )
vec3 normalShade(vec3 ray, vec3 normal, vec3 materialColor) {
    // material
    float metallic = 0.07;
    float roughness = 0.1;
    float fresnel_pow = mix(5.0, 3.5, metallic);
    vec3 color_mod = vec3(1.0);
    vec3 light_color = pow(texture(iChannel1,vec3(1.0,0.0,0.0)).xyz * 1.2, vec3(2.2));


    // IBL
    vec3 ibl_diffuse = pow(textureBlured(iChannel1,normal), vec3(2.2));
    vec3 ibl_reflection = pow(textureBlured(iChannel1,reflect(ray,normal)), vec3(2.2));

    // fresnel
    float fresnel = max(1.0 - dot(normal,-ray), 0.0);
    fresnel = pow(fresnel,fresnel_pow);    

    // reflection        
    vec3 refl = pow(texture(iChannel1,reflect(ray,normal)).xyz, vec3(2.2));
    refl = mix(refl,ibl_reflection,(1.0-fresnel)*roughness);
    refl = mix(refl,ibl_reflection,roughness);

    // specular
    vec3 light = normalize(vec3(-0.5,1.0,0.0));
    float power = 1.0 / max(roughness * 0.4,0.01);
    vec3 spec = light_color * GGX(normal,-ray,light,roughness*0.7, 0.2);
    refl -= spec;

    // diffuse
    vec3 diff = ibl_diffuse * pow(materialColor, vec3(2.2));
    diff = mix(diff * color_mod,refl,fresnel);        

    vec3 color = min( mix(diff,refl * color_mod,metallic) + spec, vec3(1., 1., 1.) );
    return pow(color, vec3(1.0/2.2));
}

bool intersect_car( vec3 ro_in, vec3 rd_in, bool flip_dir, float carScale, float car_kind, int branch, vec3 center, inout float t, float tmax, out vec3 color ) {
    // construct local basis e1, e2, e3
    vec3 e2 = -normal( center, branch );
    vec2 pole = closestPole( center.xz );
    vec3 e1 = vec3( center.x - pole.x, 0., center.z - pole.y );
    e1 = normalize( e1 - dot( e2, e1 ) * e2 );
    vec3 e3 = ( flip_dir ? -1. : 1. ) * cross( e1, e2 );

    // transform ray into e1, e2, e3 basis
    vec3 ro_rel = ro_in - center + 0.015 * carScale * e2;
    vec3 ro = vec3( dot( e1, ro_rel ), dot( e2, ro_rel ), dot ( e3, ro_rel ) );
    vec3 rd = vec3( dot( e1, rd_in  ), dot( e2, rd_in  ), dot ( e3, rd_in  ) );

    bool hit_car = intersect_car_df( ro, rd, t, tmax, carScale );
    if ( hit_car ) {
        vec3 pLocal = ro + t * rd;

        vec3 baseColor = hsv ( car_kind, .9, 1.);
        // baseColor = vec3(0.3, 1., 0.5);
        // vec3 baseColor = redblue( car_kind, vec2(0, 1) );

        if (CarDf( pLocal, carScale ) < 0. ) {
            color = baseColor * 0.3;
            return true;
        }

        vec3 pGlobal = ro_in + t * rd_in;
        float specularity, glow;
        vec3 albedo = CarColor( pLocal, baseColor, carScale, 10. * animationSpeed * iTime, specularity, glow );
        vec3 n = carNormal( pLocal, carScale );
        vec3 nGlobal = n.x * e1 + n.y * e2 + n.z * e3;
        nGlobal *= -sign( dot( nGlobal, rd_in ) );
        vec3 nshade = normalShade( normalize( rd_in ), nGlobal, vec3( 0 ) );

        color = shade( pGlobal, rd_in, nGlobal, albedo, specularity, glow, nshade, iTime );

        return true;
    } else {
        t = INF;
        return false;
    }

    return hit_car;
}

const int[20] shuffle = int[20](13, 9, 20, 18, 4, 10, 5, 8, 2, 1, 6, 12, 14, 17, 11, 15, 7, 3, 16, 19);

bool branched_car_intersection( vec3 ro, vec3 rd, bool flip_dir, int car_id, int n_cars, inout float t, float tmax, vec2 pos2D, out vec3 color ) {
    vec2 f = complexFunction( pos2D );
    float h = im( f ) / yScale();

    float sphereRadius = 0.2 * carScale();
    float best_h;
    float t_best = tmax;

    bool hit_car = false;

    float car_kind = mod(float(shuffle[int(mod(float(car_id), 5. + abs(float(n_cars))))]) / abs(float(n_cars)), 1.);

    switch ( scene ) {
        case 0:   // log( z )
        case 1: { // log( (3z + 1) / (3z - 1) )
            // branches separated by 2π vertical distance
            for (int iB = -2; iB <= 2; iB++) {
                float t_branch = t;
                float branch_h = h + float( iB ) * 2. * PI / yScale();
                bool hitBranch = intersect_bounding_sphere( ro, rd, pos2D, branch_h, sphereRadius );
                if ( hitBranch ) {
                    float t_car = t;
                    vec3 car_pos = vec3( pos2D.x, branch_h, pos2D.y );
                    vec3 car_color;
                    bool hit_this_car = intersect_car( ro, rd, flip_dir, carScale(), car_kind, 0, car_pos, t_car, t_best, car_color );
                    if ( hit_this_car ) {
                        color = car_color;
                        hit_car = true;
                    }
                    t_best = min( t_best, t_car );
                }
            }
            break;

        }
        case 2: { // sqrt( z )
            //== figure out branch that car should lie on
            float period = 2. * PI / animationSpeed;
            float start_angle = .5 - float( car_id ) / abs( float( n_cars ) );
            float dir = sign( float( n_cars ) );
            int branch = int( floor( mod( float( car_id ) + dir * iTime / period - start_angle, 2. ) ) );

            vec2 omega0 = vec2(-1, 0);
            vec2 omega = vec2(1., 0.);
            for (int k = 0; k < branch; k++) {
                omega = mul( omega, omega0 );
            }

            //== intersect a car on that branch
            float t_branch = t;
            float branch_h = im( mul( omega, f ) ) / yScale();
            bool hitBranch = intersect_bounding_sphere( ro, rd, pos2D, branch_h, sphereRadius );
            if ( hitBranch ) {
                float t_car = t;
                vec3 car_pos = vec3( pos2D.x, branch_h, pos2D.y );
                vec3 car_color;
                bool hit_this_car = intersect_car( ro, rd, flip_dir, carScale(), car_kind, branch, car_pos, t_car, t_best, car_color );

                if ( hit_this_car ) {
                    color = car_color;
                    hit_car = true;
                }
                t_best = min( t_best, t_car );
            }

            break;
        }
        case 3: { // z^1/3

            //== figure out branch that car should lie on
            float period = 2. * PI / animationSpeed;
            float start_angle = .5 - float( car_id ) / abs( float( n_cars ) );
            float dir = sign( float( n_cars ) );
            int branch = int( floor( mod( float( car_id ) + dir * iTime / period - start_angle, 3. ) ) );
            // branch = 0;

            vec2 omega0 = cexp( 2. * PI / 3. );
            vec2 omega = vec2(1., 0.);
            for (int k = 0; k < branch; k++) {
                omega = mul( omega, omega0 );
            }

            //== intersect a car on that branch
            // branches are cube roots of unity
            float t_branch = t;
            float branch_h = im( mul( omega, f ) ) / yScale();
            bool hitBranch = intersect_bounding_sphere( ro, rd, pos2D, branch_h, sphereRadius );

            if ( hitBranch ) {
                float t_car = t;
                vec3 car_pos = vec3( pos2D.x, branch_h, pos2D.y );
                vec3 car_color;
                bool hit_this_car = intersect_car( ro, rd, flip_dir, carScale(), car_kind, branch, car_pos, t_car, t_best, car_color );

                if ( hit_this_car ) {
                    color = car_color;
                    hit_car = true;
                }
                t_best = min( t_best, t_car );
            }
            break;
        }
    }


    if ( hit_car ) {
        t = t_best;
        return true;
    } else {
        t = INF;
        color = vec3( 0 );
        return false;
    }
}

const int n_outer_cars = 7;
const int n_inner_cars = 5;
bool intersect_instanced_car( vec3 ro, vec3 rd, inout float t, float tmax, out vec3 color ) {
    float t0, t1;

    if ( clipToSphere ) {
        if ( scene == 1 && colorMode == 2 ) {
            bool hitSphere = intersectEllipsoid(ro, rd, sphereCenter, sphereRadius, vec3( .9, .8, .7 ), t0, t1);

            if ( !hitSphere || tmax < 0.) return false;
            if ( t0 > t ) t = t0 + 0.01;
            if ( t1 < tmax ) tmax = t1;
        } else {
            bool hitSphere = intersectSphere(ro, rd, sphereCenter, sphereRadius, t0, t1);

            if ( !hitSphere || tmax < 0.) return false;
            if ( t0 > t ) t = t0 + 0.01;
            if ( t1 < tmax ) tmax = t1;
        }
    }


    float t_best = tmax;
    vec3 best_car_color;
    bool hit_car = false;
    float r = carRadius();

    switch( scene ) {
        case 0:   // log( z )
        case 2:   // sqrt( z )
        case 3: { // z^1/3
            for (int i_car = 0; i_car < n_outer_cars; i_car++ ) {
                // cars in outer lane
                vec2 spherePos2D = ( r + laneWidth() / 2. ) * cexp( iTime * animationSpeed
                                             + float( i_car ) * 2. * PI / float( n_outer_cars ) );
                float t_car = t;
                vec3 car_color;
                branched_car_intersection( ro, rd, false, i_car, n_outer_cars, t_car, t_best, spherePos2D, car_color );
                if ( t_car < t_best ) {
                    best_car_color = car_color;
                    t_best = t_car;
                    hit_car = true;
                }

                // cars in inner lane
                if (i_car < n_inner_cars ) {
                    spherePos2D = ( r - laneWidth() / 2. ) * cexp( -iTime * animationSpeed
                                                 + float( i_car ) * 2. * PI / float( n_inner_cars ) );
                    t_car = t;
                    branched_car_intersection( ro, rd, true, i_car + n_inner_cars, -n_inner_cars, t_car, t_best, spherePos2D, car_color );
                    if ( t_car < t_best ) {
                        best_car_color = car_color;
                        t_best = t_car;
                        hit_car = true;
                    } 
                }
            }

            break;
        }
        case 1: { // log( (3z + 1) / (3z - 1) )
            vec2 p = vec2( 1. / 3., 0. );
            for (int i_car = 0; i_car < n_outer_cars; i_car++ ) {
                // cars circling right pole in outer lane
                vec2 spherePos2D = p + ( r + laneWidth() / 2. ) * cexp( - iTime * animationSpeed
                                                 + float( i_car ) * 2. * PI / float( n_outer_cars ) );

                float t_car = t;
                vec3 car_color;
                branched_car_intersection( ro, rd, true, i_car, n_outer_cars, t_car, t_best, spherePos2D, car_color );
                if ( t_car < t_best ) {
                    best_car_color = car_color;
                    t_best = t_car;
                    hit_car = true;
                }

                // cars circling right pole in inner lane
                if (i_car < n_inner_cars ) {
                    spherePos2D = p + ( r - laneWidth() / 2. ) * cexp( iTime * animationSpeed
                                                     + float( i_car ) * 2. * PI / float( n_inner_cars ) );

                    t_car = t;
                    branched_car_intersection( ro, rd, false, i_car + n_inner_cars, n_inner_cars, t_car, t_best, spherePos2D, car_color );
                    if ( t_car < t_best ) {
                        best_car_color = car_color;
                        t_best = t_car;
                        hit_car = true;
                    }
                }


                // cars circling left pole in outer lane
                spherePos2D = -p + ( r + laneWidth() / 2. ) * cexp( - iTime * animationSpeed
                                             + float( i_car ) * 2. * PI / float( n_outer_cars ) );

                t_car = t;
                car_color;
                branched_car_intersection( ro, rd, true, i_car, n_outer_cars, t_car, t_best, spherePos2D, car_color );
                if ( t_car < t_best ) {
                    best_car_color = car_color;
                    t_best = t_car;
                    hit_car = true;
                }

                // cars circling left pole in inner lane
                if (i_car < n_inner_cars ) {
                    spherePos2D = -p + ( r - laneWidth() / 2. ) * cexp( iTime * animationSpeed
                                                 + float( i_car ) * 2. * PI / float( n_inner_cars ) );

                    t_car = t;
                    car_color;
                    branched_car_intersection( ro, rd, false, i_car + n_inner_cars, n_inner_cars, t_car, t_best, spherePos2D, car_color );
                    if ( t_car < t_best ) {
                        best_car_color = car_color;
                        t_best = t_car;
                        hit_car = true;
                    }
                }
            }
        }
    }

    if ( hit_car ) {
        color = best_car_color;
        t = t_best;
        return true;
    } else {
        return false;
    }
}

vec2 headlight_strength( vec3 pos_in, vec3 center, bool flip_dir, int branch, float carScale ) {
    vec3 e2 = -normal( center, branch );
    vec2 pole = closestPole( center.xz );
    vec3 e1 = vec3( center.x - pole.x, 0., center.z - pole.y );
    e1 = normalize( e1 - dot( e2, e1 ) * e2 );
    vec3 e3 = ( flip_dir ? -1. : 1. ) * cross( e1, e2 );

    // transform pos into e1, e2, e3 basis
    vec3 pos_rel = pos_in - center + 0.015 * carScale * e2;
    vec3 pos = vec3( dot( e1, pos_rel ), dot( e2, pos_rel ), dot ( e3, pos_rel ) );

    vec3 left_headlight = carScale * vec3( -0.05, 0.05, -.16 );
    vec3 left_disp = pos - left_headlight;
    left_disp.x *= 1.5; // narrow beam
    float left_head = -left_disp.z / dot(left_disp, left_disp) * carScale;
    vec3 left_taillight = carScale * vec3( -0.04, 0.05, .16 );
    left_disp = pos - left_taillight;
    left_disp.x *= 1.5; // narrow and shorten beam
    left_disp.z *= 1.5;
    float left_tail = left_disp.z / dot(left_disp, left_disp) * carScale;

    vec3 right_headlight = carScale * vec3( 0.05, 0.05, -.16 );
    vec3 right_disp = pos - right_headlight;
    right_disp.y *= 1.5; // narrow beam
    float right_head = -right_disp.z / dot(right_disp, right_disp) * carScale;
    vec3 right_taillight = carScale * vec3( 0.04, 0.05, .16 );
    right_disp = pos - right_taillight;
    right_disp.x *= 1.5; // narrow and shorten beam
    right_disp.z *= 1.5;
    float right_tail = right_disp.z / dot(right_disp, right_disp) * carScale;
    return max(vec2(left_head, left_tail), vec2(right_head, right_tail));
}

vec2 branched_headlight_strength( vec3 pos, bool flip_dir, int car_id, int n_cars, vec2 pos2D, float carScale ) {
    vec2 f = complexFunction( pos2D );
    float h = im( f ) / yScale();

    vec2 strength = vec2(-INF);
    switch ( scene ) {
        case 0:   // log( z )
        case 1: { // log( (3z + 1) / (3z - 1) )
            // branches separated by 2π vertical distance
            vec3 car_pos = vec3( pos2D.x, 0, pos2D.y );
            for (int iB = -2; iB <= 2; iB++) {
                car_pos.y = h + float( iB ) * 2. * PI / yScale();
                strength = max( strength, headlight_strength( pos, car_pos, flip_dir, 0, carScale ) );

            }
            break;
        }

        case 2: { // sqrt( z )
            //== figure out branch that car should lie on
            float period = 2. * PI / animationSpeed;
            float start_angle = .5 - float( car_id ) / abs( float( n_cars ) );
            float dir = sign( float( n_cars ) );
            int branch = int( floor( mod( float( car_id ) + dir * iTime / period - start_angle, 2. ) ) );

            vec2 omega0 = vec2(-1, 0);
            vec2 omega = vec2(1., 0.);
            for (int k = 0; k < branch; k++) {
                omega = mul( omega, omega0 );
            }

            //== find lights on that branch
            float branch_h = im( mul( omega, f ) ) / yScale();
            vec3 car_pos = vec3( pos2D.x, branch_h, pos2D.y );
            strength = max( strength, headlight_strength( pos, car_pos, flip_dir, branch, carScale ) );

            break;
        }
        case 3: { // z^1/3

            //== figure out branch that car should lie on
            float period = 2. * PI / animationSpeed;
            float start_angle = .5 - float( car_id ) / abs( float( n_cars ) );
            float dir = sign( float( n_cars ) );
            int branch = int( floor( mod( float( car_id ) + dir * iTime / period - start_angle, 3. ) ) );
            // branch = 0;

            vec2 omega0 = cexp( 2. * PI / 3. );
            vec2 omega = vec2(1., 0.);
            for (int k = 0; k < branch; k++) {
                omega = mul( omega, omega0 );
            }

            //== find lights on that branch
            float branch_h = im( mul( omega, f ) ) / yScale();
            vec3 car_pos = vec3( pos2D.x, branch_h, pos2D.y );
            strength = max( strength, headlight_strength( pos, car_pos, flip_dir, branch, carScale ) );

            break;
        }
    }

    return strength;
}

vec2 instanced_headlight_strength( vec3 pos ) {

    vec2 strength = vec2(-INF);
    float r = carRadius();
    float scale = carScale();

    switch( scene ) {
        case 0:   // log( z )
        case 2:   // sqrt( z )
        case 3: { // z^1/3
            for (int i_car = 0; i_car < n_outer_cars; i_car++ ) {
                // cars in outer lane
                vec2 car_center = ( r + laneWidth() / 2. ) * cexp( iTime * animationSpeed
                                             + float( i_car ) * 2. * PI / float( n_outer_cars ) );
                strength = max( strength, branched_headlight_strength( pos, true, i_car, n_outer_cars, car_center, scale ) );

                // cars in inner lane
                if (i_car < n_inner_cars ) {
                    car_center = ( r - laneWidth() / 2. ) * cexp(-iTime * animationSpeed
                                                     + float( i_car ) * 2. * PI / float( n_inner_cars ) );
                    strength = max( strength, branched_headlight_strength( pos, false, i_car, -n_inner_cars, car_center, scale ) );
                }
            }

            break;
        }
        case 1: { // log( (3z + 1) / (3z - 1) )
            vec2 p = vec2( 1. / 3., 0. );
            for (int i_car = 0; i_car < n_outer_cars; i_car++ ) {
                // cars circling right pole in outer lane
                vec2 car_center = p + ( r + laneWidth() / 2. ) * cexp( - iTime * animationSpeed
                                                 + float( i_car ) * 2. * PI / float( n_outer_cars ) );
                strength = max( strength, branched_headlight_strength( pos, false, i_car, n_outer_cars, car_center, scale ) );

                // cars circling right pole in inner lane
                if (i_car < n_inner_cars ) {
                    car_center = p + ( r - laneWidth() / 2. ) * cexp(iTime * animationSpeed
                                                     + float( i_car ) * 2. * PI / float( n_inner_cars ) );
                    strength = max( strength, branched_headlight_strength( pos, true, i_car, n_inner_cars, car_center, scale ) );
                }

                // cars circling left pole in outer lane
                car_center = -p + ( r + laneWidth() / 2. ) * cexp( - iTime * animationSpeed
                                                 + float( i_car ) * 2. * PI / float( n_outer_cars ) );
                strength = max( strength, branched_headlight_strength( pos, false, i_car, n_outer_cars, car_center, scale ) );

                // cars circling left pole in inner lane
                if (i_car < n_inner_cars ) {
                    car_center = -p + ( r - laneWidth() / 2. ) * cexp(iTime * animationSpeed
                                                     + float( i_car ) * 2. * PI / float( n_inner_cars ) );
                    strength = max( strength, branched_headlight_strength( pos, true, i_car, n_inner_cars, car_center, scale ) );
                }
            }
        }
    }

    return strength;
}


