#define PI 3.141592653589793

// ---- camera: Zoomed out to see the floor ----
#define U_ALPHA0 1.57
#define U_BETA0  0.4
#define U_ZCAM   9.0

// ---- 4D perspective ----
#define U_WCAM   1.0

// ---- 4D orbit angles ----
// Adjust these or use mouse to align the Coxeter plane projection
#define U_CXW (-0.55)
#define U_CYW (0.0)
#define U_CZW (0.0)

// ---- Animation: Slow rotation to verify symmetries ----
#define XY_SPEED 0.15
#define XY_OFFSET 0.0

// ---- Thickness knobs (Thinner for better shadow details) ----
#define U_SPHERE_R 0.015
#define U_EDGE_R   0.006

// ---- Floor Settings ----
#define PLANE_Y   -2.2
#define PLANE_ID  10.0

// ---- raymarch settings ----
#define MAX_STEPS 200
#define MAX_DIST  220.0
#define EPS       0.001
#define STEP_K    0.8 

// ---- shading ----
const vec3  COL_SPHERE    = vec3(0.22, 0.98, 0.35);
const vec3  COL_EDGE      = vec3(0.78, 0.80, 0.90);
const vec3  COL_FLOOR     = vec3(0.85, 0.85, 0.82); // Light floor
const float AMBIENT       = 0.3;
const vec3  BG_COLOR      = vec3(0.05, 0.05, 0.08);
const float FOG_K         = 0.002;
const float FOG_START     = 2.35;

// ---- Coxeter diagram (H4: 5, 3, 3) ----
// 120-cell generated by node 0 active (1,0,0,0)
const float d01 = 5.0; 
const float d02 = 2.0; 
const float d03 = 2.0; 
const float d12 = 3.0; 
const float d13 = 2.0; 
const float d23 = 3.0; 

// 1,0,0,0 = 120-cell
// 0,0,0,1 = 600-cell
const vec4 active_mirrors = vec4(1.0, 0.0, 0.0, 0.0);

mat4 M;
vec4 v0;

#define MAX_NEIGHBORS 40
vec4 vNeighbors[MAX_NEIGHBORS];
int vNeighborCount = 0;

// ---------------- helpers ----------------
vec2 rot2d(vec2 v, float a){
    float c = cos(a), s = sin(a);
    return vec2(c*v.x - s*v.y, s*v.x + c*v.y);
}

void orbitCamera(in float alpha, in float beta, in float dist, in vec2 uv, out vec3 ro, out vec3 rd){
    float cb = cos(beta), sb = sin(beta);
    float ca = cos(alpha), sa = sin(alpha);
    ro = vec3(dist * cb * ca, dist * sb, dist * cb * sa);

    vec3 fwd = normalize(-ro);
    vec3 upW = vec3(0.0,1.0,0.0);
    vec3 right = normalize(cross(fwd, upW));
    if(length(right) < 1e-5) right = vec3(1.0,0.0,0.0);
    vec3 up = normalize(cross(right, fwd));

    float focal = 1.0;
    rd = normalize(uv.x*right + uv.y*up + focal*fwd);
}

vec4 invStereoNorthPole(vec3 p){
    float r2 = dot(p,p);
    return vec4(2.0*p, r2 - 1.0) / (r2 + 1.0);
}

// Transform 4D point (Animation)
vec4 applyForwardT(vec4 q){
    // Static orbit
    q.yw = rot2d(q.yw, -U_CYW);
    q.zw = rot2d(q.zw, -U_CZW);

    // Time-based animation
    // Using Golden Ratio related speeds often reveals H4 symmetries
    float t = iTime * XY_SPEED;
    float phi = (sqrt(5.0) + 1.0) * 0.5;

    // Rotation in two orthogonal planes (Isoclinic-like)
    q.xy = rot2d(q.xy, t);
    q.zw = rot2d(q.zw, t * phi); 

    return q;
}

// Inverse Transform for sampling
vec4 applyInverseT(vec4 q){
    float t = iTime * XY_SPEED;
    float phi = (sqrt(5.0) + 1.0) * 0.5;

    q.zw = rot2d(q.zw, -t * phi);
    q.xy = rot2d(q.xy, -t);

    q.zw = rot2d(q.zw, +U_CZW);
    q.yw = rot2d(q.yw, +U_CYW);
    return q;
}

vec4 reflect4(vec4 p, vec4 n){
    return p - 2.0*dot(p,n)*n;
}

mat4 reflMat(vec4 n){
    mat4 outer = mat4(n*n.x, n*n.y, n*n.z, n*n.w);
    return mat4(1.0) - 2.0*outer;
}

// Folding logic
bool foldWithH(inout vec4 q, out mat4 h){
    h = mat4(1.0);
    for(int iter=0; iter<16; iter++){ // Reduced iterations for shadow perf
        float sum = 0.0;
        for(int i=0;i<4;i++){
            vec4 n = M[i];
            float d = dot(q,n);
            if(d < 0.0){
                q -= 2.0*d*n;
                h = h * reflMat(n);
                sum += 1.0;
            }
        }
        if(sum == 0.0) return true;
    }
    return false;
}

void proj3_withScale(vec4 q, out vec3 p3, out float s4){
    float w = min(q.w, U_WCAM - 0.001);
    s4 = U_WCAM / (U_WCAM - w);
    p3 = q.xyz * s4;
}

float sdCapsule(vec3 p, vec3 a, vec3 b, float r){
    vec3 pa = p - a;
    vec3 ba = b - a;
    float h = clamp(dot(pa,ba)/max(dot(ba,ba), 1e-8), 0.0, 1.0);
    return length(pa - ba*h) - r;
}

// ---------------- Init Topology ----------------
void initCoxeter(){
    float c01 = -cos(PI / d01);
    float c02 = -cos(PI / d02);
    float c03 = -cos(PI / d03);
    float c12 = -cos(PI / d12);
    float c13 = -cos(PI / d13);
    float c23 = -cos(PI / d23);

    vec4 A = vec4(1., 0., 0., 0.);
    vec4 B = vec4(c01, sqrt(max(0.0, 1. - c01*c01)), 0., 0.);
    vec4 C = vec4(c02, 0., 0., 0.);
    C.y = (c12 - C.x * B.x) / max(B.y, 1e-8);
    C.z = sqrt(max(0.0, abs(1. - dot(C.xy, C.xy))));
    vec4 D = vec4(c03, 0., 0., 0.);
    D.y = (c13 - D.x * B.x) / max(B.y, 1e-8);
    D.z = (c23 - dot(D.xy, C.xy)) / max(C.z, 1e-8);
    D.w = sqrt(max(0.0, abs(1. - dot(D.xyz, D.xyz))));

    M = mat4(A, B, C, D);
    v0 = normalize(active_mirrors * inverse(M));

    vNeighborCount = 0;
    // BFS Seeds
    for(int i=0; i<4; i++){
        if(active_mirrors[i] > 0.5) {
             vNeighbors[vNeighborCount++] = reflect4(v0, M[i]);
        }
    }
    // BFS Propagation
    for(int k=0; k<MAX_NEIGHBORS; k++){ 
        if(k >= vNeighborCount) break;
        vec4 curr = vNeighbors[k];
        for(int m=0; m<4; m++){
            if(active_mirrors[m] < 0.5) {
                vec4 next = reflect4(curr, M[m]);
                bool found = false;
                for(int j=0; j<MAX_NEIGHBORS; j++){
                    if(j >= vNeighborCount) break;
                    if(dot(next, vNeighbors[j]) > 0.999) { found = true; break; }
                }
                if(!found && vNeighborCount < MAX_NEIGHBORS){
                    vNeighbors[vNeighborCount++] = next;
                }
            }
        }
    }
}

// Distance to the 4D Polytope (projected)
// Returns (dist, id)
vec2 mapPolytope(vec3 p) {
    vec4 qRaw = invStereoNorthPole(p);
    vec4 q = applyInverseT(qRaw);

    mat4 h;
    if(!foldWithH(q, h)) return vec2(1e5, -1.0);

    float dMin = 1e9;
    float idMin = -1.0;

    // Helper closure
    #define CHECK(mtx) { \
        vec4 A4 = applyForwardT(mtx * v0); \
        vec3 A3; float sA; proj3_withScale(A4, A3, sA); \
        float dS = length(p - A3) - U_SPHERE_R * sA; \
        if(dS < dMin) { dMin = dS; idMin = 4.0; } \
        for(int i=0; i<MAX_NEIGHBORS; i++){ \
            if(i>=vNeighborCount) break; \
            vec4 B4 = applyForwardT(mtx * vNeighbors[i]); \
            vec3 B3; float sB; proj3_withScale(B4, B3, sB); \
            float dE = sdCapsule(p, A3, B3, U_EDGE_R * 0.5*(sA+sB)); \
            if(dE < dMin) { dMin = dE; idMin = 0.0; } \
        } \
    }

    // 1. Primary
    CHECK(h);

    // 2. Neighbor Fallback
    float closestDist = 1e9;
    int closestIdx = -1;
    for(int i=0; i<4; i++){
        float d = dot(q, M[i]);
        if(d < closestDist){ closestDist = d; closestIdx = i; }
    }
    if(closestIdx != -1){
        mat4 hN = h * reflMat(M[closestIdx]);
        CHECK(hN);
    }

    return vec2(dMin, idMin);
}

// Global map: Polytope + Floor
vec2 map(vec3 p) {
    vec2 res = mapPolytope(p);
    float dPlane = p.y - PLANE_Y;
    if(dPlane < res.x) {
        res = vec2(dPlane, PLANE_ID);
    }
    return res;
}

vec3 calcNormal(vec3 p){
    float e = 0.001;
    vec2 h = vec2(1.0, -1.0);
    float d1 = map(p + h.xyy*e).x;
    float d2 = map(p + h.yyx*e).x;
    float d3 = map(p + h.yxy*e).x;
    float d4 = map(p + h.xxx*e).x;
    return normalize(h.xyy*d1 + h.yyx*d2 + h.yxy*d3 + h.xxx*d4);
}

// Soft shadow from 'ro' towards light 'L'
float calcSoftshadow(in vec3 ro, in vec3 rd, in float mint, in float tmax) {
    float res = 1.0;
    float t = mint;
    // Lower iterations for performance
    for(int i=0; i<24; i++) {
        // Optimization: Only check polytope for shadows, ignore floor
        float h = mapPolytope(ro + rd*t).x;
        res = min(res, 12.0*h/t); // 12.0 = hardness
        t += clamp(h, 0.05, 0.2); // Big steps
        if(res<0.001 || t>tmax) break;
    }
    return clamp(res, 0.0, 1.0);
}

vec2 raymarch(vec3 ro, vec3 rd){
    float t = 0.0;
    float id = -1.0;
    for(int i=0;i<MAX_STEPS;i++){
        vec2 di = map(ro + rd*t);
        float d = di.x;
        if(d < EPS){
            id = di.y;
            return vec2(t, id);
        }
        t += d * STEP_K;
        if(t > MAX_DIST) break;
    }
    return vec2(-1.0, -1.0);
}

vec3 shade(vec3 ro, vec3 rd, float t, float id){
    vec3 p = ro + rd*t;
    vec3 n = calcNormal(p);

    // Light directly above to create a "projection" map on the floor
    vec3 lightPos = vec3(0.0, 20.0, 0.0);
    vec3 l = normalize(lightPos - p);
    vec3 v = normalize(-rd);
    vec3 h = normalize(l + v);

    // Material
    bool isFloor = (id > 9.5);
    bool isSphere = (id > 3.5 && !isFloor);

    vec3 baseCol = COL_EDGE;
    if(isSphere) baseCol = COL_SPHERE;
    if(isFloor) {
        // Checkerboard pattern for floor
        float f = mod(floor(p.x) + floor(p.z), 2.0);
        baseCol = COL_FLOOR * (0.8 + 0.2*f);
    }

    float diff = max(dot(n, l), 0.0);
    float spec = pow(max(dot(n, h), 0.0), 30.0);

    // Shadow
    float sh = 1.0;
    // Only cast shadows ON the floor or self-shadowing (optional)
    // To see the "Projected Graph", we definitely need shadow on floor
    if(diff > 0.0) {
        sh = calcSoftshadow(p + n*0.01, l, 0.02, 25.0);
    }

    vec3 col = baseCol * (AMBIENT + diff * sh * 0.8);
    if(!isFloor) col += vec3(1.0) * spec * sh * 0.5;

    // Fog
    float dFog = max(0.0, t - FOG_START);
    float fog = exp(-FOG_K * dFog * dFog);
    return mix(BG_COLOR, col, fog);
}

void mainImage(out vec4 fragColor, in vec2 fragCoord){
    initCoxeter();

    vec2 uv = (2.0*fragCoord - iResolution.xy) / iResolution.y;

    float alpha = U_ALPHA0;
    float beta  = U_BETA0;

    if(iMouse.z > 0.0){
        float mx = clamp(iMouse.x / iResolution.x, 0.0, 1.0);
        float my = clamp(iMouse.y / iResolution.y, 0.0, 1.0);
        alpha = mix(-PI, PI, mx);
        beta  = mix(-1.56, 1.56, my);
    }

    vec3 ro, rd;
    orbitCamera(alpha, beta, U_ZCAM, uv, ro, rd);

    vec2 hit = raymarch(ro, rd);
    float t  = hit.x;
    float id = hit.y;

    vec3 col = BG_COLOR;
    if(t > 0.0){
        col = shade(ro, rd, t, id);
    }

    // Gamma
    col = pow(col, vec3(0.4545));
    fragColor = vec4(col, 1.0);
}

#define AA 1

#define FOV_DIST         2.0
#define FOLDING_NUMBER   10
#define MAX_TRACE_STEPS  300
#define MIN_TRACE_DIST   0.01
#define MAX_TRACE_DIST   50.0
#define PRECISION        1e-4
#define PI               3.14159265358979323
#define T                (iTime * 0.005)

// view to world transformation
mat3 viewMatrix(vec3 camera, vec3 lookat, vec3 up) {
    vec3 f = normalize(lookat - camera);
    vec3 r = normalize(cross(f, up));
    vec3 u = normalize(cross(r, f));
    return mat3(r, u, -f);
}

// 2D rotation
void R(inout vec2 p, float a) {
    p = cos(a) * p + sin(a) * vec2(p.y, -p.x);
}


// ------------------------------------------------------------
// Folding: returns folded point and accumulated scale.
// IMPORTANT: no fwidth, no shading here.
// ------------------------------------------------------------

// 把每个分量通过 x=±1 的无限反射折回 [-1,1]
vec3 foldToBox(vec3 p) {
    // 镜像周期（period=4），返回范围 [-1,1]
    return abs(mod(p + 1.0, 4.0) - 2.0) - 1.0;
}

// 统计“真正发生了多少次反射”（在数学上等价于跨过多少面）
int countBoxReflections(vec3 p) {
    // 每跨越一个长度为 2 的区间，就相当于多一次反射
    vec3 k = floor((p + 1.0) * 0.5); // 区间编号（可正可负）
    return int(abs(k.x) + abs(k.y) + abs(k.z) + 0.5);
}

vec4 foldSpace(vec3 p, inout int count) {
    const float EPS = 1e-6;
    float scale = 1.0;
    count = 0;

    for (int i = 0; i < FOLDING_NUMBER; i++) {

        // ---- 反射到 [-1,1]^3：无 dot、少分支、向量化 ----

        // 处理 x/y/z > 1：p -> 2 - p （对 +1 平面反射）
        vec3 t = max(p - 1.0, 0.0);           // t 分量>0 表示该轴触发反射
        p -= 2.0 * t;                         // 等价于：if(p>1) p=2-p
        count += int(step(EPS, t.x)) + int(step(EPS, t.y)) + int(step(EPS, t.z));

        // 处理 x/y/z < -1：p -> -2 - p （对 -1 平面反射）
        t = max(-p - 1.0, 0.0);               // 当 p<-1 时 -p-1>0
        p += 2.0 * t;                         // 等价于：if(p<-1) p=-2-p
        count += int(step(EPS, t.x)) + int(step(EPS, t.y)) + int(step(EPS, t.z));

        // ---- 反演（单位球，原点）----
        float r2 = dot(p, p);

        // 分支版（更省算术，可能有分歧）：
        // if (r2 < 1.0 - EPS) {
        //     float k = 1.0 / max(r2, EPS);
        //     p *= k;
        //     scale *= k;
        //     count += 1;
        // }

        // 无分支版（减少分歧，但每次都会算一次除法）：
        float inv = step(r2, 1.0 - EPS);                  // r2 <= 1-EPS => inv=1
        float k   = mix(1.0, 1.0 / max(r2, EPS), inv);
        p *= k;
        scale *= k;
        count += int(inv);
    }

    return vec4(p, scale);
}

// Distance estimator ONLY
float mapDist(vec3 p) {
    int dummyCount;
    vec4 fs = foldSpace(p, dummyCount);
    vec3 q  = fs.xyz;
    float sc = fs.w;
    return 0.25 * abs(q.y) / sc;
}

// Pattern color computed ONLY at hit point (safe to use fwidth here)
vec3 patternColor(vec3 q, int count) {
    // Your original "grid/curve" distance in folded space:

    int ss = count % 4;

    vec3 col;
    if (ss == 2 || ss == )
        col = vec3(0.6, 0.4, 0.2);
    else
        col = vec3(0.2, 0.7, 1);

    float l = length(q.xz);
    l = min(l, abs(q.x + 1.0));
    l = min(l, abs(q.z + 1.0));
    l = min(l, abs(q.z - 1.0));
    l = min(l, abs(q.x - 1.0));

    // Screen-space AA (only here, never inside DE/march)
    float aa = 0.5 * fwidth(l);

    float lw = 0.02;
    float line = 1.0 - smoothstep(lw - aa, lw + aa, l);

    // Black lines on white surface
    return mix(col, vec3(0.0), line);
}

vec3 calcNormal(vec3 p) {
    // Use a fixed epsilon (do NOT call fwidth in normal calc)
    const vec2 e = vec2(0.001, 0.0);
    return normalize(vec3(
        mapDist(p + e.xyy) - mapDist(p - e.xyy),
        mapDist(p + e.yxy) - mapDist(p - e.yxy),
        mapDist(p + e.yyx) - mapDist(p - e.yyx)
    ));
}

float trace(vec3 ro, vec3 rd) {
    float t = MIN_TRACE_DIST;
    for (int i = 0; i < MAX_TRACE_STEPS; i++) {
        float h = mapDist(ro + rd * t);
        if (h < PRECISION * t || t > MAX_TRACE_DIST) return t;
        t += h;
    }
    return -1.0;
}

float softShadow(vec3 ro, vec3 rd, float tmin, float tmax, float k) {
    float res = 1.0;
    float t = tmin;
    for (int i = 0; i < 30; i++) {
        float h = mapDist(ro + rd * t);
        res = min(res, k * h / t);
        t += clamp(h, 0.01, 0.1);
        if (h < 0.001 || t > tmax) break;
    }
    return clamp(res, 0.0, 1.0);
}

float calcAO(vec3 p, vec3 n) {
    float occ = 0.0;
    float sca = 1.0;
    for (int i = 0; i < 5; i++) {
        float h = 0.01 + 0.15 * float(i) / 4.0;
        float d = mapDist(p + h * n);
        occ += (h - d) * sca;
        sca *= 0.95;
    }
    return clamp(1.0 - 3.0 * occ, 0.0, 1.0);
}

// ------------------------------------------------------------
// Render
// ------------------------------------------------------------
vec3 render(vec3 ro, vec3 rd, vec3 lig) {
    vec3 background = vec3(0.08, 0.16, 0.32);
    vec3 col = background;

    float t = trace(ro, rd);
    if (t >= 0.0 && t <= MAX_TRACE_DIST) {
        vec3 pos = ro + rd * t;

        // Re-fold once at hit point to get pattern coordinates
        int count ;
        vec4 fs = foldSpace(pos, count);
        vec3 q  = fs.xyz;

        // Base albedo with stable AA lines
        col = patternColor(q, count);

        vec3 nor = calcNormal(pos);
        vec3 ref = reflect(rd, nor);

        float occ = calcAO(pos, nor);
        float amb = clamp(0.5 + 0.5 * nor.y, 0.0, 1.0);
        float dif = clamp(dot(nor, lig), 0.0, 1.0);
        float bac = clamp(dot(nor, normalize(vec3(-lig.x, 0.0, -lig.z))), 0.0, 1.0) * clamp(1.0 - pos.y, 0.0, 1.0);
        float dom = smoothstep(-0.1, 0.1, ref.y);
        float fre = pow(clamp(1.0 + dot(nor, rd), 0.0, 1.0), 2.0);
        float spe = pow(clamp(dot(ref, lig), 0.0, 1.0), 16.0);

        dif *= softShadow(pos, lig, 0.02, 8.0, 32.0);
        dom *= softShadow(pos, ref, 0.02, 8.0, 32.0);

        vec3 lin = vec3(0.1);
        lin += 1.2 * dif * vec3(1.0, 0.8, 0.55);
        lin += 3.0 * spe * vec3(1.0, 0.9, 0.7) * dif;
        lin += 0.3 * amb * vec3(0.4, 0.6, 1.0) * occ;
        lin += 0.5 * bac * vec3(0.25) * occ;
        lin += 0.5 * dom * vec3(0.4, 0.6, 1.0) * occ;
        lin += 0.25 * fre * vec3(1.0) * occ;

        col *= lin;

        float atten = 1.0 / (1.0 + t * t * 0.1);
        col *= atten;
        col = mix(col, background, smoothstep(0.0, 0.95, t / MAX_TRACE_DIST));

        // Simple tone mapping to prevent blowout -> white patches
        col = col / (1.0 + col);
    }

    // Gamma-ish
    return sqrt(col);
}

void mainImage(out vec4 fragColor, in vec2 fragCoord) {
    vec3 tot = vec3(0.0);

    for (int ii = 0; ii < AA; ii++) {
        for (int jj = 0; jj < AA; jj++) {
            vec2 offset = vec2(float(ii), float(jj)) / float(AA);
            vec2 uv = (fragCoord + offset) / iResolution.xy;
            uv = 2.0 * uv - 1.0;
            uv.x *= iResolution.x / iResolution.y;

            vec3 camera = vec3(1.6, .6, 0.0);
            vec3 lookat = vec3(.3, 0.3, 0.3);
            vec3 up     = vec3(0.0, 1.0, 0.0);

            vec3 ro = camera;
            R(ro.xz, T);

            mat3 M = viewMatrix(ro, lookat, up);
            vec3 rd = M * normalize(vec3(uv, -FOV_DIST));

            vec3 lig = normalize(vec3(1.0, 1.0, 0.2));

            tot += render(ro, rd, lig);
        }
    }

    tot /= float(AA * AA);
    fragColor = vec4(tot, 1.0);
}

/*
~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~
2d slices of 3D Boyd-Maxwell Ball packings

authors: Chen Hao: https://num.math.uni-goettingen.de/~hchen/
         Zhao Liang: https://twitter.com/neozhaoliang

Reference: see Hao's Ph.D thesis:

    https://refubium.fu-berlin.de/bitstream/handle/fub188/1147/diss_haochen.pdf?sequence=1&isAllowed=y
~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~

The name may sound unfamiliar to most people, but basically this is a kind of
kaleidoscope structure in 4D hyperbolic space, we just draw their 2d slices here.

For a Coxeter group of rank 5 and level 2, the complement of its limit set form a dense
ball packing of the ideal boundary of hyperbolic 4-space, hence a ball packing of the
Euclidean 3-space. We use z=c or y=c planes with varying c to see the circle packing patterns
on these slices.


In Hao's paper he listed out all Coxeter groups of level 2, the diagrams that
have 5 vertices with none of them surrounded by a blue box are all valid inputs for this program.

Usage:

1. Select a configuration below and uncomment it, or you can input one manually
2. In common.frag, use `#define DrawLimitSet` to switch between the limit set view and circle packing view
3. In common.frag, change `ZOOM` to zoom in/out.
4. When drawing circle packings, use the bvec4 param 'isRealBall' to add/remove circles (explained below).
5. In common.frag, use `#define DrawVerticalSections` to show vertical sections (suggested by @mla)

Example:

This is a rank 5 group of level 2:

     v2
     x
       \   5
     |  o --- o --- x
     | / v4   v1    v0
     x
     v3

Each vertex in the diagram represents a 'virtual mirror' in 3d space (a plane or a sphere),
the labels on the edges indicate the angles between the mirrors.

A vertex drawn by `x` means it has a `real ball` correspondes to it,
A vertex drawn by `o` means it does not have a real ball correspondes to it.
There are always 5 virtual balls and at least one real ball.

If we iteratively reflect the real balls across the virual balls, we will eventually get a dense packing of
the 3d space.

The set of virtual balls are called coclusters, the set of real balls are called clusters.

You can see there is a Euclidean triangle (333) in the diagram, this holds for almost all groups of rank 5 and level 2.

The input data requires you specify:

param 1:

The type of the Euclidean triangle, must be one of 244, 236 or 333. In this example it's 333.
These virual mirrors are labelled as v2, v3, v4.

| For the remaining two vertices, at least one must be 'x', choose such one as v0. If both two are 'x',
| choose either of them as v0, the remaining one is labelled v1.

param 2:

The labels between v0 and (v2, v3, v4), in this example it's (2, 2, 2) (in a Coxeter diagram
disjoint mirrors are orthogonal with each other, hence has dihedral angle PI/2, hence label 2)

param 3:

The labels between v1 and (v2, v3, v4), in this example it's (2, 2, 5). Note v1 and v4 are connected
by an edge of label 5.

param 4:

The label between v0 and v1, in this example it's 3 (edges with labels 3 are represented by an unlabelled line)

param 5:

Four bools indicate those virtual mirrors in (v1, v2, v3, v4) that have real balls corresponde to them.
In this example v2, v3 are represented by 'x', v1, v4 are represented by 'o', hence v2, v3 have real balls,
while v1, v4 do not. So the four bools should be (false, true, true, false). Note by our choice v0 is
always 'x', so v0 has a real ball correspondes to it. This real ball is always the z=0 plane.

So the above diagram gives input

init(333, vec3(2, 2, 2), vec3(2, 2, 5), 3, bvec4(0, 1, 1, 0))


!important:

For the 333 triangle, you can arbitrarily order them as (v2, v3, v4), it doesn't matter.

But for the 236 triangle, the ordering is fixed, you must label them as

  6   3
*---*---*
v2  v3  v4

Also for the 244 triangle, the ordering must be

  4   4
*---*---*
v2  v3  v4


I have included ~60 examples below, a complete list would contain around ~180+ diagrams,
according to Hao's enumeration. You can find other diagrams in his thesis paper.

Note: 

1. Some diagrams may give equivalent packings, though the visual effects are different.
2. The bvec param 'isRealBall' does not take effect in the 'limit set' view in most times,
it's mainly used for adding/removing circles in the circle packing view. You can change some
1's in it to 0 to remove the corresponding real balls, hence produce holes in the pattern.
*/


