//*****************************************************************************

float map(vec2 p, inout int index) {
    vec2 mouse = MS.xy;
    float k = 1.0;
    if (MS.z > 0.0) {
        p -= mouse;
        k = dot(p,p);
        p /= k;
        p += mouse;
    }
    const float strong_factor = 4.;
#ifdef DrawVerticalSections
    vec3 q = vec3(p.x, TT*0.1, p.y + 1.);
#else
    vec3 q = vec3(p, mod(TT*0.2 - 0.01, SECTION_HEIGHT - 0.02) + 0.01);
#endif
    return k*DE(q, index) * strong_factor;

}

vec3 hsv2rgb(vec3 c) {
  const vec4 K = vec4(1.0, 2.0 / 3.0, 1.0 / 3.0, 3.0);
  vec3 p = abs(fract(c.xxx + K.xyz) * 6.0 - K.www);
  return c.z * mix(K.xxx, clamp(p - K.xxx, 0.0, 1.0), c.y);
}

vec3 post_process(vec3 col, vec2 uv) {
  col = pow(clamp(col, 0., 1.), vec3(1.0/2.2)); 
  col = col*0.6+0.4*col*col*(3.0-2.0*col);
  col = mix(col, vec3(dot(col, vec3(0.33))), -0.4);
  col *= 0.5 + 0.5*pow(19.0*uv.x*uv.y*(1.0-uv.x)*(1.0-uv.y), 0.7);
  return col;
}


void mainImage( out vec4 fragColor, in vec2 fragCoord ) {

    config;
    vec2 uv = fragCoord/iResolution.xy;

    vec2 p = 2.*uv - 1.;
    p.x *= iResolution.x / iResolution.y;
    p *= ZOOM;
    float aa  = 2.0 / clamp(iResolution.y, 400., 800.);

    int index, cid;

    float d = map(p, index);
    cid = index;


    float b = -0.4;
    float t = 10.0;
    const float lh = 2.;
    const vec3 lp = vec3(2.5, 2.5, lh);

    vec3 ro = vec3(0, 0, t);
    vec3 pp = vec3(p, 0);

    vec3 rd = normalize(pp - ro);

    vec3 ld = normalize(lp - pp);

    float bt = -(t-b)/rd.z;

    vec3  bp   = ro + bt*rd;
    vec3  srd = normalize(lp - bp);
    float bl = L2(lp - bp);

    float st = (0.0-b)/srd.z;
    vec3  sp = bp + srd*st;

    float bd = map(bp.xy, index);
    float sd = map(sp.xy, index);

    vec3 col = vec3(0);
    const float ss = 15.0;
    col       += vec3(1.)  * (1.0 - exp(-ss*(max(sd, 0.0)))) / bl;
    float l   = length(p);
#ifdef DrawLimitSet
    float hue = fract(0.75*l-0.3*TT) + .45;
#else
    float hue = fract(0.15*l-0.3*TT) + .5;
#endif
    float sat = .9*tanh(4.*l);
    vec3 hsv  = vec3(hue, sat, 1.0);
    vec3 bcol = hsv2rgb(hsv);

    col       *= (1.0-clamp(tanh(0.75*l), 0., .1)) * 1.3;

#ifdef DrawLimitSet
    col       = mix(col, vec3(1), smoothstep(-aa, aa, -d));
#else
    col       = mix(col, bcol, 1. - step(-d, aa));
#endif
    col       += 0.5*sqrt(bcol.zxy)*(exp(-(10.0+100.0*tanh(l))*max(d, 0.0)));

    col = post_process(col, uv);
    fragColor = vec4(col,1.0);
}

#define MAX_ITER         30
#define PI               3.141592653
#define L2(x)            dot(x, x)
#define ZOOM             4.
#define inf              -1.

// comment out this to show the circles
#define DrawLimitSet


// uncomment this to show the vertice sections
//#define DrawVerticalSections

float dihedral(float x) {
    return x == inf ? 1. : cos(PI / x);
}

vec3 dihedral(vec3 v) {
    return vec3(dihedral(v.x), dihedral(v.y), dihedral(v.z));
}

float SECTION_HEIGHT;

// For spheres n is the center, r is the radius
// For planes n is the normal vector, r is the distance between the plane and the origin
// if invert is true then the inside/outside of the sphere is interchanged (not used in this program)
// if hasRealBall is true then this virtual ball has a real ball correspondes to it
struct Ball {
    bool isplane;
    vec3 n;
    float r;
    bool invert;
    bool isRealBall;
};

// coclusters are mirror balls, they corresponde to root vectors (space-like)
Ball[5] coclusters;
// clusters are real balls, they corresponde to space-like weight vectors
Ball[5] clusters;


// create a ball. by default it's the z=0 plane with normal points to the negative half
Ball defaultBall() {
    return Ball(false, vec3(0, 0, -1), 0., false, false);
}

// Distance from a point to a ball
float sdistanceToBall(vec3 p, Ball B) {
    if (B.isplane) {
        float k = dot(vec4(p, 1), vec4(B.n, B.r));
        return k;
    }
    else
        return length(p - B.n) - B.r;
}

Ball from_plane(vec3 n, float d) {
    return Ball(true, n, d, false, false);
}

Ball from_sphere(vec3 cen, float r) {
    return Ball(false, cen, r, false, false);
}

void invertBall(inout Ball B) {
    B.invert = !B.invert;
}

// try to reflect a point p to the positive half space bounded by a ball
// if we are already in the positive half space, do nothing and return true,
// else reflect about the ball and return false
// if B is a sphere we try to reflect p into the interior of B
bool try_reflect(inout vec3 p, Ball B, inout float scale) {
    if (B.isplane) {
        float k = dot(vec4(p, 1), vec4(B.n, B.r));
        if (k >= 0.)
            return true;
        p -= 2. * k  * B.n;
        return false;
    }
    else {
        vec3 cen = B.n;
        float r = B.r;
        vec3 q = p - cen;
        float d2 = dot(q, q);
        float k = (r * r) / d2;
        if ( (k < 1.0 && B.invert) || (k > 1. && !B.invert) )
            return true;
        p = k * q + cen;
        scale *= k;
        return false;
    }
}

// return distance to the scene, and get the index of the real ball hitted
float DE(vec3 p, inout int index) {
    float scale = 3.;
    for (int i = 0; i < MAX_ITER; i++) {
        bool cond = true;
        for (int k = 0; k < 5; k++) {
            cond = try_reflect(p, coclusters[k], scale) && cond;
        }

        if (cond)
            break;
    }
    index = 0;
#ifdef DrawLimitSet
    float d = abs(p.z);
    for (int j = 1; j < 5; j++) {
        if (clusters[j].isRealBall) {
            float d1 = abs(sdistanceToBall(p, clusters[j]));
            if (d1 < d) { d = d1; index = j; }
        }
    }
#else
    float d = p.z;
    for (int j = 1; j < 5; j++) {
        if (clusters[j].isRealBall) {
            float d1 = sdistanceToBall(p, clusters[j]);
            if (d1 < d) { d = d1; index = j; }
        }
    }

#endif
    return d / scale;
}

// solve M*v = b, where v = (x, y, r) is the xy-coordinate of the center of the ball,
// r is the radius of the ball.
Ball solveBall(mat3 M, vec3 b) {
    vec3 p = b * inverse(M);
    return from_sphere(vec3(p.xy, 0.), p.z);
}

// Solve a ball with its center has xy-coordinates P, and is orthogonal to other two Balls B0, B1.
// Here B0 may be either a sphere or a plane, B1 is always a sphere. 
Ball solveBall(vec2 P, Ball B0, Ball B1) {
    if (B0.isplane) {
        float z = B0.r;
        vec3 cen = vec3(P, z);
        float R = sqrt(L2(cen - B1.n) - B1.r*B1.r);
        return from_sphere(cen, R);
    }
    else {
        float r1 = B1.r;
        float r0 = B0.r;
        float z0 = B0.n.z;
        float k0 = L2(P - B0.n.xy);
        float k1 = L2(P - B1.n.xy);
        float z = (r1*r1 - r0*r0 + z0*z0 + k0 - k1) / (2.*z0);
        float R = sqrt(k1 + z*z - r1*r1);
        return from_sphere(vec3(P, z), R);
    }

}

// triangleType: must be one of 236, 244 or 333
// dihedralAngles0: labels of the edges between v0 and (v2, v3, v4)
// dihedralAngles1: labels of the edges between v1 and (v2, v3, v4)
// dihedralAngles0_1: label of the edge between (v0, v1)
// isRealBall: specify which of (v1, v2, v3, v4) has real balls
// ------------------------------------------------------------
// Construct B0..B4 from Coxeter chain o--p--o--q--o--r--o--s--o
// and (optionally) compute C1..C4 such that
//   Ci ⟂ Bj for all j != i, and C0 is the plane z=0.
// ------------------------------------------------------------
//
// Conventions assumed for Ball in your codebase:
//   - Sphere:   B.isplane == false,  B.n = center (vec3),  B.r = radius (float)
//   - Plane:    B.isplane == true,   B.n = unit normal,     B.r = offset d in dot(n,x)=d
//   - defaultBall(), from_sphere(center,r), from_plane(normal,d), invertBall(B)
//   - Ball has field .isRealBall (bool) (as in your snippet)
//
// isRealBall bits control *which Ci are computed*:
//   isRealBall.x -> compute C1
//   isRealBall.y -> compute C2
//   isRealBall.z -> compute C3
//   isRealBall.w -> compute C4
//
// NOTE: C0 is always set to z=0 plane (clusters[0]).
//
// ------------------------------------------------------------

#ifndef PI
#define PI 3.14159265358979323846
#endif

const float EPS  = 1e-6;
const float TOL  = 5e-4;
const float INF_M = 1e6;

// ---------- helpers: m -> cos(pi/m), sin(pi/m) ----------
bool isInfM(float m) { return m > INF_M; }

float cos_pi_over_m(float m) {
    return isInfM(m) ? 1.0 : cos(PI / m);
}

float sin_pi_over_m(float m) {
    return isInfM(m) ? 0.0 : sin(PI / m);
}

// ---------- geometry: |cos(angle)| between two balls ----------
float absCosBetween(Ball A, Ball B) {
    if (A.isplane && B.isplane) {
        // plane-plane: |dot(n1,n2)|
        return abs(dot(A.n, B.n));
    }
    if (A.isplane && !B.isplane) {
        // plane-sphere: |(n·c - d)|/R
        float R = max(abs(B.r), EPS);
        return abs(dot(A.n, B.n) - A.r) / R;
    }
    if (!A.isplane && B.isplane) {
        float R = max(abs(A.r), EPS);
        return abs(dot(B.n, A.n) - B.r) / R;
    }
    // sphere-sphere: |(d^2 - R1^2 - R2^2)/(2 R1 R2)|
    vec3  dc = A.n - B.n;
    float d2 = dot(dc, dc);
    float R1 = max(abs(A.r), EPS);
    float R2 = max(abs(B.r), EPS);
    return abs((d2 - R1*R1 - R2*R2) / (2.0 * R1 * R2));
}

bool approx(float a, float b) { return abs(a - b) < TOL; }
bool approx0(float a) { return abs(a) < TOL; }

// ---------- quadratic: choose a positive root if exists ----------
bool solveQuadraticPos(float a, float b, float c, out float x0, out float x1) {
    // returns up to 2 positive roots in x0,x1 (x0 first), or false if none
    x0 = -1.0; x1 = -1.0;

    if (abs(a) < EPS) {
        if (abs(b) < EPS) return false;
        float x = -c / b;
        if (x > EPS) { x0 = x; return true; }
        return false;
    }

    float disc = b*b - 4.0*a*c;
    if (disc < 0.0) return false;

    float s = sqrt(max(disc, 0.0));
    float r0 = (-b + s) / (2.0*a);
    float r1 = (-b - s) / (2.0*a);

    // keep positives
    if (r0 > EPS) x0 = r0;
    if (r1 > EPS) {
        if (x0 < 0.0) x0 = r1;
        else x1 = r1;
    }
    return (x0 > 0.0);
}

// ---------- build "orthogonality linear row" for a constraint Bj ----------
vec4 orthoRow(Ball Bj) {
    if (Bj.isplane) {
        // n·c = d
        return vec4(Bj.n, 0.0);
    } else {
        // |c - cj|^2 = R^2 + Rj^2  ->  (-2cj)·c + u = -(||cj||^2 - Rj^2)
        // with u = ||c||^2 - R^2
        vec3 cj = Bj.n;
        return vec4(-2.0 * cj, 1.0);
    }
}

float orthoRhs(Ball Bj) {
    if (Bj.isplane) {
        return Bj.r; // d
    } else {
        vec3  cj = Bj.n;
        float Rj = abs(Bj.r);
        return -(dot(cj, cj) - Rj*Rj);
    }
}

// Solve for a sphere C such that C ⟂ A,B,C,D (4 constraints).
Ball solveOrthoSphere4(Ball A, Ball B, Ball C, Ball D) {
    vec4 r0 = orthoRow(A); float b0 = orthoRhs(A);
    vec4 r1 = orthoRow(B); float b1 = orthoRhs(B);
    vec4 r2 = orthoRow(C); float b2 = orthoRhs(C);
    vec4 r3 = orthoRow(D); float b3 = orthoRhs(D);

    // Build matrix with rows r0..r3: M * x = b, x=(cx,cy,cz,u)
    mat4 M = transpose(mat4(r0, r1, r2, r3));
    vec4  b = vec4(b0, b1, b2, b3);

    vec4 x = inverse(M) * b;

    // NaN guard
    if (any(isnan(x)) || any(isinf(x))) return defaultBall();

    vec3  c0 = x.xyz;
    float u  = x.w;
    float R2 = dot(c0, c0) - u;

    if (R2 <= EPS) return defaultBall();
    return from_sphere(c0, sqrt(R2));
}

// Validate the whole B-system (angles + orthogonality + B0 above z=0)
bool validateBSystem(Ball B0, Ball B1, Ball B2, Ball B3, Ball B4,
                     float c01, float c12, float c23, float c34)
{
    // Adjacent
    if (!approx(absCosBetween(B0, B1), c01)) return false;
    if (!approx(absCosBetween(B1, B2), c12)) return false;
    if (!approx(absCosBetween(B2, B3), c23)) return false;
    if (!approx(absCosBetween(B3, B4), c34)) return false;

    // Non-adjacent orthogonal
    if (!approx0(absCosBetween(B0, B2))) return false;
    if (!approx0(absCosBetween(B0, B3))) return false;
    if (!approx0(absCosBetween(B0, B4))) return false;
    if (!approx0(absCosBetween(B1, B3))) return false;
    if (!approx0(absCosBetween(B1, B4))) return false;
    if (!approx0(absCosBetween(B2, B4))) return false;

    // z=0 does not intersect B0
    if (!B0.isplane) {
        float zc = B0.n.z;
        float R  = abs(B0.r);
        if (!(zc > R + 1e-4)) return false;
    } else {
        // must be z=d with d!=0
        if (abs(B0.n.z) < 1.0 - 1e-4) return false;
        if (abs(B0.r) < 1e-4) return false;
    }

    return true;
}

// ------------------------------------------------------------
// Main init
// ------------------------------------------------------------
void init(float p, float q, float r , float s, 
          bvec4 isRealBall)
{
    // --- compute cos(pi/m) ---
    float c01 = cos_pi_over_m(p);
    float c12 = cos_pi_over_m(q);
    float c23 = cos_pi_over_m(r);
    float c34 = cos_pi_over_m(s);

    // --- Step 1: B2,B4 are coordinate planes ---
    Ball B2 = from_plane(vec3(1.0, 0.0, 0.0), 0.0); // x=0
    Ball B4 = from_plane(vec3(0.0, 1.0, 0.0), 0.0); // y=0

    // --- Step 2: B3 is sphere, center on z=0, with angles to B2,B4 ---
    // Choose scale R3=1 (Möbius scaling gauge).
    float R3 = 1.0;
    vec3  C3 = vec3(R3 * c23, R3 * c34, 0.0);
    Ball  B3 = from_sphere(C3, R3);

    // --- Step 3: Solve B1 (sphere if possible; plane only if q=inf / c12≈1) ---
    Ball B1 = defaultBall();

    // Candidate search (small fixed enumeration)
    bool found = false;

    // Helper: try one candidate B1 and build B0, validate. If ok, store and return.
    Ball bestB0 = defaultBall();
    Ball bestB1 = defaultBall();

    // Try plane candidates for B1 if q is infinity-ish
    if (isInfM(q) || (1.0 - c12) < 1e-6) {
        // B1 plane must be x=d1
        // Enforce B1 ⟂ B3: distance from C3 to plane equals R3 -> |C3.x - d1| = R3
        float dA = C3.x + R3;
        float dB = C3.x - R3;

        for (int t = 0; t < 2; t++) {
            float d1 = (t == 0) ? dA : dB;
            Ball candB1 = from_plane(vec3(1.0, 0.0, 0.0), d1);

            // --- Step 4: Solve B0 (prefer sphere; if p=2 and B1 is plane, plane B0 works nicely) ---
            Ball candB0 = defaultBall();
            bool okB0 = false;

            float K = R3*R3 * (1.0 - c23*c23 - c34*c34);

            if (abs(c01) < 1e-6) {
                // p=2 => angle(B0,B1)=90°
                // With B1 plane x=d1, we can take B0 plane z=±R3 to satisfy B0 ⟂ B3 and not hit z=0
                candB0 = from_plane(vec3(0.0, 0.0, 1.0), +R3);
                okB0 = true;
            } else {
                // sphere B0 with center (0,0,z0), radius R0
                float R0 = abs(d1) / max(abs(c01), EPS);
                float z0 = sqrt(max(R0*R0 + K, 0.0));
                if (z0 > R0 + 1e-4) {
                    candB0 = from_sphere(vec3(0.0, 0.0, z0), R0);
                    okB0 = true;
                }
            }

            if (okB0 && validateBSystem(candB0, candB1, B2, B3, B4, c01, c12, c23, c34)) {
                bestB0 = candB0;
                bestB1 = candB1;
                found = true;
                break;
            }
        }
    }

    // Try sphere candidates for B1 if not found yet
    if (!found) {
        // B1 sphere gauge:
        //   center (sigma*R1*c12, 0, 0), radius R1
        // enforce B1 ⟂ B3 -> quadratic in R1:
        //   (1-c12^2)R1^2 + 2*sigma*R3*c12*c23*R1 + R3^2(1 - c23^2 - c34^2)=0
        float a = 1.0 - c12*c12;
        float c = R3*R3 * (1.0 - c23*c23 - c34*c34);

        for (int si = 0; si < 2 && !found; si++) {
            float sigma = (si == 0) ? +1.0 : -1.0;
            float b = 2.0 * sigma * R3 * c12 * c23;

            float r0, r1;
            bool has = solveQuadraticPos(a, b, c, r0, r1);
            if (!has) continue;

            // try up to 2 positive roots
            for (int which = 0; which < 2 && !found; which++) {
                float R1 = (which == 0) ? r0 : r1;
                if (R1 <= EPS) continue;

                Ball candB1 = from_sphere(vec3(sigma * R1 * c12, 0.0, 0.0), R1);

                // --- Solve B0 sphere from simplified formula (in this gauge) ---
                float K = R3*R3 * (1.0 - c23*c23 - c34*c34);

                Ball candB0 = defaultBall();
                bool okB0 = false;

                if (abs(c01) < 1e-6) {
                    // p=2 needs B0 ⟂ B1: requires numerator ~ 0
                    float s12sq = 1.0 - c12*c12;
                    float numer = K - (R1*R1*s12sq);
                    if (abs(numer) < 1e-3 && K > 0.0) {
                        float R0 = 1.0;
                        float z0 = sqrt(R0*R0 + K);
                        if (z0 > R0 + 1e-4) {
                            candB0 = from_sphere(vec3(0.0, 0.0, z0), R0);
                            okB0 = true;
                        }
                    }
                } else {
                    // R0 = (K - R1^2*(1-c12^2)) / (2*R1*c01)
                    float s12sq = 1.0 - c12*c12;
                    float numer = K - (R1*R1*s12sq);
                    float R0raw = numer / (2.0 * R1 * c01);
                    float R0 = abs(R0raw);
                    float z0 = sqrt(max(R0*R0 + K, 0.0));
                    if (R0 > EPS && z0 > R0 + 1e-4) {
                        candB0 = from_sphere(vec3(0.0, 0.0, z0), R0);
                        okB0 = true;
                    }
                }

                if (okB0 && validateBSystem(candB0, candB1, B2, B3, B4, c01, c12, c23, c34)) {
                    bestB0 = candB0;
                    bestB1 = candB1;
                    found = true;
                    break;
                }
            }
        }
    }

    // If still not found, fall back to something safe-ish (will likely violate constraints)
    if (!found) {
        bestB1 = from_sphere(vec3(c12, 0.0, 0.0), 1.0);
        bestB0 = from_sphere(vec3(0.0, 0.0, 2.0), 0.5);
    }

    Ball B0 = bestB0;
    B1 = bestB1;

    // Optional orientation flips as in your template (keep if your pipeline expects it)
    //invertBall(B1);
    invertBall(B3);
      invertBall(B0);

    // --- pack coclusters ---
    coclusters = Ball[5](B0, B1, B2, B3, B4);

    SECTION_HEIGHT = B0.isplane ? 2.0 * B0.r : B0.n.z;

    // --- init clusters with defaults ---
    for (int k = 0; k < 5; k++) clusters[k] = defaultBall();

    // C0 is always z=0 plane
    clusters[0] = from_plane(vec3(0.0, 0.0, 1.0), 0.0);
    clusters[0].isRealBall = true;

    // --- compute C1..C4 only when requested ---
    if (isRealBall.x) {
        // C1 ⟂ B0,B2,B3,B4
        Ball C1 = solveOrthoSphere4(B0, B2, B3, B4);
        if (!(C1.isplane && abs(C1.r) < EPS) && !( !C1.isplane && abs(C1.r) < EPS)) {
            C1.isRealBall = true;
            clusters[1] = C1;
        }
    }

    if (isRealBall.y) {
        // C2 ⟂ B0,B1,B3,B4
        Ball C2 = solveOrthoSphere4(B0, B1, B3, B4);
        C2.isRealBall = true;
        clusters[2] = C2;
    }

    if (isRealBall.z) {
        // C3 ⟂ B0,B1,B2,B4
        Ball C3r = solveOrthoSphere4(B0, B1, B2, B4);
        C3r.isRealBall = true;
        clusters[3] = C3r;
    }

    if (isRealBall.w) {
        // C4 ⟂ B0,B1,B2,B3
        Ball C4r = solveOrthoSphere4(B0, B1, B2, B3);
        C4r.isRealBall = true;
        clusters[4] = C4r;
    }
}

#define PI 3.14159265358979323846

// ----------------------------
// Tunable parameters
// ----------------------------
const float ECC = 0.65;   // epsilon in (0,1)
const float A   = 1.15;   // semi-major axis (vertical)
const float MU  = 1.00;   // gravitational parameter (normalized)
const float ZOOM = 4.2;   // camera zoom

// ----------------------------
// Helpers
// ----------------------------
float sat(float x) { return clamp(x, 0.0, 1.0); }

mat2 rot(float a)
{
    float c = cos(a), s = sin(a);
    return mat2(c,-s,s,c);
}

vec2 toWorld(vec2 fragCoord)
{
    vec2 p = (fragCoord - 0.5 * iResolution.xy) / iResolution.y;
    return p * ZOOM;
}

// Anti-aliased line from signed distance
float aaLine(float d, float w)
{
    float px = 1.5 / iResolution.y * ZOOM;
    return 1.0 - smoothstep(w - px, w + px, abs(d));
}

// Approximate signed distance to ellipse x^2/b^2 + y^2/a^2 = 1
float sdEllipseImplicit(vec2 p, float a, float b)
{
    float F = p.x*p.x/(b*b) + p.y*p.y/(a*a) - 1.0;
    vec2 g = vec2(2.0*p.x/(b*b), 2.0*p.y/(a*a));
    return F / max(length(g), 1e-5);
}

// Distance to moving cosine y = a cos((eps/b)(x - v t))
// Using M = n t, v = (b/eps) n, this becomes y = a cos((eps/b)x - M)
float sdMovingCosine(vec2 p, float a, float b, float eps, float M)
{
    float k = eps / b;
    float phase = k * p.x - M;
    float yc = a * cos(phase);
    float dydx = -a * k * sin(phase);
    return (p.y - yc) / sqrt(1.0 + dydx*dydx);
}

float sdCircle(vec2 p, vec2 c, float r)
{
    return length(p - c) - r;
}

float hash21(vec2 p)
{
    p = fract(p * vec2(123.34, 456.21));
    p += dot(p, p + 45.32);
    return fract(p.x * p.y);
}

// Newton solve:
// sign = -1 => M = E - eps sin E   (P1)
// sign = +1 => M = E + eps sin E   (P2)
float solveKepler(float M, float eps, float sign)
{
    float E = M; // decent initial guess
    for (int i = 0; i < 7; ++i)
    {
        float f  = E + sign * eps * sin(E) - M;
        float fp = 1.0 + sign * eps * cos(E);
        E -= f / fp;
    }
    return E;
}

vec3 blend(vec3 base, vec3 ink, float a)
{
    return mix(base, ink, sat(a));
}

void mainImage(out vec4 fragColor, in vec2 fragCoord)
{
    vec2 p = toWorld(fragCoord);

    // Geometry from the paper:
    // ellipse: y^2/a^2 + x^2/b^2 = 1, with eccentricity eps
    float eps = ECC;
    float a = A;
    float b = a * sqrt(1.0 - eps * eps);

    // Mean motion n = sqrt(mu / a^3), mean anomaly M = n t
    float n = sqrt(MU / (a * a * a));
    float t = iTime * 0.9;
    float M = mod(n * t, 2.0 * PI);

    // Solve for the two orbit points used in Proposition 1
    float E1 = solveKepler(M, eps, -1.0); // M = E1 - eps sin E1
    float E2 = solveKepler(M, eps, +1.0); // M = E2 + eps sin E2

    vec2 P1 = vec2(-b * sin(E1),  a * cos(E1));
    vec2 P2 = vec2( b * sin(E2),  a * cos(E2));

    vec2 F1 = vec2(0.0,  a * eps);
    vec2 F2 = vec2(0.0, -a * eps);

    // Background
    vec3 col = vec3(0.97, 0.97, 0.98);

    // Mild grid
    {
        vec2 gp = p * 2.0;
        vec2 g = abs(fract(gp - 0.5) - 0.5) / fwidth(gp);
        float grid = 1.0 - min(min(g.x, g.y), 1.0);
        col = mix(col, vec3(0.93), 0.08 * grid);
    }

    // Axes
    float axX = aaLine(p.y, 0.003);
    float axY = aaLine(p.x, 0.003);
    col = blend(col, vec3(0.88), 0.6 * axX);
    col = blend(col, vec3(0.88), 0.6 * axY);

    // Ellipse
    float dE = sdEllipseImplicit(p, a, b);
    float ellipseInk = aaLine(dE, 0.010);
    col = blend(col, vec3(0.08, 0.12, 0.18), ellipseInk);

    // Moving cosine
    float dC = sdMovingCosine(p, a, b, eps, M);
    float cosInk = aaLine(dC, 0.010);
    col = blend(col, vec3(0.18, 0.42, 0.88), 0.95 * cosInk);

    // Foci
    float f1 = aaLine(sdCircle(p, F1, 0.025), 0.020);
    float f2 = aaLine(sdCircle(p, F2, 0.025), 0.020);
    col = blend(col, vec3(0.75, 0.18, 0.18), f1);
    col = blend(col, vec3(0.75, 0.18, 0.18), f2);

    // Lines from foci to orbit points
    // simple segment drawing by projection
    {
        vec2 a0 = F1, b0 = P1;
        vec2 pa = p - a0, ba = b0 - a0;
        float h = clamp(dot(pa, ba) / dot(ba, ba), 0.0, 1.0);
        float d = length(pa - ba * h);
        col = blend(col, vec3(0.92, 0.75, 0.35), aaLine(d, 0.006) * 0.65);
    }
    {
        vec2 a0 = F2, b0 = P2;
        vec2 pa = p - a0, ba = b0 - a0;
        float h = clamp(dot(pa, ba) / dot(ba, ba), 0.0, 1.0);
        float d = length(pa - ba * h);
        col = blend(col, vec3(0.92, 0.75, 0.35), aaLine(d, 0.006) * 0.65);
    }

    // Orbit points (the two intersections)
    float p1r = aaLine(sdCircle(p, P1, 0.040), 0.030);
    float p2r = aaLine(sdCircle(p, P2, 0.040), 0.030);
    col = blend(col, vec3(0.98, 0.45, 0.12), p1r);
    col = blend(col, vec3(0.15, 0.70, 0.35), p2r);

    // Glow around points
    col += 0.18 * vec3(1.0, 0.45, 0.12) / (1.0 + 120.0 * dot(p - P1, p - P1));
    col += 0.12 * vec3(0.15, 0.70, 0.35) / (1.0 + 120.0 * dot(p - P2, p - P2));

    // Small moving marker on cosine phase origin x = vt
    float v = (b / eps) * n;
    vec2 phaseMarker = vec2(v * t, a);
    float pm = aaLine(sdCircle(p, vec2(v*t, 0.0), 0.018), 0.012);
    col = blend(col, vec3(0.25), 0.4 * pm);

    // Optional: slight vignette
    float vign = smoothstep(2.4, 0.8, length(p));
    col *= mix(0.92, 1.0, vign);

    fragColor = vec4(col, 1.0);
}

#define PI  3.14159265358979323846
#define TAU 6.28318530717958647692

#define B 3.0
#define H 0.42
#define OCT 72

#define INV_SQRT2 0.7071067811865476
#define WORLD_HALF_WIDTH 1.45
#define Y_SCALE 0.34

float sinc1(float x)
{
    return (abs(x) < 1e-4) ? (1.0 - x*x/6.0) : sin(x)/x;
}

// This is exactly W(x0+dx)-W(x0) for x0 = 1/4,
// with W(x)=sum a^n cos(pi * 3^n * x), a = 3^{-H}.
// For x0=1/4 and B=3:
// alpha_n = pi*3^n/4 alternates between pi/4 and 3pi/4.
float weierDelta(float dx, float pixelDx)
{
    float a = pow(B, -H);

    float amp   = 1.0;
    float beta  = mod(PI * dx, TAU);
    float dbeta = PI * pixelDx;

    float sum = 0.0;
    float ca  = INV_SQRT2;   // cos(alpha_n): +,-,+,-,...
    float sa  = INV_SQRT2;   // sin(alpha_n): always +

    for (int n = 0; n < OCT; ++n)
    {
        float filt = (dbeta > 1e4) ? 0.0 : sinc1(0.5 * dbeta);

        float cb = cos(beta) * filt;
        float sb = sin(beta) * filt;

        // cos(alpha+beta)-cos(alpha)
        sum += amp * (ca * (cb - 1.0) - sa * sb);

        amp   *= a;
        beta   = mod(beta * B, TAU);
        dbeta *= B;
        ca    *= -1.0;
    }

    return sum;
}

float curveY(float sx, float zoom)
{
    float dx = WORLD_HALF_WIDTH * sx / zoom;
    float px = WORLD_HALF_WIDTH / zoom / iResolution.y;

    // true graph near x0, with vertical renormalization
    return Y_SCALE * pow(zoom, H) * weierDelta(dx, px);
}

void mainImage(out vec4 fragColor, in vec2 fragCoord)
{
    vec2 p = (2.0 * fragCoord - iResolution.xy) / iResolution.y;

    // endless zoom
    float zoom = exp2(0.22 * iTime);

    // plot the actual graph
    float y = curveY(p.x, zoom);

    vec3 col = vec3(0.03, 0.04, 0.06);

    // very faint vignette only
    col *= 1.0 - 0.06 * dot(p, p);

    // draw the curve
    float d  = abs(p.y - y);
    float aa = 1.6 / iResolution.y + 1.2 * fwidth(y);

    float line = 1.0 - smoothstep(aa, 3.5 * aa, d);
    float glow = exp(-14.0 * d);

    col += 0.08 * glow * vec3(0.4, 0.6, 1.0);
    col = mix(col, vec3(1.0, 0.97, 0.92), line);

    fragColor = vec4(col, 1.0);
}

// ------------------------------------------------------------
// Image
// Renders the surface eta(x,t) from the amplitudes evolved in Buffer A.
//
// iChannel0 must be Buffer A.
// ------------------------------------------------------------

#define PRESET 2
#define AUTO_CYCLE 0
#define REPEAT_DEMO 1
#define DEMO_PERIOD 22.0

const float PI = 3.14159265358979323846264;
const int NM = 6;

float sat(float x) { return clamp(x, 0.0, 1.0); }

float demoTime()
{
#if REPEAT_DEMO
    return mod(iTime, DEMO_PERIOD);
#else
    return iTime;
#endif
}

int getPresetFallback()
{
#if AUTO_CYCLE
    return int(mod(floor(iTime / 8.0), 3.0));
#else
    if (iMouse.z > 0.0)
    {
        return int(clamp(floor(3.0 * iMouse.x / iResolution.x), 0.0, 2.0));
    }
    return PRESET;
#endif
}

void getPresetParams(
    int preset,
    out float m,
    out float n,
    out float chi,
    out float phi,
    out float k
){
    if (preset == 0)
    {
        // Square: odd/odd-style double forcing
        m   = 3.0;
        n   = 5.0;
        chi = 42.0 * PI / 180.0;
        phi = 20.0 * PI / 180.0;
        k   = 45.0;
    }
    else if (preset == 1)
    {
        // Hexagon: even/odd 4:5 forcing
        m   = 4.0;
        n   = 5.0;
        chi = 45.0 * PI / 180.0;
        phi = 75.0 * PI / 180.0;
        k   = 44.0;
    }
    else
    {
        // Twelvefold quasi-pattern: even/odd 4:5 forcing
        m   = 4.0;
        n   = 5.0;
        chi = 45.0 * PI / 180.0;
        phi = 75.0 * PI / 180.0;
        k   = 43.0;
    }
}

float forcingSignal(float t, float m, float n, float omega, float chi, float phi)
{
    return cos(chi) * cos(m * omega * t)
         + sin(chi) * cos(n * omega * t + phi);
}

vec2 readA(int j)
{
    return texelFetch(iChannel0, ivec2(j, 0), 0).xy;
}

// eta = xi(t) sum_j Re[A_j exp(i k_j.x)] + c.c.
// return vec3(height, grad_x, grad_y)
vec3 surfaceFromAmplitudes(vec2 p, int preset, float td)
{
    float m, n, chi, phi, k;
    getPresetParams(preset, m, n, chi, phi, k);

    float omega = 1.18;

    // Real temporal eigenfunction xi(t).
    // In the paper, xi(t) carries the fast standing-wave oscillation,
    // while A_j are slow amplitudes.
    float xi1 = cos(0.5 * m * omega * td);
    float xi2 = cos(0.5 * n * omega * td + 0.5 * phi);

    float xi;
    if (preset == 0)
    {
        xi = 0.75 * xi1 + 0.25 * xi2;
    }
    else if (preset == 1)
    {
        xi = 0.70 * xi1 + 0.30 * xi2;
    }
    else
    {
        // slightly more stroboscopic for twelvefold visibility
        xi = 0.62 + 0.26 * xi1 + 0.12 * xi2;
    }

    float drive = forcingSignal(td, m, n, omega, chi, phi);
    float pumpVis = 0.92 + 0.08 * drive;

    vec3 H = vec3(0.0);

    for (int j = 0; j < NM; j++)
    {
        float theta = float(j) * PI / 6.0;
        vec2 dir = vec2(cos(theta), sin(theta));

        vec2 A = readA(j);

        float q = k * dot(p, dir);
        float c = cos(q);
        float s = sin(q);

        // Re[(a+ib)(cos q+i sin q)] = a cos q - b sin q
        float u  = A.x * c - A.y * s;

        // d/dq Re[A exp(iq)] = -a sin q - b cos q
        float du = -A.x * s - A.y * c;

        H.x  += 2.0 * u;
        H.yz += 2.0 * du * k * dir;
    }

    // Converts dimensionless amplitude-equation height to a visible surface.
    float heightScale = 0.060;

    return heightScale * xi * pumpVis * H;
}

vec3 renderSurface(vec2 p, vec3 H, float rimMask, int preset, float ramp)
{
    float h = H.x;
    vec2  g = H.yz;

    vec3 N = normalize(vec3(-g.x, -g.y, 13.0));

    float slope = length(g);

    // Reflection-like Faraday visualization:
    // bright where surface slope reflects the ring light toward the camera.
    float targetSlope = 4.8;
    float width = 1.9;
    float ringReflection = exp(-pow((slope - targetSlope) / width, 2.0));

    float heightShade = 0.5 + 0.5 * tanh(1.7 * h);
    float crest  = smoothstep(0.08, 0.65, h);
    float trough = smoothstep(0.08, 0.65, -h);

    vec3 L = normalize(vec3(-0.35, 0.45, 0.82));
    float diffuse = 0.26 + 0.74 * max(dot(N, L), 0.0);

    vec3 base;
    if (preset == 0)
    {
        base = vec3(0.14, 0.19, 0.27);
    }
    else if (preset == 1)
    {
        base = vec3(0.22, 0.20, 0.15);
    }
    else
    {
        base = vec3(0.17, 0.19, 0.22);
    }

    vec3 col = base * diffuse;

    // When the system is still below threshold, keep the surface quiet.
    float visible = smoothstep(0.18, 0.65, ramp);

    col += visible * vec3(0.95) * ringReflection;
    col += 0.22 * heightShade;
    col += visible * 0.16 * crest  * vec3(0.75, 0.86, 1.00);
    col -= visible * 0.07 * trough * vec3(0.14, 0.17, 0.22);

    vec3 V = vec3(0.0, 0.0, 1.0);
    vec3 Rr = reflect(-L, N);
    float spec = pow(max(dot(Rr, V), 0.0), 36.0);
    col += visible * 0.20 * spec;

    col *= mix(1.0, 0.35, rimMask);

    return col;
}

void mainImage(out vec4 fragColor, in vec2 fragCoord)
{
    vec2 res = iResolution.xy;
    vec2 uv = (2.0 * fragCoord - res) / res.y;

    float R = 0.92;
    float r = length(uv);

    vec4 info = texelFetch(iChannel0, ivec2(6, 0), 0);

    int presetFromBuffer = int(info.z + 0.5);
    int preset = presetFromBuffer;

    // During the first frame, Buffer A may not be initialized yet.
    if (preset < 0 || preset > 2) preset = getPresetFallback();

    float td = demoTime();
    float ramp = info.w;
    float mu = info.y;

    if (r > R + 0.045)
    {
        fragColor = vec4(vec3(0.010, 0.011, 0.013), 1.0);
        return;
    }

    float pin = 1.0 - smoothstep(R - 0.075, R, r);
    float rimMask = smoothstep(R - 0.10, R, r);

    vec3 H = surfaceFromAmplitudes(uv, preset, td);

    // Pinned boundary in the circular container.
    H *= pin;

    vec3 col = renderSurface(uv, H, rimMask, preset, ramp);

    // Container rim.
    float rimOuter = smoothstep(R - 0.012, R + 0.004, r)
                   - smoothstep(R + 0.006, R + 0.035, r);

    float rimInner = smoothstep(R - 0.050, R - 0.010, r)
                   - smoothstep(R - 0.010, R + 0.002, r);

    col = mix(col, vec3(0.74, 0.76, 0.78), sat(rimOuter));
    col += 0.22 * rimInner * vec3(0.55, 0.58, 0.62);

    if (r > R)
    {
        col = mix(vec3(0.015), vec3(0.50, 0.52, 0.55), sat(rimOuter));
    }

    // Bottom preset indicator bars.
    vec2 q = fragCoord / res;

    float barY = smoothstep(0.030, 0.034, q.y)
               * (1.0 - smoothstep(0.060, 0.064, q.y));

    float bx = floor(3.0 * q.x);
    float isChosenPreset = 1.0 - step(0.5, abs(bx - float(preset)));

    vec3 barCol = mix(vec3(0.18), vec3(0.95), isChosenPreset);

    float localX = fract(3.0 * q.x);
    float bar = barY
              * smoothstep(0.02, 0.04, localX)
              * (1.0 - smoothstep(0.96, 0.98, localX));

    col = mix(col, barCol, 0.75 * bar);

    // Top forcing-ramp bar.
    float py = q.y;
    float progBand = smoothstep(0.94, 0.945, py)
                   * (1.0 - smoothstep(0.972, 0.977, py));

    float progFill = step(q.x, 0.08 + 0.84 * ramp);
    vec3 progCol = mix(vec3(0.10), vec3(0.88, 0.92, 0.98), progFill);

    col = mix(col, progCol, 0.55 * progBand);

    // Small threshold marker on the top bar.
    float thresholdX = 0.08 + 0.84 * ((0.0 + 0.18) / (0.36 + 0.18));
    float mark = smoothstep(0.006, 0.003, abs(q.x - thresholdX)) * progBand;
    col = mix(col, vec3(1.0, 0.62, 0.25), mark);

    // Vignette and gamma.
    col *= 1.10 - 0.22 * dot(uv, uv);
    col = pow(max(col, 0.0), vec3(0.92));

    fragColor = vec4(col, 1.0);
}

// ------------------------------------------------------------
// Buffer A
// Integrates Edwards-Fauve style standing-wave amplitude equations.
//
// Stored pixels:
//   x = 0..5, y = 0: complex amplitudes A_j = R + i I
//   x = 6,    y = 0: vec4(td, mu, preset, ramp)
//
// iChannel0 of Buffer A must be Buffer A itself.
// ------------------------------------------------------------

#define PRESET 2        // 0 square, 1 hexagon, 2 twelvefold
#define AUTO_CYCLE 0
#define REPEAT_DEMO 1
#define DEMO_PERIOD 22.0

const float PI = 3.14159265358979323846264;
const int NM = 6;

float sat(float x) { return clamp(x, 0.0, 1.0); }

float hash11(float p)
{
    return fract(sin(p * 127.1 + 311.7) * 43758.5453123);
}

vec2 hash21(float p)
{
    return vec2(hash11(p + 13.1), hash11(p + 71.7));
}

vec2 cmul(vec2 a, vec2 b)
{
    return vec2(a.x*b.x - a.y*b.y, a.x*b.y + a.y*b.x);
}

vec2 cconj(vec2 a)
{
    return vec2(a.x, -a.y);
}

float demoTime()
{
#if REPEAT_DEMO
    return mod(iTime, DEMO_PERIOD);
#else
    return iTime;
#endif
}

int getPreset()
{
#if AUTO_CYCLE
    return int(mod(floor(iTime / 8.0), 3.0));
#else
    if (iMouse.z > 0.0)
    {
        return int(clamp(floor(3.0 * iMouse.x / iResolution.x), 0.0, 2.0));
    }
    return PRESET;
#endif
}

float forcingRamp(float td)
{
    // slowly increase the driving amplitude
    return smoothstep(3.0, 12.0, td);
}

float controlMu(float ramp)
{
    // effective bifurcation parameter
    // below 0: flat surface stable
    // above 0: Faraday modes grow
    return mix(-0.18, 0.36, ramp);
}

float alphaCoeff(int preset)
{
    // alpha is the quadratic triad coefficient.
    //
    // preset 0: square / odd-odd style, no quadratic term
    // preset 1: even-odd forcing, strong triad term -> hexagons
    // preset 2: even-odd forcing, weaker triad plus compatible cubic couplings -> 12-fold
    if (preset == 0) return 0.00;
    if (preset == 1) return 0.24;
    return 0.070;
}

float betaBySeparation(int d, int preset)
{
    // Six roll families are separated by 30 degrees:
    // j = 0,1,2,3,4,5 corresponds to 0,30,60,90,120,150 degrees.
    //
    // beta(0)=1 by amplitude scaling, as in the paper.
    d = min(d, 6 - d);

    if (d == 0) return 1.0;

    if (preset == 0)
    {
        // Square-favoring cubic coupling:
        // 90-degree coexistence is cheap, 30/60-degree coexistence is expensive.
        if (d == 3) return 0.22;  // 90 degrees
        if (d == 2) return 1.70;  // 60 degrees
        return 1.95;              // 30 or 150 degrees
    }
    else if (preset == 1)
    {
        // Hexagon-favoring:
        // one triad {0,2,4} or {1,3,5} wins.
        // Cross-triad competition is strong.
        if (d == 2) return 0.55;  // 60/120 degrees inside a hex triad
        if (d == 3) return 1.45;  // 90 degrees
        return 1.75;              // 30/150 degrees
    }
    else
    {
        // Twelvefold-favoring:
        // all six families can coexist because angular competition is mild.
        if (d == 1) return 0.36;  // 30 degrees
        if (d == 2) return 0.42;  // 60 degrees
        return 0.48;              // 90 degrees
    }
}

vec2 seedAmplitude(int j, int preset, float cycle)
{
    vec2 r = hash21(float(j) * 17.0 + float(preset) * 101.0 + cycle * 37.0);
    r = 2.0 * r - 1.0;
    return 0.0012 * r;
}

void mainImage(out vec4 fragColor, in vec2 fragCoord)
{
    ivec2 ip = ivec2(fragCoord);

    if (ip.y != 0 || ip.x > 6)
    {
        fragColor = vec4(0.0);
        return;
    }

    int preset = getPreset();
    float td = demoTime();
    float ramp = forcingRamp(td);
    float mu = controlMu(ramp);
    float alpha = alphaCoeff(preset);

    vec4 prevInfo = texelFetch(iChannel0, ivec2(6, 0), 0);

    bool reset = false;
    reset = reset || (iFrame < 2);
    reset = reset || (abs(prevInfo.z - float(preset)) > 0.5);

#if REPEAT_DEMO
    reset = reset || (td < prevInfo.x - 0.2);
#endif

    float cycle = floor(iTime / DEMO_PERIOD);

    vec2 A[NM];

    for (int j = 0; j < NM; j++)
    {
        vec2 oldA = texelFetch(iChannel0, ivec2(j, 0), 0).xy;
        A[j] = reset ? seedAmplitude(j, preset, cycle) : oldA;
    }

    // Integrate the slow amplitude equations.
    // The state is only 6 complex numbers, so we can afford several
    // substeps per rendered frame.
    float dt = 0.018;

    for (int step = 0; step < 6; step++)
    {
        vec2 dA[NM];

        for (int j = 0; j < NM; j++)
        {
            float cubic = 0.0;

            for (int l = 0; l < NM; l++)
            {
                int d = abs(j - l);
                float beta = betaBySeparation(d, preset);
                cubic += beta * dot(A[l], A[l]);
            }

            int jp = (j + 2) % 6;
            int jm = (j + 4) % 6;

            // Edwards-Fauve even/odd triad term:
            // alpha * conj(A_{j+2}) * conj(A_{j-2})
            vec2 triad = alpha * cconj(cmul(A[jp], A[jm]));

            // Small physical noise near onset so the pattern can emerge
            // from a nearly flat state.
            float nearOnset = exp(-18.0 * abs(mu));
            vec2 noise = 0.00008 * nearOnset *
                (2.0 * hash21(float(j) * 31.7 + float(iFrame * 7 + step) + 19.3) - 1.0);

            dA[j] = mu * A[j] + triad - cubic * A[j] + noise;
        }

        for (int j = 0; j < NM; j++)
        {
            A[j] += dt * dA[j];

            // Numerical safety clamp.
            float L = length(A[j]);
            if (L > 2.0) A[j] *= 2.0 / L;
        }
    }

    if (ip.x < 6)
    {
        fragColor = vec4(A[ip.x], 0.0, 1.0);
    }
    else
    {
        fragColor = vec4(td, mu, float(preset), ramp);
    }
}

// Bruhat--Tits tree fold renderer with a p-adic matrix isometry.
// Paste into Shadertoy Image tab.
//
// The Bruhat--Tits tree for PGL(2,Q_p) is (p+1)-regular.
//
// This version keeps the fold/SDF rendering idea:
//   - no enumeration of all vertices or edges;
//   - each pixel folds into a fundamental branch;
//   - the matrix action is used to move the root frame
//     from [O] to g[O], matching the original project's
//     "interpolate vertex v to g v" idea in the fold setting.
//
// Matrix convention, matching the original TypeScript code:
//
//        [ a  c ]
//    g = [      ]
//        [ b  d ]
//
// Change the rational constants below to change g.

#define PRIME_P 2.0
#define DEPTH 20

#define ROOT_LEN     0.58
#define EDGE_SHRINK  0.585
#define WIDTH0       0.0075
#define WIDTH_SHRINK 0.715

#define MAX_VAL_STEPS 24
#define MAX_PATH_STEPS 32

// -----------------------------------------------------------------------------
// Matrix input.
// Each entry is a rational NUM / DEN.
//
// Default:
//
//      [ 1  0 ]
//  g = [      ]
//      [ 0  p ]
//
// This sends the origin vertex to the neighbouring vertex [0]_1.
// -----------------------------------------------------------------------------

#define MAT_A_NUM 1.0
#define MAT_A_DEN 1.0

#define MAT_C_NUM 0.0
#define MAT_C_DEN 1.0

#define MAT_B_NUM 0.0
#define MAT_B_DEN 1.0

#define MAT_D_NUM PRIME_P
#define MAT_D_DEN 1.0

// Set to 0.0 to disable matrix animation.
#define MATRIX_ISOMETRY_ON 1.0

// Animation speed.
#define MATRIX_SPEED 0.075

const float PI  = 3.14159265358979323846;
const float TAU = 6.28318530717958647692;
const float INF = 1.0e9;

struct Rat {
    float n;
    float d;
};

struct Vertex {
    Rat u;
    float level;
};

struct Frame {
    vec2 pos;
    float zeroAngle;
    float depth;
};

float iround(float x)
{
    return x < 0.0 ? ceil(x - 0.5) : floor(x + 0.5);
}

float posMod(float a, float m)
{
    return mod(mod(a, m) + m, m);
}

float powP(float k)
{
    return pow(PRIME_P, k);
}

bool ratIsZero(Rat r)
{
    return abs(r.n) < 0.5;
}

Rat rat(float n, float d)
{
    if (d < 0.0) {
        n = -n;
        d = -d;
    }
    return Rat(n, d);
}

Rat ratAdd(Rat a, Rat b)
{
    return rat(a.n * b.d + b.n * a.d, a.d * b.d);
}

Rat ratSub(Rat a, Rat b)
{
    return rat(a.n * b.d - b.n * a.d, a.d * b.d);
}

Rat ratMul(Rat a, Rat b)
{
    return rat(a.n * b.n, a.d * b.d);
}

Rat ratDiv(Rat a, Rat b)
{
    return rat(a.n * b.d, a.d * b.n);
}

Rat ratMulPow(Rat a, float k)
{
    k = iround(k);

    if (k >= 0.0) {
        return rat(a.n * powP(k), a.d);
    } else {
        return rat(a.n, a.d * powP(-k));
    }
}

Rat ratDivPow(Rat a, float k)
{
    return ratMulPow(a, -k);
}

float valuationInt(float x)
{
    x = abs(iround(x));

    if (x < 0.5) return INF;

    float v = 0.0;

    for (int i = 0; i < MAX_VAL_STEPS; ++i) {
        if (abs(posMod(x, PRIME_P)) < 0.5) {
            x = iround(x / PRIME_P);
            v += 1.0;
        } else {
            break;
        }
    }

    return v;
}

float valuationRat(Rat r)
{
    if (ratIsZero(r)) return INF;
    return valuationInt(r.n) - valuationInt(r.d);
}

float invMod(float a, float m)
{
    a = posMod(iround(a), m);
    m = iround(m);

    float t = 0.0;
    float newT = 1.0;
    float r0 = m;
    float newR = a;

    for (int i = 0; i < 64; ++i) {
        if (abs(newR) < 0.5) break;

        float q = floor(r0 / newR);

        float tmpT = t - q * newT;
        t = newT;
        newT = tmpT;

        float tmpR = r0 - q * newR;
        r0 = newR;
        newR = tmpR;
    }

    return posMod(t, m);
}

float residueRat(Rat r)
{
    float v = valuationRat(r);

    if (v > 0.5) return 0.0;

    // This function is meant for p-adic integers.
    // If v < 0, the residue is not defined; return 0 as a safe fallback.
    if (v < -0.5) return 0.0;

    float n = posMod(iround(r.n), PRIME_P);
    float d = posMod(iround(r.d), PRIME_P);
    float dinv = invMod(d, PRIME_P);

    return posMod(n * dinv, PRIME_P);
}

float digitAt(Rat u, float k)
{
    // coefficient of p^k in the p-adic expansion of u
    return residueRat(ratDivPow(u, k));
}

// -----------------------------------------------------------------------------
// p-adic matrix action on the origin vertex.
// This implements the same reduction logic as BruhatTitsTree.matToVertex()
// for the specific case g * origin = matToVertex(g).
// -----------------------------------------------------------------------------

Vertex matToVertex()
{
    Rat a = rat(MAT_A_NUM, MAT_A_DEN);
    Rat c = rat(MAT_C_NUM, MAT_C_DEN);
    Rat b = rat(MAT_B_NUM, MAT_B_DEN);
    Rat d = rat(MAT_D_NUM, MAT_D_DEN);

    float va = valuationRat(a);
    float vb = valuationRat(b);

    // The original code swaps rows so that v(a) <= v(b).
    if (va > vb) {
        Rat oldA = a;
        Rat oldC = c;

        a = b;
        c = d;
        b = oldA;
        d = oldC;

        va = valuationRat(a);
    }

    if (va > INF * 0.5) {
        return Vertex(rat(0.0, 1.0), 0.0);
    }

    Rat c1 = ratDiv(c, a);
    Rat delta = ratSub(d, ratMul(b, c1));

    float vd = valuationRat(delta);

    if (vd > INF * 0.5) {
        // Singular matrix fallback.
        return Vertex(rat(0.0, 1.0), 0.0);
    }

    float n = iround(vd - va);

    Rat u = rat(0.0, 1.0);
    float vc1 = valuationRat(c1);

    if (!ratIsZero(c1) && vc1 < n - 0.5) {
        float m = iround(vc1);
        Rat c2 = ratDivPow(c1, m);

        float q = powP(n - m);

        float num = posMod(iround(c2.n), q);
        float den = posMod(iround(c2.d), q);
        float denInv = invMod(den, q);

        float uuint = posMod(num * denInv, q);

        u = ratMulPow(rat(uuint, 1.0), m);
    }

    return Vertex(u, n);
}

// -----------------------------------------------------------------------------
// Geometry.
// -----------------------------------------------------------------------------

mat2 rot(float a)
{
    float c = cos(a);
    float s = sin(a);
    return mat2(c, s, -s, c);
}

float edgeLength(float depth)
{
    return ROOT_LEN * pow(EDGE_SHRINK, depth);
}

float edgeWidth(float depth)
{
    return WIDTH0 * pow(WIDTH_SHRINK, depth);
}

float edgeAngle(float edge)
{
    return -edge * TAU / (PRIME_P + 1.0);
}

void advanceFrame(inout Frame f, float edge, float reverseEdge)
{
    float a = f.zeroAngle + edgeAngle(edge);
    float len = edgeLength(f.depth);

    f.pos += len * vec2(cos(a), sin(a));

    // Same formula as original TreeRenderer.relativeState():
    //
    // zeroAngle = PI + angle - edgeAngle(reverse)
    //
    f.zeroAngle = PI + a - edgeAngle(reverseEdge);
    f.depth += 1.0;
}

Frame vertexFrame(Vertex v)
{
    Frame f = Frame(vec2(0.0), 0.0, 0.0);

    float targetN = iround(v.level);
    float currentN = 0.0;
    float retreat = valuationRat(v.u);

    // First go down along the infinity edge if necessary.
    for (int i = 0; i < MAX_PATH_STEPS; ++i) {
        bool shouldRetreat =
            retreat < currentN - 0.5 ||
            currentN > targetN + 0.5;

        if (!shouldRetreat) break;

        // Edge PRIME_P is the infinity/backward edge in the original code.
        // Its reverse edge from the child is 0 for this origin-based path.
        advanceFrame(f, PRIME_P, 0.0);

        currentN -= 1.0;
    }

    // Then climb toward the finite p-adic expansion of u.
    for (int i = 0; i < MAX_PATH_STEPS; ++i) {
        if (!(currentN < targetN - 0.5)) break;

        float e = digitAt(v.u, currentN);

        // Finite child edge e has reverse edge PRIME_P.
        advanceFrame(f, e, PRIME_P);

        currentN += 1.0;
    }

    return f;
}

float sdSegment(vec2 p, vec2 a, vec2 b)
{
    vec2 pa = p - a;
    vec2 ba = b - a;

    float h = clamp(dot(pa, ba) / max(dot(ba, ba), 1.0e-8), 0.0, 1.0);

    return length(pa - h * ba);
}

float stroke(float d, float w, float aa)
{
    return 1.0 - smoothstep(w - aa, w + aa, d);
}

float pulse(float x)
{
    x = abs(fract(x) - 0.5);
    return exp(-72.0 * x * x);
}

vec3 palette(float t)
{
    return 0.55 + 0.45 * cos(TAU * (vec3(0.02, 0.33, 0.67) + t));
}

float angleMix(float a, float b, float t)
{
    float d = atan(sin(b - a), cos(b - a));
    return a + t * d;
}

// Root has p+1 equivalent directions.
vec2 foldRoot(vec2 z, float q, out float sectorIndex)
{
    float sector = TAU / q;
    float a = atan(z.y, z.x);

    sectorIndex = floor((a + 0.5 * sector) / sector);

    return rot(-sectorIndex * sector) * z;
}

// After one oriented edge has been selected, the backward edge is excluded.
// The remaining number of forward choices is p.
vec2 foldChild(vec2 z, float q, out float childIndex)
{
    float sector = TAU / q;
    float a = atan(z.y, z.x);

    float k = floor((a + PI + 0.5 * sector) / sector);

    // Exclude the backward direction k = 0.
    k = clamp(k, 1.0, q - 1.0);

    childIndex = k;

    float theta = -PI + k * sector;

    return rot(-theta) * z;
}

void renderEdge(
    in vec2 z,
    in float len,
    in float width,
    in float level,
    in float address,
    in float px,
    inout vec3 col,
    inout float alphaMask
)
{
    float dEdge = sdSegment(z, vec2(0.0), vec2(len, 0.0));
    float dNode0 = length(z);
    float dNode1 = length(z - vec2(len, 0.0));

    float edgeA = stroke(dEdge, width, px);
    float nodeA = max(
        stroke(dNode0, width * 2.65, px),
        stroke(dNode1, width * 2.65, px)
    );

    float localT = clamp(z.x / max(len, 1.0e-5), 0.0, 1.0);

    float wave =
        0.35 +
        0.65 * pulse(localT * 0.75 + level * 0.115 - iTime * 0.28);

    float depthFade = pow(0.925, level);

    vec3 edgeCol = palette(address + 0.075 * sin(iTime * 0.35));
    vec3 nodeCol = vec3(1.0, 0.93, 0.72);

    float a1 = edgeA * wave * depthFade;
    float a2 = nodeA * depthFade;

    col += edgeCol * a1 * 0.78;
    col += nodeCol * a2 * 0.95;

    alphaMask = max(alphaMask, max(a1, a2));
}

vec4 renderFoldedTree(vec2 z, float px)
{
    float q = PRIME_P + 1.0;

    vec3 col = vec3(0.0);
    float alphaMask = 0.0;

    float len = edgeLength(0.0);
    float width = edgeWidth(0.0);

    float rootIndex;
    z = foldRoot(z, q, rootIndex);

    float address = fract(rootIndex * 0.173);

    renderEdge(
        z,
        len,
        width,
        0.0,
        address,
        px,
        col,
        alphaMask
    );

    z -= vec2(len, 0.0);

    for (int level = 1; level < DEPTH; ++level) {
        float fLevel = float(level);

        len = edgeLength(fLevel);
        width = edgeWidth(fLevel);

        float childIndex;
        z = foldChild(z, q, childIndex);

        address = fract(
            address * 1.731 +
            childIndex * 0.271 +
            fLevel * 0.037
        );

        renderEdge(
            z,
            len,
            width,
            fLevel,
            address,
            px,
            col,
            alphaMask
        );

        z -= vec2(len, 0.0);
    }

    return vec4(col, alphaMask);
}

void mainImage(out vec4 fragColor, in vec2 fragCoord)
{
    vec2 uv = (fragCoord - 0.5 * iResolution.xy) / iResolution.y;

    float zoom = 1.32;
    float px = 1.5 * zoom / iResolution.y;

    // Small camera breathing.
    float camAng = 0.035 * sin(iTime * 0.17);
    vec2 world = rot(camAng) * (uv * zoom);

    // Compute g[origin].
    Vertex imageOfOrigin = matToVertex();
    Frame targetFrame = vertexFrame(imageOfOrigin);

    // Smooth back-and-forth interpolation:
    // origin frame <-> image frame.
    float s =
        MATRIX_ISOMETRY_ON *
        (0.5 - 0.5 * cos(TAU * MATRIX_SPEED * iTime));

    vec2 rootPos = mix(vec2(0.0), targetFrame.pos, s);
    float rootAngle = angleMix(0.0, targetFrame.zeroAngle, s);

    // Fold renderer in the moving root frame.
    vec2 local = rot(-rootAngle) * (world - rootPos);

    vec3 col = vec3(0.010, 0.014, 0.024);
    col += 0.055 * vec3(0.16, 0.20, 0.32) * (1.0 - length(uv));

    vec4 tree = renderFoldedTree(local, px);

    col += tree.rgb;
    col += vec3(0.10, 0.14, 0.22) * tree.a * 0.35;

    // Mark the moving root lightly, so the matrix action is visible.
    float rootMark = stroke(length(world - rootPos), WIDTH0 * 4.4, px);
    col += vec3(1.0, 0.78, 0.28) * rootMark * 0.65;

    // Mark the target root faintly.
    float targetMark = stroke(length(world - targetFrame.pos), WIDTH0 * 3.5, px);
    col += vec3(0.40, 0.65, 1.00) * targetMark * 0.30;

    float vignette = smoothstep(1.45, 0.15, length(uv));
    col *= 0.72 + 0.28 * vignette;

    col = 1.0 - exp(-1.35 * col);
    col = pow(col, vec3(0.4545));

    fragColor = vec4(col, 1.0);
}

/*
    Boyd-Maxwell / pseudo-Kleinian ball packing
    Shadertoy Image pass
*/

const float GAMMA_VALUE = 2.2;
const float EXPOSURE     = 1.0;
const float BRIGHTNESS   = 1.0;
const float CONTRAST     = 1.0;

// Exact Fragmentarium ToneMapping = 5 curve.
float syntopiaSigmoid(float t)
{
    float k = 1.0 - 1.0 / (1.0 + exp(-0.5 * CONTRAST * 5.0));
    t -= 0.5;
    float x = 1.0 / (1.0 + exp(-t * CONTRAST * 5.0)) - k;
    return x / (1.0 - 2.0 * k);
}

vec3 syntopiaToneMap(vec3 c)
{
    c = c * EXPOSURE + vec3(BRIGHTNESS - 1.0);
    return vec3(
        syntopiaSigmoid(c.r),
        syntopiaSigmoid(c.g),
        syntopiaSigmoid(c.b)
    );
}

void mainImage(out vec4 fragColor, in vec2 fragCoord)
{
    vec2 uv = fragCoord / iResolution.xy;
    vec4 accumulation = texture(iChannel0, uv);

    vec3 color = accumulation.rgb / max(accumulation.a, 1.0e-8);
    color = syntopiaToneMap(color);
    color = pow(max(color, vec3(0.0)), vec3(1.0 / GAMMA_VALUE));

    fragColor = vec4(color, 1.0);
}

#define MAX_RAY_STEPS      200
#define REFINE_STEPS       2
#define MAX_ITER_AO        5
#define MAX_FOLD_ITER      20
#define REFLECTIONS_NUMBER 2

const float PI      = 3.1415926535897932384626433832795;
const float MIN_EPS = 1.1920928955078125e-7;

const float FOV = 0.4;
const vec3  UP  = vec3(0.0, 0.0, 1.0);

const float GAMMA_VALUE      = 2.2;
const float GAUSSIAN_WEIGHT  = 1.0;
const float MIN_DIST         = pow(10.0, -4.0);
const float AO_EPS_DETAIL    = pow(10.0, -0.85);
const float FUDGE_FACTOR     = 0.8;
const float MAX_DISTANCE     = 85.53;
const float NORMAL_BACK_STEP = 1.0;

const float CONE_APERTURE_AO = 0.66129;
const float AO_AMBIENT       = 0.88096;

const float SPECULAR     = 0.01176;
const float SPECULAR_EXP = 27.275;
const vec3  REFLECTION   = vec3(0.380392);

const vec4  SPOT_LIGHT     = vec4(1.0, 0.972549, 0.807843, 10.0);
const float LIGHT_SIZE     = 0.0297;
const float LIGHT_FALLOFF  = 0.49438;
const float LIGHT_GLOW_EXP = 0.9524;
const float INV_LIGHT_GLOW_RAD2 = 9.602892544880799;
const vec3  LIGHT_POS      = vec3(-2.9746, 3.038, 0.5064);

const vec3  BASE_COLOR     = vec3(0.380392);
const float ORBIT_STRENGTH = 0.35065;
const vec4  ORBIT_X        = vec4(0.129412, 0.239216, 0.6, 1.0);
const vec4  ORBIT_Y        = vec4(1.0, 0.247059, 0.0196078, 0.99416);
const vec4  ORBIT_Z        = vec4(0.384314, 1.0, 0.423529, 1.0);
const vec4  ORBIT_R        = vec4(0.792157, 0.905882, 1.0, 1.0);
const float COLOR_CYCLES   = 2.70562;

const vec3  BACKGROUND_COLOR    = vec3(0.25098, 0.317647, 0.313725);
const float GRADIENT_BACKGROUND = 0.3;

const vec4  AMBIENT_LIGHT = vec4(1.0, 1.0, 1.0, 0.70588);

const float HF_CONST   = 0.08631;
const float HF_SCATTER = 1.577;
const vec3  FOG_EXT    = vec3(0.06058625391, 0.06938650782, 0.08258684553);
const vec3  FOG_BG     = vec3(0.17038699353, 0.19513598706, 0.23225935599);

const vec3  EYE      = vec3(1.41939, 0.540671, -0.7);
const vec3  TARGET   = vec3(1.4, 1.2, -0.7);
const float APERTURE = 0.00619;
const float INV_FOCAL_PLANE  = 0.6820305413276406;
const float IN_FOCUS_A_WIDTH = 0.35484;
const float FP_TERM          = 0.6728094586723594;
const float ANTI_ALIAS_SCALE = 1.5;
const float DITHER           = 0.52542;

const float AP_ROT = 1.1414627840968115; // 130.802 * PI / 360
const float NGON_D  = 3.077683537175254; // cot(PI / 10)
const float NGON_LH = 0.3090169943749474;

const float INV_SPHERE_RADIUS = 1.0;
const vec3  FOLD_SIZE = vec3(0.90276, 1.01192, 0.988);

vec2 gViewCoord;
vec2 gCoord;
vec4 orbitTrap;
vec2 aoSeed;

float rand1(vec2 p)
{
    return fract(sin(dot(p, vec2(12.9898, 78.233))) * 43758.5453);
}

vec2 rand2(vec2 p)
{
    return vec2(
        fract(sin(dot(p, vec2(12.9898, 78.233))) * 43758.5453),
        fract(cos(dot(p, vec2(4.898, 7.23))) * 23421.631)
    );
}

vec2 uniformDisc(vec2 co)
{
    vec2 r = rand2(co);
    float a = 2.0 * PI * r.x;
    return sqrt(r.y) * vec2(cos(a), sin(a));
}

vec2 nGonDisc(vec2 co)
{
    vec2 r = rand2(co);
    vec2 p = vec2((r.x + r.y) * NGON_D, r.x - r.y) * NGON_LH;

    float a = floor(dot(rand2(11.0 * co + vec2(1.0)), vec2(1.0)) * 10.0) *
              (2.0 * PI / 10.0) + AP_ROT;
    vec2 cs = vec2(cos(a), sin(a));
    return vec2(cs.x * p.x - cs.y * p.y, cs.x * p.y + cs.y * p.x);
}

// -----------------------------------------------------------------------------
// Boyd-Maxwell distance estimator
// -----------------------------------------------------------------------------

float DE(vec3 p)
{
    p.z += FOLD_SIZE.z;
    float deFactor = 1.0;

    for (int i = 0; i < MAX_FOLD_ITER; ++i)
    {
        vec3 oldP = p;

        p = 2.0 * clamp(p, -FOLD_SIZE, FOLD_SIZE) - p;
        float r2 = max(dot(p, p), 1.0e-30);
        orbitTrap = min(orbitTrap, abs(vec4(p, r2)));

        float k = max(INV_SPHERE_RADIUS / r2, 1.0);
        p *= k;
        deFactor *= k;

        if (all(equal(oldP, p))) break;
    }

    return abs(p.z) / deFactor * 0.4;
}

float DElight(vec3 p)
{
    return length(LIGHT_POS - p) - LIGHT_SIZE;
}

vec3 currentPt(vec3 ro, vec3 rd, vec3 offset, float rayPos, float rayFudge)
{
    float d = 1.0 - (rayPos + rayFudge) * INV_FOCAL_PLANE;
    d -= IN_FOCUS_A_WIDTH *
         (2.0 * smoothstep(-1.5 * IN_FOCUS_A_WIDTH,
                            1.5 * IN_FOCUS_A_WIDTH, d) - 1.0);
    return ro + rd * rayPos + offset * d;
}

// -----------------------------------------------------------------------------
// Normal, shadow and AO
// -----------------------------------------------------------------------------

vec3 calcNormal(vec3 p, float normalDistance)
{
    float e = max(normalDistance * 0.5, 1.0e-5);
    vec3 ex = vec3(e, 0.0, 0.0);
    vec3 ey = vec3(0.0, e, 0.0);
    vec3 ez = vec3(0.0, 0.0, e);

    vec3 n = vec3(
        DE(p + ex) - DE(p - ex),
        DE(p + ey) - DE(p - ey),
        DE(p + ez) - DE(p - ez)
    );

    float n2 = dot(n, n);
    return (n2 > 0.0 && n2 < 1.0e30) ? n * inversesqrt(n2) : vec3(0.0);
}

float shadow(vec3 ro, float eps)
{
    float r = max(eps, MIN_EPS);
    vec3 rd = LIGHT_POS - ro;
    float lightDist = length(rd);
    rd /= max(lightDist, MIN_EPS);

    float t = DE(ro) * FUDGE_FACTOR + r;
    float s = 1.0;
    float jitter = DITHER * (rand1(ro.xy * (float(iFrame) + 1.0)) - 0.5);

    for (int i = 0; i < MAX_RAY_STEPS; ++i)
    {
        if (t > lightDist || s < 0.001) break;

        float d = DE(ro + rd * (t + r * jitter)) * FUDGE_FACTOR + r;
        s *= clamp(d / (2.0 * r), 0.0, 1.0);
        t += abs(0.75 * d) + MIN_EPS;
    }

    s = max(0.0, s - 0.001) / 0.999;
    return clamp(1.0 - s, 0.0, 1.0);
}

vec3 ortho(vec3 v)
{
    return abs(v.x) > abs(v.z) ? vec3(-v.y, v.x, 0.0) : vec3(0.0, -v.z, v.y);
}

vec2 rand2AO()
{
    aoSeed += vec2(-1.0, 1.0);
    return rand2(aoSeed);
}

vec3 getAODirection(vec3 dir)
{
    vec3 o1 = normalize(ortho(dir));
    vec3 o2 = cross(dir, o1);
    vec2 r = rand2AO();

    r.x *= 2.0 * PI;
    r.y *= CONE_APERTURE_AO;

    float ry = sqrt(r.y);
    float rz = sqrt(max(0.0, 1.0 - r.y));
    return cos(r.x) * ry * o1 + sin(r.x) * ry * o2 + rz * dir;
}

float ambientOcclusion(vec3 p, vec3 n)
{
    vec3 vdir = getAODirection(n);
    float de = DE(p) / AO_EPS_DETAIL;
    float ao = 0.0;
    float d = 1.0 - DITHER * rand1(p.xy);
    float D = 1.0;

    for (int i = 1; i < MAX_ITER_AO; ++i)
    {
        float prevD = D;
        float denom = max(abs(d * de * dot(vdir, n)), MIN_EPS);

        D = min(prevD, DE(p + d * vdir * de) / denom);
        ao += clamp(1.0 - D, 0.0, 1.0);
        d *= 1.61;
    }

    return ao / float(MAX_ITER_AO - 1);
}

// -----------------------------------------------------------------------------
// Fog, glow, lighting and volumetric scattering
// -----------------------------------------------------------------------------

vec3 fogTransmission(vec3 p0, vec3 p1)
{
    return exp(-FOG_EXT * length(p1 - p0));
}

vec3 pointLightGlow(float glow)
{
    float g = max(glow, 0.0);
    return SPOT_LIGHT.rgb *
        (SPOT_LIGHT.w * exp(-20.0 * g) + exp(-INV_LIGHT_GLOW_RAD2 * pow(g, LIGHT_GLOW_EXP)));
}

vec3 lighting(vec3 n, vec3 materialColor, vec3 pos, vec3 rayDir, float eps, float ao)
{
    vec3 toLight = LIGHT_POS - pos;
    float d2 = max(dot(toLight, toLight), MIN_EPS);
    float falloff = pow(d2, -LIGHT_FALLOFF);
    vec3 lightDir = toLight * inversesqrt(d2);

    float nDotL = max(0.0, dot(n, lightDir));
    vec3 halfVector = normalize(-rayDir + lightDir);
    float hDotN = max(0.0, dot(n, halfVector));

    float f0 = (SPECULAR_EXP - 1.0) / (SPECULAR_EXP + 1.0);
    f0 *= f0;
    float fresnel = f0 + (1.0 - f0) * pow(1.0 + dot(n, rayDir), 5.0);

    float specular = ((SPECULAR_EXP + 2.0) / 8.0) * fresnel * nDotL *
                     pow(hDotN, SPECULAR_EXP + 0.00001) * SPECULAR;

    float sh = shadow(pos + n * eps, eps);
    vec3 fogToLight = fogTransmission(pos, LIGHT_POS);

    vec3 col = fogToLight * SPOT_LIGHT.rgb * SPOT_LIGHT.w * falloff *
               (nDotL + specular) * (1.0 - sh);

    col += AMBIENT_LIGHT.rgb * AMBIENT_LIGHT.w *
           (1.0 - clamp(AO_AMBIENT * ao, 0.0, 1.0));

    return col * materialColor;
}

// Importance-sampled homogeneous fog scattering from the point light.
vec3 volumetricPointLight(vec3 p0, vec3 p1)
{
    vec3 segment = p1 - p0;
    float C = dot(segment, segment);
    if (C < MIN_EPS) return vec3(0.0);

    vec3 q = p0 - LIGHT_POS;
    float A = dot(q, q);
    float B = dot(segment, q);
    float delta = sqrt(max(A * C - B * B, 1.0e-12));

    float x = DITHER * rand1(gViewCoord + vec2(1.6183 + float(iFrame)));

    float atanB  = atan(B / delta);
    float atanBC = atan((B + C) / delta);
    float pdfNorm = (atanBC - atanB) / delta;

    float t = (tan(mix(atanB, atanBC, x)) * delta - B) / C;
    t = clamp(t, 0.00001, 1.0);

    vec3 pt = p0 + t * segment;
    float visibility = 1.0 - shadow(pt, 0.001);

    vec3 sampleValue = fogTransmission(p0, pt) *
                       fogTransmission(pt, LIGHT_POS) *
                       (HF_CONST * visibility * sqrt(C));

    return SPOT_LIGHT.rgb * SPOT_LIGHT.w * pdfNorm * sampleValue * HF_SCATTER;
}

// -----------------------------------------------------------------------------
// Orbit-trap material
// -----------------------------------------------------------------------------

vec3 cycleColor(vec3 c, float s)
{
    return vec3(0.5) + 0.5 * vec3(
        cos(s * COLOR_CYCLES + c.x),
        cos(s * COLOR_CYCLES + c.y),
        cos(s * COLOR_CYCLES + c.z)
    );
}

vec3 orbitMaterial()
{
    orbitTrap.w = sqrt(max(orbitTrap.w, 0.0));

    vec3 orbitColor =
        cycleColor(ORBIT_X.xyz, orbitTrap.x) * ORBIT_X.w * orbitTrap.x +
        cycleColor(ORBIT_Y.xyz, orbitTrap.y) * ORBIT_Y.w * orbitTrap.y +
        cycleColor(ORBIT_Z.xyz, orbitTrap.z) * ORBIT_Z.w * orbitTrap.z +
        cycleColor(ORBIT_R.xyz, orbitTrap.w) * ORBIT_R.w * orbitTrap.w;

    return mix(BASE_COLOR, 3.0 * orbitColor, ORBIT_STRENGTH);
}

// -----------------------------------------------------------------------------
// Ray tracing
// -----------------------------------------------------------------------------

float rayHitEpsilon(float t)
{
    return max(2.0e-5, max(t * MIN_DIST * FUDGE_FACTOR, t * 0.5 * FOV / iResolution.y));
}

void reflectRay(inout vec3 ro, inout vec3 rd, inout vec3 offset,
                inout float rayPos, float rayFudge, vec3 normal, float eps)
{
    vec3 hit = currentPt(ro, rd, offset, rayPos, rayFudge);
    rd = reflect(rd, normal);
    offset = reflect(offset, normal);
    ro = hit + reflect(ro - hit, normal);
    rayPos += eps;
}

vec3 trace(vec3 ro, vec3 rd, vec3 offset, float rayFudge,
           inout float rayPos, out vec3 hitNormal, out float glow, out bool hitLight)
{
    glow = 1000.0;
    orbitTrap = vec4(10000.0);
    hitNormal = vec3(0.0);
    hitLight = false;

    bool hitSomething = false;
    float dist = 0.0;
    float lightDE = 0.0;
    float eps = rayHitEpsilon(rayPos);

    vec3 p = currentPt(ro, rd, offset, rayPos, rayFudge);
    float firstStep = min(DE(p) * FUDGE_FACTOR, DElight(p));
    rayPos += firstStep * (DITHER * rand1(rd.xy) + (1.0 - DITHER)) * rayFudge;

    for (int i = 0; i < MAX_RAY_STEPS; ++i)
    {
        p = currentPt(ro, rd, offset, rayPos, rayFudge);

        lightDE = DElight(p);
        dist = min(lightDE, DE(p) * FUDGE_FACTOR);
        glow = min(lightDE, glow);

        rayPos += dist * rayFudge;
        eps = rayHitEpsilon(rayPos);

        if (dist < eps)
        {
            for (int j = 0; j < REFINE_STEPS; ++j)
            {
                rayPos += (dist - 1.5 * eps) * rayFudge;
                p = currentPt(ro, rd, offset, rayPos, rayFudge);
                lightDE = DElight(p);
                dist = min(lightDE, DE(p) * FUDGE_FACTOR);
                glow = min(lightDE, glow);
            }
            hitSomething = true;
            break;
        }

        if (rayPos > MAX_DISTANCE) break;
    }

    vec3 backColor = BACKGROUND_COLOR * (1.0 - length(gCoord) * GRADIENT_BACKGROUND);

    if (!hitSomething)
    {
        rayPos = MAX_DISTANCE;
        return backColor;
    }

    if (dist == lightDE && dist == glow)
    {
        hitLight = true;
        return SPOT_LIGHT.rgb * SPOT_LIGHT.w / (LIGHT_SIZE + 0.01);
    }

    vec3 hit = currentPt(ro, rd, offset, rayPos, rayFudge);
    hitNormal = calcNormal(hit - NORMAL_BACK_STEP * eps * rd, eps);

    vec3 hitColor = pow(clamp(orbitMaterial(), 0.0, 1.0), vec3(GAMMA_VALUE));
    return lighting(hitNormal, hitColor, hit, rd, eps, ambientOcclusion(hit, hitNormal));
}

vec3 renderScene(vec3 ro, vec3 rd, vec3 offset, float rayFudge)
{
    aoSeed = gViewCoord * (float(iFrame) + 1.0);

    vec3 col = vec3(0.0);
    vec3 reflectionWeight = vec3(1.0);
    float rayPos = 0.0;
    vec3 previousPos = currentPt(ro, rd, offset, rayPos, rayFudge);

    for (int bounce = 0; bounce <= REFLECTIONS_NUMBER; ++bounce)
    {
        vec3 hitNormal;
        float glow;
        bool hitLight;
        vec3 bounceColor = trace(ro, rd, offset, rayFudge, rayPos, hitNormal, glow, hitLight);
        vec3 currentPos = currentPt(ro, rd, offset, rayPos, rayFudge);

        vec3 fog = fogTransmission(previousPos, currentPos);
        bounceColor = mix(FOG_BG, bounceColor, fog);
        bounceColor += pointLightGlow(glow);
        bounceColor += volumetricPointLight(previousPos, currentPos);

        col += bounceColor * reflectionWeight;
        reflectionWeight *= REFLECTION * fog;

        if (all(equal(hitNormal, vec3(0.0))) ||
            dot(reflectionWeight, reflectionWeight) < 0.00001 ||
            hitLight || rayPos >= MAX_DISTANCE)
        {
            break;
        }

        reflectRay(ro, rd, offset, rayPos, rayFudge, hitNormal, MIN_DIST);
        previousPos = currentPos;
    }

    return max(col, vec3(0.0));
}

void makeCameraRay(vec2 fragCoord, out vec3 ro, out vec3 rd,
                   out vec3 offset, out float rayFudge, out vec2 disc)
{
    vec2 uv = fragCoord / iResolution.xy;

    gViewCoord = uv * 2.0 - 1.0;
    gCoord = (2.0 * fragCoord - iResolution.xy) / iResolution.y * FOV;

    vec3 camDir = normalize(TARGET - EYE);
    vec3 up = normalize(UP - dot(camDir, UP) * camDir);
    vec3 right = normalize(cross(camDir, up));

    float frame = float(iFrame) + 1.0;
    vec2 apertureSample = APERTURE * nGonDisc(gViewCoord * frame);
    disc = uniformDisc(gCoord * frame);

    vec2 jitteredCoord = gCoord + ANTI_ALIAS_SCALE * (2.0 / iResolution.xy) * FOV * disc;

    offset = apertureSample.x * right + apertureSample.y * up;
    vec3 rayDir = camDir + jitteredCoord.x * right + jitteredCoord.y * up;

    ro = EYE;
    rd = normalize(rayDir);
    rayFudge = 1.0 / max(1.0, length(rayDir + offset * FP_TERM));
}

void mainImage(out vec4 fragColor, in vec2 fragCoord)
{
    vec3 ro, rd, offset;
    float rayFudge;
    vec2 disc;
    makeCameraRay(fragCoord, ro, rd, offset, rayFudge, disc);

    vec3 sampleColor = renderScene(ro, rd, offset, rayFudge);
    float w = exp(-dot(disc, disc) / GAUSSIAN_WEIGHT) - exp(-1.0 / GAUSSIAN_WEIGHT);

    vec4 previous = (iFrame > 0) ? texelFetch(iChannel0, ivec2(fragCoord), 0) : vec4(0.0);
    fragColor = previous + vec4(sampleColor * w, w);
}

/*
    Coxeter hyperbolic honeycomb: Fragmentarium postprocess -> Shadertoy Image pass

    Shadertoy setup:
      Image / iChannel0 = Buffer A

    Buffer A is expected to store:
      rgb = weighted HDR color sum
      a   = accumulated sample weight

    The constants below reproduce the honeycomb preset supplied with the scene shader.
*/

// -----------------------------------------------------------------------------
// Preset values
// -----------------------------------------------------------------------------

const float GAMMA_VALUE     = 2.2;
const int   TONE_MAPPING    = 5;
const float EXPOSURE        = 1.0;
const float BRIGHTNESS      = 1.0;
const float CONTRAST        = 1.0;
const float SATURATION      = 1.0;

const bool  ENABLE_BLOOM    = false;
const float BLOOM_INTENSITY = 0.25;
const float BLOOM_POW       = 2.0;
const int   BLOOM_TAPS      = 4;

// Lens flare was commented out in the supplied Fragmentarium shader.
// It is included here as an optional Shadertoy-compatible path.
const bool  ENABLE_LENS_FLARE = false;
const float FLARE_INTENSITY   = 0.25;
const int   FLARE_SAMPLES     = 8;
const float FLARE_DISPERSAL   = 0.25;
const float FLARE_HALO_WIDTH  = 0.5;
const float FLARE_DISTORTION  = 1.0;

const vec3 RGB_TO_LUMA = vec3(0.2125, 0.7154, 0.0721);

// -----------------------------------------------------------------------------
// Accumulation-buffer access
// -----------------------------------------------------------------------------

vec4 sampleAccumulation(vec2 uv)
{
    return texture(iChannel0, uv);
}

vec3 resolveAccumulation(vec4 value)
{
    return value.rgb / max(value.a, 1.0e-8);
}

vec3 sampleResolved(vec2 uv)
{
    return resolveAccumulation(sampleAccumulation(uv));
}

// -----------------------------------------------------------------------------
// RGB <-> HSV
// Kept from the original postprocessor for compatibility and future edits.
// -----------------------------------------------------------------------------

vec3 rgb2hsv(vec3 c)
{
    vec4 K = vec4(0.0, -1.0 / 3.0, 2.0 / 3.0, -1.0);
    vec4 p = mix(vec4(c.bg, K.wz), vec4(c.gb, K.xy), step(c.b, c.g));
    vec4 q = mix(vec4(p.xyw, c.r), vec4(c.r, p.yzx), step(p.x, c.r));

    float d = q.x - min(q.w, q.y);
    float e = 1.0e-10;
    return vec3(
        abs(q.z + (q.w - q.y) / (6.0 * d + e)),
        d / (q.x + e),
        q.x
    );
}

vec3 hsv2rgb(vec3 c)
{
    vec4 K = vec4(1.0, 2.0 / 3.0, 1.0 / 3.0, 3.0);
    vec3 p = abs(fract(c.xxx + K.xyz) * 6.0 - K.www);
    return c.z * mix(K.xxx, clamp(p - K.xxx, 0.0, 1.0), c.y);
}

// -----------------------------------------------------------------------------
// Brightness / saturation / contrast
// -----------------------------------------------------------------------------

vec3 contrastSaturationBrightness(
    vec3 color,
    float brightness,
    float saturation,
    float contrast
)
{
    const vec3 LUMA = vec3(0.2125, 0.7154, 0.0721);

    vec3 brightColor = color * brightness;
    float intensityValue = dot(brightColor, LUMA);
    vec3 intensity = vec3(intensityValue);
    vec3 saturatedColor = mix(intensity, brightColor, saturation);
    vec3 contrastedColor = mix(vec3(0.5), saturatedColor, contrast);

    return clamp(contrastedColor, 0.0, 1.0);
}

// -----------------------------------------------------------------------------
// Tone mapping functions
// -----------------------------------------------------------------------------

float syntopiaSigmoid(float t)
{
    float k = 1.0 - 1.0 / (1.0 + exp(-0.5 * CONTRAST * 5.0));
    t -= 0.5;

    float x = 1.0 / (1.0 + exp(-t * CONTRAST * 5.0)) - k;
    return x / (1.0 - 2.0 * k);
}

vec3 syntopiaSigmoid(vec3 value)
{
    return vec3(
        syntopiaSigmoid(value.r),
        syntopiaSigmoid(value.g),
        syntopiaSigmoid(value.b)
    );
}

// Lottes 2016, "Advanced Techniques and Optimization of HDR Color Pipelines"
vec3 lottesToneMap(vec3 x)
{
    const vec3 a      = vec3(1.6);
    const vec3 d      = vec3(0.977);
    const vec3 hdrMax = vec3(8.0);
    const vec3 midIn  = vec3(0.18);
    const vec3 midOut = vec3(0.267);

    const vec3 b =
        (-pow(midIn, a) + pow(hdrMax, a) * midOut) /
        ((pow(hdrMax, a * d) - pow(midIn, a * d)) * midOut);

    const vec3 c =
        (pow(hdrMax, a * d) * pow(midIn, a)
        - pow(hdrMax, a) * pow(midIn, a * d) * midOut) /
        ((pow(hdrMax, a * d) - pow(midIn, a * d)) * midOut);

    return pow(x, a) / (pow(x, a * d) * b + c);
}

// Uchimura 2017, "HDR theory and practice"
vec3 uchimuraToneMap(
    vec3 x,
    float maximumDisplayBrightness,
    float contrast,
    float linearStart,
    float linearLength,
    float black,
    float pedestal
)
{
    float P = maximumDisplayBrightness;
    float a = contrast;
    float m = linearStart;
    float l = linearLength;
    float c = black;
    float b = pedestal;

    float l0 = ((P - m) * l) / a;
    float L0 = m - m / a;
    float L1 = m + (1.0 - m) / a;
    float S0 = m + l0;
    float S1 = m + a * l0;
    float C2 = (a * P) / (P - S1);
    float CP = -C2 / P;

    vec3 w0 = vec3(1.0) - smoothstep(vec3(0.0), vec3(m), x);
    vec3 w2 = step(vec3(m + l0), x);
    vec3 w1 = vec3(1.0) - w0 - w2;

    vec3 T = vec3(m) * pow(x / m, vec3(c)) + vec3(b);
    vec3 S = vec3(P) - (P - S1) * exp(CP * (x - S0));
    vec3 L = vec3(m) + a * (x - m);

    // L0 and L1 are retained to mirror the published formulation.
    // They are not needed by the final piecewise expression.
    L0 += 0.0;
    L1 += 0.0;

    return T * w0 + L * w1 + S * w2;
}

vec3 uchimuraToneMap(vec3 x)
{
    const float P = 1.0;
    const float a = 1.0;
    const float m = 0.22;
    const float l = 0.4;
    const float c = 1.33;
    const float b = 0.0;

    return uchimuraToneMap(x, P, a, m, l, c, b);
}

vec3 uncharted2Partial(vec3 x)
{
    const float A = 0.15;
    const float B = 0.50;
    const float C = 0.10;
    const float D = 0.20;
    const float E = 0.02;
    const float F = 0.30;

    return ((x * (A * x + C * B) + D * E) /
           (x * (A * x + B) + D * F)) - E / F;
}

vec3 uncharted2ToneMap(vec3 color)
{
    const float WHITE_POINT = 11.2;
    const float EXPOSURE_BIAS = 2.0;

    vec3 current = uncharted2Partial(EXPOSURE_BIAS * color);
    vec3 whiteScale = vec3(1.0) / uncharted2Partial(vec3(WHITE_POINT));
    return current * whiteScale;
}

vec3 applyToneMapping(vec3 color)
{
    vec3 c = color;

    if (TONE_MAPPING == 1)
    {
        // Linear
        c *= EXPOSURE;
        c = contrastSaturationBrightness(c, BRIGHTNESS, SATURATION, CONTRAST);
    }
    else if (TONE_MAPPING == 2)
    {
        // Exponential exposure
        c = vec3(1.0) - exp(-c * EXPOSURE);
        c = contrastSaturationBrightness(c, BRIGHTNESS, SATURATION, CONTRAST);
    }
    else if (TONE_MAPPING == 3)
    {
        // Filmic curve used by the original Fragmentarium shader
        c *= EXPOSURE;
        vec3 x = max(vec3(0.0), c - vec3(0.004));
        c = (x * (6.2 * x + 0.5)) /
            (x * (6.2 * x + 1.7) + 0.06);

        // This curve includes a 2.2 encoding step in the original code.
        c = pow(max(c, vec3(0.0)), vec3(2.2));
        c = contrastSaturationBrightness(c, BRIGHTNESS, SATURATION, CONTRAST);
    }
    else if (TONE_MAPPING == 4)
    {
        // Reinhard (called "Reinhart" in the source comments)
        c *= EXPOSURE;
        c = c / (vec3(1.0) + c);
        c = contrastSaturationBrightness(c, BRIGHTNESS, SATURATION, CONTRAST);
    }
    else if (TONE_MAPPING == 5)
    {
        // Exact Fragmentarium / Syntopia sigmoid path.
        // As in the original code, Saturation is not applied in this mode.
        c = syntopiaSigmoid(c * EXPOSURE + vec3(BRIGHTNESS - 1.0));
    }
    else if (TONE_MAPPING == 6)
    {
        c *= EXPOSURE;
        c = lottesToneMap(max(c, vec3(0.0)));
        c = contrastSaturationBrightness(c, BRIGHTNESS, SATURATION, CONTRAST);
    }
    else if (TONE_MAPPING == 7)
    {
        c *= EXPOSURE;
        c = uchimuraToneMap(max(c, vec3(0.0)));
        c = contrastSaturationBrightness(c, BRIGHTNESS, SATURATION, CONTRAST);
    }
    else if (TONE_MAPPING == 8)
    {
        c *= EXPOSURE;
        c = uncharted2ToneMap(max(c, vec3(0.0)));
        c = contrastSaturationBrightness(c, BRIGHTNESS, SATURATION, CONTRAST);
    }
    else if (TONE_MAPPING == 9)
    {
        // 3Dickulus luminance map
        c *= EXPOSURE;
        c *= dot(c, RGB_TO_LUMA);
        c = contrastSaturationBrightness(c, BRIGHTNESS, SATURATION, CONTRAST);
    }

    return c;
}

// -----------------------------------------------------------------------------
// Bloom
// -----------------------------------------------------------------------------

vec3 bloomColor(vec2 uv)
{
    vec2 texelSize = 1.0 / iResolution.xy;
    vec4 sum = vec4(0.0);

    // BLOOM_TAPS is a compile-time constant, which keeps this loop compatible
    // with Shadertoy's WebGL compiler.
    for (int x = -BLOOM_TAPS; x <= BLOOM_TAPS; ++x)
    {
        float fx = float(x) / max(float(BLOOM_TAPS), 1.0);
        float wx = 1.0 - fx * fx;
        wx = wx * wx * wx;

        for (int y = -BLOOM_TAPS; y <= BLOOM_TAPS; ++y)
        {
            float fy = float(y) / max(float(BLOOM_TAPS), 1.0);
            float wy = 1.0 - fy * fy;
            wy = wy * wy * wy;

            vec2 offset = vec2(float(x), float(y)) * texelSize;
            sum += sampleAccumulation(uv + offset) * (wx * wy);
        }
    }

    // Dividing the raw accumulated sum by its alpha reproduces the original
    // b = bloom(...); b /= b.w behavior. The omitted sample-count factor
    // cancels between numerator and denominator.
    return resolveAccumulation(sum);
}

// -----------------------------------------------------------------------------
// Optional lens flare conversion
// -----------------------------------------------------------------------------

vec4 textureDistorted(
    vec2 uv,
    vec2 direction,
    vec4 distortion
)
{
    return vec4(
        sampleAccumulation(uv + direction * distortion.r).r,
        sampleAccumulation(uv + direction * distortion.g).g,
        sampleAccumulation(uv + direction * distortion.b).b,
        sampleAccumulation(uv + direction * distortion.a).a
    );
}

vec4 lensFlare(vec2 uv)
{
    vec2 texelSize = 1.0 / iResolution.xy;
    vec2 ghostVector = (vec2(0.5) - uv) * FLARE_DISPERSAL;

    float ghostLength = length(ghostVector);
    vec2 ghostDirection = ghostLength > 1.0e-8
        ? ghostVector / ghostLength
        : vec2(0.0);

    vec2 haloVector = ghostDirection * FLARE_HALO_WIDTH;
    vec4 distortion = vec4(
        -texelSize.x * FLARE_DISTORTION,
         0.0,
         texelSize.x * FLARE_DISTORTION,
         0.0
    );

    vec4 result = vec4(0.0);

    for (int i = 0; i < FLARE_SAMPLES; ++i)
    {
        vec2 offset = fract(uv + ghostVector * float(i));
        float radial = length(vec2(0.5) - offset) / length(vec2(0.5));
        float weight = pow(max(1.0 - radial, 0.0), 10.0);
        result += textureDistorted(offset, ghostDirection, distortion) * weight;
    }

    vec2 haloUV = fract(uv + haloVector);
    float haloRadial = length(vec2(0.5) - haloUV) / length(vec2(0.5));
    float haloWeight = pow(max(1.0 - haloRadial, 0.0), 10.0);
    result += textureDistorted(haloUV, ghostDirection, distortion) * haloWeight;

    return result;
}

// -----------------------------------------------------------------------------
// Shadertoy entry point
// -----------------------------------------------------------------------------

void mainImage(out vec4 fragColor, in vec2 fragCoord)
{
    vec2 uv = fragCoord / iResolution.xy;

    vec4 accumulated = sampleAccumulation(uv);
    vec3 color = resolveAccumulation(accumulated);

    if (ENABLE_BLOOM)
    {
        vec3 blurred = bloomColor(uv);
        color += BLOOM_INTENSITY * pow(
            max(blurred, vec3(0.0)),
            vec3(BLOOM_POW)
        );
    }

    if (ENABLE_LENS_FLARE)
    {
        vec4 flare = lensFlare(uv);
        color += FLARE_INTENSITY * resolveAccumulation(flare);
    }

    color = applyToneMapping(color);

    // Protect pow() from negative values generated by unusual parameter sets.
    color = pow(max(color, vec3(0.0)), vec3(1.0 / GAMMA_VALUE));

    fragColor = vec4(color, 1.0);
}

/*
    Coxeter hyperbolic honeycomb
    Fragmentarium -> Shadertoy Buffer A port

    Shadertoy setup:
      Buffer A / iChannel0 = Buffer A (feedback)
      Image    / iChannel0 = Buffer A

    Buffer A stores the progressively accumulated HDR weighted sum in RGB
    and the accumulated Gaussian sample weight in A.
*/

#define MAX_RAY_STEPS       1200
#define REFINE_STEPS        3
#define MAX_AO_ITER         5
#define MAX_FOLD4D_ITER     800
#define MAX_FOLD3D_ITER     300
#define REFLECTIONS_NUMBER  1
#define HF_FOG_ITER         4

const float PI      = 3.1415926535897932384626433832795;
const float TWO_PI  = 6.283185307179586476925286766559;
const float MIN_EPS = 1.1920928955078125e-7;

// -----------------------------------------------------------------------------
// Fixed values from the supplied Fragmentarium preset
// -----------------------------------------------------------------------------

// Camera
const bool  AUTO_FOCUS          = false;
const float FOV                 = 0.817734;
const vec3  EYE                 = vec3(0.816800721, 0.052520444, 1.50772028);
const vec3  TARGET              = vec3(0.342595542, 0.036920363, 0.627444138);
const vec3  UP                  = vec3(0.0, 0.0, 1.0);
const bool  EQUIRECTANGULAR     = false;
const float FOCAL_PLANE         = 1.0;
const float APERTURE            = 0.0;
const float IN_FOCUS_A_WIDTH    = 0.0;
const int   APERTURE_NBR_SIDES  = 5;
const float APERTURE_ROT        = 0.0;
const bool  AP_STAR_SHAPED      = false;

// Accumulation and ray marcher
const float GAMMA_VALUE         = 2.2;
const float GAUSSIAN_WEIGHT     = 1.0;
const float ANTI_ALIAS_SCALE    = 2.0;
const float DETAIL              = -4.8;
const float FUDGE_FACTOR        = 0.5;
const float MAX_DISTANCE        = 20.0;
const float DITHER              = 0.55852;
const float NORMAL_BACK_STEP    = 1.0;

// AO
const float DETAIL_AO           = -1.55554;
const float CONE_APERTURE_AO    = 1.0;
const float FUDGE_AO            = 1.0;
const float AO_AMBIENT          = 0.8;
const float AO_CAMLIGHT         = 0.0;
const float AO_POINTLIGHT       = 0.0;
const float AO_CORRECT          = 0.0;

// Lighting
const float SPECULAR            = 0.5598;
const float SPECULAR_EXP        = 271.35;
const vec4  CAM_LIGHT           = vec4(0.878431, 0.921569, 0.956863, 0.22);
const vec4  AMBIENT_LIGHT       = vec4(1.0, 1.0, 1.0, 0.44219068);
const vec3  REFLECTION          = vec3(0.243137255);
const bool  SPOT_GLOW           = false;
const vec4  SPOT_LIGHT          = vec4(0.843137255, 0.91372549, 1.0, 5.1663406);
const vec3  LIGHT_POS           = vec3(-0.1249998, -0.4663212, 2.4352332);
const float LIGHT_SIZE          = 0.02806;
const float LIGHT_FALLOFF       = 1.19474;
const float LIGHT_GLOW_RAD      = 0.0;
const float LIGHT_GLOW_EXP      = 1.0;
const float HARD_SHADOW         = 1.0;
const float SHADOW_SOFT         = 0.0;

// Material and background
const vec3  BASE_COLOR          = vec3(0.67451);
const float ORBIT_STRENGTH      = 0.72011;
const vec3  BACKGROUND_COLOR    = vec3(0.0);
const float GRADIENT_BACKGROUND = 0.0;

// External Euclidean floor from the generic renderer
const bool  ENABLE_FLOOR        = true;
const vec3  FLOOR_NORMAL_RAW    = vec3(0.0, 0.0, 1.0);
const float FLOOR_HEIGHT        = -1.0;
const vec3  FLOOR_COLOR         = vec3(0.0980392157, 0.380392157, 0.529411765);

// Height fog / volumetric point-light scattering
const float HF_FALLOFF          = 0.85936;
const float HF_CONST            = 0.00775;
const float HF_INTENSITY        = 0.0;
const vec3  HF_DIR              = vec3(0.0, 0.0, 1.0);
const float HF_OFFSET           = 0.0;
const vec4  HF_COLOR            = vec4(1.0, 0.537255, 0.305882, 1.0);
const float HF_SCATTER          = 2.174;
const vec3  HF_ANISOTROPY       = vec3(0.12549, 0.266667, 0.215686);
const bool  HF_CAST_SHADOW      = true;

// Honeycomb colors
const vec3 SEG_A_COLOR          = vec3(0.709803922, 0.631372549, 0.278431373);
const vec3 SEG_B_COLOR          = vec3(0.666666667, 0.133333333, 0.0392156863);
const vec3 SEG_C_COLOR          = vec3(0.384313725, 1.0, 0.537254902);
const vec3 SEG_D_COLOR          = vec3(0.149019608, 0.596078431, 0.8);
const vec3 VERTICES_COLOR       = vec3(0.709803922, 0.647058824, 0.258823529);
const vec3 FLOOR_CHECKER_COLOR1 = vec3(0.0);
const vec3 FLOOR_CHECKER_COLOR2 = vec3(0.0);
const vec3 FLOOR_LINE_COLOR     = vec3(0.0);

// Honeycomb settings
const bool  DO_UPPER_HALF_SPACE = false;
const bool  DRAW_FLOOR_PATTERN  = false;
const int   AB                  = 4;
const int   AC                  = 2;
const int   AD                  = 2;
const int   BC                  = 2;
const int   BD                  = 4;
const int   CD                  = 5;
const vec4  ACTIVE_MIRRORS      = vec4(0.0, 1.0, 0.0, 0.0);
const float VERTEX_SIZE         = 0.136684305;
const float EDGE_SIZE           = 0.039032816;
const float FLOOR_LINE_THICKNESS= 0.01;
const float C_SPHERE_RADIUS     = 0.99992;

// RotA is present in the source shader but absent from the supplied preset.
// Fragmentarium therefore uses its default value; zero is the neutral rotation.
const float ROT_A               = 0.0;

// -----------------------------------------------------------------------------
// Per-fragment state replacing Fragmentarium varyings and uniforms
// -----------------------------------------------------------------------------

vec2 gViewCoord;
vec2 gCoord;
vec2 gPixelScale;
vec3 gFrom;
vec3 gDir;
vec3 gUpOrtho;
vec3 gRight;

vec2 gAOSeed;
float gMinDist;
float gAOEps;
bool gLightHit;

mat4 gMirrors;
mat4 gMirrors3D;
vec4 gInitialVertex;
float gCoshVertexRadius;
float gSinhVertexRadius;
float gCoshSegmentRadius;
float gSinhSegmentRadius;

const vec3 FLOOR_NORMAL = vec3(0.0, 0.0, 1.0);

// -----------------------------------------------------------------------------
// Random helpers
// -----------------------------------------------------------------------------

float rand1(float v)
{
    return fract(sin(v * 78.233) * 43758.5453);
}

float rand1(vec2 p)
{
    return fract(sin(dot(p, vec2(12.9898, 78.233))) * 43758.5453);
}

vec2 rand2(vec2 p)
{
    return vec2(
        fract(sin(dot(p, vec2(12.9898, 78.233))) * 43758.5453),
        fract(cos(dot(p, vec2(4.898, 7.23))) * 23421.631)
    );
}

vec2 uniformDisc(vec2 co)
{
    vec2 r = rand2(co);
    return sqrt(r.y) * vec2(cos(r.x * TWO_PI), sin(r.x * TWO_PI));
}

vec2 nGonDisc(vec2 co)
{
    vec2 r = rand2(co);
    float sides = float(APERTURE_NBR_SIDES);
    float d = 1.0 / tan(PI / sides);
    float lh = inversesqrt(1.0 + d * d);

    vec2 p = vec2(r.x + r.y, r.x - r.y);
    if (!AP_STAR_SHAPED) p.x = 1.0 - abs(p.x - 1.0);
    p.x *= d;
    p *= lh;

    float a = dot(rand2(11.0 * co + vec2(1.0)), vec2(1.0));
    a = floor(a * sides) * TWO_PI / sides + APERTURE_ROT * PI / 360.0;
    vec2 cs = vec2(cos(a), sin(a));
    return vec2(cs.x * p.x - cs.y * p.y,
                cs.x * p.y + cs.y * p.x);
}

// -----------------------------------------------------------------------------
// Coxeter honeycomb geometry
// -----------------------------------------------------------------------------

float hdot(vec4 p, vec4 q)
{
    return dot(p.xyz, q.xyz) - p.w * q.w;
}

vec4 hnormalize(vec4 p)
{
    return p / sqrt(max(-hdot(p, p), 1.0e-30));
}

float tryReflect4D(inout vec4 p, vec4 n)
{
    float k = min(0.0, hdot(p, n));
    p -= 2.0 * k * n;
    return k;
}

bool tryReflectPlane3D(inout vec3 p, vec3 n, inout int count)
{
    float k = dot(p, n);
    if (k >= 0.0) return true;
    p -= 2.0 * k * n;
    count += 1;
    return false;
}

bool tryReflectSphere3D(inout vec3 p, vec4 sphere, inout int count)
{
    vec3 center = sphere.xyz;
    float radius = sphere.w;
    vec3 q = p - center;
    float d2 = dot(q, q);
    if (d2 <= 1.0e-30) return true;

    float k = radius * radius / d2;
    if (k < 1.0) return true;

    p = k * q + center;
    count += 1;
    return false;
}

void rotateXY(inout vec3 p)
{
    float ca = cos(TWO_PI * ROT_A);
    float sa = -sin(TWO_PI * ROT_A);
    p.xy = mat2(ca, -sa, sa, ca) * p.xy;
}

void initHoneycomb()
{
    float c01 = -cos(PI / float(AB));
    float c02 = -cos(PI / float(AC));
    float c03 = -cos(PI / float(AD));
    float c12 = -cos(PI / float(BC));
    float c13 = -cos(PI / float(BD));
    float c23 = -cos(PI / float(CD));

    vec4 A = vec4(1.0, 0.0, 0.0, 0.0);
    vec4 B = vec4(c01, sqrt(max(1.0 - c01 * c01, 0.0)), 0.0, 0.0);

    vec4 C = vec4(c02, 0.0, 0.0, 0.0);
    C.y = (c12 - C.x * B.x) / B.y;
    C.z = sqrt(abs(1.0 - dot(C.xy, C.xy)));

    vec4 D = vec4(c03, 0.0, 0.0, 0.0);
    D.y = (c13 - D.x * B.x) / B.y;
    D.z = (c23 - dot(D.xy, C.xy)) / C.z;
    D.w = -sqrt(abs(dot(D.xyz, D.xyz) - 1.0));

    vec4 H = vec4(1.0, 1.0, 1.0, -1.0);
    mat4 inverseMirrorMatrix = inverse(mat4(H * A, H * B, H * C, H * D));
    gInitialVertex = hnormalize(ACTIVE_MIRRORS * inverseMirrorMatrix);
    gMirrors = mat4(A, B, C, D);

    gCoshVertexRadius  = cosh(VERTEX_SIZE);
    gSinhVertexRadius  = sinh(VERTEX_SIZE);
    gCoshSegmentRadius = cosh(EDGE_SIZE);
    gSinhSegmentRadius = sinh(EDGE_SIZE);

    vec3 center = -vec3(c03, c13, c23) * inverse(mat3(A.xyz, B.xyz, C.xyz));
    vec4 inversionSphere = vec4(center, 1.0);
    inversionSphere /= sqrt(max(dot(center, center) - 1.0, 1.0e-30));
    gMirrors3D = mat4(A, B, C, inversionSphere);
}

bool fold3D(inout vec3 p, inout int count)
{
    for (int i = 0; i < MAX_FOLD3D_ITER; ++i)
    {
        bool inA = tryReflectPlane3D(p, gMirrors3D[0].xyz, count);
        bool inB = tryReflectPlane3D(p, gMirrors3D[1].xyz, count);
        bool inC = tryReflectPlane3D(p, gMirrors3D[2].xyz, count);
        bool inD = tryReflectSphere3D(p, gMirrors3D[3], count);
        if (inA && inB && inC && inD) return true;
    }
    return false;
}

bool fold4D(inout vec4 p)
{
    for (int i = 0; i < MAX_FOLD4D_ITER; ++i)
    {
        float k = 0.0;
        p.x = abs(p.x);
        k += tryReflect4D(p, gMirrors[1]);
        k += tryReflect4D(p, gMirrors[2]);
        k += tryReflect4D(p, gMirrors[3]);
        if (k == 0.0) return true;
    }
    return false;
}

float knightyDistanceConversion(float ca, float sa, float r)
{
    float x = 1.0 + r * r;
    float y = 2.0 - x;
    float denominator = x * ca + 2.0 * r * sa + y;
    if (abs(denominator) < 1.0e-30)
        denominator = (denominator < 0.0 ? -1.0 : 1.0) * 1.0e-30;
    return (2.0 * r * ca + x * sa) / denominator - r;
}

float vertexDistance(vec4 p, float r)
{
    float ca = -hdot(p, gInitialVertex);
    float radicand = -hdot(p - gInitialVertex, p - gInitialVertex) *
                      hdot(p + gInitialVertex, p + gInitialVertex);
    float sa = 0.5 * sqrt(max(radicand, 0.0));

    return knightyDistanceConversion(
        ca * gCoshVertexRadius - sa * gSinhVertexRadius,
        sa * gCoshVertexRadius - ca * gSinhVertexRadius,
        r
    );
}

float segmentDistance(vec4 p, vec4 n, float r)
{
    float pn = hdot(p, n);
    float pv = hdot(p, gInitialVertex);
    float nv = hdot(n, gInitialVertex);
    float determinant = -1.0 - nv * nv;

    float a = (-nv * pv - pn) / determinant;
    float b = (pv - pn * nv) / determinant;
    vec4 projected = hnormalize(min(a, 0.0) * n + b * gInitialVertex);

    float ca = -hdot(p, projected);
    float radicand = -hdot(p - projected, p - projected) *
                      hdot(p + projected, p + projected);
    float sa = 0.5 * sqrt(max(radicand, 0.0));

    return knightyDistanceConversion(
        ca * gCoshSegmentRadius - sa * gSinhSegmentRadius,
        sa * gCoshSegmentRadius - ca * gSinhSegmentRadius,
        r
    );
}

float segmentDistances(vec4 p, float r)
{
    float dA = segmentDistance(p, gMirrors[0], r);
    float dB = segmentDistance(p, gMirrors[1], r);
    float dC = segmentDistance(p, gMirrors[2], r);
    float dD = segmentDistance(p, gMirrors[3], r);
    return min(min(dA, dB), min(dC, dD));
}

vec4 ballLift(vec3 p)
{
    float r2 = dot(p, p);
    float denominator = 1.0 - r2;
    if (abs(denominator) < 1.0e-9)
        denominator = (denominator < 0.0 ? -1.0 : 1.0) * 1.0e-9;
    return vec4(2.0 * p, 1.0 + r2) / denominator;
}

float DE(vec3 p)
{
    float floorHeightDistance = p.z - 1.0e-3;
    rotateXY(p);

    if (DO_UPPER_HALF_SPACE)
    {
        p.z += 1.0;
        float p2 = max(dot(p, p), 1.0e-30);
        p *= 2.0 / p2;
        p.z -= 1.0;
    }

    float r = length(p);
    vec4 q = ballLift(p);
    fold4D(q);

    float geometryDistance = min(vertexDistance(q, r), segmentDistances(q, r));
    if (DO_UPPER_HALF_SPACE)
        return min(floorHeightDistance, geometryDistance);

    return max(r - C_SPHERE_RADIUS, geometryDistance);
}

float mirrorDistance3D(vec3 p)
{
    float dA = abs(dot(p, gMirrors3D[0].xyz));
    float dB = abs(dot(p, gMirrors3D[1].xyz));
    float dC = abs(dot(p, gMirrors3D[2].xyz));
    float dD = abs(length(p - gMirrors3D[3].xyz) - gMirrors3D[3].w);
    return min(dA, min(dB, min(dC, dD)));
}

vec3 planeToSphere(vec2 p)
{
    float r2 = dot(p, p);
    return vec3(2.0 * p, r2 - 1.0) / (1.0 + r2);
}

vec3 floorPatternColor(bool found, int count)
{
    if (found)
        return (count % 2 == 0) ? FLOOR_CHECKER_COLOR1 : FLOOR_CHECKER_COLOR2;
    return FLOOR_LINE_COLOR;
}

vec3 honeycombBaseColor(vec3 pos)
{
    vec3 originalPos = pos;
    float upperFloorDistance = pos.z - 1.0e-3;

    // RotA is zero in this preset. Keep color evaluation aligned with DE if edited.
    rotateXY(pos);

    if (DO_UPPER_HALF_SPACE)
    {
        pos.z += 1.0;
        float p2 = max(dot(pos, pos), 1.0e-30);
        pos *= 2.0 / p2;
        pos.z -= 1.0;
    }

    float r = length(pos);
    vec4 q = ballLift(pos);
    bool found = fold4D(q);
    if (!found) return BACKGROUND_COLOR;

    float dA = segmentDistance(q, gMirrors[0], r);
    float dB = segmentDistance(q, gMirrors[1], r);
    float dC = segmentDistance(q, gMirrors[2], r);
    float dD = segmentDistance(q, gMirrors[3], r);
    float dV = vertexDistance(q, r);

    float d = min(min(min(dA, dB), min(dC, dD)), dV);
    if (DO_UPPER_HALF_SPACE) d = min(d, upperFloorDistance);

    vec3 color = SEG_A_COLOR;
    if (d == dB) color = SEG_B_COLOR;
    if (d == dC) color = SEG_C_COLOR;
    if (d == dD) color = SEG_D_COLOR;
    if (d == dV) color = VERTICES_COLOR;

    if (DO_UPPER_HALF_SPACE && d == upperFloorDistance)
    {
        if (DRAW_FLOOR_PATTERN)
        {
            int count = 0;
            vec3 spherePoint = planeToSphere(originalPos.xy);
            bool patternFound = fold3D(spherePoint, count);
            color = floorPatternColor(patternFound, count);
            float edgeDistance = mirrorDistance3D(spherePoint);
            color = mix(
                color,
                FLOOR_LINE_COLOR,
                (1.0 - smoothstep(0.0, 0.005, edgeDistance)) * FLOOR_LINE_THICKNESS
            );
        }
        else
        {
            color = BACKGROUND_COLOR;
        }
    }

    return color;
}

// -----------------------------------------------------------------------------
// Scene distance with the generic Euclidean floor
// -----------------------------------------------------------------------------

float externalFloorDistance(vec3 p)
{
    return abs(dot(FLOOR_NORMAL, p) - FLOOR_HEIGHT);
}

float sceneDistance(vec3 p)
{
    float d = DE(p);
    return ENABLE_FLOOR ? min(d, externalFloorDistance(p)) : d;
}

bool isExternalFloorClosest(vec3 p)
{
    return ENABLE_FLOOR && externalFloorDistance(p) <= DE(p);
}

float lightDistance(vec3 p)
{
    return length(LIGHT_POS - p) - LIGHT_SIZE;
}

// -----------------------------------------------------------------------------
// Thin-lens ray representation
// -----------------------------------------------------------------------------

struct SRay
{
    vec3 Origin;
    vec3 Direction;
    vec3 Offset;
    float Pos;
    float fudge;
    float iFP;
};

vec3 rayCurrentPoint(SRay ray)
{
    float t = ray.Pos;
    return ray.Origin + ray.Direction * t + ray.Offset *
        (1.0 - t * ray.iFP +
         clamp(t * ray.iFP - 1.0, -IN_FOCUS_A_WIDTH, IN_FOCUS_A_WIDTH));
}

void rayAdvance(inout SRay ray, float distance)
{
    ray.Pos += distance * ray.fudge;
}

SRay rayReflect(SRay ray, vec3 normal, float eps)
{
    vec3 hit = rayCurrentPoint(ray);
    ray.Direction = reflect(ray.Direction, normal);
    ray.Offset = reflect(ray.Offset, normal);
    ray.Origin = hit + reflect(ray.Origin - hit, normal);
    ray.Pos += eps;
    return ray;
}

// -----------------------------------------------------------------------------
// Normal, shadow and ambient occlusion
// -----------------------------------------------------------------------------

vec3 calcNormal(vec3 p, float normalDistance)
{
    float e = max(normalDistance * 0.5, 1.0e-5);
    vec3 ex = vec3(e, 0.0, 0.0);
    vec3 ey = vec3(0.0, e, 0.0);
    vec3 ez = vec3(0.0, 0.0, e);

    vec3 n = vec3(
        DE(p + ex) - DE(p - ex),
        DE(p + ey) - DE(p - ey),
        DE(p + ez) - DE(p - ez)
    );

    float n2 = dot(n, n);
    return (n2 > 0.0 && n2 < 1.0e30) ? n * inversesqrt(n2) : vec3(0.0);
}

float linstep(float a, float b, float t)
{
    return clamp((t - a) / max(b - a, MIN_EPS), 0.0, 1.0);
}

float shadow(vec3 ro, vec3 lightPos, float eps)
{
    float rCoC = max(eps, MIN_EPS);
    vec3 rd = lightPos - ro;
    float lightDist = length(rd);
    rd /= max(lightDist, MIN_EPS);

    float coneGrad = (SHADOW_SOFT == 0.0)
        ? LIGHT_SIZE / max(lightDist, MIN_EPS)
        : 1.0 / SHADOW_SOFT;

    float t = sceneDistance(ro) + rCoC;
    float s = 1.0;
    float jitter = DITHER * (rand1(ro.xy * (float(iFrame) + 1.0)) - 0.5);

    for (int i = 0; i < MAX_RAY_STEPS; ++i)
    {
        if (t > lightDist || s < 0.001) break;

        float radius = rCoC + t * coneGrad;
        float d = sceneDistance(ro + rd * (t + radius * jitter));
        s *= linstep(-radius, radius, d);
        t += abs(0.75 * d + 0.25 * radius) + MIN_EPS;
    }

    s = max(0.0, s - 0.001) / 0.999;
    return clamp(1.0 - s, 0.0, 1.0);
}

vec3 ortho(vec3 v)
{
    return abs(v.x) > abs(v.z)
        ? vec3(-v.y, v.x, 0.0)
        : vec3(0.0, -v.z, v.y);
}

vec2 rand2AO()
{
    gAOSeed += vec2(-1.0, 1.0);
    return rand2(gAOSeed);
}

vec3 getAODirection(vec3 direction)
{
    vec3 o1 = normalize(ortho(direction));
    vec3 o2 = cross(direction, o1);
    vec2 r = rand2AO();

    r.x *= TWO_PI;
    r.y *= CONE_APERTURE_AO;

    float radial = sqrt(max(r.y, 0.0));
    float axial = sqrt(max(1.0 - r.y, 0.0));
    return cos(r.x) * radial * o1 +
           sin(r.x) * radial * o2 + axial * direction;
}

float ambientOcclusion(vec3 p, vec3 n)
{
    vec3 sampleDirection = getAODirection(n);
    float de = sceneDistance(p) / max(gAOEps, MIN_EPS);
    if (abs(de) < MIN_EPS) de = MIN_EPS;

    float ao = 0.0;
    float weightSum = 0.0;
    float d = 1.0 - DITHER * rand1(p.xy);
    float D = 1.0;

    for (int i = 1; i < MAX_AO_ITER; ++i)
    {
        float previousD = D;
        float denominator = d * de * dot(sampleDirection, n) * FUDGE_AO;
        if (abs(denominator) < MIN_EPS)
            denominator = (denominator < 0.0 ? -1.0 : 1.0) * MIN_EPS;

        D = sceneDistance(p + d * sampleDirection * de) / denominator;
        D = min(previousD, D);

        ao += clamp(1.0 - D, 0.0, 1.0);
        weightSum += 1.0;
        d *= 1.61;
    }

    return ao / max(weightSum, 1.0);
}

// -----------------------------------------------------------------------------
// Fog and lighting
// -----------------------------------------------------------------------------

float expSafe(float x)
{
    return exp(clamp(x, -80.0, 80.0));
}

vec3 expSafe(vec3 x)
{
    return exp(clamp(x, vec3(-80.0), vec3(80.0)));
}

float oneMinusExpNegOverX(float x)
{
    if (abs(x) < 1.0e-5)
        return 1.0 - 0.5 * x + x * x / 6.0;
    return (1.0 - expSafe(-x)) / x;
}

vec3 fogTransmission(vec3 p0, vec3 p1)
{
    vec3 fogDirection = normalize(HF_DIR);
    vec3 segment = p1 - p0;
    float distanceTravelled = length(segment);
    float x = HF_FALLOFF * dot(segment, fogDirection);
    float integralFactor = oneMinusExpNegOverX(x);

    vec3 amount = HF_COLOR.rgb *
        (HF_INTENSITY *
         expSafe(-HF_FALLOFF * (dot(p0, fogDirection) - HF_OFFSET)) *
         integralFactor + HF_CONST) * distanceTravelled;

    return clamp(expSafe(-amount), vec3(0.0), vec3(1.0));
}

vec3 pointLightGlow(float glow)
{
    if (!SPOT_GLOW) return vec3(0.0);

    float glow1 = exp(-pow(LIGHT_GLOW_RAD + 0.0001, -2.0) *
                      pow(max(glow, 0.0), LIGHT_GLOW_EXP));
    float glow2 = exp(-20.0 * max(glow, 0.0));
    return SPOT_LIGHT.rgb * (glow2 * SPOT_LIGHT.w + glow1);
}

vec3 lighting(
    vec3 n,
    vec3 materialColor,
    vec3 pos,
    vec3 rayDirection,
    float eps,
    out float shadowStrength,
    float ao)
{
    shadowStrength = 0.0;
    vec3 color = vec3(0.0);

    vec3 toLight = LIGHT_POS - pos;
    float distanceSquared = max(dot(toLight, toLight), MIN_EPS);
    float falloff = pow(distanceSquared, -LIGHT_FALLOFF);
    vec3 lightDirection = toLight * inversesqrt(distanceSquared);

    float nDotL = max(AO_CORRECT, dot(n, lightDirection));
    vec3 halfVector = normalize(-rayDirection + lightDirection);
    float hDotN = max(0.0, dot(n, halfVector));

    float f0 = (SPECULAR_EXP - 1.0) / (SPECULAR_EXP + 1.0);
    f0 *= f0;
    float fresnel = f0 + (1.0 - f0) * pow(1.0 + dot(n, rayDirection), 5.0);

    float diffuse = nDotL;
    float specular = ((SPECULAR_EXP + 2.0) / 8.0) * fresnel * nDotL *
                     pow(hDotN, SPECULAR_EXP + 0.00001) * SPECULAR;

    if (HARD_SHADOW > 0.0)
    {
        shadowStrength = shadow(pos + n * eps, LIGHT_POS, eps);
        diffuse = mix(diffuse, 0.0, HARD_SHADOW * shadowStrength);
        specular *= 1.0 - shadowStrength;
    }

    vec3 fogToLight = fogTransmission(pos, LIGHT_POS);
    color += fogToLight * SPOT_LIGHT.rgb * SPOT_LIGHT.w * falloff *
             (diffuse + specular) *
             (1.0 - clamp(AO_POINTLIGHT * ao, 0.0, 1.0));

    nDotL = max(AO_CORRECT, dot(n, -rayDirection));
    hDotN = max(0.0, dot(n, -rayDirection));
    diffuse = nDotL;
    specular = ((SPECULAR_EXP + 2.0) / 8.0) * fresnel * nDotL *
               pow(hDotN, SPECULAR_EXP + 0.00001) * SPECULAR;

    color += CAM_LIGHT.rgb * CAM_LIGHT.a * (diffuse + specular) *
             (1.0 - clamp(AO_CAMLIGHT * ao, 0.0, 1.0));

    color += AMBIENT_LIGHT.rgb * AMBIENT_LIGHT.a *
             (1.0 - clamp(AO_AMBIENT * ao, 0.0, 1.0));

    return color * materialColor;
}

vec3 volumetricPointLight(vec3 p0, vec3 p1, float stratum)
{
    vec3 segment = p1 - p0;
    float C = dot(segment, segment);
    if (C < MIN_EPS) return vec3(0.0);

    vec3 fromLight = p0 - LIGHT_POS;
    float A = dot(fromLight, fromLight);
    float B = dot(segment, fromLight);
    float delta = sqrt(max(A * C - B * B, 1.0e-12));

    float x = (rand1(gViewCoord + vec2(1.6183 + float(iFrame) + stratum)) +
               stratum) / float(HF_FOG_ITER);

    float atanB = atan(B / delta);
    float atanBC = atan((B + C) / delta);
    float pdfNormalization = (atanBC - atanB) / delta;

    float t = (tan(mix(atanB, atanBC, x)) * delta - B) / C;
    t = clamp(t, 0.0001, 1.0);

    vec3 samplePoint = p0 + t * segment;
    vec3 extinctionEye = fogTransmission(p0, samplePoint);
    vec3 extinctionLight = fogTransmission(samplePoint, LIGHT_POS);

    vec3 fogDirection = normalize(HF_DIR);
    float height = HF_FALLOFF * (dot(samplePoint, fogDirection) - HF_OFFSET);
    vec3 density = HF_COLOR.rgb * HF_INTENSITY * expSafe(-height) + vec3(HF_CONST);

    float visibility = 1.0;
    if (HF_CAST_SHADOW)
        visibility = 1.0 - shadow(samplePoint, LIGHT_POS, 0.001);

    float cosTheta = dot(
        normalize(samplePoint - p0),
        normalize(LIGHT_POS - samplePoint)
    );

    vec3 denominator = vec3(1.0) + HF_ANISOTROPY * HF_ANISOTROPY -
                       2.0 * HF_ANISOTROPY * cosTheta;
    vec3 phase = (vec3(1.0) - HF_ANISOTROPY * HF_ANISOTROPY) /
                 sqrt(max(denominator * denominator * denominator,
                          vec3(1.0e-12)));

    vec3 sampleValue = extinctionEye * extinctionLight * density * phase *
                       visibility * length(segment);

    return SPOT_LIGHT.rgb * SPOT_LIGHT.w * pdfNormalization *
           sampleValue * HF_SCATTER;
}

// -----------------------------------------------------------------------------
// Ray tracing
// -----------------------------------------------------------------------------

vec3 trace(inout SRay ray, out vec3 hitNormal, out float glow)
{
    glow = 1000.0;
    hitNormal = vec3(0.0);

    bool hitSomething = false;
    bool hitFloor = false;
    bool hitPointLight = false;

    float distanceStep = 0.0;
    float lightDE = 0.0;
    float epsModified = max(MIN_EPS, ray.Pos * gMinDist);

    vec3 p = rayCurrentPoint(ray);
    float firstSceneDistance = sceneDistance(p);
    float firstStep = min(firstSceneDistance * FUDGE_FACTOR, lightDistance(p));
    firstStep *= DITHER * rand1(ray.Direction.xy) + (1.0 - DITHER);
    rayAdvance(ray, firstStep);

    for (int i = 0; i < MAX_RAY_STEPS; ++i)
    {
        p = rayCurrentPoint(ray);

        lightDE = lightDistance(p);
        float sceneDE = sceneDistance(p);
        distanceStep = min(lightDE, sceneDE * FUDGE_FACTOR);
        glow = min(lightDE, glow);

        rayAdvance(ray, distanceStep);
        epsModified = max(MIN_EPS, ray.Pos * gMinDist);

        if (distanceStep < epsModified)
        {
            for (int j = 0; j < REFINE_STEPS; ++j)
            {
                rayAdvance(ray, distanceStep - 1.5 * epsModified);
                p = rayCurrentPoint(ray);
                lightDE = lightDistance(p);
                sceneDE = sceneDistance(p);
                distanceStep = min(lightDE, sceneDE * FUDGE_FACTOR);
                glow = min(lightDE, glow);
            }

            hitSomething = true;
            p = rayCurrentPoint(ray);
            hitPointLight = lightDE <= sceneDistance(p) * FUDGE_FACTOR;
            hitFloor = !hitPointLight && isExternalFloorClosest(p);
            break;
        }

        if (ray.Pos > MAX_DISTANCE) break;
    }

    vec3 background = BACKGROUND_COLOR;
    if (GRADIENT_BACKGROUND > 0.0)
        background = mix(background, vec3(0.0), length(gCoord) * GRADIENT_BACKGROUND);

    if (!hitSomething)
    {
        ray.Pos = MAX_DISTANCE;
        return background;
    }

    if (hitPointLight)
    {
        gLightHit = true;
        return SPOT_LIGHT.rgb * SPOT_LIGHT.w / (LIGHT_SIZE + 0.01);
    }

    vec3 hit = rayCurrentPoint(ray);
    if (hitFloor)
    {
        hitNormal = FLOOR_NORMAL;
        if (dot(FLOOR_NORMAL, hit) - FLOOR_HEIGHT < 0.0)
            hitNormal = -hitNormal;
    }
    else
    {
        hitNormal = calcNormal(
            hit - NORMAL_BACK_STEP * epsModified * ray.Direction,
            epsModified
        );
    }

    vec3 materialColor = hitFloor
        ? FLOOR_COLOR
        : mix(BASE_COLOR, honeycombBaseColor(hit), ORBIT_STRENGTH);

    materialColor = pow(clamp(materialColor, 0.0, 1.0), vec3(GAMMA_VALUE));

    float ao = 0.0;
    if (DETAIL_AO < 0.0)
        ao = ambientOcclusion(hit, hitNormal);

    float shadowStrength;
    return lighting(
        hitNormal,
        materialColor,
        hit,
        ray.Direction,
        epsModified,
        shadowStrength,
        ao
    );
}

vec3 renderScene(SRay ray)
{
    gMinDist = pow(10.0, DETAIL);
    gAOEps = pow(10.0, DETAIL_AO);
    gAOSeed = gViewCoord * (float(iFrame) + 1.0);
    gLightHit = false;

    vec3 color = vec3(0.0);
    vec3 reflectionWeight = vec3(1.0);

    for (int bounce = 0; bounce <= REFLECTIONS_NUMBER; ++bounce)
    {
        vec3 previousPosition = rayCurrentPoint(ray);

        vec3 hitNormal;
        float glow;
        vec3 bounceColor = trace(ray, hitNormal, glow);
        vec3 currentPosition = rayCurrentPoint(ray);

        vec3 fog = fogTransmission(previousPosition, currentPosition);
        bounceColor = mix(HF_COLOR.rgb * HF_COLOR.a, bounceColor, fog);
        bounceColor += pointLightGlow(max(0.0, glow));

        if (HF_SCATTER * (HF_INTENSITY + HF_CONST) > 0.0)
        {
            vec3 fogGlow = vec3(0.0);
            for (int j = 0; j < HF_FOG_ITER; ++j)
                fogGlow += volumetricPointLight(
                    previousPosition,
                    currentPosition,
                    float(j)
                );
            bounceColor += fogGlow / float(HF_FOG_ITER);
        }

        color += bounceColor * reflectionWeight;
        reflectionWeight *= REFLECTION * fog;

        if (dot(hitNormal, hitNormal) < 1.0e-20 ||
            dot(reflectionWeight, reflectionWeight) < 0.0001 ||
            gLightHit || ray.Pos >= MAX_DISTANCE)
        {
            break;
        }

        ray = rayReflect(ray, hitNormal, gMinDist);
    }

    return max(color, vec3(0.0));
}

// -----------------------------------------------------------------------------
// Camera and progressive accumulation
// -----------------------------------------------------------------------------

vec3 equirectangularDirection(vec2 screenCoord, vec3 dir, vec3 up, vec3 right)
{
    vec2 angles = vec2(screenCoord.x, (1.0 - screenCoord.y) * 0.5) * PI;
    return cos(angles.x) * sin(angles.y) * dir +
           sin(angles.x) * sin(angles.y) * right +
           cos(angles.y) * up;
}

SRay makeCameraRay(vec2 fragCoord, out vec2 discSample)
{
    vec2 uv = fragCoord / iResolution.xy;

    gViewCoord = uv * 2.0 - 1.0;
    gCoord = (2.0 * fragCoord - iResolution.xy) / iResolution.y;
    gPixelScale = 2.0 / iResolution.xy;

    gFrom = EYE;
    gDir = normalize(TARGET - EYE);
    vec3 normalizedUp = normalize(UP);
    gUpOrtho = normalize(normalizedUp - dot(gDir, normalizedUp) * gDir);
    gRight = normalize(cross(gDir, gUpOrtho));

    gCoord *= FOV;

    float frame = float(iFrame) + 1.0;
    vec2 apertureSample = APERTURE *
        ((APERTURE_NBR_SIDES == 2)
            ? uniformDisc(gViewCoord * frame)
            : nGonDisc(gViewCoord * frame));

    discSample = uniformDisc(gCoord * frame);

    vec2 jitteredCoord;
    if (EQUIRECTANGULAR)
        jitteredCoord = ANTI_ALIAS_SCALE * gPixelScale * discSample;
    else
        jitteredCoord = gCoord +
            ANTI_ALIAS_SCALE * gPixelScale * FOV * discSample;

    vec3 lensOffset = apertureSample.x * gRight +
                      apertureSample.y * gUpOrtho;

    vec3 rayDirection = gDir +
                        jitteredCoord.x * gRight +
                        jitteredCoord.y * gUpOrtho;

    if (EQUIRECTANGULAR)
        rayDirection = equirectangularDirection(
            gViewCoord,
            rayDirection,
            gUpOrtho,
            gRight
        );

    float rayDirectionLength = length(rayDirection);
    float focusTerm = 1.0 - 1.0 / FOCAL_PLANE +
        clamp(1.0 / FOCAL_PLANE - 1.0,
              -IN_FOCUS_A_WIDTH,
               IN_FOCUS_A_WIDTH);
    float fpO1 = length(rayDirection + lensOffset * focusTerm);

    SRay ray;
    ray.Origin = gFrom;
    ray.Direction = rayDirection / rayDirectionLength;
    ray.Offset = lensOffset;
    ray.Pos = 0.0;
    ray.fudge = 1.0 / max(1.0, fpO1);
    ray.iFP = 1.0 / FOCAL_PLANE;
    return ray;
}

void mainImage(out vec4 fragColor, in vec2 fragCoord)
{
    initHoneycomb();

    vec2 discSample;
    SRay ray = makeCameraRay(fragCoord, discSample);
    vec3 sampleColor = renderScene(ray);

    float weight = 1.0 - length(discSample);
    if (GAUSSIAN_WEIGHT > 0.0)
    {
        weight = exp(-dot(discSample, discSample) / GAUSSIAN_WEIGHT) -
                 exp(-1.0 / GAUSSIAN_WEIGHT);
    }

    vec4 previous = vec4(0.0);
    if (iFrame > 0)
        previous = texelFetch(iChannel0, ivec2(fragCoord), 0);

    fragColor = previous + vec4(sampleColor * weight, weight);
}

/*
    454-1101 Coxeter honeycomb: Fragmentarium postprocess -> Shadertoy Image pass

    Shadertoy setup:
      Image / iChannel0 = Buffer A

    Buffer A is expected to store:
      rgb = weighted HDR color sum
      a   = accumulated sample weight

    The constants below reproduce the honeycomb preset supplied with the scene shader.
*/

// -----------------------------------------------------------------------------
// Preset values
// -----------------------------------------------------------------------------

const float GAMMA_VALUE     = 2.2;
const int   TONE_MAPPING    = 4;
const float EXPOSURE        = 1.0;
const float BRIGHTNESS      = 1.0;
const float CONTRAST        = 1.0;
const float SATURATION      = 1.0;

const bool  ENABLE_BLOOM    = false;
const float BLOOM_INTENSITY = 0.25;
const float BLOOM_POW       = 2.0;
const int   BLOOM_TAPS      = 4;

// Lens flare was commented out in the supplied Fragmentarium shader.
// It is included here as an optional Shadertoy-compatible path.
const bool  ENABLE_LENS_FLARE = false;
const float FLARE_INTENSITY   = 0.25;
const int   FLARE_SAMPLES     = 8;
const float FLARE_DISPERSAL   = 0.25;
const float FLARE_HALO_WIDTH  = 0.5;
const float FLARE_DISTORTION  = 1.0;

const vec3 RGB_TO_LUMA = vec3(0.2125, 0.7154, 0.0721);

// -----------------------------------------------------------------------------
// Accumulation-buffer access
// -----------------------------------------------------------------------------

vec4 sampleAccumulation(vec2 uv)
{
    return texture(iChannel0, uv);
}

vec3 resolveAccumulation(vec4 value)
{
    return value.rgb / max(value.a, 1.0e-8);
}

vec3 sampleResolved(vec2 uv)
{
    return resolveAccumulation(sampleAccumulation(uv));
}

// -----------------------------------------------------------------------------
// RGB <-> HSV
// Kept from the original postprocessor for compatibility and future edits.
// -----------------------------------------------------------------------------

vec3 rgb2hsv(vec3 c)
{
    vec4 K = vec4(0.0, -1.0 / 3.0, 2.0 / 3.0, -1.0);
    vec4 p = mix(vec4(c.bg, K.wz), vec4(c.gb, K.xy), step(c.b, c.g));
    vec4 q = mix(vec4(p.xyw, c.r), vec4(c.r, p.yzx), step(p.x, c.r));

    float d = q.x - min(q.w, q.y);
    float e = 1.0e-10;
    return vec3(
        abs(q.z + (q.w - q.y) / (6.0 * d + e)),
        d / (q.x + e),
        q.x
    );
}

vec3 hsv2rgb(vec3 c)
{
    vec4 K = vec4(1.0, 2.0 / 3.0, 1.0 / 3.0, 3.0);
    vec3 p = abs(fract(c.xxx + K.xyz) * 6.0 - K.www);
    return c.z * mix(K.xxx, clamp(p - K.xxx, 0.0, 1.0), c.y);
}

// -----------------------------------------------------------------------------
// Brightness / saturation / contrast
// -----------------------------------------------------------------------------

vec3 contrastSaturationBrightness(
    vec3 color,
    float brightness,
    float saturation,
    float contrast
)
{
    const vec3 LUMA = vec3(0.2125, 0.7154, 0.0721);

    vec3 brightColor = color * brightness;
    float intensityValue = dot(brightColor, LUMA);
    vec3 intensity = vec3(intensityValue);
    vec3 saturatedColor = mix(intensity, brightColor, saturation);
    vec3 contrastedColor = mix(vec3(0.5), saturatedColor, contrast);

    return clamp(contrastedColor, 0.0, 1.0);
}

// -----------------------------------------------------------------------------
// Tone mapping functions
// -----------------------------------------------------------------------------

float syntopiaSigmoid(float t)
{
    float k = 1.0 - 1.0 / (1.0 + exp(-0.5 * CONTRAST * 5.0));
    t -= 0.5;

    float x = 1.0 / (1.0 + exp(-t * CONTRAST * 5.0)) - k;
    return x / (1.0 - 2.0 * k);
}

vec3 syntopiaSigmoid(vec3 value)
{
    return vec3(
        syntopiaSigmoid(value.r),
        syntopiaSigmoid(value.g),
        syntopiaSigmoid(value.b)
    );
}

// Lottes 2016, "Advanced Techniques and Optimization of HDR Color Pipelines"
vec3 lottesToneMap(vec3 x)
{
    const vec3 a      = vec3(1.6);
    const vec3 d      = vec3(0.977);
    const vec3 hdrMax = vec3(8.0);
    const vec3 midIn  = vec3(0.18);
    const vec3 midOut = vec3(0.267);

    const vec3 b =
        (-pow(midIn, a) + pow(hdrMax, a) * midOut) /
        ((pow(hdrMax, a * d) - pow(midIn, a * d)) * midOut);

    const vec3 c =
        (pow(hdrMax, a * d) * pow(midIn, a)
        - pow(hdrMax, a) * pow(midIn, a * d) * midOut) /
        ((pow(hdrMax, a * d) - pow(midIn, a * d)) * midOut);

    return pow(x, a) / (pow(x, a * d) * b + c);
}

// Uchimura 2017, "HDR theory and practice"
vec3 uchimuraToneMap(
    vec3 x,
    float maximumDisplayBrightness,
    float contrast,
    float linearStart,
    float linearLength,
    float black,
    float pedestal
)
{
    float P = maximumDisplayBrightness;
    float a = contrast;
    float m = linearStart;
    float l = linearLength;
    float c = black;
    float b = pedestal;

    float l0 = ((P - m) * l) / a;
    float L0 = m - m / a;
    float L1 = m + (1.0 - m) / a;
    float S0 = m + l0;
    float S1 = m + a * l0;
    float C2 = (a * P) / (P - S1);
    float CP = -C2 / P;

    vec3 w0 = vec3(1.0) - smoothstep(vec3(0.0), vec3(m), x);
    vec3 w2 = step(vec3(m + l0), x);
    vec3 w1 = vec3(1.0) - w0 - w2;

    vec3 T = vec3(m) * pow(x / m, vec3(c)) + vec3(b);
    vec3 S = vec3(P) - (P - S1) * exp(CP * (x - S0));
    vec3 L = vec3(m) + a * (x - m);

    // L0 and L1 are retained to mirror the published formulation.
    // They are not needed by the final piecewise expression.
    L0 += 0.0;
    L1 += 0.0;

    return T * w0 + L * w1 + S * w2;
}

vec3 uchimuraToneMap(vec3 x)
{
    const float P = 1.0;
    const float a = 1.0;
    const float m = 0.22;
    const float l = 0.4;
    const float c = 1.33;
    const float b = 0.0;

    return uchimuraToneMap(x, P, a, m, l, c, b);
}

vec3 uncharted2Partial(vec3 x)
{
    const float A = 0.15;
    const float B = 0.50;
    const float C = 0.10;
    const float D = 0.20;
    const float E = 0.02;
    const float F = 0.30;

    return ((x * (A * x + C * B) + D * E) /
           (x * (A * x + B) + D * F)) - E / F;
}

vec3 uncharted2ToneMap(vec3 color)
{
    const float WHITE_POINT = 11.2;
    const float EXPOSURE_BIAS = 2.0;

    vec3 current = uncharted2Partial(EXPOSURE_BIAS * color);
    vec3 whiteScale = vec3(1.0) / uncharted2Partial(vec3(WHITE_POINT));
    return current * whiteScale;
}

vec3 applyToneMapping(vec3 color)
{
    vec3 c = color;

    if (TONE_MAPPING == 1)
    {
        // Linear
        c *= EXPOSURE;
        c = contrastSaturationBrightness(c, BRIGHTNESS, SATURATION, CONTRAST);
    }
    else if (TONE_MAPPING == 2)
    {
        // Exponential exposure
        c = vec3(1.0) - exp(-c * EXPOSURE);
        c = contrastSaturationBrightness(c, BRIGHTNESS, SATURATION, CONTRAST);
    }
    else if (TONE_MAPPING == 3)
    {
        // Filmic curve used by the original Fragmentarium shader
        c *= EXPOSURE;
        vec3 x = max(vec3(0.0), c - vec3(0.004));
        c = (x * (6.2 * x + 0.5)) /
            (x * (6.2 * x + 1.7) + 0.06);

        // This curve includes a 2.2 encoding step in the original code.
        c = pow(max(c, vec3(0.0)), vec3(2.2));
        c = contrastSaturationBrightness(c, BRIGHTNESS, SATURATION, CONTRAST);
    }
    else if (TONE_MAPPING == 4)
    {
        // Reinhard (called "Reinhart" in the source comments)
        c *= EXPOSURE;
        c = c / (vec3(1.0) + c);
        c = contrastSaturationBrightness(c, BRIGHTNESS, SATURATION, CONTRAST);
    }
    else if (TONE_MAPPING == 5)
    {
        // Exact Fragmentarium / Syntopia sigmoid path.
        // As in the original code, Saturation is not applied in this mode.
        c = syntopiaSigmoid(c * EXPOSURE + vec3(BRIGHTNESS - 1.0));
    }
    else if (TONE_MAPPING == 6)
    {
        c *= EXPOSURE;
        c = lottesToneMap(max(c, vec3(0.0)));
        c = contrastSaturationBrightness(c, BRIGHTNESS, SATURATION, CONTRAST);
    }
    else if (TONE_MAPPING == 7)
    {
        c *= EXPOSURE;
        c = uchimuraToneMap(max(c, vec3(0.0)));
        c = contrastSaturationBrightness(c, BRIGHTNESS, SATURATION, CONTRAST);
    }
    else if (TONE_MAPPING == 8)
    {
        c *= EXPOSURE;
        c = uncharted2ToneMap(max(c, vec3(0.0)));
        c = contrastSaturationBrightness(c, BRIGHTNESS, SATURATION, CONTRAST);
    }
    else if (TONE_MAPPING == 9)
    {
        // 3Dickulus luminance map
        c *= EXPOSURE;
        c *= dot(c, RGB_TO_LUMA);
        c = contrastSaturationBrightness(c, BRIGHTNESS, SATURATION, CONTRAST);
    }

    return c;
}

// -----------------------------------------------------------------------------
// Bloom
// -----------------------------------------------------------------------------

vec3 bloomColor(vec2 uv)
{
    vec2 texelSize = 1.0 / iResolution.xy;
    vec4 sum = vec4(0.0);

    // BLOOM_TAPS is a compile-time constant, which keeps this loop compatible
    // with Shadertoy's WebGL compiler.
    for (int x = -BLOOM_TAPS; x <= BLOOM_TAPS; ++x)
    {
        float fx = float(x) / max(float(BLOOM_TAPS), 1.0);
        float wx = 1.0 - fx * fx;
        wx = wx * wx * wx;

        for (int y = -BLOOM_TAPS; y <= BLOOM_TAPS; ++y)
        {
            float fy = float(y) / max(float(BLOOM_TAPS), 1.0);
            float wy = 1.0 - fy * fy;
            wy = wy * wy * wy;

            vec2 offset = vec2(float(x), float(y)) * texelSize;
            sum += sampleAccumulation(uv + offset) * (wx * wy);
        }
    }

    // Dividing the raw accumulated sum by its alpha reproduces the original
    // b = bloom(...); b /= b.w behavior. The omitted sample-count factor
    // cancels between numerator and denominator.
    return resolveAccumulation(sum);
}

// -----------------------------------------------------------------------------
// Optional lens flare conversion
// -----------------------------------------------------------------------------

vec4 textureDistorted(
    vec2 uv,
    vec2 direction,
    vec4 distortion
)
{
    return vec4(
        sampleAccumulation(uv + direction * distortion.r).r,
        sampleAccumulation(uv + direction * distortion.g).g,
        sampleAccumulation(uv + direction * distortion.b).b,
        sampleAccumulation(uv + direction * distortion.a).a
    );
}

vec4 lensFlare(vec2 uv)
{
    vec2 texelSize = 1.0 / iResolution.xy;
    vec2 ghostVector = (vec2(0.5) - uv) * FLARE_DISPERSAL;

    float ghostLength = length(ghostVector);
    vec2 ghostDirection = ghostLength > 1.0e-8
        ? ghostVector / ghostLength
        : vec2(0.0);

    vec2 haloVector = ghostDirection * FLARE_HALO_WIDTH;
    vec4 distortion = vec4(
        -texelSize.x * FLARE_DISTORTION,
         0.0,
         texelSize.x * FLARE_DISTORTION,
         0.0
    );

    vec4 result = vec4(0.0);

    for (int i = 0; i < FLARE_SAMPLES; ++i)
    {
        vec2 offset = fract(uv + ghostVector * float(i));
        float radial = length(vec2(0.5) - offset) / length(vec2(0.5));
        float weight = pow(max(1.0 - radial, 0.0), 10.0);
        result += textureDistorted(offset, ghostDirection, distortion) * weight;
    }

    vec2 haloUV = fract(uv + haloVector);
    float haloRadial = length(vec2(0.5) - haloUV) / length(vec2(0.5));
    float haloWeight = pow(max(1.0 - haloRadial, 0.0), 10.0);
    result += textureDistorted(haloUV, ghostDirection, distortion) * haloWeight;

    return result;
}

// -----------------------------------------------------------------------------
// Shadertoy entry point
// -----------------------------------------------------------------------------

void mainImage(out vec4 fragColor, in vec2 fragCoord)
{
    vec2 uv = fragCoord / iResolution.xy;

    vec4 accumulated = sampleAccumulation(uv);
    vec3 color = resolveAccumulation(accumulated);

    if (ENABLE_BLOOM)
    {
        vec3 blurred = bloomColor(uv);
        color += BLOOM_INTENSITY * pow(
            max(blurred, vec3(0.0)),
            vec3(BLOOM_POW)
        );
    }

    if (ENABLE_LENS_FLARE)
    {
        vec4 flare = lensFlare(uv);
        color += FLARE_INTENSITY * resolveAccumulation(flare);
    }

    color = applyToneMapping(color);

    // Protect pow() from negative values generated by unusual parameter sets.
    color = pow(max(color, vec3(0.0)), vec3(1.0 / GAMMA_VALUE));

    fragColor = vec4(color, 1.0);
}

