float rand1(float v)
{
    return fract(sin(v * 78.233) * 43758.5453);
}

float rand1(vec2 p)
{
    return fract(sin(dot(p, vec2(12.9898, 78.233))) * 43758.5453);
}

vec2 rand2(vec2 p)
{
    return vec2(
        fract(sin(dot(p, vec2(12.9898, 78.233))) * 43758.5453),
        fract(cos(dot(p, vec2(4.898, 7.23))) * 23421.631)
    );
}

vec2 uniformDisc(vec2 co)
{
    vec2 r = rand2(co);
    return sqrt(r.y) * vec2(cos(r.x * TWO_PI), sin(r.x * TWO_PI));
}

vec2 nGonDisc(vec2 co)
{
    vec2 r = rand2(co);
    float sides = float(APERTURE_NBR_SIDES);
    float d = 1.0 / tan(PI / sides);
    float lh = inversesqrt(1.0 + d * d);

    vec2 p = vec2(r.x + r.y, r.x - r.y);
    if (!AP_STAR_SHAPED) p.x = 1.0 - abs(p.x - 1.0);
    p.x *= d;
    p *= lh;

    float a = dot(rand2(11.0 * co + vec2(1.0)), vec2(1.0));
    a = floor(a * sides) * TWO_PI / sides + APERTURE_ROT * PI / 360.0;
    vec2 cs = vec2(cos(a), sin(a));
    return vec2(cs.x * p.x - cs.y * p.y,
                cs.x * p.y + cs.y * p.x);
}

// -----------------------------------------------------------------------------
// Coxeter honeycomb geometry
// -----------------------------------------------------------------------------

float hdot(vec4 p, vec4 q)
{
    return dot(p.xyz, q.xyz) - p.w * q.w;
}

vec4 hnormalize(vec4 p)
{
    return p / sqrt(max(-hdot(p, p), 1.0e-30));
}

float tryReflect4D(inout vec4 p, vec4 n)
{
    float k = min(0.0, hdot(p, n));
    p -= 2.0 * k * n;
    return k;
}

bool tryReflectPlane3D(inout vec3 p, vec3 n, inout int count)
{
    float k = dot(p, n);
    if (k >= 0.0) return true;
    p -= 2.0 * k * n;
    count += 1;
    return false;
}

bool tryReflectSphere3D(inout vec3 p, vec4 sphere, inout int count)
{
    vec3 center = sphere.xyz;
    float radius = sphere.w;
    vec3 q = p - center;
    float d2 = dot(q, q);
    if (d2 <= 1.0e-30) return true;

    float k = radius * radius / d2;
    if (k < 1.0) return true;

    p = k * q + center;
    count += 1;
    return false;
}

void rotateXY(inout vec3 p)
{
    float ca = cos(TWO_PI * ROT_A);
    float sa = -sin(TWO_PI * ROT_A);
    p.xy = mat2(ca, -sa, sa, ca) * p.xy;
}

void initHoneycomb()
{
    float c01 = -cos(PI / float(AB));
    float c02 = -cos(PI / float(AC));
    float c03 = -cos(PI / float(AD));
    float c12 = -cos(PI / float(BC));
    float c13 = -cos(PI / float(BD));
    float c23 = -cos(PI / float(CD));

    vec4 A = vec4(1.0, 0.0, 0.0, 0.0);
    vec4 B = vec4(c01, sqrt(max(1.0 - c01 * c01, 0.0)), 0.0, 0.0);

    vec4 C = vec4(c02, 0.0, 0.0, 0.0);
    C.y = (c12 - C.x * B.x) / B.y;
    C.z = sqrt(abs(1.0 - dot(C.xy, C.xy)));

    vec4 D = vec4(c03, 0.0, 0.0, 0.0);
    D.y = (c13 - D.x * B.x) / B.y;
    D.z = (c23 - dot(D.xy, C.xy)) / C.z;
    D.w = -sqrt(abs(dot(D.xyz, D.xyz) - 1.0));

    vec4 H = vec4(1.0, 1.0, 1.0, -1.0);
    mat4 inverseMirrorMatrix = inverse(mat4(H * A, H * B, H * C, H * D));
    gInitialVertex = hnormalize(ACTIVE_MIRRORS * inverseMirrorMatrix);
    gMirrors = mat4(A, B, C, D);

    gCoshVertexRadius  = cosh(VERTEX_SIZE);
    gSinhVertexRadius  = sinh(VERTEX_SIZE);
    gCoshSegmentRadius = cosh(EDGE_SIZE);
    gSinhSegmentRadius = sinh(EDGE_SIZE);

    vec3 center = -vec3(c03, c13, c23) * inverse(mat3(A.xyz, B.xyz, C.xyz));
    vec4 inversionSphere = vec4(center, 1.0);
    inversionSphere /= sqrt(max(dot(center, center) - 1.0, 1.0e-30));
    gMirrors3D = mat4(A, B, C, inversionSphere);
}

bool fold3D(inout vec3 p, inout int count)
{
    for (int i = 0; i < MAX_FOLD3D_ITER; ++i)
    {
        bool inA = tryReflectPlane3D(p, gMirrors3D[0].xyz, count);
        bool inB = tryReflectPlane3D(p, gMirrors3D[1].xyz, count);
        bool inC = tryReflectPlane3D(p, gMirrors3D[2].xyz, count);
        bool inD = tryReflectSphere3D(p, gMirrors3D[3], count);
        if (inA && inB && inC && inD) return true;
    }
    return false;
}

bool fold4D(inout vec4 p)
{
    for (int i = 0; i < MAX_FOLD4D_ITER; ++i)
    {
        float k = 0.0;
        p.x = abs(p.x);
        k += tryReflect4D(p, gMirrors[1]);
        k += tryReflect4D(p, gMirrors[2]);
        k += tryReflect4D(p, gMirrors[3]);
        if (k == 0.0) return true;
    }
    return false;
}

float knightyDistanceConversion(float ca, float sa, float r)
{
    float x = 1.0 + r * r;
    float y = 2.0 - x;
    float denominator = x * ca + 2.0 * r * sa + y;
    if (abs(denominator) < 1.0e-30)
        denominator = (denominator < 0.0 ? -1.0 : 1.0) * 1.0e-30;
    return (2.0 * r * ca + x * sa) / denominator - r;
}

float vertexDistance(vec4 p, float r)
{
    float ca = -hdot(p, gInitialVertex);
    float radicand = -hdot(p - gInitialVertex, p - gInitialVertex) *
                      hdot(p + gInitialVertex, p + gInitialVertex);
    float sa = 0.5 * sqrt(max(radicand, 0.0));

    return knightyDistanceConversion(
        ca * gCoshVertexRadius - sa * gSinhVertexRadius,
        sa * gCoshVertexRadius - ca * gSinhVertexRadius,
        r
    );
}

float segmentDistance(vec4 p, vec4 n, float r)
{
    float pn = hdot(p, n);
    float pv = hdot(p, gInitialVertex);
    float nv = hdot(n, gInitialVertex);
    float determinant = -1.0 - nv * nv;

    float a = (-nv * pv - pn) / determinant;
    float b = (pv - pn * nv) / determinant;
    vec4 projected = hnormalize(min(a, 0.0) * n + b * gInitialVertex);

    float ca = -hdot(p, projected);
    float radicand = -hdot(p - projected, p - projected) *
                      hdot(p + projected, p + projected);
    float sa = 0.5 * sqrt(max(radicand, 0.0));

    return knightyDistanceConversion(
        ca * gCoshSegmentRadius - sa * gSinhSegmentRadius,
        sa * gCoshSegmentRadius - ca * gSinhSegmentRadius,
        r
    );
}

float segmentDistances(vec4 p, float r)
{
    float dA = segmentDistance(p, gMirrors[0], r);
    float dB = segmentDistance(p, gMirrors[1], r);
    float dC = segmentDistance(p, gMirrors[2], r);
    float dD = segmentDistance(p, gMirrors[3], r);
    return min(min(dA, dB), min(dC, dD));
}

float faceDistance(vec4 p, float r, vec4 n1, vec4 n2)
{
    mat3 m = mat3(
        -1.0, hdot(gInitialVertex, n1), hdot(gInitialVertex, n2),
        hdot(gInitialVertex, n1), 1.0, hdot(n1, n2),
        hdot(gInitialVertex, n2), hdot(n1, n2), 1.0
    );

    vec3 b = vec3(
        hdot(p, gInitialVertex),
        hdot(p, n1),
        hdot(p, n2)
    );
    vec3 c = b * inverse(m);

    // The perpendicular projection lies outside the triangular face cone.
    if (c.y > 0.0 || c.z > 0.0)
        return 1.0e5;

    vec4 projected = hnormalize(
        c.x * gInitialVertex + c.y * n1 + c.z * n2
    );

    float ca = -hdot(p, projected);
    float radicand = -hdot(p - projected, p - projected) *
                      hdot(p + projected, p + projected);
    float sa = 0.5 * sqrt(max(radicand, 0.0));
    float ct = cosh(FACE_THICKNESS);
    float st = sinh(FACE_THICKNESS);

    return knightyDistanceConversion(
        ca * ct - sa * st,
        sa * ct - ca * st,
        r
    );
}

float faceDistances(vec4 p, float r)
{
    float d = 1.0e5;
    if (ENABLE_FACE_AB) d = min(d, faceDistance(p, r, gMirrors[0], gMirrors[1]));
    if (ENABLE_FACE_AC) d = min(d, faceDistance(p, r, gMirrors[0], gMirrors[2]));
    if (ENABLE_FACE_AD) d = min(d, faceDistance(p, r, gMirrors[0], gMirrors[3]));
    if (ENABLE_FACE_BC) d = min(d, faceDistance(p, r, gMirrors[1], gMirrors[2]));
    if (ENABLE_FACE_BD) d = min(d, faceDistance(p, r, gMirrors[1], gMirrors[3]));
    if (ENABLE_FACE_CD) d = min(d, faceDistance(p, r, gMirrors[2], gMirrors[3]));
    return d;
}

vec4 ballLift(vec3 p)
{
    float r2 = dot(p, p);
    float denominator = 1.0 - r2;
    if (abs(denominator) < 1.0e-9)
        denominator = (denominator < 0.0 ? -1.0 : 1.0) * 1.0e-9;
    return vec4(2.0 * p, 1.0 + r2) / denominator;
}

float DE(vec3 p)
{
    float floorHeightDistance = p.z - 1.0e-3;

    if (DO_UPPER_HALF_SPACE)
    {
        p.z += 1.0;
        float p2 = max(dot(p, p), 1.0e-30);
        p *= 2.0 / p2;
        p.z -= 1.0;
    }

    float r = length(p);
    vec4 q = ballLift(p);
    fold4D(q);

    float dVertexValue = vertexDistance(q, r);
    float dSegmentValue = segmentDistances(q, r);
    float dFaceValue = faceDistances(q, r);
    float geometryDistance = min(dFaceValue, min(dVertexValue, dSegmentValue));

    if (DO_UPPER_HALF_SPACE)
        return min(floorHeightDistance, geometryDistance);

    return max(r - C_SPHERE_RADIUS, geometryDistance);
}

float mirrorDistance3D(vec3 p)
{
    float dA = abs(dot(p, gMirrors3D[0].xyz));
    float dB = abs(dot(p, gMirrors3D[1].xyz));
    float dC = abs(dot(p, gMirrors3D[2].xyz));
    float dD = abs(length(p - gMirrors3D[3].xyz) - gMirrors3D[3].w);
    return min(dA, min(dB, min(dC, dD)));
}

vec3 planeToSphere(vec2 p)
{
    float r2 = dot(p, p);
    return vec3(2.0 * p, r2 - 1.0) / (1.0 + r2);
}

vec3 floorPatternColor(bool found, int count)
{
    if (found)
        return (count % 2 == 0) ? FLOOR_CHECKER_COLOR1 : FLOOR_CHECKER_COLOR2;
    return FLOOR_LINE_COLOR;
}

vec3 honeycombBaseColor(vec3 pos)
{
    vec3 originalPos = pos;
    float upperFloorDistance = pos.z - 1.0e-3;

    if (DO_UPPER_HALF_SPACE)
    {
        pos.z += 1.0;
        float p2 = max(dot(pos, pos), 1.0e-30);
        pos *= 2.0 / p2;
        pos.z -= 1.0;
    }

    float r = length(pos);
    vec4 q = ballLift(pos);
    bool found = fold4D(q);
    if (!found) return BACKGROUND_COLOR;

    float dA = segmentDistance(q, gMirrors[0], r);
    float dB = segmentDistance(q, gMirrors[1], r);
    float dC = segmentDistance(q, gMirrors[2], r);
    float dD = segmentDistance(q, gMirrors[3], r);
    float dV = vertexDistance(q, r);

    float dAB = ENABLE_FACE_AB ? faceDistance(q, r, gMirrors[0], gMirrors[1]) : 1.0e5;
    float dAC = ENABLE_FACE_AC ? faceDistance(q, r, gMirrors[0], gMirrors[2]) : 1.0e5;
    float dAD = ENABLE_FACE_AD ? faceDistance(q, r, gMirrors[0], gMirrors[3]) : 1.0e5;
    float dBC = ENABLE_FACE_BC ? faceDistance(q, r, gMirrors[1], gMirrors[2]) : 1.0e5;
    float dBD = ENABLE_FACE_BD ? faceDistance(q, r, gMirrors[1], gMirrors[3]) : 1.0e5;
    float dCD = ENABLE_FACE_CD ? faceDistance(q, r, gMirrors[2], gMirrors[3]) : 1.0e5;

    float dF = min(dAB, min(dAC, min(dAD, min(dBC, min(dBD, dCD)))));
    vec3 faceColor = FACES_COLOR;
    if (dF == dAB) faceColor = FACE_AB_COLOR;
    if (dF == dAC) faceColor = FACE_AC_COLOR;
    if (dF == dAD) faceColor = FACE_AD_COLOR;
    if (dF == dBC) faceColor = FACE_BC_COLOR;
    if (dF == dBD) faceColor = FACE_BD_COLOR;
    if (dF == dCD) faceColor = FACE_CD_COLOR;

    float d = min(dF, min(min(min(dA, dB), min(dC, dD)), dV));
    if (DO_UPPER_HALF_SPACE)
        d = min(d, upperFloorDistance);

    vec3 color = SEG_A_COLOR;
    if (d == dB) color = SEG_B_COLOR;
    if (d == dC) color = SEG_C_COLOR;
    if (d == dD) color = SEG_D_COLOR;
    if (d == dV) color = VERTICES_COLOR;
    if (d == dF) color = faceColor;

    if (DO_UPPER_HALF_SPACE && d == upperFloorDistance)
    {
        if (DRAW_FLOOR_PATTERN)
        {
            int count = 0;
            vec3 spherePoint = planeToSphere(originalPos.xy);
            bool patternFound = fold3D(spherePoint, count);
            color = floorPatternColor(patternFound, count);

            float edgeDistance = mirrorDistance3D(spherePoint);
            float aa = 0.5 * fwidth(edgeDistance);
            float lineMask = 1.0 - smoothstep(
                FLOOR_LINE_THICKNESS - aa,
                FLOOR_LINE_THICKNESS + aa,
                edgeDistance
            );
            color = mix(color, FLOOR_LINE_COLOR, lineMask);
        }
        else
        {
            color = BACKGROUND_COLOR;
        }
    }

    return color;
}

// -----------------------------------------------------------------------------
// Scene distance with the generic Euclidean floor
// -----------------------------------------------------------------------------

float externalFloorDistance(vec3 p)
{
    return abs(dot(FLOOR_NORMAL, p) - FLOOR_HEIGHT);
}

float sceneDistance(vec3 p)
{
    float d = DE(p);
    return ENABLE_FLOOR ? min(d, externalFloorDistance(p)) : d;
}

bool isExternalFloorClosest(vec3 p)
{
    return ENABLE_FLOOR && externalFloorDistance(p) <= DE(p);
}

float lightDistance(vec3 p)
{
    return length(LIGHT_POS - p) - LIGHT_SIZE;
}

// -----------------------------------------------------------------------------
// Thin-lens ray representation
// -----------------------------------------------------------------------------

struct SRay
{
    vec3 Origin;
    vec3 Direction;
    vec3 Offset;
    float Pos;
    float fudge;
    float iFP;
};

vec3 rayCurrentPoint(SRay ray)
{
    float t = ray.Pos;
    return ray.Origin + ray.Direction * t + ray.Offset *
        (1.0 - t * ray.iFP +
         clamp(t * ray.iFP - 1.0, -IN_FOCUS_A_WIDTH, IN_FOCUS_A_WIDTH));
}

void rayAdvance(inout SRay ray, float distance)
{
    ray.Pos += distance * ray.fudge;
}

SRay rayReflect(SRay ray, vec3 normal, float eps)
{
    vec3 hit = rayCurrentPoint(ray);
    ray.Direction = reflect(ray.Direction, normal);
    ray.Offset = reflect(ray.Offset, normal);
    ray.Origin = hit + reflect(ray.Origin - hit, normal);
    ray.Pos += eps;
    return ray;
}

// -----------------------------------------------------------------------------
// Normal, shadow and ambient occlusion
// -----------------------------------------------------------------------------

vec3 calcNormal(vec3 p, float normalDistance)
{
    float e = max(normalDistance * 0.5, 1.0e-5);
    vec3 ex = vec3(e, 0.0, 0.0);
    vec3 ey = vec3(0.0, e, 0.0);
    vec3 ez = vec3(0.0, 0.0, e);

    vec3 n = vec3(
        DE(p + ex) - DE(p - ex),
        DE(p + ey) - DE(p - ey),
        DE(p + ez) - DE(p - ez)
    );

    float n2 = dot(n, n);
    return (n2 > 0.0 && n2 < 1.0e30) ? n * inversesqrt(n2) : vec3(0.0);
}

float linstep(float a, float b, float t)
{
    return clamp((t - a) / max(b - a, MIN_EPS), 0.0, 1.0);
}

float shadow(vec3 ro, vec3 lightPos, float eps)
{
    float rCoC = max(eps, MIN_EPS);
    vec3 rd = lightPos - ro;
    float lightDist = length(rd);
    rd /= max(lightDist, MIN_EPS);

    float coneGrad = (SHADOW_SOFT == 0.0)
        ? LIGHT_SIZE / max(lightDist, MIN_EPS)
        : 1.0 / SHADOW_SOFT;

    float t = sceneDistance(ro) + rCoC;
    float s = 1.0;
    float jitter = DITHER * (rand1(ro.xy * (float(iFrame) + 1.0)) - 0.5);

    for (int i = 0; i < MAX_RAY_STEPS; ++i)
    {
        if (t > lightDist || s < 0.001) break;

        float radius = rCoC + t * coneGrad;
        float d = sceneDistance(ro + rd * (t + radius * jitter));
        s *= linstep(-radius, radius, d);
        t += abs(0.75 * d + 0.25 * radius) + MIN_EPS;
    }

    s = max(0.0, s - 0.001) / 0.999;
    return clamp(1.0 - s, 0.0, 1.0);
}

vec3 ortho(vec3 v)
{
    return abs(v.x) > abs(v.z)
        ? vec3(-v.y, v.x, 0.0)
        : vec3(0.0, -v.z, v.y);
}

vec2 rand2AO()
{
    gAOSeed += vec2(-1.0, 1.0);
    return rand2(gAOSeed);
}

vec3 getAODirection(vec3 direction)
{
    vec3 o1 = normalize(ortho(direction));
    vec3 o2 = cross(direction, o1);
    vec2 r = rand2AO();

    r.x *= TWO_PI;
    r.y *= CONE_APERTURE_AO;

    float radial = sqrt(max(r.y, 0.0));
    float axial = sqrt(max(1.0 - r.y, 0.0));
    return cos(r.x) * radial * o1 +
           sin(r.x) * radial * o2 + axial * direction;
}

float ambientOcclusion(vec3 p, vec3 n)
{
    vec3 sampleDirection = getAODirection(n);
    float de = sceneDistance(p) / max(gAOEps, MIN_EPS);
    if (abs(de) < MIN_EPS) de = MIN_EPS;

    float ao = 0.0;
    float weightSum = 0.0;
    float d = 1.0 - DITHER * rand1(p.xy);
    float D = 1.0;

    for (int i = 1; i < MAX_AO_ITER; ++i)
    {
        float previousD = D;
        float denominator = d * de * dot(sampleDirection, n) * FUDGE_AO;
        if (abs(denominator) < MIN_EPS)
            denominator = (denominator < 0.0 ? -1.0 : 1.0) * MIN_EPS;

        D = sceneDistance(p + d * sampleDirection * de) / denominator;
        D = min(previousD, D);

        ao += clamp(1.0 - D, 0.0, 1.0);
        weightSum += 1.0;
        d *= 1.61;
    }

    return ao / max(weightSum, 1.0);
}

// -----------------------------------------------------------------------------
// Fog and lighting
// -----------------------------------------------------------------------------

float expSafe(float x)
{
    return exp(clamp(x, -80.0, 80.0));
}

vec3 expSafe(vec3 x)
{
    return exp(clamp(x, vec3(-80.0), vec3(80.0)));
}

float oneMinusExpNegOverX(float x)
{
    if (abs(x) < 1.0e-5)
        return 1.0 - 0.5 * x + x * x / 6.0;
    return (1.0 - expSafe(-x)) / x;
}

vec3 fogTransmission(vec3 p0, vec3 p1)
{
    vec3 fogDirection = normalize(HF_DIR);
    vec3 segment = p1 - p0;
    float distanceTravelled = length(segment);
    float x = HF_FALLOFF * dot(segment, fogDirection);
    float integralFactor = oneMinusExpNegOverX(x);

    vec3 amount = HF_COLOR.rgb *
        (HF_INTENSITY *
         expSafe(-HF_FALLOFF * (dot(p0, fogDirection) - HF_OFFSET)) *
         integralFactor + HF_CONST) * distanceTravelled;

    return clamp(expSafe(-amount), vec3(0.0), vec3(1.0));
}

vec3 pointLightGlow(float glow)
{
    if (!SPOT_GLOW) return vec3(0.0);

    float glow1 = exp(-pow(LIGHT_GLOW_RAD + 0.0001, -2.0) *
                      pow(max(glow, 0.0), LIGHT_GLOW_EXP));
    float glow2 = exp(-20.0 * max(glow, 0.0));
    return SPOT_LIGHT.rgb * (glow2 * SPOT_LIGHT.w + glow1);
}

vec3 lighting(
    vec3 n,
    vec3 materialColor,
    vec3 pos,
    vec3 rayDirection,
    float eps,
    out float shadowStrength,
    float ao)
{
    shadowStrength = 0.0;
    vec3 color = vec3(0.0);

    vec3 toLight = LIGHT_POS - pos;
    float distanceSquared = max(dot(toLight, toLight), MIN_EPS);
    float falloff = pow(distanceSquared, -LIGHT_FALLOFF);
    vec3 lightDirection = toLight * inversesqrt(distanceSquared);

    float nDotL = max(AO_CORRECT, dot(n, lightDirection));
    vec3 halfVector = normalize(-rayDirection + lightDirection);
    float hDotN = max(0.0, dot(n, halfVector));

    float f0 = (SPECULAR_EXP - 1.0) / (SPECULAR_EXP + 1.0);
    f0 *= f0;
    float fresnel = f0 + (1.0 - f0) * pow(1.0 + dot(n, rayDirection), 5.0);

    float diffuse = nDotL;
    float specular = ((SPECULAR_EXP + 2.0) / 8.0) * fresnel * nDotL *
                     pow(hDotN, SPECULAR_EXP + 0.00001) * SPECULAR;

    if (HARD_SHADOW > 0.0)
    {
        shadowStrength = shadow(pos + n * eps, LIGHT_POS, eps);
        diffuse = mix(diffuse, 0.0, HARD_SHADOW * shadowStrength);
        specular *= 1.0 - shadowStrength;
    }

    vec3 fogToLight = fogTransmission(pos, LIGHT_POS);
    color += fogToLight * SPOT_LIGHT.rgb * SPOT_LIGHT.w * falloff *
             (diffuse + specular) *
             (1.0 - clamp(AO_POINTLIGHT * ao, 0.0, 1.0));

    nDotL = max(AO_CORRECT, dot(n, -rayDirection));
    hDotN = max(0.0, dot(n, -rayDirection));
    diffuse = nDotL;
    specular = ((SPECULAR_EXP + 2.0) / 8.0) * fresnel * nDotL *
               pow(hDotN, SPECULAR_EXP + 0.00001) * SPECULAR;

    color += CAM_LIGHT.rgb * CAM_LIGHT.a * (diffuse + specular) *
             (1.0 - clamp(AO_CAMLIGHT * ao, 0.0, 1.0));

    color += AMBIENT_LIGHT.rgb * AMBIENT_LIGHT.a *
             (1.0 - clamp(AO_AMBIENT * ao, 0.0, 1.0));

    return color * materialColor;
}

vec3 volumetricPointLight(vec3 p0, vec3 p1, float stratum)
{
    vec3 segment = p1 - p0;
    float C = dot(segment, segment);
    if (C < MIN_EPS) return vec3(0.0);

    vec3 fromLight = p0 - LIGHT_POS;
    float A = dot(fromLight, fromLight);
    float B = dot(segment, fromLight);
    float delta = sqrt(max(A * C - B * B, 1.0e-12));

    float x = (rand1(gViewCoord + vec2(1.6183 + float(iFrame) + stratum)) +
               stratum) / float(HF_FOG_ITER);

    float atanB = atan(B / delta);
    float atanBC = atan((B + C) / delta);
    float pdfNormalization = (atanBC - atanB) / delta;

    float t = (tan(mix(atanB, atanBC, x)) * delta - B) / C;
    t = clamp(t, 0.0001, 1.0);

    vec3 samplePoint = p0 + t * segment;
    vec3 extinctionEye = fogTransmission(p0, samplePoint);
    vec3 extinctionLight = fogTransmission(samplePoint, LIGHT_POS);

    vec3 fogDirection = normalize(HF_DIR);
    float height = HF_FALLOFF * (dot(samplePoint, fogDirection) - HF_OFFSET);
    vec3 density = HF_COLOR.rgb * HF_INTENSITY * expSafe(-height) + vec3(HF_CONST);

    float visibility = 1.0;
    if (HF_CAST_SHADOW)
        visibility = 1.0 - shadow(samplePoint, LIGHT_POS, 0.001);

    float cosTheta = dot(
        normalize(samplePoint - p0),
        normalize(LIGHT_POS - samplePoint)
    );

    vec3 denominator = vec3(1.0) + HF_ANISOTROPY * HF_ANISOTROPY -
                       2.0 * HF_ANISOTROPY * cosTheta;
    vec3 phase = (vec3(1.0) - HF_ANISOTROPY * HF_ANISOTROPY) /
                 sqrt(max(denominator * denominator * denominator,
                          vec3(1.0e-12)));

    vec3 sampleValue = extinctionEye * extinctionLight * density * phase *
                       visibility * length(segment);

    return SPOT_LIGHT.rgb * SPOT_LIGHT.w * pdfNormalization *
           sampleValue * HF_SCATTER;
}

// -----------------------------------------------------------------------------
// Ray tracing
// -----------------------------------------------------------------------------

vec3 trace(inout SRay ray, out vec3 hitNormal, out float glow)
{
    glow = 1000.0;
    hitNormal = vec3(0.0);

    bool hitSomething = false;
    bool hitFloor = false;
    bool hitPointLight = false;

    float distanceStep = 0.0;
    float lightDE = 0.0;
    float epsModified = max(MIN_EPS, ray.Pos * gMinDist);

    vec3 p = rayCurrentPoint(ray);
    float firstSceneDistance = sceneDistance(p);
    float firstStep = min(firstSceneDistance * FUDGE_FACTOR, lightDistance(p));
    firstStep *= DITHER * rand1(ray.Direction.xy) + (1.0 - DITHER);
    rayAdvance(ray, firstStep);

    for (int i = 0; i < MAX_RAY_STEPS; ++i)
    {
        p = rayCurrentPoint(ray);

        lightDE = lightDistance(p);
        float sceneDE = sceneDistance(p);
        distanceStep = min(lightDE, sceneDE * FUDGE_FACTOR);
        glow = min(lightDE, glow);

        rayAdvance(ray, distanceStep);
        epsModified = max(MIN_EPS, ray.Pos * gMinDist);

        if (distanceStep < epsModified)
        {
            for (int j = 0; j < REFINE_STEPS; ++j)
            {
                rayAdvance(ray, distanceStep - 1.5 * epsModified);
                p = rayCurrentPoint(ray);
                lightDE = lightDistance(p);
                sceneDE = sceneDistance(p);
                distanceStep = min(lightDE, sceneDE * FUDGE_FACTOR);
                glow = min(lightDE, glow);
            }

            hitSomething = true;
            p = rayCurrentPoint(ray);
            hitPointLight = lightDE <= sceneDistance(p) * FUDGE_FACTOR;
            hitFloor = !hitPointLight && isExternalFloorClosest(p);
            break;
        }

        if (ray.Pos > MAX_DISTANCE) break;
    }

    vec3 background = BACKGROUND_COLOR;
    if (GRADIENT_BACKGROUND > 0.0)
        background = mix(background, vec3(0.0), length(gCoord) * GRADIENT_BACKGROUND);

    if (!hitSomething)
    {
        ray.Pos = MAX_DISTANCE;
        return background;
    }

    if (hitPointLight)
    {
        gLightHit = true;
        return SPOT_LIGHT.rgb * SPOT_LIGHT.w / (LIGHT_SIZE + 0.01);
    }

    vec3 hit = rayCurrentPoint(ray);
    if (hitFloor)
    {
        hitNormal = FLOOR_NORMAL;
        if (dot(FLOOR_NORMAL, hit) - FLOOR_HEIGHT < 0.0)
            hitNormal = -hitNormal;
    }
    else
    {
        hitNormal = calcNormal(
            hit - NORMAL_BACK_STEP * epsModified * ray.Direction,
            epsModified
        );
    }

    vec3 materialColor = hitFloor
        ? FLOOR_COLOR
        : mix(BASE_COLOR, honeycombBaseColor(hit), ORBIT_STRENGTH);

    materialColor = pow(clamp(materialColor, 0.0, 1.0), vec3(GAMMA_VALUE));

    float ao = 0.0;
    if (DETAIL_AO < 0.0)
        ao = ambientOcclusion(hit, hitNormal);

    float shadowStrength;
    return lighting(
        hitNormal,
        materialColor,
        hit,
        ray.Direction,
        epsModified,
        shadowStrength,
        ao
    );
}

vec3 renderScene(SRay ray)
{
    gMinDist = pow(10.0, DETAIL);
    gAOEps = pow(10.0, DETAIL_AO);
    gAOSeed = gViewCoord * (float(iFrame) + 1.0);
    gLightHit = false;

    vec3 color = vec3(0.0);
    vec3 reflectionWeight = vec3(1.0);

    for (int bounce = 0; bounce <= REFLECTIONS_NUMBER; ++bounce)
    {
        vec3 previousPosition = rayCurrentPoint(ray);

        vec3 hitNormal;
        float glow;
        vec3 bounceColor = trace(ray, hitNormal, glow);
        vec3 currentPosition = rayCurrentPoint(ray);

        vec3 fog = fogTransmission(previousPosition, currentPosition);
        bounceColor = mix(HF_COLOR.rgb * HF_COLOR.a, bounceColor, fog);
        bounceColor += pointLightGlow(max(0.0, glow));

        if (HF_SCATTER * (HF_INTENSITY + HF_CONST) > 0.0)
        {
            vec3 fogGlow = vec3(0.0);
            for (int j = 0; j < HF_FOG_ITER; ++j)
                fogGlow += volumetricPointLight(
                    previousPosition,
                    currentPosition,
                    float(j)
                );
            bounceColor += fogGlow / float(HF_FOG_ITER);
        }

        color += bounceColor * reflectionWeight;
        reflectionWeight *= REFLECTION * fog;

        if (dot(hitNormal, hitNormal) < 1.0e-20 ||
            dot(reflectionWeight, reflectionWeight) < 0.0001 ||
            gLightHit || ray.Pos >= MAX_DISTANCE)
        {
            break;
        }

        ray = rayReflect(ray, hitNormal, gMinDist);
    }

    return max(color, vec3(0.0));
}

// -----------------------------------------------------------------------------
// Camera and progressive accumulation
// -----------------------------------------------------------------------------

vec3 equirectangularDirection(vec2 screenCoord, vec3 dir, vec3 up, vec3 right)
{
    vec2 angles = vec2(screenCoord.x, (1.0 - screenCoord.y) * 0.5) * PI;
    return cos(angles.x) * sin(angles.y) * dir +
           sin(angles.x) * sin(angles.y) * right +
           cos(angles.y) * up;
}

SRay makeCameraRay(vec2 fragCoord, out vec2 discSample)
{
    vec2 uv = fragCoord / iResolution.xy;

    gViewCoord = uv * 2.0 - 1.0;
    gCoord = (2.0 * fragCoord - iResolution.xy) / iResolution.y;
    gPixelScale = 2.0 / iResolution.xy;

    gFrom = EYE;
    gDir = normalize(TARGET - EYE);
    vec3 normalizedUp = normalize(UP);
    gUpOrtho = normalize(normalizedUp - dot(gDir, normalizedUp) * gDir);
    gRight = normalize(cross(gDir, gUpOrtho));

    gCoord *= FOV;

    float frame = float(iFrame) + 1.0;
    vec2 apertureSample = APERTURE *
        ((APERTURE_NBR_SIDES == 2)
            ? uniformDisc(gViewCoord * frame)
            : nGonDisc(gViewCoord * frame));

    discSample = uniformDisc(gCoord * frame);

    vec2 jitteredCoord;
    if (EQUIRECTANGULAR)
        jitteredCoord = ANTI_ALIAS_SCALE * gPixelScale * discSample;
    else
        jitteredCoord = gCoord +
            ANTI_ALIAS_SCALE * gPixelScale * FOV * discSample;

    vec3 lensOffset = apertureSample.x * gRight +
                      apertureSample.y * gUpOrtho;

    vec3 rayDirection = gDir +
                        jitteredCoord.x * gRight +
                        jitteredCoord.y * gUpOrtho;

    if (EQUIRECTANGULAR)
        rayDirection = equirectangularDirection(
            gViewCoord,
            rayDirection,
            gUpOrtho,
            gRight
        );

    float rayDirectionLength = length(rayDirection);
    float focusTerm = 1.0 - 1.0 / FOCAL_PLANE +
        clamp(1.0 / FOCAL_PLANE - 1.0,
              -IN_FOCUS_A_WIDTH,
               IN_FOCUS_A_WIDTH);
    float fpO1 = length(rayDirection + lensOffset * focusTerm);

    SRay ray;
    ray.Origin = gFrom;
    ray.Direction = rayDirection / rayDirectionLength;
    ray.Offset = lensOffset;
    ray.Pos = 0.0;
    ray.fudge = 1.0 / max(1.0, fpO1);
    ray.iFP = 1.0 / FOCAL_PLANE;
    return ray;
}

void mainImage(out vec4 fragColor, in vec2 fragCoord)
{
    initHoneycomb();

    vec2 discSample;
    SRay ray = makeCameraRay(fragCoord, discSample);
    vec3 sampleColor = renderScene(ray);

    float weight = 1.0 - length(discSample);
    if (GAUSSIAN_WEIGHT > 0.0)
    {
        weight = exp(-dot(discSample, discSample) / GAUSSIAN_WEIGHT) -
                 exp(-1.0 / GAUSSIAN_WEIGHT);
    }

    vec4 previous = vec4(0.0);
    if (iFrame > 0)
        previous = texelFetch(iChannel0, ivec2(fragCoord), 0);

    fragColor = previous + vec4(sampleColor * weight, weight);
}

/* PRESET: 535-1100; ToneMapping=5 */

/*
    Coxeter hyperbolic honeycomb: Fragmentarium postprocess -> Shadertoy Image pass

    Shadertoy setup:
      Image / iChannel0 = Buffer A

    Buffer A is expected to store:
      rgb = weighted HDR color sum
      a   = accumulated sample weight

    The constants below reproduce the honeycomb preset supplied with the scene shader.
*/

// -----------------------------------------------------------------------------
// Preset values
// -----------------------------------------------------------------------------

const float GAMMA_VALUE     = 2.2;
const int   TONE_MAPPING    = 5;
const float EXPOSURE        = 1.0;
const float BRIGHTNESS      = 1.0;
const float CONTRAST        = 1.0;
const float SATURATION      = 1.0;

const bool  ENABLE_BLOOM    = false;
const float BLOOM_INTENSITY = 0.25;
const float BLOOM_POW       = 2.0;
const int   BLOOM_TAPS      = 4;

// Lens flare was commented out in the supplied Fragmentarium shader.
// It is included here as an optional Shadertoy-compatible path.
const bool  ENABLE_LENS_FLARE = false;
const float FLARE_INTENSITY   = 0.25;
const int   FLARE_SAMPLES     = 8;
const float FLARE_DISPERSAL   = 0.25;
const float FLARE_HALO_WIDTH  = 0.5;
const float FLARE_DISTORTION  = 1.0;

const vec3 RGB_TO_LUMA = vec3(0.2125, 0.7154, 0.0721);

// -----------------------------------------------------------------------------
// Accumulation-buffer access
// -----------------------------------------------------------------------------

vec4 sampleAccumulation(vec2 uv)
{
    return texture(iChannel0, uv);
}

vec3 resolveAccumulation(vec4 value)
{
    return value.rgb / max(value.a, 1.0e-8);
}

vec3 sampleResolved(vec2 uv)
{
    return resolveAccumulation(sampleAccumulation(uv));
}

// -----------------------------------------------------------------------------
// RGB <-> HSV
// Kept from the original postprocessor for compatibility and future edits.
// -----------------------------------------------------------------------------

vec3 rgb2hsv(vec3 c)
{
    vec4 K = vec4(0.0, -1.0 / 3.0, 2.0 / 3.0, -1.0);
    vec4 p = mix(vec4(c.bg, K.wz), vec4(c.gb, K.xy), step(c.b, c.g));
    vec4 q = mix(vec4(p.xyw, c.r), vec4(c.r, p.yzx), step(p.x, c.r));

    float d = q.x - min(q.w, q.y);
    float e = 1.0e-10;
    return vec3(
        abs(q.z + (q.w - q.y) / (6.0 * d + e)),
        d / (q.x + e),
        q.x
    );
}

vec3 hsv2rgb(vec3 c)
{
    vec4 K = vec4(1.0, 2.0 / 3.0, 1.0 / 3.0, 3.0);
    vec3 p = abs(fract(c.xxx + K.xyz) * 6.0 - K.www);
    return c.z * mix(K.xxx, clamp(p - K.xxx, 0.0, 1.0), c.y);
}

// -----------------------------------------------------------------------------
// Brightness / saturation / contrast
// -----------------------------------------------------------------------------

vec3 contrastSaturationBrightness(
    vec3 color,
    float brightness,
    float saturation,
    float contrast
)
{
    const vec3 LUMA = vec3(0.2125, 0.7154, 0.0721);

    vec3 brightColor = color * brightness;
    float intensityValue = dot(brightColor, LUMA);
    vec3 intensity = vec3(intensityValue);
    vec3 saturatedColor = mix(intensity, brightColor, saturation);
    vec3 contrastedColor = mix(vec3(0.5), saturatedColor, contrast);

    return clamp(contrastedColor, 0.0, 1.0);
}

// -----------------------------------------------------------------------------
// Tone mapping functions
// -----------------------------------------------------------------------------

float syntopiaSigmoid(float t)
{
    float k = 1.0 - 1.0 / (1.0 + exp(-0.5 * CONTRAST * 5.0));
    t -= 0.5;

    float x = 1.0 / (1.0 + exp(-t * CONTRAST * 5.0)) - k;
    return x / (1.0 - 2.0 * k);
}

vec3 syntopiaSigmoid(vec3 value)
{
    return vec3(
        syntopiaSigmoid(value.r),
        syntopiaSigmoid(value.g),
        syntopiaSigmoid(value.b)
    );
}

// Lottes 2016, "Advanced Techniques and Optimization of HDR Color Pipelines"
vec3 lottesToneMap(vec3 x)
{
    const vec3 a      = vec3(1.6);
    const vec3 d      = vec3(0.977);
    const vec3 hdrMax = vec3(8.0);
    const vec3 midIn  = vec3(0.18);
    const vec3 midOut = vec3(0.267);

    const vec3 b =
        (-pow(midIn, a) + pow(hdrMax, a) * midOut) /
        ((pow(hdrMax, a * d) - pow(midIn, a * d)) * midOut);

    const vec3 c =
        (pow(hdrMax, a * d) * pow(midIn, a)
        - pow(hdrMax, a) * pow(midIn, a * d) * midOut) /
        ((pow(hdrMax, a * d) - pow(midIn, a * d)) * midOut);

    return pow(x, a) / (pow(x, a * d) * b + c);
}

// Uchimura 2017, "HDR theory and practice"
vec3 uchimuraToneMap(
    vec3 x,
    float maximumDisplayBrightness,
    float contrast,
    float linearStart,
    float linearLength,
    float black,
    float pedestal
)
{
    float P = maximumDisplayBrightness;
    float a = contrast;
    float m = linearStart;
    float l = linearLength;
    float c = black;
    float b = pedestal;

    float l0 = ((P - m) * l) / a;
    float L0 = m - m / a;
    float L1 = m + (1.0 - m) / a;
    float S0 = m + l0;
    float S1 = m + a * l0;
    float C2 = (a * P) / (P - S1);
    float CP = -C2 / P;

    vec3 w0 = vec3(1.0) - smoothstep(vec3(0.0), vec3(m), x);
    vec3 w2 = step(vec3(m + l0), x);
    vec3 w1 = vec3(1.0) - w0 - w2;

    vec3 T = vec3(m) * pow(x / m, vec3(c)) + vec3(b);
    vec3 S = vec3(P) - (P - S1) * exp(CP * (x - S0));
    vec3 L = vec3(m) + a * (x - m);

    // L0 and L1 are retained to mirror the published formulation.
    // They are not needed by the final piecewise expression.
    L0 += 0.0;
    L1 += 0.0;

    return T * w0 + L * w1 + S * w2;
}

vec3 uchimuraToneMap(vec3 x)
{
    const float P = 1.0;
    const float a = 1.0;
    const float m = 0.22;
    const float l = 0.4;
    const float c = 1.33;
    const float b = 0.0;

    return uchimuraToneMap(x, P, a, m, l, c, b);
}

vec3 uncharted2Partial(vec3 x)
{
    const float A = 0.15;
    const float B = 0.50;
    const float C = 0.10;
    const float D = 0.20;
    const float E = 0.02;
    const float F = 0.30;

    return ((x * (A * x + C * B) + D * E) /
           (x * (A * x + B) + D * F)) - E / F;
}

vec3 uncharted2ToneMap(vec3 color)
{
    const float WHITE_POINT = 11.2;
    const float EXPOSURE_BIAS = 2.0;

    vec3 current = uncharted2Partial(EXPOSURE_BIAS * color);
    vec3 whiteScale = vec3(1.0) / uncharted2Partial(vec3(WHITE_POINT));
    return current * whiteScale;
}

vec3 applyToneMapping(vec3 color)
{
    vec3 c = color;

    if (TONE_MAPPING == 1)
    {
        // Linear
        c *= EXPOSURE;
        c = contrastSaturationBrightness(c, BRIGHTNESS, SATURATION, CONTRAST);
    }
    else if (TONE_MAPPING == 2)
    {
        // Exponential exposure
        c = vec3(1.0) - exp(-c * EXPOSURE);
        c = contrastSaturationBrightness(c, BRIGHTNESS, SATURATION, CONTRAST);
    }
    else if (TONE_MAPPING == 3)
    {
        // Filmic curve used by the original Fragmentarium shader
        c *= EXPOSURE;
        vec3 x = max(vec3(0.0), c - vec3(0.004));
        c = (x * (6.2 * x + 0.5)) /
            (x * (6.2 * x + 1.7) + 0.06);

        // This curve includes a 2.2 encoding step in the original code.
        c = pow(max(c, vec3(0.0)), vec3(2.2));
        c = contrastSaturationBrightness(c, BRIGHTNESS, SATURATION, CONTRAST);
    }
    else if (TONE_MAPPING == 4)
    {
        // Reinhard (called "Reinhart" in the source comments)
        c *= EXPOSURE;
        c = c / (vec3(1.0) + c);
        c = contrastSaturationBrightness(c, BRIGHTNESS, SATURATION, CONTRAST);
    }
    else if (TONE_MAPPING == 5)
    {
        // Exact Fragmentarium / Syntopia sigmoid path.
        // As in the original code, Saturation is not applied in this mode.
        c = syntopiaSigmoid(c * EXPOSURE + vec3(BRIGHTNESS - 1.0));
    }
    else if (TONE_MAPPING == 6)
    {
        c *= EXPOSURE;
        c = lottesToneMap(max(c, vec3(0.0)));
        c = contrastSaturationBrightness(c, BRIGHTNESS, SATURATION, CONTRAST);
    }
    else if (TONE_MAPPING == 7)
    {
        c *= EXPOSURE;
        c = uchimuraToneMap(max(c, vec3(0.0)));
        c = contrastSaturationBrightness(c, BRIGHTNESS, SATURATION, CONTRAST);
    }
    else if (TONE_MAPPING == 8)
    {
        c *= EXPOSURE;
        c = uncharted2ToneMap(max(c, vec3(0.0)));
        c = contrastSaturationBrightness(c, BRIGHTNESS, SATURATION, CONTRAST);
    }
    else if (TONE_MAPPING == 9)
    {
        // 3Dickulus luminance map
        c *= EXPOSURE;
        c *= dot(c, RGB_TO_LUMA);
        c = contrastSaturationBrightness(c, BRIGHTNESS, SATURATION, CONTRAST);
    }

    return c;
}

// -----------------------------------------------------------------------------
// Bloom
// -----------------------------------------------------------------------------

vec3 bloomColor(vec2 uv)
{
    vec2 texelSize = 1.0 / iResolution.xy;
    vec4 sum = vec4(0.0);

    // BLOOM_TAPS is a compile-time constant, which keeps this loop compatible
    // with Shadertoy's WebGL compiler.
    for (int x = -BLOOM_TAPS; x <= BLOOM_TAPS; ++x)
    {
        float fx = float(x) / max(float(BLOOM_TAPS), 1.0);
        float wx = 1.0 - fx * fx;
        wx = wx * wx * wx;

        for (int y = -BLOOM_TAPS; y <= BLOOM_TAPS; ++y)
        {
            float fy = float(y) / max(float(BLOOM_TAPS), 1.0);
            float wy = 1.0 - fy * fy;
            wy = wy * wy * wy;

            vec2 offset = vec2(float(x), float(y)) * texelSize;
            sum += sampleAccumulation(uv + offset) * (wx * wy);
        }
    }

    // Dividing the raw accumulated sum by its alpha reproduces the original
    // b = bloom(...); b /= b.w behavior. The omitted sample-count factor
    // cancels between numerator and denominator.
    return resolveAccumulation(sum);
}

// -----------------------------------------------------------------------------
// Optional lens flare conversion
// -----------------------------------------------------------------------------

vec4 textureDistorted(
    vec2 uv,
    vec2 direction,
    vec4 distortion
)
{
    return vec4(
        sampleAccumulation(uv + direction * distortion.r).r,
        sampleAccumulation(uv + direction * distortion.g).g,
        sampleAccumulation(uv + direction * distortion.b).b,
        sampleAccumulation(uv + direction * distortion.a).a
    );
}

vec4 lensFlare(vec2 uv)
{
    vec2 texelSize = 1.0 / iResolution.xy;
    vec2 ghostVector = (vec2(0.5) - uv) * FLARE_DISPERSAL;

    float ghostLength = length(ghostVector);
    vec2 ghostDirection = ghostLength > 1.0e-8
        ? ghostVector / ghostLength
        : vec2(0.0);

    vec2 haloVector = ghostDirection * FLARE_HALO_WIDTH;
    vec4 distortion = vec4(
        -texelSize.x * FLARE_DISTORTION,
         0.0,
         texelSize.x * FLARE_DISTORTION,
         0.0
    );

    vec4 result = vec4(0.0);

    for (int i = 0; i < FLARE_SAMPLES; ++i)
    {
        vec2 offset = fract(uv + ghostVector * float(i));
        float radial = length(vec2(0.5) - offset) / length(vec2(0.5));
        float weight = pow(max(1.0 - radial, 0.0), 10.0);
        result += textureDistorted(offset, ghostDirection, distortion) * weight;
    }

    vec2 haloUV = fract(uv + haloVector);
    float haloRadial = length(vec2(0.5) - haloUV) / length(vec2(0.5));
    float haloWeight = pow(max(1.0 - haloRadial, 0.0), 10.0);
    result += textureDistorted(haloUV, ghostDirection, distortion) * haloWeight;

    return result;
}

// -----------------------------------------------------------------------------
// Shadertoy entry point
// -----------------------------------------------------------------------------

void mainImage(out vec4 fragColor, in vec2 fragCoord)
{
    vec2 uv = fragCoord / iResolution.xy;

    vec4 accumulated = sampleAccumulation(uv);
    vec3 color = resolveAccumulation(accumulated);

    if (ENABLE_BLOOM)
    {
        vec3 blurred = bloomColor(uv);
        color += BLOOM_INTENSITY * pow(
            max(blurred, vec3(0.0)),
            vec3(BLOOM_POW)
        );
    }

    if (ENABLE_LENS_FLARE)
    {
        vec4 flare = lensFlare(uv);
        color += FLARE_INTENSITY * resolveAccumulation(flare);
    }

    color = applyToneMapping(color);

    // Protect pow() from negative values generated by unusual parameter sets.
    color = pow(max(color, vec3(0.0)), vec3(1.0 / GAMMA_VALUE));

    fragColor = vec4(color, 1.0);
}

/*
    PRESET: 535-1100
    Coxeter diagram parameters: AB=5, AC=2, AD=2, BC=3, BD=2, CD=5
    activeMirrors = (1,1,0,0)
*/

/*
    Coxeter hyperbolic honeycomb
    Fragmentarium -> Shadertoy Buffer A port

    Shadertoy setup:
      Buffer A / iChannel0 = Buffer A (feedback)
      Image    / iChannel0 = Buffer A

    Buffer A stores the progressively accumulated HDR weighted sum in RGB
    and the accumulated Gaussian sample weight in A.
*/

#define MAX_RAY_STEPS       461
#define REFINE_STEPS        4
#define MAX_AO_ITER         5
#define MAX_FOLD4D_ITER     50
#define MAX_FOLD3D_ITER     300
#define REFLECTIONS_NUMBER  1
#define HF_FOG_ITER         1

const float PI      = 3.1415926535897932384626433832795;
const float TWO_PI  = 6.283185307179586476925286766559;
const float MIN_EPS = 1.1920928955078125e-7;

// -----------------------------------------------------------------------------
// Fixed values from the supplied Fragmentarium preset
// -----------------------------------------------------------------------------

// Camera
const bool  AUTO_FOCUS          = false;
const float FOV                 = 0.69812;
const vec3  EYE                 = vec3(0.030391141, 0.017976396, -0.238794912);
