int gFogStrata = 0;

// -----------------------------------------------------------------------------
// Random numbers
// -----------------------------------------------------------------------------

uint wangHash(uint seed)
{
    seed = (seed ^ 61u) ^ (seed >> 16u);
    seed *= 9u;
    seed ^= seed >> 4u;
    seed *= 0x27d4eb2du;
    seed ^= seed >> 15u;
    return seed;
}

float random2D(vec2 p)
{
    uint x = floatBitsToUint(p.x);
    uint y = floatBitsToUint(p.y);
    return float(wangHash(wangHash(x) + y)) / 4294967296.0;
}

float random3D(vec3 p)
{
    uint x = floatBitsToUint(p.x);
    uint y = floatBitsToUint(p.y);
    uint z = floatBitsToUint(p.z);
    return float(wangHash(wangHash(wangHash(x) + y) + z)) / 4294967296.0;
}

float random1D(float p)
{
    return random2D(vec2(p, p + 17.0));
}

vec2 random2(vec2 p)
{
    return vec2(
        fract(sin(dot(p, vec2(random1D(p.x) * 12.9898,
                               random1D(p.y) * 78.233))) * 43758.5453),
        fract(cos(dot(p, vec2(random1D(p.x) * 4.898,
                               random1D(p.y) * 7.23))) * 23421.631)
    );
}

vec2 uniformDisc(vec2 p)
{
    vec2 r = random2(p);
    float angle = r.x * 2.0 * PI;
    return sqrt(r.y) * vec2(cos(angle), sin(angle));
}

vec2 pentagonalStarAperture(vec2 p)
{
    vec2 r = random2(p);
    float d = 1.0 / tan(PI / 5.0);
    float scale = 1.0 / sqrt(1.0 + d * d);

    // ApStarShaped=true: do not fold p.x into a regular polygon.
    vec2 q = vec2(r.x + r.y, r.x - r.y);
    q.x *= d;
    q *= scale;

    float sectorRandom = dot(random2(11.0 * p + vec2(1.0)), vec2(1.0));
    float angle = floor(sectorRandom * 5.0) * (2.0 * PI / 5.0);
    vec2 cs = vec2(cos(angle), sin(angle));
    return vec2(cs.x * q.x - cs.y * q.y,
                cs.x * q.y + cs.y * q.x);
}

// -----------------------------------------------------------------------------
// Camera ray
// -----------------------------------------------------------------------------

struct SRay
{
    vec3 origin;
    vec3 direction;
    vec3 offset;
    float position;
    float fudge;
    float inverseFocalPlane;
};

vec3 currentPoint(SRay ray)
{
    float t = ray.position;
    vec3 p = ray.origin + ray.direction * t;
    t = 1.0 - t * ray.inverseFocalPlane;

    float d = t - IN_FOCUS_WIDTH *
        (2.0 * smoothstep(-1.5 * IN_FOCUS_WIDTH,
                           1.5 * IN_FOCUS_WIDTH, t) - 1.0);

    return p + ray.offset * d;
}

void advanceRay(inout SRay ray, float distance)
{
    ray.position += distance * ray.fudge;
}

SRay reflectRay(SRay ray, vec3 normal, float epsilon)
{
    vec3 hit = currentPoint(ray);
    ray.direction = reflect(ray.direction, normal);
    ray.offset = reflect(ray.offset, normal);
    ray.origin = hit + reflect(ray.origin - hit, normal);
    ray.position += epsilon;
    return ray;
}

float DE(vec3 p);
float DEFast(vec3 p);
float objectDistance(vec3 p){ return DEFast(p); }
float marchDistance(vec3 p){ return DE(p)*FUDGE_FACTOR; }
float marchDistanceFast(vec3 p){ return DEFast(p)*FUDGE_FACTOR; }

float lightDistance(vec3 p)
{
    return length(LIGHT_POS - p) - LIGHT_SIZE;
}

vec3 surfaceNormal(vec3 p, float normalDistance)
{
    normalDistance = max(normalDistance * 0.5, 1.0e-5);
    vec3 e = vec3(0.0, normalDistance, 0.0);
    vec3 n = vec3(
        DE(p + e.yxx) - DE(p - e.yxx),
        DE(p + e.xyx) - DE(p - e.xyx),
        DE(p + e.xxy) - DE(p - e.xxy)
    );
    n = normalize(n);
    return all(equal(n, n)) ? n : vec3(0.0);
}

// HF_Intensity=0, so the directional exponential-density term vanishes.
vec3 fogTransmission(vec3 p0, vec3 p1)
{
    float distance = length(p1 - p0);
    vec3 opticalDepth = HF_COLOR.rgb * HF_CONST * distance;
    return exp(-opticalDepth);
}

vec3 pointLightGlow(float glow)
{
    float g = max(glow, 0.0);
    float narrowGlow = exp(-1.0e8 * g); // LightGlowRad=0, LightGlowExp=1
    float broadGlow = exp(-20.0 * g);
    return SPOT_LIGHT.rgb * (broadGlow * SPOT_LIGHT.a + narrowGlow);
}

float linearStep(float a, float b, float t)
{
    return clamp((t - a) / (b - a), 0.0, 1.0);
}

// Eiffie shadow, specialized to perf=false and ShadowBlur=0.
float shadowAmount(vec3 origin, vec3 lightPosition, float epsilon)
{
    vec3 direction = lightPosition - origin;
    float lightLength = length(direction);
    direction /= lightLength;

    float coneRadius = epsilon;
    float t = marchDistanceFast(origin) + coneRadius;
    float shadow = 1.0;
    float jitter = DITHER *
        (random2D(origin.xy * (float(FRAME) + 1.0)) - 0.5);

    for (int i = 0; i < MAX_RAY_STEPS; ++i)
    {
        if (t > lightLength || shadow < 0.001)
            break;

        float d = marchDistanceFast(origin + direction * (t + coneRadius * jitter))
                + coneRadius;
        shadow *= linearStep(0.0, 2.0 * coneRadius, d);
        t += abs(0.75 * d + SHADOW_SOFT * coneRadius);
    }

    shadow = max(0.0, shadow - 0.001) / 0.999;
    return clamp(1.0 - shadow, 0.0, 1.0);
}

vec2 nextAORandom()
{
    gAOSeed += vec2(-1.0, 1.0);
    return vec2(
        fract(sin(dot(gAOSeed, vec2(12.9898, 78.233))) * 43758.5453),
        fract(cos(dot(gAOSeed, vec2(4.898, 7.23))) * 23421.631)
    );
}

vec3 orthogonalVector(vec3 v)
{
    return abs(v.x) > abs(v.z)
        ? vec3(-v.y, v.x, 0.0)
        : vec3(0.0, -v.z, v.y);
}

vec3 randomAODirection(vec3 normal)
{
    vec3 axis1 = normalize(orthogonalVector(normal));
    vec3 axis2 = cross(normal, axis1);
    vec2 r = nextAORandom();

    float angle = r.x * 2.0 * PI;
    float radial = sqrt(r.y * CONE_APERTURE_AO);
    float normalPart = sqrt(1.0 - r.y * CONE_APERTURE_AO);

    return cos(angle) * radial * axis1
         + sin(angle) * radial * axis2
         + normalPart * normal;
}

float ambientOcclusion(vec3 p, vec3 normal)
{
    vec3 direction = randomAODirection(normal);
    float baseDistance = objectDistance(p) / AO_EPS;
    float sampleDistance = 1.0 - DITHER * random2D(p.xy);
    float previousVisibility = 1.0;
    float occlusion = 0.0;

    for (int i = 1; i < MAX_ITER_AO; ++i)
    {
        float visibility = objectDistance(p + sampleDistance * direction * baseDistance);
        visibility /= sampleDistance * baseDistance
                    * dot(direction, normal) * FUDGE_AO;
        visibility = min(previousVisibility, visibility);

        occlusion += clamp(1.0 - visibility, 0.0, 1.0);
        previousVisibility = visibility;
        sampleDistance *= 1.61;
    }

    return occlusion / float(MAX_ITER_AO - 1);
}

vec3 applyLighting(
    vec3 normal,
    vec3 materialColor,
    vec3 position,
    vec3 rayDirection,
    float epsilon,
    float ao)
{
    vec3 color = vec3(0.0);
    vec3 lightDirection = normalize(LIGHT_POS - position);

    float nDotL = max(AO_CORRECT, dot(normal, lightDirection));
    vec3 halfVector = normalize(-rayDirection + lightDirection);
    float hDotN = max(0.0, dot(normal, halfVector));

    float f0 = (SPECULAR_EXP - 1.0) / (SPECULAR_EXP + 1.0);
    f0 *= f0;
    float fresnel = f0 + (1.0 - f0)
        * pow(1.0 + dot(normal, rayDirection), 5.0);

    float diffuse = nDotL;
    float specular = ((SPECULAR_EXP + 2.0) / 8.0)
        * fresnel * nDotL
        * pow(hDotN, SPECULAR_EXP + 0.00001) * SPECULAR;

    float shadow = shadowAmount(position + normal * epsilon,
                                LIGHT_POS, epsilon);
    diffuse = mix(diffuse, 0.0, HARD_SHADOW * shadow);
    specular *= 1.0 - shadow;

    vec3 lightFog = fogTransmission(position, LIGHT_POS);
    color += lightFog * SPOT_LIGHT.rgb * SPOT_LIGHT.a
        * (diffuse + specular)
        * (1.0 - clamp(AO_POINTLIGHT * ao, 0.0, 1.0));

    nDotL = max(AO_CORRECT, dot(normal, -rayDirection));
    hDotN = max(0.0, dot(normal, -rayDirection));
    diffuse = nDotL;
    specular = ((SPECULAR_EXP + 2.0) / 8.0)
        * fresnel * nDotL
        * pow(hDotN, SPECULAR_EXP + 0.00001) * SPECULAR;

    color += CAM_LIGHT.rgb * CAM_LIGHT.a
        * (diffuse + specular)
        * (1.0 - clamp(AO_CAMLIGHT * ao, 0.0, 1.0));

    color += AMBIENT_LIGHT.rgb * AMBIENT_LIGHT.a
        * (1.0 - clamp(AO_AMBIENT * ao, 0.0, 1.0));

    return color * materialColor;
}

vec3 orbitColor()
{
    gOrbitTrap.w = sqrt(gOrbitTrap.w);

    vec3 trapped =
        ORBIT_X.rgb * ORBIT_X.a * gOrbitTrap.x +
        ORBIT_Y.rgb * ORBIT_Y.a * gOrbitTrap.y +
        ORBIT_Z.rgb * ORBIT_Z.a * gOrbitTrap.z +
        ORBIT_R.rgb * ORBIT_R.a * gOrbitTrap.w;

    return mix(BASE_COLOR, 3.0 * trapped, ORBIT_STRENGTH);
}

vec3 traceScene(inout SRay ray, out vec3 hitNormal, out float glow)
{
    glow = 1000.0;
    hitNormal = vec3(0.0);
    gOrbitTrap = vec4(10000.0);

    float distance = 0.0;
    float lightDE = 0.0;
    float epsilon = max(MIN_EPS, ray.position * MIN_DIST * FUDGE_FACTOR);
    bool hitSomething = false;
    int steps = 0;

    vec3 p = currentPoint(ray);
    float firstStep = min(marchDistance(p), lightDistance(p));
    firstStep *= (1.0 - DITHER)
               + DITHER * random2D(ray.direction.xy);
    advanceRay(ray, firstStep);

    for (steps = 0; steps < MAX_RAY_STEPS; ++steps)
    {
        p = currentPoint(ray);
        lightDE = lightDistance(p);
        distance = min(lightDE, marchDistance(p));
        glow = min(glow, lightDE);
        advanceRay(ray, distance);

        epsilon = max(MIN_EPS,
                      ray.position * MIN_DIST * FUDGE_FACTOR);

        if (distance < epsilon)
        {
            for (int i = 0; i < REFINE_STEPS; ++i)
            {
                advanceRay(ray, distance - 1.5 * epsilon);
                p = currentPoint(ray);
                lightDE = lightDistance(p);
                distance = min(lightDE, marchDistance(p));
                glow = min(glow, lightDE);
            }
            hitSomething = true;
            break;
        }

        if (ray.position > MAX_DISTANCE)
            break;
    }

    if (steps == MAX_RAY_STEPS)
        gOrbitTrap = vec4(0.0);

    if (!hitSomething)
    {
        ray.position = MAX_DISTANCE;
        return BACKGROUND_COLOR;
    }

    if (distance == lightDE)
    {
        gLightHit = true;
        return SPOT_LIGHT.rgb * SPOT_LIGHT.a / (LIGHT_SIZE + 0.01);
    }

    vec3 hit = currentPoint(ray);
    hitNormal = surfaceNormal(
        hit - NORMAL_BACK_STEP * epsilon * ray.direction,
        epsilon
    );

    // Gamma=1 in the preset, so this is only the original clamp.
    vec3 material = clamp(orbitColor(), 0.0, 1.0);
    float ao = ambientOcclusion(hit, hitNormal);
    return applyLighting(hitNormal, material, hit,
                         ray.direction, epsilon, ao);
}

// -----------------------------------------------------------------------------
// Clouds and volumetric point-light scattering
// -----------------------------------------------------------------------------

float hashToUnit(uint value)
{
    return float(value) / 4294967296.0;
}

float cloudNoise(vec3 p)
{
    vec3 f = smoothstep(0.0, 1.0, fract(p));
    vec3 i = floor(p);
    uvec3 b0 = floatBitsToUint(i);
    uvec3 b1 = floatBitsToUint(i + vec3(1.0));
    uint hx0 = wangHash(b0.x), hx1 = wangHash(b1.x);
    uint hxy00 = wangHash(hx0 + b0.y);
    uint hxy10 = wangHash(hx1 + b0.y);
    uint hxy01 = wangHash(hx0 + b1.y);
    uint hxy11 = wangHash(hx1 + b1.y);
    float n000 = hashToUnit(wangHash(hxy00 + b0.z));
    float n100 = hashToUnit(wangHash(hxy10 + b0.z));
    float n010 = hashToUnit(wangHash(hxy01 + b0.z));
    float n110 = hashToUnit(wangHash(hxy11 + b0.z));
    float n001 = hashToUnit(wangHash(hxy00 + b1.z));
    float n101 = hashToUnit(wangHash(hxy10 + b1.z));
    float n011 = hashToUnit(wangHash(hxy01 + b1.z));
    float n111 = hashToUnit(wangHash(hxy11 + b1.z));
    return mix(mix(mix(n000,n100,f.x),mix(n010,n110,f.x),f.y),
               mix(mix(n001,n101,f.x),mix(n011,n111,f.x),f.y),f.z);
}

float cloudDensityAt(vec3 p, vec3 cloudDirection)
{
    vec3 q = p; // CloudScale=1 and CloudFlatness=0
    float noise = 0.0;
    float amplitude = 0.5;

    for (int i = 0; i < 3; ++i)
    {
        noise += amplitude * cloudNoise(q);
        q *= 2.03;
        amplitude *= 0.5;
    }

    float height = dot(p, cloudDirection);
    float verticalProfile = 1.0 - abs(height);

    return clamp(CLOUD_DENSITY * verticalProfile - noise, 0.0, 1.0);
}

vec4 integrateCloudSample(vec4 sum, float diffuse,
                          float density, float distance)
{
    vec3 lighting = CLOUD_COLOR * 1.3 + SUN_LIGHT_COLOR * diffuse;
    vec4 sampleColor = vec4(
        mix(1.15 * vec3(1.0, 0.95, 0.8), CLOUD_COLOR_2, density),
        density
    );

    sampleColor.rgb *= lighting;
    sampleColor = clamp(sampleColor, 0.0, 1.0);

    // CloudBgMix=1.
    sampleColor.rgb = mix(
        sampleColor.rgb,
        BACKGROUND_COLOR,
        1.0 - exp(-0.0025 * distance * distance)
    );

    sampleColor.a *= mix(
        0.9, 0.0,
        clamp(distance * distance / (MAX_DISTANCE * MAX_DISTANCE),
              0.0, 1.0)
    );
    sampleColor.rgb *= sampleColor.a;

    return sum + sampleColor * (1.0 - sum.a);
}

vec4 renderClouds(vec3 p0, vec3 p1)
{
    vec3 rayDirection = normalize(p1 - p0);
    vec3 cloudDirection = normalize(CLOUD_DIR);
    vec4 sum = vec4(0.0);

    float t = 0.1 * random3D(
        vec3(gl_FragCoord.xyy + float(FRAME) * 30.0)
    );
    float maxT = length(p1 - p0);
    bool goingUp = dot(rayDirection, cloudDirection) > 0.0;

    while (t < maxT)
    {
        vec3 p = p0 + t * rayDirection;
        float height = dot(p, cloudDirection);

        if ((!goingUp && height < CLOUD_BASE)
            || (goingUp && height > CLOUD_TOPS)
            || sum.a > 0.99)
            break;

        float density = cloudDensityAt(p, cloudDirection);
        if (density > 0.01)
        {
            vec3 sunDirection = normalize(LIGHT_POS - p);
            float diffuse = clamp(
                (density - cloudDensityAt(p + 0.3 * sunDirection,
                                          cloudDirection)) / 0.6,
                -1.0, 1.0
            );
            sum = integrateCloudSample(sum, diffuse, density, t);
        }

        t += 0.1 + 0.0198 * t; // Cloudvar1=0.99
    }

    return clamp(sum, 0.0, 1.0);
}

float squaredLength(vec3 p)
{
    return dot(p, p);
}

vec3 volumetricPointLight(vec3 p0, vec3 p1)
{
    float a = squaredLength(p0 - LIGHT_POS);
    float b = dot(p1 - p0, p0 - LIGHT_POS);
    float c = squaredLength(p1 - p0);
    float delta = sqrt(max(a * c - b * b, 1.0e-12));

    float randomValue = random2D(
        gViewCoord + vec2(1.6183 + float(FRAME + gFogStrata))
    );
    gFogStrata++;

    float atanB = atan(b / delta);
    float atanBC = atan((b + c) / delta);
    float pdfNormalization = (atanBC - atanB) / delta;

    float t = (tan(mix(atanB, atanBC, randomValue)) * delta - b)
            / max(c, 1.0e-12);
    t = clamp(t, 0.00001, 1.0);

    vec3 samplePoint = p0 + t * (p1 - p0);
    vec3 eyeTransmission = fogTransmission(p0, samplePoint);
    vec3 lightTransmission = fogTransmission(samplePoint, LIGHT_POS);
    vec3 density = HF_COLOR.rgb * HF_CONST;

    float visibility = 1.0
        - shadowAmount(samplePoint, LIGHT_POS, 0.001);

    float cosTheta = dot(normalize(samplePoint - p0),
                         normalize(LIGHT_POS - samplePoint));
    vec3 denominator = 1.0 + HF_ANISOTROPY * HF_ANISOTROPY
        - 2.0 * HF_ANISOTROPY * cosTheta;
    vec3 anisotropy = (1.0 - HF_ANISOTROPY * HF_ANISOTROPY)
        / sqrt(denominator * denominator * denominator);

    vec3 scattering = eyeTransmission * lightTransmission
        * density * anisotropy * visibility * sqrt(max(c, 0.0));

    return SPOT_LIGHT.rgb * SPOT_LIGHT.a
        * pdfNormalization * scattering * HF_SCATTER;
}

vec3 renderColor(SRay ray)
{
    vec3 color = vec3(0.0);
    vec3 reflectionWeight = vec3(1.0);
    gLightHit = false;
    gFogStrata = 0;

    // ReflectionsNumber=1: primary ray plus one reflected ray.
    for (int bounce = 0; bounce < 2; ++bounce)
    {
        vec3 previousPosition = currentPoint(ray);
        vec3 hitNormal;
        float glow;
        vec3 layer = traceScene(ray, hitNormal, glow);
        vec3 currentPosition = currentPoint(ray);

        vec3 fog = fogTransmission(previousPosition, currentPosition);
        layer = mix(HF_COLOR.rgb * HF_COLOR.a, layer, fog);
        if (bounce == 0)
{
        layer += pointLightGlow(glow);
        layer += volumetricPointLight(previousPosition, currentPosition);

        vec4 clouds = renderClouds(previousPosition, currentPosition);
        layer = layer * (1.0 - clouds.a) + clouds.rgb;
}
        color += layer * reflectionWeight;
        reflectionWeight *= REFLECTION * fog;

        if (all(equal(hitNormal, vec3(0.0)))
            || dot(reflectionWeight, reflectionWeight) < 0.0001
            || gLightHit
            || ray.position >= MAX_DISTANCE)
            break;

        ray = reflectRay(ray, hitNormal, MIN_DIST);
    }

    return max(color, vec3(0.0));
}

// -----------------------------------------------------------------------------
// Kleinian distance estimator
// -----------------------------------------------------------------------------

float squaredNorm(vec3 p)
{
    return dot(p, p);
}

vec2 wrap2(vec2 p, vec2 period, vec2 offset)
{
    p -= offset;
    return p - period * floor(p / period) + offset;
}

void transformA(inout vec3 p, inout float derivative,
                float a, float b)
{
    float inverseRadius = 1.0 / squaredNorm(p);
    p *= -inverseRadius;
    p.x = -b - p.x;
    p.y = a + p.y;
    derivative *= inverseRadius;
}

void transformAWithRadiusSquared(inout vec3 p, inout float derivative,
                                 float radiusSquared, float a, float b)
{
    float inverseRadius = 1.0 / radiusSquared;
    p *= -inverseRadius;
    p.x = -b - p.x;
    p.y = a + p.y;
    derivative *= inverseRadius;
}

float josKleinian(vec3 p)
{
    vec3 previous = p + vec3(1.0);
    vec3 previous2 = p - vec3(1.0);
    float distance = 1.0e10;
    float derivative = 1.0;
    float a = KLEIN_R;
    float b = KLEIN_I;
    float signB = sign(b);

    for (int i = 0; i < BOX_ITERATIONS; ++i)
    {
        p.x += KLEIN_SHEAR * p.y;
        p.xz = wrap2(
            p.xz,
            KLEIN_WRAP_PERIOD,
            KLEIN_WRAP_OFFSET
        );
        p.x -= KLEIN_SHEAR * p.y;

        float centeredX = p.x + KLEIN_HALF_I;
        float separation = SEPARATION_BASE
            + SEPARATION_AMPLITUDE * sign(centeredX)
            * (1.0 - exp(-SEPARATION_DECAY * abs(centeredX)));

        if (p.y >= separation)
            p = vec3(-b, a, 0.0) - p;

        float radiusSquared = dot(p, p);
        gOrbitTrap = min(gOrbitTrap, abs(vec4(p, radiusSquared)));
        transformAWithRadiusSquared(p, derivative, radiusSquared, a, b);

        if (squaredNorm(p - previous2) < 1.0e-12)
            break;

        previous2 = previous;
        previous = p;
    }

    for (int i = 0; i < FINAL_ITERATIONS; ++i)
    {
        float y = min(p.y, a - p.y); // ShowBalls=true
        distance = min(distance,
                       min(y, CLAMP_Y) / max(derivative, CLAMP_DF));
        transformA(p, derivative, a, b);
    }

    float y = min(p.y, a - p.y);
    distance = min(distance,
                   min(y, CLAMP_Y) / max(derivative, CLAMP_DF));
    return distance;
}

float josKleinianFast(vec3 p)
{
    vec3 previous = p + vec3(1.0);
    vec3 previous2 = p - vec3(1.0);
    float distance = 1.0e10;
    float derivative = 1.0;
    float a = KLEIN_R;
    float b = KLEIN_I;
    float signB = sign(b);

    for (int i = 0; i < BOX_ITERATIONS; ++i)
    {
        p.x += KLEIN_SHEAR * p.y;
        p.xz = wrap2(
            p.xz,
            KLEIN_WRAP_PERIOD,
            KLEIN_WRAP_OFFSET
        );
        p.x -= KLEIN_SHEAR * p.y;

        float centeredX = p.x + KLEIN_HALF_I;
        float separation = SEPARATION_BASE
            + SEPARATION_AMPLITUDE * sign(centeredX)
            * (1.0 - exp(-SEPARATION_DECAY * abs(centeredX)));

        if (p.y >= separation)
            p = vec3(-b, a, 0.0) - p;

        transformA(p, derivative, a, b);

        if (squaredNorm(p - previous2) < 1.0e-12)
            break;

        previous2 = previous;
        previous = p;
    }

    for (int i = 0; i < FINAL_ITERATIONS; ++i)
    {
        float y = min(p.y, a - p.y); // ShowBalls=true
        distance = min(distance,
                       min(y, CLAMP_Y) / max(derivative, CLAMP_DF));
        transformA(p, derivative, a, b);
    }

    float y = min(p.y, a - p.y);
    distance = min(distance,
                   min(y, CLAMP_Y) / max(derivative, CLAMP_DF));
    return distance;
}

float DE(vec3 p)
{
    // roty=0, DoAnimation=false and DoInversion=false.
    return josKleinian(p);
}

float DEFast(vec3 p)
{
    return josKleinianFast(p);
}

// -----------------------------------------------------------------------------
// Shadertoy entry point and accumulation
// -----------------------------------------------------------------------------

void setupCamera(vec2 fragCoord)
{
    gViewCoord = 2.0 * fragCoord / iResolution.xy - 1.0;
    gCoord = (2.0 * fragCoord - iResolution.xy) / iResolution.y;
    gCoord *= FOV;
    gPixelScale = 2.0 / iResolution.xy;

    gCameraPos = EYE;
    gCameraDir = normalize(TARGET - EYE);

    vec3 up = normalize(CAMERA_UP); // UpLock=false
    gCameraUp = normalize(up - dot(gCameraDir, up) * gCameraDir);
    gCameraRight = normalize(cross(gCameraDir, gCameraUp));
    gAOSeed = gViewCoord * (float(FRAME) + 1.0);
}

void mainImage(out vec4 fragColor, in vec2 fragCoord)
{
    setupCamera(fragCoord);

    vec2 apertureSample = APERTURE * pentagonalStarAperture(
        gViewCoord * (float(FRAME) + 1.0)
    );

    vec2 disc = uniformDisc(gCoord * float(FRAME + 1));
    vec2 jitteredCoord = gCoord - vec2(0.3, 0.)
        + ANTI_ALIAS_SCALE * gPixelScale.y * FOV * disc;

    vec3 lensOffset = apertureSample.x * gCameraRight
                    + apertureSample.y * gCameraUp;
    vec3 unnormalizedDirection = gCameraDir
        + jitteredCoord.x * gCameraRight
        + jitteredCoord.y * gCameraUp;

    float rayLength = length(unnormalizedDirection);
    float focusCorrection = length(
        unnormalizedDirection
        + lensOffset * (
            1.0 - 1.0 / FOCAL_PLANE
            + clamp(1.0 / FOCAL_PLANE - 1.0,
                    -IN_FOCUS_WIDTH, IN_FOCUS_WIDTH)
        )
    );

    SRay ray = SRay(
        gCameraPos,
        unnormalizedDirection / rayLength,
        lensOffset,
        0.0,
        1.0 / max(1.0, focusCorrection),
        1.0 / FOCAL_PLANE
    );

    vec3 sampleColor = renderColor(ray);

    vec2 uv = fragCoord / iResolution.xy;
    vec4 previous = FRAME == 0 ? vec4(0.0) : texture(iChannel0, uv);

    float weight = exp(-dot(disc, disc) / GAUSSIAN_WEIGHT)
                 - exp(-1.0 / GAUSSIAN_WEIGHT);

    fragColor = previous + vec4(sampleColor * weight, weight);
}

void mainImage(out vec4 fragColor, in vec2 fragCoord)
{
    vec2 uv = fragCoord / iResolution.xy;
    vec2 halfTexel = 0.5 / iResolution.xy;
    float stepX = BLOOM_STRONG / iResolution.x;
    vec4 sum = vec4(0.0);

    for (int x = -BLOOM_TAPS; x <= BLOOM_TAPS; ++x)
    {
        float nx = float(x) / float(BLOOM_TAPS);
        float wx = 1.0 - nx * nx;
        wx *= wx;

        vec2 sampleUV = vec2(
            clamp(uv.x + float(x) * stepX,
                  halfTexel.x, 1.0 - halfTexel.x),
            clamp(uv.y, halfTexel.y, 1.0 - halfTexel.y)
        );
        sum += texture(iChannel0, sampleUV) * wx;
    }

    fragColor = sum;
}

void mainImage( out vec4 fragColor, in vec2 fragCoord )
{
    // Normalized pixel coordinates (from 0 to 1)
    vec2 uv = fragCoord/iResolution.xy;

    // Time varying pixel color
    vec3 col = 0.5 + 0.5*cos(iTime+uv.xyx+vec3(0,2,4));

    // Output to screen
    fragColor = vec4(col,1.0);
}

void mainImage( out vec4 fragColor, in vec2 fragCoord )
{
    fragColor = vec4(0.0,0.0,1.0,1.0);
}

void mainImage( out vec4 fragColor, in vec2 fragCoord )
{
    fragColor = vec4(0.0,0.0,1.0,1.0);
}

const float BLOOM_INTENSITY = 0.4331;
const float BLOOM_POWER = 6.22093;
const int BLOOM_TAPS = 4;
const float BLOOM_STRONG = 2.57901;

// Preset values: Exposure=Brightness=Contrast=Gamma=1.
const float CONTRAST = 1.0;

float sigmoid(float t)
{
    float k = 1.0 - 1.0 / (1.0 + exp(-0.5 * CONTRAST * 5.0));
    t -= 0.5;
    float x = 1.0 / (1.0 + exp(-t * CONTRAST * 5.0)) - k;
    return x / (1.0 - 2.0 * k);
}

vec3 sigmoid3(vec3 v)
{
    return vec3(sigmoid(v.x), sigmoid(v.y), sigmoid(v.z));
}

vec4 accumulatedTexture(vec2 uv)
{
    return texture(iChannel0, clamp(uv, vec2(0.0), vec2(1.0)));
}

vec4 bloom(vec2 uv)
{
    vec2 stepSize = BLOOM_STRONG / iResolution.xy;
    vec4 sum = vec4(0.0);

    for (int x = -BLOOM_TAPS; x <= BLOOM_TAPS; ++x)
    {
        float wx = float(x) / float(BLOOM_TAPS);
        wx = 1.0 - wx * wx;
        wx *= wx;

        for (int y = -BLOOM_TAPS; y <= BLOOM_TAPS; ++y)
        {
            float wy = float(y) / float(BLOOM_TAPS);
            wy = 1.0 - wy * wy;
            wy *= wy;

            vec2 offset = vec2(float(x), float(y)) * stepSize;
            sum += accumulatedTexture(uv + offset) * (wx * wy);
        }
    }

    return sum;
}

void mainImage(out vec4 fragColor, in vec2 fragCoord)
{
    vec2 uv = fragCoord / iResolution.xy;

    vec4 raw = accumulatedTexture(uv);
    vec3 color = raw.rgb / max(raw.a, 1.0e-8);

    vec4 blurred = bloom(uv);
    vec3 bloomColor = blurred.rgb / max(blurred.a, 1.0e-8);
    color += BLOOM_INTENSITY * pow(max(bloomColor, vec3(0.0)),
                                   vec3(BLOOM_POWER));

    // ToneMapping=5 (Syntopia sigmoid), Exposure=1, Brightness=1.
    color = sigmoid3(color);

    // Gamma=1 in the preset, so no final gamma power is required.
    fragColor = vec4(color, 1.0);
}

#define PI 3.1415926535897932384626433832795
#define MAX_FLIPS 40

const float FOV = 0.685022;
const vec3 EYE = vec3(5.52166, -0.807811, 2.62172);
const vec3 CAM_FWD = vec3(-0.41786894, 0.64231093, -0.64251243);
const vec3 CAM_UP  = vec3(-0.35037799, 0.53856985, 0.76627526);
const vec3 CAM_RIGHT = vec3(0.8382248, 0.54532484, 0.0);

const float APERTURE = 0.003;
const float ANTI_ALIAS_SCALE = 1.5;
const float MIN_DIST = 1.0e-4;
const float AO_EPS = 0.030758457287605118;
const float MIN_EPS = 1.1920928955078125e-7;
const int REFINE_STEPS = 5;
const float FUDGE_FACTOR = 0.7;
const int MAX_RAY_STEPS = 300;
const float MAX_DISTANCE = 200.0;
const float DITHER = 0.5;
const float NORMAL_BACK_STEP = 30.6125;

const float CONE_APERTURE_AO = 0.378985;
const int MAX_ITER_AO = 19;
const float FUDGE_AO = 0.349943;
const float AO_AMBIENT = 1.0;
const float AO_CAMLIGHT = 1.59217;
const float AO_POINTLIGHT = 0.449594;

const float SPECULAR = 0.4;
const float SPECULAR_EXP = 200.0;
const vec4 CAM_LIGHT = vec4(1.0, 1.0, 1.0, 0.2);
const vec4 AMBIENT_LIGHT = vec4(0.972549, 0.972549, 0.972549, 0.5);
const vec3 REFLECTION = vec3(0.352941);
const int REFLECTIONS_NUMBER = 1;

const vec4 SPOT_LIGHT = vec4(1.0, 1.0, 1.0, 0.7);
const vec3 LIGHT_POS = vec3(2.7888, -0.0764, 10.0);
const float LIGHT_FALLOFF = 0.38016;
const float SHADOW_SOFT = 19.0118;

const vec3 BASE_COLOR = vec3(0.72549, 0.72549, 0.521569);
const vec4 ORBIT_X = vec4(0.898039, 0.937255, 0.976471, 1.0);
const vec4 ORBIT_R = vec4(0.898039, 0.937255, 0.976471, 1.0);
const float COLOR_CYCLES = 0.1;

const vec3 BACKGROUND_COLOR = vec3(0.270588, 0.403922, 0.6);
const float FLOOR_HEIGHT = 1.8;
const vec3 FLOOR_COLOR = vec3(0.313725);

const vec3 FOG_EXT = vec3(0.03011577098, 0.04015434353, 0.04684672523);
const vec3 FOG_COLOR = vec3(0.564706, 0.752941, 0.878431);
const float HF_CONST = 0.05333;
const float HF_SCATTER = 10.0;
const vec3 HF_ANISOTROPY = vec3(0.133333, 0.00784314, 0.0);

const vec3 CLOUD_DIR = vec3(0.25809884, -0.20813084, -0.94343338);
const float CLOUD_SCALE = 2.50337;
const float CLOUD_TOPS = 1.0;
const float CLOUD_BASE = -5.8;
const float CLOUD_DENSITY = 0.484136;
const vec3 CLOUD_COLOR = vec3(0.65, 0.68, 0.7);
const vec3 CLOUD_COLOR_2 = vec3(0.07, 0.17, 0.24);
const vec3 SUN_LIGHT_COLOR = vec3(0.968627);
const int CLOUD_ITER = 3;

const vec3 B0_CENTER = vec3(0.1213203435596426, 0.5073059368893476, 2.3483438081515593);
const float B0_RADIUS = 1.0146118737786951;
const vec3 B1_CENTER = vec3(0.0, 1.73205081, 0.0);
const float B1_RADIUS = 2.4494897462213041;
const vec3 B2_NORMAL = vec3(0.866025405, -0.5, 0.0);
const vec3 B3_NORMAL = vec3(-0.866025405, -0.5, 0.0);

vec2 gViewCoord, gCoord, gFragCoord, aoSeed;
vec4 orbitTrap;
float floorDist;
bool lightHit;

uint wangHash(uint seed)
{
    seed = (seed ^ 61u) ^ (seed >> 16u);
    seed *= 9u;
    seed ^= seed >> 4u;
    seed *= 0x27d4eb2du;
    seed ^= seed >> 15u;
    return seed;
}

float rand(float p) { return float(wangHash(floatBitsToUint(p))) / 4294967296.0; }

float rand(vec2 p)
{
    uint ix = floatBitsToUint(p.x), iy = floatBitsToUint(p.y);
    return float(wangHash(wangHash(ix) + iy)) / 4294967296.0;
}

float rand(vec3 p)
{
    uint ix = floatBitsToUint(p.x), iy = floatBitsToUint(p.y), iz = floatBitsToUint(p.z);
    return float(wangHash(wangHash(wangHash(ix) + iy) + iz)) / 4294967296.0;
}

vec2 rand2(vec2 p)
{
    vec2 k = vec2(rand(p.x) * 12.9898, rand(p.y) * 78.233);
    vec2 h = vec2(rand(p.x) * 4.898, rand(p.y) * 7.23);
    return vec2(fract(sin(dot(p, k)) * 43758.5453),
                fract(cos(dot(p, h)) * 23421.631));
}

vec2 uniformDisc(vec2 p)
{
    vec2 r = rand2(p);
    float a = 2.0 * PI * r.x;
    return sqrt(r.y) * vec2(cos(a), sin(a));
}

vec2 nGonDisc(vec2 p)
{
    vec2 r = rand2(p);
    vec2 q = vec2((r.x + r.y) * 1.3763819204711736, r.x - r.y) * 0.5877852522924731;

    float a = floor(dot(rand2(11.0 * p + vec2(1.0)), vec2(1.0)) * 5.0) * (2.0 * PI / 5.0);
    vec2 cs = vec2(cos(a), sin(a));
    return vec2(cs.x * q.x - cs.y * q.y, cs.x * q.y + cs.y * q.x);
}

// -----------------------------------------------------------------------------
// Coxeter-ball folding
// -----------------------------------------------------------------------------

bool foldInvertedSphere(inout vec3 p, vec3 center, float radius, inout float scale, inout vec4 orb)
{
    vec3 q = p - center;
    float d2 = dot(q, q);
    float k = radius * radius / max(d2, 1.0e-30);

    if (k < 1.0) return true;

    orb = min(orb, vec4(abs(p), d2));
    scale *= k;
    p = k * q + center;
    return false;
}

bool foldPlane(inout vec3 p, vec3 normal, float offset)
{
    float k = dot(p, normal) + offset;
    if (k >= 0.0) return true;
    p -= 2.0 * k * normal;
    return false;
}

float mapScene(inout vec3 p, inout float scale, inout vec4 orb)
{
    for (int i = 0; i < MAX_FLIPS; ++i)
    {
        bool ok = true;
        if (ok) ok = foldInvertedSphere(p, B0_CENTER, B0_RADIUS, scale, orb);
        if (ok) ok = foldInvertedSphere(p, B1_CENTER, B1_RADIUS, scale, orb);
        if (ok) ok = foldPlane(p, B2_NORMAL, 0.866025405);
        if (ok) ok = foldPlane(p, B3_NORMAL, 0.866025405);
        if (ok) ok = foldPlane(p, vec3(0.0, 1.0, 0.0), 0.0);
        if (ok) break;
    }
    return abs(p.z);
}

float DE(vec3 p)
{
    float scale = 1.0;
    return 0.25 * mapScene(p, scale, orbitTrap) / scale;
}

// -----------------------------------------------------------------------------
// Scene helpers
// -----------------------------------------------------------------------------

vec3 rayPoint(vec3 ro, vec3 rd, vec3 offset, float rayPos)
{
    float t = 1.0 - rayPos;
    float d = t - (2.0 * smoothstep(-1.5, 1.5, t) - 1.0);
    return ro + rd * rayPos + offset * d;
}

void reflectRay(inout vec3 ro, inout vec3 rd, inout vec3 offset, inout float rayPos, vec3 normal)
{
    vec3 hit = rayPoint(ro, rd, offset, rayPos);
    rd = reflect(rd, normal);
    offset = reflect(offset, normal);
    ro = hit + reflect(ro - hit, normal);
    rayPos += MIN_DIST;
}

float distanceToLight(vec3 p) { return length(LIGHT_POS - p); }

float sceneWithFloor(vec3 p)
{
    floorDist = abs(p.z - FLOOR_HEIGHT);
    return min(DE(p), floorDist);
}

float sceneWithFloorFudged(vec3 p)
{
    floorDist = abs(p.z - FLOOR_HEIGHT);
    return min(floorDist, DE(p) * FUDGE_FACTOR);
}

vec3 sceneNormal(vec3 p, float normalDistance)
{
    float h = max(normalDistance * 0.5, 1.0e-5);
    vec3 ex = vec3(h, 0.0, 0.0);
    vec3 ey = vec3(0.0, h, 0.0);
    vec3 ez = vec3(0.0, 0.0, h);
    vec3 n = normalize(vec3(
        DE(p + ex) - DE(p - ex),
        DE(p + ey) - DE(p - ey),
        DE(p + ez) - DE(p - ez)
    ));
    return all(equal(n, n)) ? n : vec3(0.0);
}

vec3 fogTransmission(vec3 p0, vec3 p1)
{
    return exp(-FOG_EXT * length(p1 - p0));
}

float shadow(vec3 ro, float eps)
{
    vec3 rd = LIGHT_POS - ro;
    float lightDistance = length(rd);
    rd /= max(lightDistance, 1.0e-20);

    float t = sceneWithFloorFudged(ro) + eps;
    float s = 1.0;
    float jitter = DITHER * (rand(ro.xy * (float(iFrame) + 1.0)) - 0.5);

    for (int i = 0; i < MAX_RAY_STEPS; ++i)
    {
        if (t > lightDistance || s < 0.001) break;

        float d = sceneWithFloorFudged(ro + rd * (t + eps * jitter)) + eps;
        s *= clamp(d / (2.0 * eps), 0.0, 1.0);
        t += abs(0.75 * d + SHADOW_SOFT * eps);
    }

    s = max(0.0, s - 0.001) / 0.999;
    return clamp(1.0 - s, 0.0, 1.0);
}

vec2 rand2AO()
{
    aoSeed += vec2(-1.0, 1.0);
    return vec2(
        fract(sin(dot(aoSeed, vec2(12.9898, 78.233))) * 43758.5453),
        fract(cos(dot(aoSeed, vec2(4.898, 7.23))) * 23421.631)
    );
}

vec3 orthogonalVector(vec3 v)
{
    return abs(v.x) > abs(v.z) ? vec3(-v.y, v.x, 0.0) : vec3(0.0, -v.z, v.y);
}

vec3 aoDirection(vec3 n)
{
    vec3 o1 = normalize(orthogonalVector(n));
    vec3 o2 = cross(n, o1);
    vec2 r = rand2AO();
    r.x *= 2.0 * PI;
    r.y *= CONE_APERTURE_AO;

    float ry = sqrt(r.y);
    return cos(r.x) * ry * o1 + sin(r.x) * ry * o2 + sqrt(max(0.0, 1.0 - r.y)) * n;
}

float ambientOcclusion(vec3 p, vec3 n)
{
    vec3 vdir = aoDirection(n);
    float ao = 0.0;
    float de = sceneWithFloor(p) / AO_EPS;
    float d = 1.0 - DITHER * rand(p.xy);
    float previousD = 1.0;
    float nd = max(dot(vdir, n), 1.0e-5);

    for (int i = 1; i < MAX_ITER_AO; ++i)
    {
        float currentD = sceneWithFloor(p + d * vdir * de) /
                         max(d * de * nd * FUDGE_AO, 1.0e-20);
        currentD = min(previousD, currentD);
        previousD = currentD;
        ao += clamp(1.0 - currentD, 0.0, 1.0);
        d *= 1.61;
    }

    return ao / float(MAX_ITER_AO - 1);
}

vec3 lighting(vec3 n, vec3 baseColor, vec3 pos, vec3 rayDir, float eps, float ao)
{
    vec3 toLight = LIGHT_POS - pos;
    float distance2 = dot(toLight, toLight);
    float falloff = pow(max(distance2, 1.0e-20), -LIGHT_FALLOFF);
    vec3 lightDir = normalize(toLight);

    float nDotL = max(0.0, dot(n, lightDir));
    vec3 halfVector = normalize(lightDir - rayDir);
    float hDotN = max(0.0, dot(n, halfVector));

    float f0 = (SPECULAR_EXP - 1.0) / (SPECULAR_EXP + 1.0);
    f0 *= f0;
    float fresnel = f0 + (1.0 - f0) * pow(1.0 + dot(n, rayDir), 5.0);
    float specular = ((SPECULAR_EXP + 2.0) / 8.0) * fresnel * nDotL
                   * pow(hDotN, SPECULAR_EXP + 0.00001) * SPECULAR;

    float sh = shadow(pos + n * eps, eps);
    nDotL *= 1.0 - sh;
    specular *= 1.0 - sh;

    vec3 col = fogTransmission(pos, LIGHT_POS) * SPOT_LIGHT.rgb * SPOT_LIGHT.a * falloff
             * (nDotL + specular)
             * (1.0 - clamp(AO_POINTLIGHT * ao, 0.0, 1.0));

    nDotL = max(0.0, dot(n, -rayDir));
    hDotN = max(0.0, dot(n, -rayDir));
    specular = ((SPECULAR_EXP + 2.0) / 8.0) * fresnel * nDotL
             * pow(hDotN, SPECULAR_EXP + 0.00001) * SPECULAR;

    col += CAM_LIGHT.rgb * CAM_LIGHT.a * (nDotL + specular)
         * (1.0 - clamp(AO_CAMLIGHT * ao, 0.0, 1.0));

    col += AMBIENT_LIGHT.rgb * AMBIENT_LIGHT.a
         * (1.0 - clamp(AO_AMBIENT * ao, 0.0, 1.0));

    return col * baseColor;
}

vec3 cycleColor(vec3 c, float s)
{
    return vec3(0.5) + 0.5 * cos(vec3(s * COLOR_CYCLES) + c);
}

vec3 orbitColor()
{
    orbitTrap.w = sqrt(max(orbitTrap.w, 0.0));
    return 3.0 * (
        cycleColor(ORBIT_X.rgb, orbitTrap.x) * orbitTrap.x +
        cycleColor(ORBIT_R.rgb, orbitTrap.w) * orbitTrap.w
    );
}

// -----------------------------------------------------------------------------
// Clouds and volumetric scattering
// -----------------------------------------------------------------------------

float cloudNoise(vec3 p)
{
    vec3 d = smoothstep(0.0, 1.0, fract(p));
    p = floor(p);
    const vec2 v = vec2(1.0, 0.0);

    return mix(
        mix(
            mix(rand(p), rand(p + v.xyy), d.x),
            mix(rand(p + v.yxy), rand(p + v.xxy), d.x),
            d.y
        ),
        mix(
            mix(rand(p + v.yyx), rand(p + v.xyx), d.x),
            mix(rand(p + v.yxx), rand(p + v.xxx), d.x),
            d.y
        ),
        d.z
    );
}

float cloudDensityAt(vec3 p)
{
    vec3 q = p / CLOUD_SCALE;
    float f = 0.0, a = 0.5;

    for (int i = 0; i < CLOUD_ITER; ++i)
    {
        f += a * cloudNoise(q);
        q *= 2.03;
        a *= 0.5;
    }

    float y = dot(p, CLOUD_DIR);
    float layer = 1.0 - 2.0 * abs(-2.4 - y) / 6.8;
    return clamp(CLOUD_DENSITY * layer - f, 0.0, 1.0);
}

vec4 integrateClouds(vec4 sum, float diffuse, float density, float t)
{
    vec3 lin = CLOUD_COLOR * 1.3 + SUN_LIGHT_COLOR * diffuse;
    vec4 col = vec4(mix(1.15 * vec3(1.0, 0.95, 0.8), CLOUD_COLOR_2, density), density);
    col.rgb *= lin;
    col = clamp(col, 0.0, 1.0);

    col.rgb = mix(col.rgb, BACKGROUND_COLOR, 1.0 - exp(-0.0025 * t * t));
    col.a *= mix(0.9, 0.0, clamp(t * t / (MAX_DISTANCE * MAX_DISTANCE), 0.0, 1.0));
    col.rgb *= col.a;
    return sum + col * (1.0 - sum.a);
}

vec4 clouds(vec3 p0, vec3 p1)
{
    vec3 rd = normalize(p1 - p0);
    vec4 sum = vec4(0.0);

    float t = 0.1 * CLOUD_SCALE *
              rand(vec3(gFragCoord.x, gFragCoord.y, gFragCoord.y) + float(iFrame) * 30.0);
    float maxT = length(p1 - p0);
    bool goingUp = dot(rd, CLOUD_DIR) > 0.0;

    for (int i = 0; i < 160; ++i)
    {
        if (t >= maxT || sum.a > 0.99) break;

        vec3 pos = p0 + t * rd;
        float h = dot(pos, CLOUD_DIR);
        if ((!goingUp && h < CLOUD_BASE) || (goingUp && h > CLOUD_TOPS)) break;

        float density = cloudDensityAt(pos);
        if (density > 0.01)
        {
            vec3 sunDir = normalize(LIGHT_POS - pos);
            float diffuse = clamp(
                (density - cloudDensityAt(pos + 0.3 * CLOUD_SCALE * sunDir)) / 0.6,
                -1.0, 1.0
            );
            sum = integrateClouds(sum, diffuse, density, t);
        }

        t += 0.1 * CLOUD_SCALE + 0.02 * CLOUD_SCALE * t * 0.99;
    }

    return clamp(sum, 0.0, 1.0);
}

vec3 volumetricPointLight(vec3 p0, vec3 p1)
{
    vec3 segment = p1 - p0;
    vec3 q = p0 - LIGHT_POS;
    float A = dot(q, q);
    float B = dot(segment, q);
    float C = max(dot(segment, segment), 1.0e-20);
    float delta = sqrt(max(A * C - B * B, 1.0e-20));

    float x = rand(gViewCoord + vec2(1.6183 + float(iFrame)));

    float atanB = atan(B / delta);
    float atanBC = atan((B + C) / delta);
    float pdfNormalization = (atanBC - atanB) / delta;
    float t = clamp((tan(mix(atanB, atanBC, x)) * delta - B) / C, 0.00001, 1.0);

    vec3 samplePoint = p0 + t * segment;
    float visibility = 1.0 - shadow(samplePoint, 0.001);

    float cosTheta = dot(normalize(samplePoint - p0), normalize(LIGHT_POS - samplePoint));
    vec3 denom = vec3(1.0) + HF_ANISOTROPY * HF_ANISOTROPY
               - 2.0 * HF_ANISOTROPY * cosTheta;
    vec3 phase = (vec3(1.0) - HF_ANISOTROPY * HF_ANISOTROPY)
               / sqrt(max(denom * denom * denom, vec3(1.0e-20)));

    vec3 sampleValue = fogTransmission(p0, samplePoint)
                     * fogTransmission(samplePoint, LIGHT_POS)
                     * vec3(HF_CONST) * phase * visibility * sqrt(C);

    return SPOT_LIGHT.rgb * SPOT_LIGHT.a * pdfNormalization * sampleValue * HF_SCATTER;
}

// -----------------------------------------------------------------------------
// Ray tracing
// -----------------------------------------------------------------------------

vec3 trace(
    inout vec3 ro,
    inout vec3 rd,
    inout vec3 offset,
    inout float rayPos,
    float rayFudge,
    out vec3 hitNormal,
    out float glow
)
{
    glow = 1000.0;
    orbitTrap = vec4(10000.0);
    floorDist = 0.0;

    bool hitSomething = false;
    bool floorHit = false;
    float dist = 0.0;
    float lightDE = 0.0;
    int steps = 0;
    float eps = max(MIN_EPS, rayPos * MIN_DIST * FUDGE_FACTOR);

    vec3 p = rayPoint(ro, rd, offset, rayPos);
    float firstStep = min(sceneWithFloor(p) * FUDGE_FACTOR, distanceToLight(p));
    firstStep *= DITHER * rand(rd.xy) + (1.0 - DITHER);
    rayPos += firstStep * rayFudge;

    for (steps = 0; steps < MAX_RAY_STEPS; ++steps)
    {
        p = rayPoint(ro, rd, offset, rayPos);
        lightDE = distanceToLight(p);
        dist = min(lightDE, sceneWithFloor(p) * FUDGE_FACTOR);
        glow = min(lightDE, glow);
        rayPos += dist * rayFudge;

        eps = max(MIN_EPS, rayPos * MIN_DIST * FUDGE_FACTOR);
        if (dist < eps)
        {
            for (int i = 0; i < REFINE_STEPS; ++i)
            {
                rayPos += (dist - 1.5 * eps) * rayFudge;
                p = rayPoint(ro, rd, offset, rayPos);
                lightDE = distanceToLight(p);
                dist = min(lightDE, sceneWithFloor(p) * FUDGE_FACTOR);
                glow = min(lightDE, glow);
            }
            hitSomething = true;
            break;
        }

        if (rayPos > MAX_DISTANCE) break;
    }

    floorHit = abs(dist - floorDist * FUDGE_FACTOR) < 1.0e-7;
    if (steps == MAX_RAY_STEPS) orbitTrap = vec4(0.0);

    if (!hitSomething)
    {
        hitNormal = vec3(0.0);
        rayPos = MAX_DISTANCE;
        return BACKGROUND_COLOR;
    }

    if (dist == lightDE)
    {
        lightHit = true;
        return SPOT_LIGHT.rgb * SPOT_LIGHT.a / 0.01;
    }

    vec3 hit = rayPoint(ro, rd, offset, rayPos);
    if (floorHit)
    {
        hitNormal = (hit.z - FLOOR_HEIGHT < 0.0) ? -vec3(0.0, 0.0, 1.0) : vec3(0.0, 0.0, 1.0);
    }
    else
    {
        hitNormal = sceneNormal(hit - NORMAL_BACK_STEP * eps * rd, eps);
    }

    vec3 hitColor = floorHit ? FLOOR_COLOR : clamp(orbitColor(), 0.0, 1.0);
    float ao = ambientOcclusion(hit, hitNormal);
    return lighting(hitNormal, hitColor, hit, rd, eps, ao);
}

vec3 renderRay(vec3 ro, vec3 rd, vec3 offset, float rayFudge)
{
    float rayPos = 0.0;
    float glow = 0.5;
    vec3 hitNormal = vec3(0.0);
    vec3 col = vec3(0.0);
    vec3 reflectionWeight = vec3(1.0);

    for (int i = 0; i <= REFLECTIONS_NUMBER; ++i)
    {
        vec3 previousPosition = rayPoint(ro, rd, offset, rayPos);
        vec3 segmentColor = trace(ro, rd, offset, rayPos, rayFudge, hitNormal, glow);
        vec3 currentPosition = rayPoint(ro, rd, offset, rayPos);

        vec3 fog = fogTransmission(previousPosition, currentPosition);
        segmentColor = mix(FOG_COLOR, segmentColor, fog);
        segmentColor += volumetricPointLight(previousPosition, currentPosition);

        vec4 cloud = clouds(previousPosition, currentPosition);
        segmentColor = segmentColor * (1.0 - cloud.a) + cloud.rgb;

        col += segmentColor * reflectionWeight;
        reflectionWeight *= REFLECTION * fog;

        if (all(equal(hitNormal, vec3(0.0))) ||
            dot(reflectionWeight, reflectionWeight) < 0.0001 ||
            lightHit || rayPos >= MAX_DISTANCE)
            break;

        reflectRay(ro, rd, offset, rayPos, hitNormal);
    }

    return max(col, vec3(0.0));
}

vec3 renderSample(vec2 fragCoord)
{
    gFragCoord = fragCoord;
    gViewCoord = 2.0 * fragCoord / iResolution.xy - 1.0;
    gCoord = vec2(gViewCoord.x * iResolution.x / iResolution.y, gViewCoord.y) * FOV;

    aoSeed = gViewCoord * (float(iFrame) + 1.0);
    lightHit = false;

    float frame = float(iFrame) + 1.0;
    vec2 lensSample = APERTURE * nGonDisc(gViewCoord * frame);
    vec2 disc = uniformDisc(gCoord * frame);
    vec2 jitteredCoord = gCoord + ANTI_ALIAS_SCALE * (1.0 / iResolution.y) * FOV * disc;

    vec3 lensOffset = lensSample.x * CAM_RIGHT + lensSample.y * CAM_UP;
    vec3 rayDirection = CAM_FWD + jitteredCoord.x * CAM_RIGHT + jitteredCoord.y * CAM_UP;
    float rayDirectionLength = length(rayDirection);

    return renderRay(
        EYE,
        rayDirection / rayDirectionLength,
        lensOffset,
        1.0 / max(1.0, rayDirectionLength)
    );
}

void mainImage(out vec4 fragColor, in vec2 fragCoord)
{
    vec3 sampleColor = renderSample(fragCoord);

    vec2 disc = uniformDisc(gCoord * float(iFrame + 1));
    float weight = exp(-dot(disc, disc)) - exp(-1.0);

    vec4 previous = (iFrame == 0)
                  ? vec4(0.0)
                  : texelFetch(iChannel0, ivec2(fragCoord), 0);

    fragColor = previous + vec4(sampleColor * weight, weight);
}

/*

Adapted from Fragmentarium code:

    https://github.com/neozhaoliang/Hyperbolic-Honeycombs

The honeycomb data are precomputed for performance optimization. 
See the GitHub repository for details on how the data are defined
and generated.

You can see a circle-packing pattern in the plane, 
where each circle contains a (8,3) hyperbolic tiling.

*/
const float GAMMA_VALUE = 2.2;

void mainImage(out vec4 fragColor, in vec2 fragCoord)
{
    vec2 uv = fragCoord / iResolution.xy;
    vec4 accumulated = texture(iChannel0, uv);

    if (accumulated.a <= 1.0e-8)
    {
        fragColor = vec4(0.0, 0.0, 0.0, 1.0);
        return;
    }

    // Resolve the weighted accumulation buffer.
    vec3 color = max(accumulated.rgb / accumulated.a, vec3(0.0));

    // Preset: ToneMapping = 4, Exposure = 1.
    color = color / (1.0 + color);

    // Brightness = Contrast = Saturation = 1, so that stage is an identity.
    color = clamp(color, 0.0, 1.0);
    color = pow(color, vec3(1.0 / GAMMA_VALUE));

    fragColor = vec4(color, 1.0);
}

const float PI = 3.14159265358979323846;
const float MIN_EPS = 1.1920928955078125e-7;

const float FOV = 0.66;
const vec3 CAMERA_POS   = vec3(0.68534756, 1.50286375, 6.02741241);
const vec3 CAMERA_DIR   = vec3(-0.069559431916197, -0.181127092711777, -0.980996667536274);
const vec3 CAMERA_UP    = vec3(-0.453970180144104, -0.869906389479763,  0.192805469533965);
const vec3 CAMERA_RIGHT = vec3(-0.888297563303776,  0.458754672813326, -0.021716104634861);

const float GAMMA = 2.2;
const float ANTI_ALIAS_SCALE = 2.0;
const float MIN_DIST = 1.0e-7;
const int REFINE_STEPS = 2;
const float FUDGE_FACTOR = 0.95;
const int MAX_RAY_STEPS = 1200;
const int MAX_SHADOW_STEPS = 300;
const float MAX_DISTANCE = 100.0;
const float DITHER = 0.55852;
const float NORMAL_BACK_STEP = 6.5875;

const float AO_EPS = 0.05186447666087581;
const float AO_CONE_APERTURE = 0.85;
const int AO_ITERATIONS = 7;
const float AO_AMBIENT = 0.7;

const float SPECULAR = 0.21538;
const float SPECULAR_EXP = 248.51;
const float AMBIENT_STRENGTH = 0.59682;
const vec3 REFLECTION = vec3(0.254902);
const int REFLECTION_COUNT = 1;

const vec3 SPOT_COLOR = vec3(0.94902, 0.882353, 0.772549);
const float SPOT_STRENGTH = 10.0;
const vec3 LIGHT_POS = vec3(-1.7558, -2.2138, 4.6564);
const float LIGHT_SIZE = 0.03475;
const float LIGHT_FALLOFF = 0.50202;
const float SHADOW_CONE_BIAS = 0.201;

const vec3 BASE_COLOR = vec3(0.67451);
const float ORBIT_STRENGTH = 0.55319;
const vec3 BACKGROUND_COLOR = vec3(0.172549, 0.235294, 0.294118);
const float BACKGROUND_GRADIENT = 0.47295;

const vec3 SEG_A_COLOR = vec3(0.811765, 0.733333, 0.32549);
const vec3 SEG_B_COLOR = vec3(0.0, 0.486275, 0.729412);
const vec3 SEG_C_COLOR = vec3(0.647059, 0.866667, 0.843137);
const vec3 SEG_D_COLOR = vec3(0.717647, 0.415686, 0.847059);
const vec3 FACE_BD_COLOR = vec3(0.835294118, 0.647058824, 0.784313725);
const vec3 VERTEX_COLOR = vec3(0.909804, 0.937255, 0.976471);
const vec3 FLOOR_COLOR_1 = vec3(0.968627451, 1.0, 0.6);
const vec3 FLOOR_COLOR_2 = vec3(0.552941176, 0.380392157, 0.521568627);
const vec3 FLOOR_LINE_COLOR = vec3(0.0);

const float FLOOR_Z = 1.0e-3;
const float FLOOR_LINE_THICKNESS = 0.008;
const int FOLD4_ITERATIONS = 180;
const int FOLD3_ITERATIONS = 70;

const vec4 MIRROR_A = vec4(1.0, 0.0, 0.0, 0.0);
const vec4 MIRROR_B = vec4(-0.5, 0.8660254037844386, 0.0, 0.0);
const vec4 MIRROR_C = vec4(0.0, 0.0, 1.0, 0.0);
const vec4 MIRROR_D = vec4(0.0, -0.57735026918962595, -0.92387953251128685, -0.43230397167572659);
const vec4 INITIAL_VERTEX = vec4(0.0, 0.0, 0.0, 1.0);
const vec4 INVERSION_SPHERE = vec4(0.0, 1.335519232014724, 2.1371062825819451, 2.3131871672861219);

const float VERTEX_COSH = 1.0050041680558035;
const float VERTEX_SINH = 0.10016675001984403;
const float EDGE_COSH = 1.0012502604383691;
const float EDGE_SINH = 0.050020835937655016;
const float FACE_COSH = 1.0000125000260416;
const float FACE_SINH = 0.0050000208333593754;

const mat3 FACE_BD_INV = mat3(
   -0.80052367148149761,  0.23071304173459076,  0.4614260834691814,
    0.23071304173459076,  1.266841223827166,    0.53368244765433193,
    0.4614260834691814,   0.53368244765433193,  1.0673648953086636
);

vec2 viewCoord, coord, aoSeed;
float lastHoneycombDistance = 1.0e20;
float lastPatternFloorHeight = 1.0e20;

float random1(vec2 p) {
    return fract(sin(dot(p, vec2(12.9898, 78.233))) * 43758.5453);
}

vec2 random2(vec2 p) {
    return vec2(
        fract(sin(dot(p, vec2(12.9898, 78.233))) * 43758.5453),
        fract(cos(dot(p, vec2(4.898, 7.23))) * 23421.631)
    );
}

vec2 uniformDisc(vec2 p) {
    vec2 r = random2(p);
    float a = 6.28 * r.x;
    return sqrt(r.y) * vec2(cos(a), sin(a));
}

vec3 currentPoint(vec3 origin, vec3 direction, float pos) {
    return origin + direction * pos;
}

void reflectRay(inout vec3 origin, inout vec3 direction, inout float pos, vec3 normal) {
    vec3 hit = currentPoint(origin, direction, pos);
    direction = reflect(direction, normal);
    origin = hit + reflect(origin - hit, normal);
    pos += MIN_DIST;
}

float hdot(vec4 p, vec4 q) {
    return dot(p.xyz, q.xyz) - p.w * q.w;
}

vec4 hnormalize(vec4 p) {
    return p * inversesqrt(-hdot(p, p));
}

float tryReflect4(inout vec4 p, vec4 n) {
    float k = min(0.0, hdot(p, n));
    p -= 2.0 * k * n;
    return k;
}

bool fold4d(inout vec4 p) {
    for (int i = 0; i < FOLD4_ITERATIONS; ++i) {
        float k = 0.0;
        p.x = abs(p.x);
        k += tryReflect4(p, MIRROR_B);
        k += tryReflect4(p, MIRROR_C);
        k += tryReflect4(p, MIRROR_D);
        if (k == 0.0) return true;
    }
    return false;
}

bool foldB(inout vec3 p, inout int count) {
    float k = dot(p, MIRROR_B.xyz);
    if (k >= 0.0) return true;
    p -= 2.0 * k * MIRROR_B.xyz;
    count += 1;
    return false;
}

bool foldSphere(inout vec3 p, inout int count) {
    vec3 q = p - INVERSION_SPHERE.xyz;
    float d2 = dot(q, q);
    if (d2 == 0.0) return true;

    float k = INVERSION_SPHERE.w * INVERSION_SPHERE.w / d2;
    if (k < 1.0) return true;

    p = k * q + INVERSION_SPHERE.xyz;
    count += 1;
    return false;
}

bool fold3d(inout vec3 p, inout int count) {
    for (int i = 0; i < FOLD3_ITERATIONS; ++i) {
        bool inA = p.x >= 0.0;
        if (!inA) { p.x = -p.x; count += 1; }

        bool inB = foldB(p, count);

        bool inC = p.z >= 0.0;
        if (!inC) { p.z = -p.z; count += 1; }

        bool inD = foldSphere(p, count);
        if (inA && inB && inC && inD) return true;
    }
    return false;
}

float distABCD(vec3 p) {
    return min(
        min(abs(p.x), abs(dot(p, MIRROR_B.xyz))),
        min(abs(p.z), abs(length(p - INVERSION_SPHERE.xyz) - INVERSION_SPHERE.w))
    );
}

vec3 planeToSphere(vec2 p) {
    float r2 = dot(p, p);
    return vec3(2.0 * p, r2 - 1.0) / (1.0 + r2);
}

float knightyDD(float ca, float sa, float r) {
    float rr = r * r;
    float cm1 = ca - 1.0;
    return (1.0 - rr) * (sa + r * cm1) /
           (1.0 + ca + rr * cm1 + 2.0 * r * sa);
}

float hsind(vec4 p, vec4 q) {
    return 0.5 * sqrt(-hdot(p - q, p - q) * hdot(p + q, p + q));
}

float dVertexCached(vec4 p, float r, float pv) {
    float ca = -pv;
    float sa = hsind(p, INITIAL_VERTEX);
    return knightyDD(ca * VERTEX_COSH - sa * VERTEX_SINH,
                     sa * VERTEX_COSH - ca * VERTEX_SINH, r);
}

float dSegmentCached(vec4 p, vec4 n, float r, float pv, float pn) {
    float nv = -n.w;
    float det = -1.0 - nv * nv;
    vec4 q = hnormalize(min((-nv * pv - pn) / det, 0.0) * n +
                        ((pv - pn * nv) / det) * INITIAL_VERTEX);

    float ca = -hdot(p, q);
    float sa = hsind(p, q);
    return knightyDD(ca * EDGE_COSH - sa * EDGE_SINH,
                     sa * EDGE_COSH - ca * EDGE_SINH, r);
}

float dFaceBDCached(vec4 p, float r, float pv, float pB, float pD) {
    vec3 c = vec3(pv, pB, pD) * FACE_BD_INV;
    if (c.y > 0.0 || c.z > 0.0) return 1.0e5;

    vec4 q = hnormalize(c.x * INITIAL_VERTEX + c.y * MIRROR_B + c.z * MIRROR_D);
    float ca = -hdot(p, q);
    float sa = hsind(p, q);
    return knightyDD(ca * FACE_COSH - sa * FACE_SINH,
                     sa * FACE_COSH - ca * FACE_SINH, r);
}

float dSegmentsCached(vec4 p, float r, float pv, float pA, float pB, float pC, float pD) {
    return min(
        min(dSegmentCached(p, MIRROR_A, r, pv, pA), dSegmentCached(p, MIRROR_B, r, pv, pB)),
        min(dSegmentCached(p, MIRROR_C, r, pv, pC), dSegmentCached(p, MIRROR_D, r, pv, pD))
    );
}

vec4 toHyperboloid(inout vec3 p, out float r) {
    p.z += 1.0;
    p *= 2.0 / dot(p, p);
    p.z -= 1.0;
    r = length(p);
    return vec4(2.0 * p, 1.0 + r * r) / (1.0 - r * r);
}

void getDots(vec4 q, out float qV, out float qA, out float qB, out float qC, out float qD) {
    qV = -q.w;
    qA = q.x;
    qB = dot(q.xyz, MIRROR_B.xyz);
    qC = q.z;
    qD = hdot(q, MIRROR_D);
}

float DE(vec3 p) {
    float h = p.z - FLOOR_Z;
    float r;
    vec4 q = toHyperboloid(p, r);
    fold4d(q);

    float qV, qA, qB, qC, qD;
    getDots(q, qV, qA, qB, qC, qD);

    float dHoneycomb = min(
        dFaceBDCached(q, r, qV, qB, qD),
        min(dVertexCached(q, r, qV), dSegmentsCached(q, r, qV, qA, qB, qC, qD))
    );

    lastHoneycombDistance = dHoneycomb;
    lastPatternFloorHeight = h;
    return min(h, dHoneycomb);
}

vec3 baseColor(vec3 pos) {
    vec3 floorPoint = pos;
    float h = pos.z - FLOOR_Z;

    float r;
    vec4 q = toHyperboloid(pos, r);
    if (!fold4d(q)) return BACKGROUND_COLOR;

    float qV, qA, qB, qC, qD;
    getDots(q, qV, qA, qB, qC, qD);

    float dA = dSegmentCached(q, MIRROR_A, r, qV, qA);
    float dB = dSegmentCached(q, MIRROR_B, r, qV, qB);
    float dC = dSegmentCached(q, MIRROR_C, r, qV, qC);
    float dD = dSegmentCached(q, MIRROR_D, r, qV, qD);
    float dV = dVertexCached(q, r, qV);
    float dF = dFaceBDCached(q, r, qV, qB, qD);

    float d = min(min(dF, dV), min(min(dA, dB), min(dC, dD)));
    d = min(d, h);

    vec3 color = SEG_A_COLOR;
    if (d == dB) color = SEG_B_COLOR;
    if (d == dC) color = SEG_C_COLOR;
    if (d == dD) color = SEG_D_COLOR;
    if (d == dV) color = VERTEX_COLOR;
    if (d == dF) color = FACE_BD_COLOR;

    if (d == h) {
        int count = 0;
        vec3 folded = planeToSphere(floorPoint.xy);
        bool found = fold3d(folded, count);
        color = found ? ((count % 2 == 0) ? FLOOR_COLOR_1 : FLOOR_COLOR_2) : FLOOR_LINE_COLOR;

        float edgeDistance = distABCD(folded);
        float aa = 0.5 * fwidth(edgeDistance);
        float lineMask = 1.0 - smoothstep(
            FLOOR_LINE_THICKNESS - aa,
            FLOOR_LINE_THICKNESS + aa,
            edgeDistance
        );
        color = mix(color, FLOOR_LINE_COLOR, lineMask);
    }

    return color;
}

float sceneDistanceAlongRay(vec3 p, vec3 rd, float floorClearance) {
    DE(p);
    float h = lastPatternFloorHeight;
    float floorRayDistance = 1.0e20;

    if (h <= floorClearance) floorRayDistance = h;
    else if (rd.z < -1.0e-7) floorRayDistance = (h - floorClearance) / (-rd.z);

    return min(lastHoneycombDistance, floorRayDistance);
}

float lightDistance(vec3 p) {
    return length(LIGHT_POS - p) - LIGHT_SIZE;
}

vec3 surfaceNormal(vec3 p, float normalDistance) {
    float e = max(0.5 * normalDistance, 1.0e-5);
    vec3 ex = vec3(e, 0.0, 0.0);
    vec3 ey = vec3(0.0, e, 0.0);
    vec3 ez = vec3(0.0, 0.0, e);
    vec3 n = normalize(vec3(
        DE(p + ex) - DE(p - ex),
        DE(p + ey) - DE(p - ey),
        DE(p + ez) - DE(p - ez)
    ));
    return all(equal(n, n)) ? n : vec3(0.0);
}

float softShadow(vec3 ro, float eps) {
    vec3 rd = LIGHT_POS - ro;
    float lightDist = length(rd);
    rd /= lightDist;

    float coneGrad = lightDist / SHADOW_CONE_BIAS;
    float totalDist = 2.0 * eps;
    float visibility = 1.0;
    float jitterScale = 1.0 + DITHER * (random1(ro.xy) - 0.5) / coneGrad;

    for (int i = 0; i < MAX_SHADOW_STEPS && totalDist < lightDist; ++i) {
        float dist = DE(ro + totalDist * jitterScale * rd) * FUDGE_FACTOR;
        if (dist < eps) return 1.0;
        visibility = min(visibility, coneGrad * dist / totalDist);
        totalDist += dist;
    }
    return 1.0 - visibility;
}

vec3 orthogonal(vec3 v) {
    return abs(v.x) > abs(v.z) ? vec3(-v.y, v.x, 0.0) : vec3(0.0, -v.z, v.y);
}

vec3 aoDirection(vec3 n) {
    aoSeed += vec2(-1.0, 1.0);
    vec2 r = random2(aoSeed);
    r.x *= 2.0 * PI;
    r.y *= AO_CONE_APERTURE;

    vec3 o1 = normalize(orthogonal(n));
    vec3 o2 = cross(n, o1);
    float radial = sqrt(r.y);
    return cos(r.x) * radial * o1 +
           sin(r.x) * radial * o2 +
           sqrt(1.0 - r.y) * n;
}

float ambientOcclusion(vec3 p, vec3 n) {
    vec3 direction = aoDirection(n);
    float de = DE(p) / AO_EPS;
    float d = 1.0 - DITHER * random1(p.xy);
    float previous = 1.0;
    float ao = 0.0;
    float directionDotNormal = dot(direction, n);

    for (int i = 1; i < AO_ITERATIONS; ++i) {
        float current = DE(p + d * direction * de) / (d * de * directionDotNormal);
        current = min(previous, current);
        previous = current;
        ao += clamp(1.0 - current, 0.0, 1.0);
        d *= 1.61;
    }

    return ao / float(AO_ITERATIONS - 1);
}

vec3 pointLightGlow(float glow) {
    return SPOT_COLOR * (SPOT_STRENGTH * exp(-20.0 * glow) + exp(-1.0e8 * glow));
}

vec3 lighting(vec3 n, vec3 surfaceColor, vec3 pos, vec3 rayDir, float eps, float ao) {
    vec3 toLight = LIGHT_POS - pos;
    float d2 = dot(toLight, toLight);
    float falloff = pow(d2, -LIGHT_FALLOFF);
    vec3 lightDir = toLight * inversesqrt(d2);

    float nDotL = max(0.0, dot(n, lightDir));
    vec3 halfVector = normalize(lightDir - rayDir);
    float hDotN = max(0.0, dot(n, halfVector));

    float f0 = (SPECULAR_EXP - 1.0) / (SPECULAR_EXP + 1.0);
    f0 *= f0;
    float fresnel = f0 + (1.0 - f0) * pow(1.0 + dot(n, rayDir), 5.0);
    float specular = ((SPECULAR_EXP + 2.0) / 8.0) *
                     fresnel * nDotL *
                     pow(hDotN, SPECULAR_EXP + 0.00001) *
                     SPECULAR;

    float lightVisibility = 1.0 - softShadow(pos + n * eps, eps);
    vec3 direct = SPOT_COLOR * SPOT_STRENGTH * falloff *
                  (nDotL + specular) * lightVisibility;

    vec3 ambient = vec3(AMBIENT_STRENGTH) *
                   (1.0 - clamp(AO_AMBIENT * ao, 0.0, 1.0));

    return (direct + ambient) * surfaceColor;
}

float rayEps(float rayPos) {
    return max(MIN_EPS, rayPos * MIN_DIST * FUDGE_FACTOR);
}

vec3 trace(
    inout vec3 origin,
    inout vec3 direction,
    inout float rayPos,
    float rayFudge,
    out vec3 hitNormal,
    out float glow,
    out bool hitLight
) {
    glow = 1000.0;
    hitLight = false;
    bool hitSomething = false;

    float dist = 0.0;
    float lightDE = 0.0;
    float eps = rayEps(rayPos);

    vec3 p = currentPoint(origin, direction, rayPos);
    float initialStep = min(
        sceneDistanceAlongRay(p, direction, 0.5 * eps) * FUDGE_FACTOR,
        lightDistance(p)
    );
    initialStep *= DITHER * random1(direction.xy) + (1.0 - DITHER);
    rayPos += initialStep * rayFudge;

    for (int steps = 0; steps < MAX_RAY_STEPS; ++steps) {
        p = currentPoint(origin, direction, rayPos);
        lightDE = lightDistance(p);
        dist = min(lightDE, sceneDistanceAlongRay(p, direction, 0.5 * eps) * FUDGE_FACTOR);

        glow = min(lightDE, glow);
        rayPos += dist * rayFudge;
        eps = rayEps(rayPos);

        if (dist < eps) {
            for (int i = 0; i < REFINE_STEPS; ++i) {
                rayPos += (dist - 1.5 * eps) * rayFudge;
                p = currentPoint(origin, direction, rayPos);
                lightDE = lightDistance(p);
                dist = min(lightDE, sceneDistanceAlongRay(p, direction, 0.5 * eps) * FUDGE_FACTOR);
                glow = min(lightDE, glow);
            }
            hitSomething = true;
            break;
        }

        if (rayPos > MAX_DISTANCE) break;
    }

    vec3 background = mix(BACKGROUND_COLOR, vec3(0.0), length(coord) * BACKGROUND_GRADIENT);

    if (!hitSomething) {
        hitNormal = vec3(0.0);
        rayPos = MAX_DISTANCE;
        return background;
    }

    if (dist == lightDE && dist == glow) {
        hitLight = true;
        return SPOT_COLOR * SPOT_STRENGTH / (LIGHT_SIZE + 0.01);
    }

    vec3 hit = currentPoint(origin, direction, rayPos);
    hitNormal = surfaceNormal(hit - NORMAL_BACK_STEP * eps * direction, eps);

    vec3 hitColor = mix(BASE_COLOR, baseColor(hit), ORBIT_STRENGTH);
    hitColor = pow(clamp(hitColor, 0.0, 1.0), vec3(GAMMA));

    return lighting(hitNormal, hitColor, hit, direction, eps, ambientOcclusion(hit, hitNormal));
}

vec3 render(vec3 origin, vec3 direction, float rayFudge) {
    aoSeed = viewCoord * (float(iFrame) + 1.0);

    float glow = 0.5;
    float rayPos = 0.0;
    bool hitLight = false;
    vec3 hitNormal = vec3(0.0);
    vec3 color = vec3(0.0);
    vec3 reflectionWeight = vec3(1.0);

    for (int i = 0; i <= REFLECTION_COUNT; ++i) {
        vec3 passColor = trace(origin, direction, rayPos, rayFudge, hitNormal, glow, hitLight);
        passColor += pointLightGlow(max(0.0, glow));

        color += passColor * reflectionWeight;
        reflectionWeight *= REFLECTION;

        if (all(equal(hitNormal, vec3(0.0))) ||
            dot(reflectionWeight, reflectionWeight) < 0.00001 ||
            hitLight || rayPos >= MAX_DISTANCE) {
            break;
        }

        reflectRay(origin, direction, rayPos, hitNormal);
    }

    return max(color, vec3(0.0));
}

void mainImage(out vec4 fragColor, in vec2 fragCoord) {
    viewCoord = 2.0 * fragCoord / iResolution.xy - 1.0;
    coord = vec2(viewCoord.x * iResolution.x / iResolution.y, viewCoord.y) * FOV;

    vec2 disc = uniformDisc(coord * float(1 + iFrame));
    vec2 jitteredCoord = coord + ANTI_ALIAS_SCALE * FOV * disc / iResolution.xy;

    vec3 rayDirection =
        CAMERA_DIR +
        jitteredCoord.x * CAMERA_RIGHT +
        jitteredCoord.y * CAMERA_UP;

    float directionLength = length(rayDirection);
    vec3 sampleColor = render(
        CAMERA_POS,
        rayDirection / directionLength,
        1.0 / max(1.0, directionLength)
    );

    float weight = exp(-dot(disc, disc)) - exp(-1.0);
    vec4 previous = (iFrame == 0) ? vec4(0.0) : texture(iChannel0, fragCoord / iResolution.xy);
    fragColor = previous + vec4(sampleColor * weight, weight);
}

const float GAMMA_VALUE = 1.9;
const float EXPOSURE = 1.14;
const float BRIGHTNESS = 1.0;
const float CONTRAST = 1.14;
const float SATURATION = 1.1;
const float BLOOM_INTENSITY = 2.0;
const float BLOOM_POWER = 1.4118;
const int BLOOM_TAPS = 2;
const float INV_BLOOM_TAPS = 1.0 / float(BLOOM_TAPS);
const float BLOOM_SAMPLE_COUNT = float((2 * BLOOM_TAPS + 1) * (2 * BLOOM_TAPS + 1));

vec3 contrastSaturationBrightness(vec3 color, float brt, float sat, float con) {
    const vec3 LUMA = vec3(0.2125, 0.7154, 0.0721);
    vec3 brtColor = color * brt;
    vec3 intensity = vec3(dot(brtColor, LUMA));
    return mix(vec3(0.5), mix(intensity, brtColor, sat), con);
}

vec4 bloom(vec2 uv) {
    vec4 sum = vec4(0.0);
    // Keep the original isotropic texel size to preserve the previous look.
    vec2 texel = vec2(1.0 / iResolution.x);

    for (int x = -BLOOM_TAPS; x <= BLOOM_TAPS; ++x) {
        float fx = float(x) * INV_BLOOM_TAPS;
        float wx = 1.0 - fx * fx;
        wx *= wx;

        for (int y = -BLOOM_TAPS; y <= BLOOM_TAPS; ++y) {
            float fy = float(y) * INV_BLOOM_TAPS;
            float wy = 1.0 - fy * fy;
            wy *= wy;
            sum += texture(iChannel0, uv + vec2(float(x), float(y)) * texel) * (wx * wy);
        }
    }

    return sum / BLOOM_SAMPLE_COUNT;
}

void mainImage(out vec4 fragColor, in vec2 fragCoord) {
    vec2 uv = fragCoord / iResolution.xy;

    vec4 accumulated = texture(iChannel0, uv);
    vec3 color = accumulated.rgb / max(accumulated.a, 1.0e-8);

    vec4 blurred = bloom(uv);
    color += BLOOM_INTENSITY * pow(blurred.rgb / max(blurred.a, 1.0e-8), vec3(BLOOM_POWER));

    color *= EXPOSURE;
    vec3 x = max(vec3(0.0), color - vec3(0.004));
    color = (x * (6.2 * x + 0.5)) / (x * (6.2 * x + 1.7) + 0.06);
    color = pow(color, vec3(2.2));
    color = contrastSaturationBrightness(color, BRIGHTNESS, SATURATION, CONTRAST);
    color = pow(color, vec3(1.0 / GAMMA_VALUE));

    fragColor = vec4(color, 1.0);
}

const float PI = 3.14159265358979323846264;
const float MIN_EPS = 2.0 / 16777216.0;

const float FOV = 0.6;
const vec3  EYE = vec3(-1.24309, -0.228511, -0.0106397);
const vec3  TARGET = vec3(4.52812, 6.09633, -2.29487);
const vec3  CAMERA_UP = vec3(-0.115517, -0.241343, -0.960116);

// Precomputed from EYE / TARGET / CAMERA_UP. This avoids per-pixel normalizations.
const vec3  CAMERA_DIR_FIXED   = vec3( 0.65125953,  0.71373473, -0.25776687);
const vec3  CAMERA_UP_FIXED    = vec3(-0.11589911, -0.24214153, -0.96329376);
const vec3  CAMERA_RIGHT_FIXED = vec3(-0.74995228,  0.65722920, -0.07497576);

const float FOCAL_PLANE = 0.029;
const float INV_FOCAL_PLANE = 1.0 / FOCAL_PLANE;
const float APERTURE = 0.01;
const float IN_FOCUS_WIDTH = 7.1;
const float FOCUS_SHIFT = -26.38275862068965;
const float GAUSSIAN_WEIGHT = 1.0;
const float ANTIALIAS_SCALE = 1.7;

// Fixed 5-sided aperture.
const float NGON_D = 1.3763819204711736;    // cot(PI / 5)
const float NGON_LH = 0.5877852522924731;  // 1.0 / sqrt(1.0 + NGON_D^2)

const int   ITERATIONS = 35;
const int   COLOR_ITERATIONS = 10;
const int   SKIP_COLOR_ITERATIONS = 2;
const float BAILOUT = 2.0;
const vec3  JULIA_C = vec3(-0.28036, -0.88288, -0.00084);

const float GAMMA_VALUE = 2.2;
const float MIN_DIST = 0.00005;
const float FUDGE_FACTOR = 0.55;
const float EPS_SCALE = MIN_DIST * FUDGE_FACTOR;
const int   MAX_RAY_STEPS = 1500;
const int   MAX_SHADOW_STEPS = 96;    // aggressive: secondary rays only; main ray still uses 1500
const float MAX_DISTANCE = 20.0;
const float NORMAL_BACK_STEP = 1.5;

const float SPECULAR = 0.25397;
const float SPECULAR_EXP = 9.722;
const float SPECULAR_MAX = 10.0;
const vec4  CAM_LIGHT = vec4(1.0, 0.803922, 0.627451, 3.4);
const float CAM_LIGHT_MIN = 0.59494;
const vec4  GLOW = vec4(1.0, 0.584314, 0.0, 0.15116);
const int   GLOW_MAX = 100;

const vec4  AO_VALUE = vec4(0.0, 0.0, 0.0, 1.0);
const float AO_EPS = 0.0643472512963583;
const vec3  AO_POW = vec3(1.36448, 1.19626, 2.45244);
const float AO_WEIGHT_MULT = 0.1 * AO_POW.z;

const vec4  SPOT_LIGHT = vec4(0.792157, 1.0, 1.0, 1.0);
const vec3  LIGHT_POS = vec3(3.0338, 3.7078, 1.4606);
const float LIGHT_SIZE = 0.47423;
const float INV_LIGHT_GLOW_RAD2 = 1.0 / ((0.94595 + 0.0001) * (0.94595 + 0.0001));
const float LIGHT_GLOW_EXP = 1.46665;
const float SHADOW_SOFT2 = 27.7332;
const float SHADOW_BLUR = 6.2338;

const vec4 COLOR_X = vec4(0.780392, 0.2, 0.0980392, 1.0);
const vec4 COLOR_Y = vec4(0.223529, 0.988235, 1.0, -0.59596);
const vec4 COLOR_Z = vec4(0.415686, 1.0, 0.0235294, 1.0);
const vec4 COLOR_R = vec4(0.694118, 0.764706, 0.564706, 0.28572);
const vec3 BACKGROUND_COLOR = vec3(0.258824, 0.623529, 0.866667);
const float GRADIENT_BACKGROUND = 1.1905;

const float FOG_DENSITY = 0.2;
const vec3  FOG_COLOR = vec3(0.62714691855, 1.21248251946, 1.52307);

vec2 screenCoord;

float rand1(vec2 p) {
    return fract(sin(dot(p, vec2(12.9898, 78.233))) * 43758.5453);
}

vec2 rand2(vec2 p) {
    return vec2(
        fract(sin(dot(p, vec2(12.9898, 78.233))) * 43758.5453),
        fract(cos(dot(p, vec2(4.898, 7.23))) * 23421.631)
    );
}

vec2 uniformDisc(vec2 p) {
    vec2 r = rand2(p);
    float a = 6.28 * r.x;
    return sqrt(r.y) * vec2(cos(a), sin(a));
}

vec2 nGonDisc(vec2 p) {
    vec2 r = rand2(p);
    vec2 q = vec2(r.x + r.y, r.x - r.y);
    q.x = (1.0 - abs(q.x - 1.0)) * NGON_D;
    q *= NGON_LH;

    float a = floor(dot(rand2(11.0 * p + vec2(1.0)), vec2(1.0)) * 5.0) * (2.0 * PI / 5.0);
    vec2 cs = vec2(cos(a), sin(a));
    return vec2(cs.x * q.x - cs.y * q.y, cs.x * q.y + cs.y * q.x);
}

vec3 currentPt(vec3 ro, vec3 rd, vec3 offset, float rayPos) {
    float t = 1.0 - rayPos * INV_FOCAL_PLANE;
    float d = t - IN_FOCUS_WIDTH *
        (2.0 * smoothstep(-1.5 * IN_FOCUS_WIDTH, 1.5 * IN_FOCUS_WIDTH, t) - 1.0);
    return ro + rd * rayPos + offset * d;
}

vec3 triplexSqr(vec3 a) {
    a = abs(a);
    float r2 = dot(a.xy, a.xy);
    float rz = r2 - a.z * a.z;
    vec2 xy = vec2(a.x * a.x - a.y * a.y, 2.0 * a.x * a.y) / r2;
    return vec3(xy * rz, 2.0 * sqrt(r2) * a.z);
}

float DE(vec3 pos, inout vec4 trap) {
    float lenPos = length(pos);
    float delta = exp2(-18.0 + max(floor(log2(lenPos)), 0.0));
    float invDelta = 1.0 / delta;

    vec3 z  = pos;
    vec3 z2 = pos + vec3(delta, 0.0, 0.0);
    vec3 z3 = pos + vec3(0.0, delta, 0.0);
    vec3 z4 = pos + vec3(0.0, 0.0, delta);

    float r = lenPos;
    for (int i = 0; i < ITERATIONS; ++i) {
        if (r >= BAILOUT) break;

        z  = triplexSqr(z ) + JULIA_C;
        z2 = triplexSqr(z2) + JULIA_C;
        z3 = triplexSqr(z3) + JULIA_C;
        z4 = triplexSqr(z4) + JULIA_C;

        r = length(z);
        if (i >= SKIP_COLOR_ITERATIONS && i < COLOR_ITERATIONS) {
            trap = min(trap, abs(vec4(z, r * r)));
        }
    }

    float dr = length(vec3(length(z2 - z), length(z3 - z), length(z4 - z))) * invDelta;
    return max(0.5 * log(r) * r / dr, pos.z);
}

// Same distance estimator as DE(), but with the orbit-trap result ignored.
// After inlining, a good compiler can eliminate the dead trap writes here.
float DEnoTrap(vec3 pos) {
    vec4 unusedTrap = vec4(10000.0);
    return DE(pos, unusedTrap);
}

float DElight(vec3 p) {
    return length(p + LIGHT_POS) - LIGHT_SIZE;
}

vec3 normalAt(vec3 p, float normalDistance) {
    // Tetrahedral normal: 4 DE evaluations instead of central differences' 6.
    // Uses DEnoTrap so normal sampling does not overwrite the hit orbit color.
    float h = max(0.65 * normalDistance, 1.0e-5);
    vec2 k = vec2(1.0, -1.0);
    return normalize(
        k.xyy * DEnoTrap(p + k.xyy * h) +
        k.yyx * DEnoTrap(p + k.yyx * h) +
        k.yxy * DEnoTrap(p + k.yxy * h) +
        k.xxx * DEnoTrap(p + k.xxx * h)
    );
}

float shadowMarch(vec3 pos, vec3 dir, float eps, out bool hit) {
    float s = 1.0;
    float totalDist = 2.0 * eps;
    hit = false;

    for (int i = 0; i < MAX_SHADOW_STEPS; ++i) {
        if (totalDist >= MAX_DISTANCE) break;

        vec3 p = pos + totalDist * dir;
        float lightDE = DElight(p);
        float dist = min(DEnoTrap(p), lightDE);

        if (dist < eps) {
            hit = true;
            return (dist == lightDE) ? 0.0 : 1.0;
        }

        s = min(s, 30.0 * SHADOW_SOFT2 * dist / totalDist);
        if (s < 0.001) break;
        totalDist += dist;
    }

    return s;
}

float shadow(vec3 pos, vec3 sdir, float eps) {
    // Single soft-shadow march. This is the biggest safe-ish speedup after capping
    // shadow steps: one expensive secondary march instead of two.
    // Keep the same deterministic blur direction so the accumulated image is stable.
    vec3 axis = (abs(sdir.x) > 0.9) ? vec3(0.0, 1.0, 0.0)
                                    : vec3(1.0, 0.0, 0.0);
    vec3 perp = normalize(cross(sdir, axis));
    vec3 perp2 = cross(sdir, perp);

    float angle = PI * rand1(vec2(pos.x, pos.y + pos.z)) + 2.0 * PI / 3.0;
    float fac = SHADOW_BLUR / SHADOW_SOFT2 * rand1(vec2(pos.y, pos.x + pos.z));
    vec3 sdirBlur = normalize(sdir + fac * (perp * cos(angle) + perp2 * sin(angle)));

    bool hit;
    float s = shadowMarch(pos, sdirBlur, eps, hit);
    if (hit) return s;
    return 1.0 - s;
}

float ambientOcclusion(vec3 p, vec3 n) {
    // 3-sample AO instead of 5. The later samples are broad/low-frequency and
    // relatively expensive for this DE, so dropping them is usually hard to see.
    float de0 = DEnoTrap(p);
    float ao = 0.0;
    float wSum = 0.0;
    float w = 1.0;

    for (int i = 1; i < 4; ++i) {
        float fi = float(i);
        float scale = fi * fi * AO_EPS;
        float D = (DEnoTrap(p + n * scale * AO_POW.x) - de0) / (scale * AO_POW.y);
        w *= AO_WEIGHT_MULT;
        ao += w * clamp(1.0 - D, 0.0, 1.0);
        wSum += w;
    }

    return clamp(AO_VALUE.w * ao / wSum, 0.0, 1.0);
}

vec3 getColor(vec4 trap) {
    trap.w = sqrt(trap.w);
    return 3.0 * (
        COLOR_X.rgb * COLOR_X.w * trap.x +
        COLOR_Y.rgb * COLOR_Y.w * trap.y +
        COLOR_Z.rgb * COLOR_Z.w * trap.z +
        COLOR_R.rgb * COLOR_R.w * trap.w
    );
}

vec3 lighting(vec3 n, vec3 color, vec3 pos, vec3 rd, float eps, float ao) {
    // Analytic normal of DElight sphere. Equivalent to -lightNormal(pos, eps).
    vec3 spotDir = normalize(-pos - LIGHT_POS);
    vec3 halfVector = normalize(spotDir - rd);
    float hDotN = max(0.0, dot(n, halfVector));

    float f0 = (SPECULAR_EXP - 1.0) / (SPECULAR_EXP + 1.0);
    f0 *= f0;

    // AO_CORRECT = 1.0, so nDotL = max(1.0, dot(n, spotDir)) is effectively 1.0.
    float specular = ((SPECULAR_EXP + 2.0) / 8.0)
                   * (f0 + (1.0 - f0) * pow(1.0 + dot(n, rd), 5.0))
                   * pow(hDotN, SPECULAR_EXP + 0.00001)
                   * SPECULAR;
    specular = min(SPECULAR_MAX, specular);

    float sh = shadow(pos + n * eps, spotDir, eps);
    return (
        SPOT_LIGHT.rgb * ((1.0 - sh) + specular * (1.0 - sh)) +
        CAM_LIGHT.rgb * CAM_LIGHT.w * max(CAM_LIGHT_MIN, dot(-n, rd)) * (1.0 - ao)
    ) * color;
}

vec3 trace(vec3 ro, vec3 rd, vec3 offset, float rayFudge, inout float rayPos, out float glow) {
    glow = 1000.0;
    vec4 orbitTrap = vec4(10000.0);

    float fSteps = 1.0;
    float dist = 0.0;
    float lightDE = 0.0;
    float eps = max(MIN_EPS, rayPos * EPS_SCALE);

    vec3 p = currentPt(ro, rd, offset, rayPos);
    rayPos += DE(p, orbitTrap) * FUDGE_FACTOR * rayFudge;

    int steps = 0;
    for (; steps < MAX_RAY_STEPS; ++steps) {
        p = currentPt(ro, rd, offset, rayPos);

        float de = DE(p, orbitTrap);
        lightDE = DElight(p);
        dist = min(de * FUDGE_FACTOR, lightDE);

        glow = min(glow, lightDE);
        rayPos += dist * rayFudge;
        fSteps += 1.0;

        eps = max(MIN_EPS, rayPos * EPS_SCALE);
        if (dist < eps) {
            rayPos += (dist - 2.5 * eps) * rayFudge;
            break;
        }

        if (rayPos > MAX_DISTANCE) {
            fSteps -= (rayPos - MAX_DISTANCE) / dist;
            break;
        }
    }

    vec3 backColor = BACKGROUND_COLOR * (1.0 - length(screenCoord) * GRADIENT_BACKGROUND);
    if (steps == MAX_RAY_STEPS) orbitTrap = vec4(0.0);

    if (dist < eps) {
        if (dist == lightDE) return SPOT_LIGHT.rgb * 2.0;

        vec3 hit = currentPt(ro, rd, offset, rayPos);
        vec3 n = normalAt(hit - NORMAL_BACK_STEP * eps * rd, eps);
        vec3 hitColor = pow(clamp(getColor(orbitTrap), 0.0, 1.0), vec3(GAMMA_VALUE));
        return lighting(n, hitColor, hit, rd, eps, ambientOcclusion(hit, n));
    }

    rayPos = 10000.0;
    return backColor + GLOW.rgb * clamp(fSteps / float(GLOW_MAX), 0.0, 1.0) * GLOW.w;
}

vec3 renderColor(vec3 ro, vec3 rd, vec3 offset, float rayFudge) {
    float rayPos = 0.0;
    float glow;
    vec3 p0 = currentPt(ro, rd, offset, rayPos);
    vec3 col = trace(ro, rd, offset, rayFudge, rayPos, glow);
    vec3 p1 = currentPt(ro, rd, offset, rayPos);

    float fog = 1.0 - exp(-FOG_DENSITY * length(p1 - p0));
    float g = max(glow, 0.0);
    return mix(col, FOG_COLOR, fog) + SPOT_LIGHT.rgb *
        (SPOT_LIGHT.w * exp(-20.0 * g) + exp(-INV_LIGHT_GLOW_RAD2 * pow(g, LIGHT_GLOW_EXP)));
}

void mainImage(out vec4 fragColor, in vec2 fragCoord) {
    vec2 invRes = 1.0 / iResolution.xy;
    vec2 uv = fragCoord * invRes;
    screenCoord = (2.0 * fragCoord - iResolution.xy) * (FOV * invRes.y);

    vec3 cameraDir = CAMERA_DIR_FIXED;
    vec3 up = CAMERA_UP_FIXED;
    vec3 right = CAMERA_RIGHT_FIXED;

    float frame = float(iFrame) + 1.0;
    vec2 apertureSample = APERTURE * nGonDisc((uv * 2.0 - 1.0) * frame);
    vec2 disc = uniformDisc(screenCoord * frame);
    vec2 jitteredCoord = screenCoord + ANTIALIAS_SCALE * FOV * disc * invRes.y;

    vec3 lensOffset = apertureSample.x * right + apertureSample.y * up;
    vec3 rayDir = cameraDir + jitteredCoord.x * right + jitteredCoord.y * up;

    float rayFudge = 1.0 / max(1.0, length(rayDir + lensOffset * FOCUS_SHIFT));

    vec3 color = renderColor(EYE, normalize(rayDir), lensOffset, rayFudge);

    vec4 previous = (iFrame == 0) ? vec4(0.0) : texture(iChannel0, uv);
    float weight = exp(-dot(disc, disc) / GAUSSIAN_WEIGHT) - exp(-1.0 / GAUSSIAN_WEIGHT);
    fragColor = previous + vec4(color * weight, weight);
}

const float GAMMA_VALUE = 1.9;
const float EXPOSURE = 1.14;
const float BRIGHTNESS = 1.0;
const float CONTRAST = 1.14;
const float SATURATION = 1.1;
const float BLOOM_INTENSITY = 2.0;
const float BLOOM_POWER = 1.4118;
const int BLOOM_TAPS = 2;
const float INV_BLOOM_TAPS = 1.0 / float(BLOOM_TAPS);
const float BLOOM_SAMPLE_COUNT = float((2 * BLOOM_TAPS + 1) * (2 * BLOOM_TAPS + 1));

vec3 contrastSaturationBrightness(vec3 color, float brt, float sat, float con) {
    const vec3 LUMA = vec3(0.2125, 0.7154, 0.0721);
    vec3 brtColor = color * brt;
    vec3 intensity = vec3(dot(brtColor, LUMA));
    return mix(vec3(0.5), mix(intensity, brtColor, sat), con);
}

vec4 bloom(vec2 uv) {
    vec4 sum = vec4(0.0);
    // Keep the original isotropic texel size to preserve the previous look.
    vec2 texel = vec2(1.0 / iResolution.x);

    for (int x = -BLOOM_TAPS; x <= BLOOM_TAPS; ++x) {
        float fx = float(x) * INV_BLOOM_TAPS;
        float wx = 1.0 - fx * fx;
        wx *= wx;

        for (int y = -BLOOM_TAPS; y <= BLOOM_TAPS; ++y) {
            float fy = float(y) * INV_BLOOM_TAPS;
            float wy = 1.0 - fy * fy;
            wy *= wy;
            sum += texture(iChannel0, uv + vec2(float(x), float(y)) * texel) * (wx * wy);
        }
    }

    return sum / BLOOM_SAMPLE_COUNT;
}

void mainImage(out vec4 fragColor, in vec2 fragCoord) {
    vec2 uv = fragCoord / iResolution.xy;

    vec4 accumulated = texture(iChannel0, uv);
    vec3 color = accumulated.rgb / max(accumulated.a, 1.0e-8);

    vec4 blurred = bloom(uv);
    color += BLOOM_INTENSITY * pow(blurred.rgb / max(blurred.a, 1.0e-8), vec3(BLOOM_POWER));

    color *= EXPOSURE;
    vec3 x = max(vec3(0.0), color - vec3(0.004));
    color = (x * (6.2 * x + 0.5)) / (x * (6.2 * x + 1.7) + 0.06);
    color = pow(color, vec3(2.2));
    color = contrastSaturationBrightness(color, BRIGHTNESS, SATURATION, CONTRAST);
    color = pow(color, vec3(1.0 / GAMMA_VALUE));

    fragColor = vec4(color, 1.0);
}

const float PI = 3.14159265358979323846264;
const float MIN_EPS = 2.0 / 16777216.0;

const float FOV = 0.6;
const vec3  EYE = vec3(-1.24309, -0.228511, -0.0106397);
const vec3  TARGET = vec3(4.52812, 6.09633, -2.29487);
const vec3  CAMERA_UP = vec3(-0.115517, -0.241343, -0.960116);

// Precomputed from EYE / TARGET / CAMERA_UP. This avoids per-pixel normalizations.
const vec3  CAMERA_DIR_FIXED   = vec3( 0.65125953,  0.71373473, -0.25776687);
const vec3  CAMERA_UP_FIXED    = vec3(-0.11589911, -0.24214153, -0.96329376);
const vec3  CAMERA_RIGHT_FIXED = vec3(-0.74995228,  0.65722920, -0.07497576);

const float FOCAL_PLANE = 0.029;
const float INV_FOCAL_PLANE = 1.0 / FOCAL_PLANE;
const float APERTURE = 0.01;
const float IN_FOCUS_WIDTH = 7.1;
const float FOCUS_SHIFT = -26.38275862068965;
const float GAUSSIAN_WEIGHT = 1.0;
const float ANTIALIAS_SCALE = 1.7;

// Fixed 5-sided aperture.
const float NGON_D = 1.3763819204711736;    // cot(PI / 5)
const float NGON_LH = 0.5877852522924731;  // 1.0 / sqrt(1.0 + NGON_D^2)

const int   ITERATIONS = 35;
const int   COLOR_ITERATIONS = 10;
const int   SKIP_COLOR_ITERATIONS = 2;
const float BAILOUT = 2.0;
const vec3  JULIA_C = vec3(-0.28036, -0.88288, -0.00084);

const float GAMMA_VALUE = 2.2;
const float MIN_DIST = 0.00005;
const float FUDGE_FACTOR = 0.55;
const float EPS_SCALE = MIN_DIST * FUDGE_FACTOR;
const int   MAX_RAY_STEPS = 1500;
const int   MAX_SHADOW_STEPS = 96;    // aggressive: secondary rays only; main ray still uses 1500
const float MAX_DISTANCE = 20.0;
const float NORMAL_BACK_STEP = 1.5;

const float SPECULAR = 0.25397;
const float SPECULAR_EXP = 9.722;
const float SPECULAR_MAX = 10.0;
const vec4  CAM_LIGHT = vec4(1.0, 0.803922, 0.627451, 3.4);
const float CAM_LIGHT_MIN = 0.59494;
const vec4  GLOW = vec4(1.0, 0.584314, 0.0, 0.15116);
const int   GLOW_MAX = 100;

const vec4  AO_VALUE = vec4(0.0, 0.0, 0.0, 1.0);
const float AO_EPS = 0.0643472512963583;
const vec3  AO_POW = vec3(1.36448, 1.19626, 2.45244);
const float AO_WEIGHT_MULT = 0.1 * AO_POW.z;

const vec4  SPOT_LIGHT = vec4(0.792157, 1.0, 1.0, 1.0);
const vec3  LIGHT_POS = vec3(3.0338, 3.7078, 1.4606);
const float LIGHT_SIZE = 0.47423;
const float INV_LIGHT_GLOW_RAD2 = 1.0 / ((0.94595 + 0.0001) * (0.94595 + 0.0001));
const float LIGHT_GLOW_EXP = 1.46665;
const float SHADOW_SOFT2 = 27.7332;
const float SHADOW_BLUR = 6.2338;

const vec4 COLOR_X = vec4(0.780392, 0.2, 0.0980392, 1.0);
const vec4 COLOR_Y = vec4(0.223529, 0.988235, 1.0, -0.59596);
const vec4 COLOR_Z = vec4(0.415686, 1.0, 0.0235294, 1.0);
const vec4 COLOR_R = vec4(0.694118, 0.764706, 0.564706, 0.28572);
const vec3 BACKGROUND_COLOR = vec3(0.258824, 0.623529, 0.866667);
const float GRADIENT_BACKGROUND = 1.1905;

const float FOG_DENSITY = 0.2;
const vec3  FOG_COLOR = vec3(0.62714691855, 1.21248251946, 1.52307);

vec4 orbitTrap;
vec2 screenCoord;

float rand1(vec2 p) {
    return fract(sin(dot(p, vec2(12.9898, 78.233))) * 43758.5453);
}

vec2 rand2(vec2 p) {
    return vec2(
        fract(sin(dot(p, vec2(12.9898, 78.233))) * 43758.5453),
        fract(cos(dot(p, vec2(4.898, 7.23))) * 23421.631)
    );
}

vec2 uniformDisc(vec2 p) {
    vec2 r = rand2(p);
    float a = 6.28 * r.x;
    return sqrt(r.y) * vec2(cos(a), sin(a));
}

vec2 nGonDisc(vec2 p) {
    vec2 r = rand2(p);
    vec2 q = vec2(r.x + r.y, r.x - r.y);
    q.x = (1.0 - abs(q.x - 1.0)) * NGON_D;
    q *= NGON_LH;

    float a = floor(dot(rand2(11.0 * p + vec2(1.0)), vec2(1.0)) * 5.0) * (2.0 * PI / 5.0);
    vec2 cs = vec2(cos(a), sin(a));
    return vec2(cs.x * q.x - cs.y * q.y, cs.x * q.y + cs.y * q.x);
}

vec3 currentPt(vec3 ro, vec3 rd, vec3 offset, float rayPos) {
    float t = 1.0 - rayPos * INV_FOCAL_PLANE;
    float d = t - IN_FOCUS_WIDTH *
        (2.0 * smoothstep(-1.5 * IN_FOCUS_WIDTH, 1.5 * IN_FOCUS_WIDTH, t) - 1.0);
    return ro + rd * rayPos + offset * d;
}

vec3 triplexSqr(vec3 a) {
    a = abs(a);
    float r2 = dot(a.xy, a.xy);
    float rz = r2 - a.z * a.z;
    vec2 xy = vec2(a.x * a.x - a.y * a.y, 2.0 * a.x * a.y) / r2;
    return vec3(xy * rz, 2.0 * sqrt(r2) * a.z);
}

float DE(vec3 pos) {
    float lenPos = length(pos);
    float delta = exp2(-18.0 + max(floor(log2(lenPos)), 0.0));
    float invDelta = 1.0 / delta;

    vec3 z  = pos;
    vec3 z2 = pos + vec3(delta, 0.0, 0.0);
    vec3 z3 = pos + vec3(0.0, delta, 0.0);
    vec3 z4 = pos + vec3(0.0, 0.0, delta);

    float r = lenPos;
    for (int i = 0; i < ITERATIONS; ++i) {
        if (r >= BAILOUT) break;

        z  = triplexSqr(z ) + JULIA_C;
        z2 = triplexSqr(z2) + JULIA_C;
        z3 = triplexSqr(z3) + JULIA_C;
        z4 = triplexSqr(z4) + JULIA_C;

        r = length(z);
        if (i >= SKIP_COLOR_ITERATIONS && i < COLOR_ITERATIONS) {
            orbitTrap = min(orbitTrap, abs(vec4(z, r * r)));
        }
    }

    float dr = length(vec3(length(z2 - z), length(z3 - z), length(z4 - z))) * invDelta;
    return max(0.5 * log(r) * r / dr, pos.z);
}

// Same distance estimator as DE(), but without orbit-trap side effects.
// Use this for secondary rays whose result should not affect surface color.
float DEnoTrap(vec3 pos) {
    float lenPos = length(pos);
    float delta = exp2(-18.0 + max(floor(log2(lenPos)), 0.0));
    float invDelta = 1.0 / delta;

    vec3 z  = pos;
    vec3 z2 = pos + vec3(delta, 0.0, 0.0);
    vec3 z3 = pos + vec3(0.0, delta, 0.0);
    vec3 z4 = pos + vec3(0.0, 0.0, delta);

    float r = lenPos;
    for (int i = 0; i < ITERATIONS; ++i) {
        if (r >= BAILOUT) break;

        z  = triplexSqr(z ) + JULIA_C;
        z2 = triplexSqr(z2) + JULIA_C;
        z3 = triplexSqr(z3) + JULIA_C;
        z4 = triplexSqr(z4) + JULIA_C;

        r = length(z);
    }

    float dr = length(vec3(length(z2 - z), length(z3 - z), length(z4 - z))) * invDelta;
    return max(0.5 * log(r) * r / dr, pos.z);
}

float DElight(vec3 p) {
    return length(p + LIGHT_POS) - LIGHT_SIZE;
}

vec3 normalAt(vec3 p, float normalDistance) {
    // Tetrahedral normal: 4 DE evaluations instead of central differences' 6.
    // Uses DEnoTrap so normal sampling does not overwrite the hit orbit color.
    float h = max(0.65 * normalDistance, 1.0e-5);
    vec2 k = vec2(1.0, -1.0);
    return normalize(
        k.xyy * DEnoTrap(p + k.xyy * h) +
        k.yyx * DEnoTrap(p + k.yyx * h) +
        k.yxy * DEnoTrap(p + k.yxy * h) +
        k.xxx * DEnoTrap(p + k.xxx * h)
    );
}

float shadowMarch(vec3 pos, vec3 dir, float eps, out bool hit) {
    float s = 1.0;
    float totalDist = 2.0 * eps;
    hit = false;

    for (int i = 0; i < MAX_SHADOW_STEPS; ++i) {
        if (totalDist >= MAX_DISTANCE) break;

        vec3 p = pos + totalDist * dir;
        float lightDE = DElight(p);
        float dist = min(DEnoTrap(p), lightDE);

        if (dist < eps) {
            hit = true;
            return (dist == lightDE) ? 0.0 : 1.0;
        }

        s = min(s, 30.0 * SHADOW_SOFT2 * dist / totalDist);
        if (s < 0.001) break;
        totalDist += dist;
    }

    return s;
}

float shadow(vec3 pos, vec3 sdir, float eps) {
    // Single soft-shadow march. This is the biggest safe-ish speedup after capping
    // shadow steps: one expensive secondary march instead of two.
    // Keep the same deterministic blur direction so the accumulated image is stable.
    vec3 axis = (abs(sdir.x) > 0.9) ? vec3(0.0, 1.0, 0.0)
                                    : vec3(1.0, 0.0, 0.0);
    vec3 perp = normalize(cross(sdir, axis));
    vec3 perp2 = cross(sdir, perp);

    float angle = PI * rand1(vec2(pos.x, pos.y + pos.z)) + 2.0 * PI / 3.0;
    float fac = SHADOW_BLUR / SHADOW_SOFT2 * rand1(vec2(pos.y, pos.x + pos.z));
    vec3 sdirBlur = normalize(sdir + fac * (perp * cos(angle) + perp2 * sin(angle)));

    bool hit;
    float s = shadowMarch(pos, sdirBlur, eps, hit);
    if (hit) return s;
    return 1.0 - s;
}

float ambientOcclusion(vec3 p, vec3 n) {
    // 3-sample AO instead of 5. The later samples are broad/low-frequency and
    // relatively expensive for this DE, so dropping them is usually hard to see.
    float de0 = DEnoTrap(p);
    float ao = 0.0;
    float wSum = 0.0;
    float w = 1.0;

    for (int i = 1; i < 4; ++i) {
        float fi = float(i);
        float scale = fi * fi * AO_EPS;
        float D = (DEnoTrap(p + n * scale * AO_POW.x) - de0) / (scale * AO_POW.y);
        w *= AO_WEIGHT_MULT;
        ao += w * clamp(1.0 - D, 0.0, 1.0);
        wSum += w;
    }

    return clamp(AO_VALUE.w * ao / wSum, 0.0, 1.0);
}

vec3 getColor() {
    orbitTrap.w = sqrt(orbitTrap.w);
    return 3.0 * (
        COLOR_X.rgb * COLOR_X.w * orbitTrap.x +
        COLOR_Y.rgb * COLOR_Y.w * orbitTrap.y +
        COLOR_Z.rgb * COLOR_Z.w * orbitTrap.z +
        COLOR_R.rgb * COLOR_R.w * orbitTrap.w
    );
}

vec3 lighting(vec3 n, vec3 color, vec3 pos, vec3 rd, float eps, float ao) {
    // Analytic normal of DElight sphere. Equivalent to -lightNormal(pos, eps).
    vec3 spotDir = normalize(-pos - LIGHT_POS);
    vec3 halfVector = normalize(spotDir - rd);
    float hDotN = max(0.0, dot(n, halfVector));

    float f0 = (SPECULAR_EXP - 1.0) / (SPECULAR_EXP + 1.0);
    f0 *= f0;

    // AO_CORRECT = 1.0, so nDotL = max(1.0, dot(n, spotDir)) is effectively 1.0.
    float specular = ((SPECULAR_EXP + 2.0) / 8.0)
                   * (f0 + (1.0 - f0) * pow(1.0 + dot(n, rd), 5.0))
                   * pow(hDotN, SPECULAR_EXP + 0.00001)
                   * SPECULAR;
    specular = min(SPECULAR_MAX, specular);

    float sh = shadow(pos + n * eps, spotDir, eps);
    return (
        SPOT_LIGHT.rgb * ((1.0 - sh) + specular * (1.0 - sh)) +
        CAM_LIGHT.rgb * CAM_LIGHT.w * max(CAM_LIGHT_MIN, dot(-n, rd)) * (1.0 - ao)
    ) * color;
}

vec3 trace(vec3 ro, vec3 rd, vec3 offset, float rayFudge, inout float rayPos, out float glow) {
    glow = 1000.0;
    orbitTrap = vec4(10000.0);

    float fSteps = 1.0;
    float dist = 0.0;
    float lightDE = 0.0;
    float eps = max(MIN_EPS, rayPos * EPS_SCALE);

    vec3 p = currentPt(ro, rd, offset, rayPos);
    rayPos += DE(p) * FUDGE_FACTOR * rayFudge;

    int steps = 0;
    for (; steps < MAX_RAY_STEPS; ++steps) {
        p = currentPt(ro, rd, offset, rayPos);

        float de = DE(p);
        lightDE = DElight(p);
        dist = min(de * FUDGE_FACTOR, lightDE);

        glow = min(glow, lightDE);
        rayPos += dist * rayFudge;
        fSteps += 1.0;

        eps = max(MIN_EPS, rayPos * EPS_SCALE);
        if (dist < eps) {
            rayPos += (dist - 2.5 * eps) * rayFudge;
            break;
        }

        if (rayPos > MAX_DISTANCE) {
            fSteps -= (rayPos - MAX_DISTANCE) / dist;
            break;
        }
    }

    vec3 backColor = BACKGROUND_COLOR * (1.0 - length(screenCoord) * GRADIENT_BACKGROUND);
    if (steps == MAX_RAY_STEPS) orbitTrap = vec4(0.0);

    if (dist < eps) {
        if (dist == lightDE) return SPOT_LIGHT.rgb * 2.0;

        vec3 hit = currentPt(ro, rd, offset, rayPos);
        vec3 n = normalAt(hit - NORMAL_BACK_STEP * eps * rd, eps);
        vec3 hitColor = pow(clamp(getColor(), 0.0, 1.0), vec3(GAMMA_VALUE));
        return lighting(n, hitColor, hit, rd, eps, ambientOcclusion(hit, n));
    }

    rayPos = 10000.0;
    return backColor + GLOW.rgb * clamp(fSteps / float(GLOW_MAX), 0.0, 1.0) * GLOW.w;
}

vec3 renderColor(vec3 ro, vec3 rd, vec3 offset, float rayFudge) {
    float rayPos = 0.0;
    float glow;
    vec3 p0 = currentPt(ro, rd, offset, rayPos);
    vec3 col = trace(ro, rd, offset, rayFudge, rayPos, glow);
    vec3 p1 = currentPt(ro, rd, offset, rayPos);

    float fog = 1.0 - exp(-FOG_DENSITY * length(p1 - p0));
    float g = max(glow, 0.0);
    return mix(col, FOG_COLOR, fog) + SPOT_LIGHT.rgb *
        (SPOT_LIGHT.w * exp(-20.0 * g) + exp(-INV_LIGHT_GLOW_RAD2 * pow(g, LIGHT_GLOW_EXP)));
}

void mainImage(out vec4 fragColor, in vec2 fragCoord) {
    vec2 invRes = 1.0 / iResolution.xy;
    vec2 uv = fragCoord * invRes;
    screenCoord = (2.0 * fragCoord - iResolution.xy) * (FOV * invRes.y);

    vec3 cameraDir = CAMERA_DIR_FIXED;
    vec3 up = CAMERA_UP_FIXED;
    vec3 right = CAMERA_RIGHT_FIXED;

    float frame = float(iFrame) + 1.0;
    vec2 apertureSample = APERTURE * nGonDisc((uv * 2.0 - 1.0) * frame);
    vec2 disc = uniformDisc(screenCoord * frame);
    vec2 jitteredCoord = screenCoord + ANTIALIAS_SCALE * FOV * disc * invRes.y;

    vec3 lensOffset = apertureSample.x * right + apertureSample.y * up;
    vec3 rayDir = cameraDir + jitteredCoord.x * right + jitteredCoord.y * up;

    float rayFudge = 1.0 / max(1.0, length(rayDir + lensOffset * FOCUS_SHIFT));

    vec3 color = renderColor(EYE, normalize(rayDir), lensOffset, rayFudge);

    vec4 previous = (iFrame == 0) ? vec4(0.0) : texture(iChannel0, uv);
    float weight = exp(-dot(disc, disc) / GAUSSIAN_WEIGHT) - exp(-1.0 / GAUSSIAN_WEIGHT);
    fragColor = previous + vec4(color * weight, weight);
}
